{
  "name": "Pomo Deep",
  "description": "Advanced Pomodoro timer with distraction-free focus mode, integrated note-taking, and an action-oriented inbox system."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum TimerMode {
  FOCUS = 'FOCUS',
  SHORT_BREAK = 'SHORT_BREAK',
  LONG_BREAK = 'LONG_BREAK',
}

export interface Note {
  id: string;
  content: string;
  createdAt: Date;
}

export interface InboxItem {
  id: string;
  noteContent: string;
  createdAt: Date;
  deadline: Date;
  status: 'pending' | 'completed' | 'scheduled';
  nextAction?: string;
  scheduledDate?: Date;
}

export interface UserCredits {
  available: number;
  used: number;
}

export interface Settings {
  focusDuration: number; // in minutes
  shortBreakDuration: number;
  longBreakDuration: number;
  longBreakInterval: number;
}

export type View = 'timer' | 'inbox' | 'dashboard' | 'settings';

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export const formatTime = (seconds: number): string => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
};

export const calculateDaysRemaining = (deadline: Date): number => {
  const now = new Date();
  const diffTime = deadline.getTime() - now.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  return diffDays;
};

export const generateId = () => Math.random().toString(36).substr(2, 9);

import React, { useState, useEffect, useCallback } from 'react';
import { Play, Pause, RotateCcw, Lock, Unlock, CheckCircle2, Coffee, Zap } from 'lucide-react';
import { TimerMode, Settings } from '../types';
import { formatTime, cn } from '../utils';

interface TimerProps {
  settings: Settings;
  onSessionComplete: (mode: TimerMode) => void;
  onNoteChange: (note: string) => void;
  currentNote: string;
}

const Timer: React.FC<TimerProps> = ({ settings, onSessionComplete, onNoteChange, currentNote }) => {
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const [isFocusLocked, setIsFocusLocked] = useState(false);

  // Initialize timer based on settings changes or mode changes
  useEffect(() => {
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  }, [mode, settings]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      if (newCompleted % settings.longBreakInterval === 0) {
        setMode(TimerMode.LONG_BREAK);
      } else {
        setMode(TimerMode.SHORT_BREAK);
      }
    } else {
      setMode(TimerMode.FOCUS);
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      setIsFocusLocked(false); // Auto unlock on finish
      onSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, onSessionComplete, switchMode]);

  const toggleTimer = () => {
    if (!isActive && mode === TimerMode.FOCUS) {
      // Allow user to choose if they want lock screen or not, enforcing it for now for "Deep" feel
      setIsFocusLocked(true); 
    }
    setIsActive(!isActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    setIsFocusLocked(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const progress = 100 - (timeLeft / ((mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60)) * 100;

  // Render Full Screen Lock Mode
  if (isFocusLocked && isActive) {
    return (
      <div className="fixed inset-0 z-50 bg-slate-900 text-white flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
        <div className="absolute top-8 left-8 flex items-center gap-2 opacity-50">
          <Lock className="w-5 h-5" />
          <span className="text-sm font-medium tracking-widest uppercase">Deep Work Mode Locked</span>
        </div>

        <div className="text-[12rem] font-bold tabular-nums leading-none tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-orange-400 to-red-600 select-none">
          {formatTime(timeLeft)}
        </div>

        <div className="mt-12 w-full max-w-2xl space-y-4">
          <p className="text-center text-slate-400 mb-2 text-sm uppercase tracking-wide">Capture thoughts quickly & return to focus</p>
          <textarea
            value={currentNote}
            onChange={(e) => onNoteChange(e.target.value)}
            placeholder="Type your distraction/idea here..."
            className="w-full h-32 bg-slate-800/50 border border-slate-700 rounded-xl p-6 text-lg text-slate-200 focus:outline-none focus:ring-2 focus:ring-orange-500/50 resize-none transition-all"
            autoFocus
          />
        </div>

        <button 
          onClick={() => setIsFocusLocked(false)}
          className="absolute bottom-8 text-slate-500 hover:text-white transition-colors flex items-center gap-2 text-sm"
        >
           <Unlock className="w-4 h-4" /> Pause & Unlock
        </button>
      </div>
    );
  }

  // Normal UI
  return (
    <div className="flex flex-col items-center w-full max-w-xl mx-auto space-y-8 py-8">

      {/* Mode Indicator */}
      <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200">
        <button
          onClick={() => { setMode(TimerMode.FOCUS); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.FOCUS ? "bg-orange-100 text-orange-700 shadow-sm" : "text-slate-500 hover:text-slate-700")}
        >
          Deep Focus
        </button>
        <button
          onClick={() => { setMode(TimerMode.SHORT_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.SHORT_BREAK ? "bg-blue-100 text-blue-700 shadow-sm" : "text-slate-500 hover:text-slate-700")}
        >
          Short Break
        </button>
        <button
          onClick={() => { setMode(TimerMode.LONG_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.LONG_BREAK ? "bg-indigo-100 text-indigo-700 shadow-sm" : "text-slate-500 hover:text-slate-700")}
        >
          Long Break
        </button>
      </div>

      {/* Timer Display */}
      <div className="relative w-80 h-80 flex items-center justify-center">
        {/* SVG Progress Circle */}
        <svg className="absolute inset-0 w-full h-full transform -rotate-90">
          <circle
            cx="160"
            cy="160"
            r="150"
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            className="text-slate-100"
          />
          <circle
            cx="160"
            cy="160"
            r="150"
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            strokeDasharray={2 * Math.PI * 150}
            strokeDashoffset={2 * Math.PI * 150 * (1 - progress / 100)}
            className={cn("transition-all duration-1000 ease-linear", 
              mode === TimerMode.FOCUS ? "text-orange-500" : "text-blue-500"
            )}
            strokeLinecap="round"
          />
        </svg>

        <div className="flex flex-col items-center z-10">
          <span className="text-7xl font-bold text-slate-800 tracking-tighter tabular-nums">
            {formatTime(timeLeft)}
          </span>
          <span className="text-slate-400 mt-2 font-medium uppercase tracking-widest text-xs">
            {isActive ? 'Running' : 'Paused'}
          </span>
        </div>
      </div>

      {/* Controls */}
      <div className="flex items-center gap-6">
        <button
          onClick={toggleTimer}
          className={cn(
            "h-16 w-16 rounded-2xl flex items-center justify-center shadow-lg hover:shadow-xl hover:-translate-y-1 transition-all",
            isActive ? "bg-slate-100 text-slate-600" : "bg-slate-900 text-white"
          )}
        >
          {isActive ? <Pause className="w-8 h-8" /> : <Play className="w-8 h-8 ml-1" />}
        </button>

        <button
          onClick={resetTimer}
          className="h-12 w-12 rounded-xl bg-slate-100 text-slate-500 flex items-center justify-center hover:bg-slate-200 transition-all"
        >
          <RotateCcw className="w-5 h-5" />
        </button>
      </div>

      {/* Session Stats */}
      <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-xl border border-slate-100 shadow-sm">
        <div className="flex items-center gap-2">
            <Zap className="w-4 h-4 text-orange-500" />
            <span>{sessionsCompleted} Sessions</span>
        </div>
        <div className="w-px h-4 bg-slate-200"></div>
        <div className="flex items-center gap-2">
            <Coffee className="w-4 h-4 text-blue-500" />
            <span>Next: {sessionsCompleted > 0 && (sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long Break' : 'Short Break'}</span>
        </div>
      </div>
    </div>
  );
};

export default Timer;

import React from 'react';
import { InboxItem } from '../types';
import { calculateDaysRemaining, cn } from '../utils';
import { Trash2, Calendar, ArrowRightCircle, CheckCircle, AlertCircle } from 'lucide-react';

interface InboxProps {
  items: InboxItem[];
  onAction: (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction') => void;
}

const Inbox: React.FC<InboxProps> = ({ items, onAction }) => {
  const pendingItems = items.filter(i => i.status === 'pending');

  if (pendingItems.length === 0) {
    return (
        <div className="flex flex-col items-center justify-center h-96 text-center p-8">
            <div className="bg-green-50 rounded-full p-6 mb-4">
                <CheckCircle className="w-12 h-12 text-green-500" />
            </div>
            <h3 className="text-xl font-semibold text-slate-900 mb-2">Inbox Zero!</h3>
            <p className="text-slate-500 max-w-sm">You have processed all your notes. Start a new session to capture more ideas.</p>
        </div>
    )
  }

  return (
    <div className="w-full max-w-4xl mx-auto py-8 px-4">
      <div className="flex items-center justify-between mb-8">
        <h2 className="text-2xl font-bold text-slate-900">Inbox Processing</h2>
        <span className="bg-orange-100 text-orange-700 px-3 py-1 rounded-full text-xs font-semibold">
            {pendingItems.length} Pending
        </span>
      </div>

      <div className="grid gap-4">
        {pendingItems.map((item) => {
          const daysLeft = calculateDaysRemaining(item.deadline);
          const isUrgent = daysLeft <= 2;

          return (
            <div 
              key={item.id} 
              className="bg-white rounded-xl p-6 shadow-sm border border-slate-100 hover:shadow-md transition-shadow flex flex-col md:flex-row gap-6 items-start md:items-center justify-between group"
            >
              <div className="flex-1 space-y-2">
                <p className="text-lg text-slate-800 font-medium leading-relaxed">{item.noteContent}</p>
                <div className="flex items-center gap-3 text-xs">
                  <span className={cn(
                    "px-2 py-1 rounded-md font-medium flex items-center gap-1",
                    isUrgent ? "bg-red-50 text-red-600" : "bg-slate-100 text-slate-500"
                  )}>
                    <AlertCircle className="w-3 h-3" />
                    {daysLeft} days remaining
                  </span>
                  <span className="text-slate-400">Created {item.createdAt.toLocaleDateString()}</span>
                </div>
              </div>

              <div className="flex items-center gap-2 w-full md:w-auto">
                <button
                    onClick={() => onAction(item.id, 'schedule')}
                    className="flex-1 md:flex-none flex flex-col items-center justify-center gap-1 p-3 rounded-lg hover:bg-slate-50 text-slate-500 hover:text-blue-600 transition-colors border border-transparent hover:border-slate-200"
                    title="Schedule in Calendar"
                >
                    <Calendar className="w-5 h-5" />
                    <span className="text-[10px] uppercase font-bold tracking-wider">Plan</span>
                </button>

                <button
                    onClick={() => onAction(item.id, 'nextAction')}
                    className="flex-1 md:flex-none flex flex-col items-center justify-center gap-1 p-3 rounded-lg hover:bg-slate-50 text-slate-500 hover:text-indigo-600 transition-colors border border-transparent hover:border-slate-200"
                    title="Define Next Action"
                >
                    <ArrowRightCircle className="w-5 h-5" />
                    <span className="text-[10px] uppercase font-bold tracking-wider">Act</span>
                </button>

                <div className="w-px h-8 bg-slate-200 mx-2 hidden md:block"></div>

                <button
                    onClick={() => onAction(item.id, 'complete')}
                    className="flex-1 md:flex-none flex flex-col items-center justify-center gap-1 p-3 rounded-lg hover:bg-slate-50 text-slate-500 hover:text-green-600 transition-colors border border-transparent hover:border-slate-200"
                    title="Done"
                >
                    <CheckCircle className="w-5 h-5" />
                    <span className="text-[10px] uppercase font-bold tracking-wider">Done</span>
                </button>

                <button
                    onClick={() => onAction(item.id, 'delete')}
                    className="flex-1 md:flex-none flex flex-col items-center justify-center gap-1 p-3 rounded-lg hover:bg-slate-50 text-slate-500 hover:text-red-500 transition-colors border border-transparent hover:border-slate-200"
                    title="Delete"
                >
                    <Trash2 className="w-5 h-5" />
                    <span className="text-[10px] uppercase font-bold tracking-wider">Del</span>
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Inbox;

import React from 'react';
import { View } from '../types';
import { Timer, Inbox as InboxIcon, BarChart2, Settings, LogOut } from 'lucide-react';
import { cn } from '../utils';

interface SidebarProps {
  currentView: View;
  onChangeView: (view: View) => void;
  badgeCount?: number;
}

const Sidebar: React.FC<SidebarProps> = ({ currentView, onChangeView, badgeCount }) => {
  const NavItem = ({ view, icon: Icon, label }: { view: View; icon: React.ElementType; label: string }) => (
    <button
      onClick={() => onChangeView(view)}
      className={cn(
        "w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all group relative",
        currentView === view 
          ? "bg-slate-900 text-white shadow-md" 
          : "text-slate-500 hover:bg-slate-100 hover:text-slate-900"
      )}
    >
      <Icon className={cn("w-5 h-5", currentView === view ? "text-orange-400" : "text-current")} />
      <span className="font-medium">{label}</span>
      {view === 'inbox' && badgeCount && badgeCount > 0 && (
        <span className="absolute right-3 top-3 w-2 h-2 rounded-full bg-red-500"></span>
      )}
    </button>
  );

  return (
    <div className="w-64 h-screen bg-white border-r border-slate-200 flex flex-col p-6 fixed left-0 top-0">
      <div className="mb-10 px-2 flex items-center gap-2">
        <div className="w-8 h-8 bg-gradient-to-br from-orange-400 to-red-600 rounded-lg shadow-sm"></div>
        <h1 className="text-xl font-bold tracking-tight text-slate-900">Pomo<span className="text-slate-400">Deep</span></h1>
      </div>

      <nav className="space-y-2 flex-1">
        <NavItem view="timer" icon={Timer} label="Focus Timer" />
        <NavItem view="inbox" icon={InboxIcon} label="Inbox" />
        <NavItem view="dashboard" icon={BarChart2} label="Dashboard" />
      </nav>

      <div className="pt-6 border-t border-slate-100 space-y-2">
         <NavItem view="settings" icon={Settings} label="Settings" />
         <button className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-slate-400 hover:text-slate-600 hover:bg-slate-50 transition-all">
            <LogOut className="w-5 h-5" />
            <span className="font-medium">Sign Out</span>
         </button>
      </div>

      <div className="mt-6 px-4 py-4 bg-slate-50 rounded-xl border border-slate-100">
        <p className="text-xs font-semibold text-slate-900 mb-1">Pro Plan Active</p>
        <p className="text-[10px] text-slate-500 leading-tight">Next billing: Oct 24, 2024</p>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Timer from './components/Timer';
import Inbox from './components/Inbox';
import Dashboard from './components/Dashboard';
import { View, TimerMode, InboxItem, Settings, UserCredits } from './types';
import { generateId } from './utils';

// Mock Data
const INITIAL_SETTINGS: Settings = {
  focusDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  longBreakInterval: 4,
};

const INITIAL_INBOX: InboxItem[] = [
  {
    id: '1',
    noteContent: 'Research API endpoints for Notion integration',
    createdAt: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000), // 3 days ago
    deadline: new Date(Date.now() + 5 * 24 * 60 * 60 * 1000),
    status: 'pending',
  },
  {
    id: '2',
    noteContent: 'Email client about project roadmap changes',
    createdAt: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000), // 7 days ago (urgent)
    deadline: new Date(Date.now() + 1 * 24 * 60 * 60 * 1000),
    status: 'pending',
  }
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState<string>('');
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });

  // Cron Job Simulation: Check for expired notes every minute
  useEffect(() => {
    const checkExpiration = () => {
      const now = new Date();
      setInbox(prev => prev.filter(item => item.deadline > now));
    };

    const interval = setInterval(checkExpiration, 60000);
    return () => clearInterval(interval);
  }, []);

  const handleSessionComplete = (mode: TimerMode) => {
    if (mode === TimerMode.FOCUS && currentNote.trim().length > 0) {
      // Save note to Inbox automatically
      const newItem: InboxItem = {
        id: generateId(),
        noteContent: currentNote,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), // 8 days from now
        status: 'pending'
      };
      setInbox(prev => [newItem, ...prev]);
      setCurrentNote('');
      // Show simple notification (using alert for MVP)
      // alert('Note saved to Inbox!');
    }
  };

  const handleInboxAction = (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction') => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else {
        // For other actions, we mark it as processed (completed/scheduled)
        // In a real app, this would trigger modals for GCal or Notion
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: action === 'schedule' ? 'scheduled' : 'completed' } : i));

        if (action === 'schedule') alert('Opened Google Calendar Integration Mock');
        if (action === 'nextAction') alert('Opened Next Action Definition Mock');
    }
  };

  const handleExport = (type: string) => {
      if (credits.available > 0) {
          setCredits(prev => ({ ...prev, available: prev.available - 1, used: prev.used + 1}));
          alert(`Exporting to ${type}... Credit deducted.`);
      } else {
          alert('Insufficient credits. Please upgrade.');
      }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 font-sans">
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        badgeCount={inbox.filter(i => i.status === 'pending').length}
      />

      <main className="flex-1 ml-64 p-8 overflow-y-auto h-screen">
        <header className="mb-8 flex justify-between items-center">
             <div>
                <h2 className="text-2xl font-bold text-slate-900 capitalize">
                    {currentView === 'timer' ? 'Focus Session' : currentView}
                </h2>
                <p className="text-slate-500 text-sm">
                    {currentView === 'timer' ? 'Stay in the flow.' : 'Manage your outcomes.'}
                </p>
             </div>
             {/* Simple User Profile Mock */}
             <div className="flex items-center gap-3">
                <div className="text-right hidden sm:block">
                    <p className="text-sm font-medium text-slate-900">Alex Designer</p>
                    <p className="text-xs text-slate-500">Free Tier</p>
                </div>
                <div className="w-10 h-10 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden">
                    <img src="https://picsum.photos/100/100" alt="Avatar" className="w-full h-full object-cover" />
                </div>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            {currentView === 'timer' && (
            <Timer 
                settings={settings} 
                onSessionComplete={handleSessionComplete}
                onNoteChange={setCurrentNote}
                currentNote={currentNote}
            />
            )}

            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} />
            )}

            {currentView === 'dashboard' && (
            <Dashboard credits={credits} onExport={handleExport} />
            )}

            {currentView === 'settings' && (
                <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl border border-slate-100 shadow-sm">
                    <h3 className="text-lg font-bold mb-6">Timer Configuration</h3>
                    <div className="space-y-6">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">Deep Work Duration (min)</label>
                            <input 
                                type="range" 
                                min="15" 
                                max="60" 
                                value={settings.focusDuration}
                                onChange={(e) => setSettings({...settings, focusDuration: parseInt(e.target.value)})}
                                className="w-full accent-orange-500" 
                            />
                            <div className="flex justify-between text-xs text-slate-400 mt-1">
                                <span>15m</span>
                                <span className="font-bold text-orange-600">{settings.focusDuration}m</span>
                                <span>60m</span>
                            </div>
                        </div>

                        <div className="flex items-center justify-between pt-4 border-t border-slate-100">
                             <div>
                                <h4 className="font-medium text-slate-900">Deep Work Extension</h4>
                                <p className="text-xs text-slate-500">Enable 1 hour deep work sessions</p>
                             </div>
                             <button 
                                onClick={() => setSettings(prev => ({...prev, focusDuration: prev.focusDuration === 60 ? 25 : 60}))}
                                className={
                                    `w-12 h-6 rounded-full transition-colors relative ${settings.focusDuration === 60 ? 'bg-orange-500' : 'bg-slate-200'}`
                                }
                             >
                                <span className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform ${settings.focusDuration === 60 ? 'translate-x-6' : ''}`} />
                             </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
      </main>
    </div>
  );
};

export default App;

export enum TimerMode {
  FOCUS = 'FOCUS',
  SHORT_BREAK = 'SHORT_BREAK',
  LONG_BREAK = 'LONG_BREAK',
}

export interface Note {
  id: string;
  content: string;
  createdAt: Date;
}

export interface InboxItem {
  id: string;
  noteContent: string;
  createdAt: Date;
  deadline: Date;
  status: 'pending' | 'completed' | 'scheduled';
  nextAction?: string;
  scheduledDate?: Date;
}

export interface UserCredits {
  available: number;
  used: number;
}

export interface Settings {
  focusDuration: number; // in minutes
  shortBreakDuration: number;
  longBreakDuration: number;
  longBreakInterval: number;
}

export interface SessionHistoryItem {
  id: string;
  startTime: Date;
  endTime: Date;
  mode: TimerMode;
  duration: number; // in minutes
  noteSnapshot?: string;
}

