import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Play, Pause, RotateCcw, Lock, Unlock, CheckCircle2, Coffee, Zap } from 'lucide-react';
import { TimerMode, Settings } from '../types';
import { formatTime, cn } from '../utils';

interface TimerProps {
  settings: Settings;
  onSessionComplete: (mode: TimerMode) => void;
  onNoteChange: (note: string) => void;
  currentNote: string;
}

const Timer: React.FC<TimerProps> = ({ settings, onSessionComplete, onNoteChange, currentNote }) => {
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const [isFocusLocked, setIsFocusLocked] = useState(false);
  const startTimeRef = useRef<Date | null>(null);

  // Request notification permissions
  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  // Initialize timer based on settings changes or mode changes
  useEffect(() => {
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  }, [mode, settings]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      if (newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      setIsFocusLocked(false); // Auto unlock on finish
      onSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, onSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      // Allow user to choose if they want lock screen or not, enforcing it for now for "Deep" feel
      setIsFocusLocked(true); 
      sendNotification("Deep Work Started", "Stay focused and minimize distractions.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    setIsFocusLocked(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const progress = 100 - (timeLeft / ((mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60)) * 100;

  // Render Full Screen Lock Mode
  if (isFocusLocked && isActive) {
    return (
      <div className="fixed inset-0 z-50 bg-slate-900 text-white flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
        <div className="absolute top-8 left-8 flex items-center gap-2 opacity-50">
          <Lock className="w-5 h-5" />
          <span className="text-sm font-medium tracking-widest uppercase">Deep Work Mode Locked</span>
        </div>

        <div className="text-[12rem] font-bold tabular-nums leading-none tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-orange-400 to-red-600 select-none">
          {formatTime(timeLeft)}
        </div>

        <div className="mt-12 w-full max-w-2xl space-y-4">
          <p className="text-center text-slate-400 mb-2 text-sm uppercase tracking-wide">Capture thoughts quickly & return to focus</p>
          <textarea
            value={currentNote}
            onChange={(e) => onNoteChange(e.target.value)}
            placeholder="Type your distraction/idea here..."
            className="w-full h-32 bg-slate-800/50 border border-slate-700 rounded-xl p-6 text-lg text-slate-200 focus:outline-none focus:ring-2 focus:ring-orange-500/50 resize-none transition-all"
            autoFocus
          />
        </div>

        <button 
          onClick={() => setIsFocusLocked(false)}
          className="absolute bottom-8 text-slate-500 hover:text-white transition-colors flex items-center gap-2 text-sm"
        >
           <Unlock className="w-4 h-4" /> Pause & Unlock
        </button>
      </div>
    );
  }

  // Normal UI
  return (
    <div className="flex flex-col items-center w-full max-w-xl mx-auto space-y-8 py-8">

      {/* Mode Indicator */}
      <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700">
        <button
          onClick={() => { setMode(TimerMode.FOCUS); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.FOCUS ? "bg-orange-100 text-orange-700 shadow-sm dark:bg-orange-900/50 dark:text-orange-200" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Deep Focus
        </button>
        <button
          onClick={() => { setMode(TimerMode.SHORT_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.SHORT_BREAK ? "bg-blue-100 text-blue-700 shadow-sm dark:bg-blue-900/50 dark:text-blue-200" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Short Break
        </button>
        <button
          onClick={() => { setMode(TimerMode.LONG_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.LONG_BREAK ? "bg-indigo-100 text-indigo-700 shadow-sm dark:bg-indigo-900/50 dark:text-indigo-200" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Long Break
        </button>
      </div>

      {/* Timer Display */}
      <div className="relative w-80 h-80 flex items-center justify-center">
        {/* SVG Progress Circle */}
        <svg className="absolute inset-0 w-full h-full transform -rotate-90">
          <circle
            cx="160"
            cy="160"
            r="150"
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            className="text-slate-100 dark:text-slate-800"
          />
          <circle
            cx="160"
            cy="160"
            r="150"
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            strokeDasharray={2 * Math.PI * 150}
            strokeDashoffset={2 * Math.PI * 150 * (1 - progress / 100)}
            className={cn("transition-all duration-1000 ease-linear", 
              mode === TimerMode.FOCUS ? "text-orange-500" : "text-blue-500"
            )}
            strokeLinecap="round"
          />
        </svg>

        <div className="flex flex-col items-center z-10">
          <span className="text-7xl font-bold text-slate-800 tracking-tighter tabular-nums dark:text-slate-100">
            {formatTime(timeLeft)}
          </span>
          <span className="text-slate-400 mt-2 font-medium uppercase tracking-widest text-xs dark:text-slate-500">
            {isActive ? 'Running' : 'Paused'}
          </span>
        </div>
      </div>

      {/* Controls */}
      <div className="flex items-center gap-6">
        <button
          onClick={toggleTimer}
          className={cn(
            "h-16 w-16 rounded-2xl flex items-center justify-center shadow-lg hover:shadow-xl hover:-translate-y-1 transition-all",
            isActive ? "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : "bg-slate-900 text-white dark:bg-orange-600 dark:text-white"
          )}
        >
          {isActive ? <Pause className="w-8 h-8" /> : <Play className="w-8 h-8 ml-1" />}
        </button>

        <button
          onClick={resetTimer}
          className="h-12 w-12 rounded-xl bg-slate-100 text-slate-500 flex items-center justify-center hover:bg-slate-200 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700"
        >
          <RotateCcw className="w-5 h-5" />
        </button>
      </div>

      {/* Session Stats */}
      <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-xl border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400">
        <div className="flex items-center gap-2">
            <Zap className="w-4 h-4 text-orange-500" />
            <span>{sessionsCompleted} Sessions</span>
        </div>
        <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
        <div className="flex items-center gap-2">
            <Coffee className="w-4 h-4 text-blue-500" />
            <span>Next: {sessionsCompleted > 0 && (sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long Break' : 'Short Break'}</span>
        </div>
      </div>
    </div>
  );
};

export default Timer;

import React, { useState } from 'react';
import { SessionHistoryItem, TimerMode } from '../types';
import { Clock, Calendar, Search } from 'lucide-react';
import { cn } from '../utils';

interface HistoryProps {
  history: SessionHistoryItem[];
}

const History: React.FC<HistoryProps> = ({ history }) => {
  const [filterMode, setFilterMode] = useState<'ALL' | TimerMode>('ALL');

  // Calculate date 7 days ago for default filter
  const defaultStartDate = new Date();
  defaultStartDate.setDate(defaultStartDate.getDate() - 30);

  const [startDate, setStartDate] = useState<string>(defaultStartDate.toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const filteredHistory = history.filter(item => {
    const itemDate = new Date(item.startTime);
    const start = new Date(startDate);
    const end = new Date(endDate);
    end.setHours(23, 59, 59, 999); // Include full end day

    const dateMatch = itemDate >= start && itemDate <= end;
    const modeMatch = filterMode === 'ALL' || item.mode === filterMode;

    return dateMatch && modeMatch;
  });

  const totalMinutes = filteredHistory.reduce((acc, curr) => acc + curr.duration, 0);

  return (
    <div className="w-full max-w-5xl mx-auto py-8 px-4 space-y-8">

      {/* Filters */}
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 dark:bg-slate-900 dark:border-slate-800">
        <div className="flex flex-col md:flex-row gap-6 items-end md:items-center justify-between">
          <div className="flex flex-col md:flex-row gap-4 w-full md:w-auto">
            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-1 dark:text-slate-400">From</label>
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-orange-500 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-1 dark:text-slate-400">To</label>
              <input 
                type="date" 
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-orange-500 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
              />
            </div>
            <div className="w-full md:w-48">
              <label className="block text-xs font-semibold text-slate-500 mb-1 dark:text-slate-400">Session Type</label>
              <select 
                value={filterMode}
                onChange={(e) => setFilterMode(e.target.value as 'ALL' | TimerMode)}
                className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-orange-500 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
              >
                <option value="ALL">All Types</option>
                <option value={TimerMode.FOCUS}>Deep Focus</option>
                <option value={TimerMode.SHORT_BREAK}>Short Break</option>
                <option value={TimerMode.LONG_BREAK}>Long Break</option>
              </select>
            </div>
          </div>

          <div className="text-right">
             <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">Total Time</p>
             <p className="text-2xl font-bold text-slate-900 dark:text-white">
                {Math.floor(totalMinutes / 60)}h {totalMinutes % 60}m
             </p>
          </div>
        </div>
      </div>

      {/* List */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden dark:bg-slate-900 dark:border-slate-800">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100 dark:bg-slate-800 dark:border-slate-700">
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider dark:text-slate-400">Date & Time</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider dark:text-slate-400">Type</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider dark:text-slate-400">Duration</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider dark:text-slate-400">Notes Snapshot</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {filteredHistory.length > 0 ? filteredHistory.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors dark:hover:bg-slate-800/50">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                        <span className="text-sm font-medium text-slate-900 dark:text-slate-200">{item.startTime.toLocaleDateString()}</span>
                        <span className="text-xs text-slate-500 dark:text-slate-500">
                            {item.startTime.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                            {item.endTime.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                        </span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={cn(
                        "px-2 py-1 rounded-full text-xs font-semibold",
                        item.mode === TimerMode.FOCUS ? "bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400" :
                        item.mode === TimerMode.SHORT_BREAK ? "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400" :
                        "bg-indigo-100 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-400"
                    )}>
                        {item.mode === TimerMode.FOCUS ? 'Focus' : item.mode === TimerMode.SHORT_BREAK ? 'Short Break' : 'Long Break'}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 dark:text-slate-400">
                    {item.duration} min
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-400 max-w-xs truncate">
                    {item.noteSnapshot || <span className="text-slate-300 dark:text-slate-600 italic">No notes</span>}
                  </td>
                </tr>
              )) : (
                <tr>
                    <td colSpan={4} className="px-6 py-12 text-center text-slate-500 dark:text-slate-400">
                        No sessions found for this period.
                    </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default History;

import React from 'react';
import { InboxItem } from '../types';
import { calculateDaysRemaining, cn } from '../utils';
import { Trash2, Calendar, ArrowRightCircle, CheckCircle, AlertCircle } from 'lucide-react';

interface InboxProps {
  items: InboxItem[];
  onAction: (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction') => void;
}

const Inbox: React.FC<InboxProps> = ({ items, onAction }) => {
  const pendingItems = items.filter(i => i.status === 'pending');

  if (pendingItems.length === 0) {
    return (
        <div className="flex flex-col items-center justify-center h-96 text-center p-8">
            <div className="bg-green-50 rounded-full p-6 mb-4 dark:bg-green-900/20">
                <CheckCircle className="w-12 h-12 text-green-500 dark:text-green-400" />
            </div>
            <h3 className="text-xl font-semibold text-slate-900 mb-2 dark:text-slate-100">Inbox Zero!</h3>
            <p className="text-slate-500 max-w-sm dark:text-slate-400">You have processed all your notes. Start a new session to capture more ideas.</p>
        </div>
    )
  }

  return (
    <div className="w-full max-w-4xl mx-auto py-8 px-4">
      <div className="flex items-center justify-between mb-8">
        <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Inbox Processing</h2>
        <span className="bg-orange-100 text-orange-700 px-3 py-1 rounded-full text-xs font-semibold dark:bg-orange-900/50 dark:text-orange-200">
            {pendingItems.length} Pending
        </span>
      </div>

      <div className="grid gap-4">
        {pendingItems.map((item) => {
          const daysLeft = calculateDaysRemaining(item.deadline);
          const isUrgent = daysLeft <= 2;

          return (
            <div 
              key={item.id} 
              className="bg-white rounded-xl p-6 shadow-sm border border-slate-100 hover:shadow-md transition-shadow flex flex-col md:flex-row gap-6 items-start md:items-center justify-between group dark:bg-slate-900 dark:border-slate-800"
            >
              <div className="flex-1 space-y-2">
                <p className="text-lg text-slate-800 font-medium leading-relaxed dark:text-slate-200">{item.noteContent}</p>
                <div className="flex items-center gap-3 text-xs">
                  <span className={cn(
                    "px-2 py-1 rounded-md font-medium flex items-center gap-1",
                    isUrgent ? "bg-red-50 text-red-600 dark:bg-red-900/30 dark:text-red-400" : "bg-slate-100 text-slate-500 dark:bg-slate-800 dark:text-slate-400"
                  )}>
                    <AlertCircle className="w-3 h-3" />
                    {daysLeft} days remaining
                  </span>
                  <span className="text-slate-400">Created {item.createdAt.toLocaleDateString()}</span>
                </div>
              </div>

              <div className="flex items-center gap-2 w-full md:w-auto">
                <button
                    onClick={() => onAction(item.id, 'schedule')}
