import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Play, Pause, RotateCcw, Lock, Unlock, CheckCircle2, Coffee, Zap } from 'lucide-react';
import { TimerMode, Settings } from '../types';
import { formatTime, cn } from '../utils';

interface TimerProps {
  settings: Settings;
  onSessionComplete: (mode: TimerMode) => void;
  onNoteChange: (note: string) => void;
  currentNote: string;
}

const Timer: React.FC<TimerProps> = ({ settings, onSessionComplete, onNoteChange, currentNote }) => {
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const [isFocusLocked, setIsFocusLocked] = useState(false);
  const startTimeRef = useRef<Date | null>(null);

  // Request notification permissions
  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  // Initialize timer based on settings changes or mode changes
  useEffect(() => {
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  }, [mode, settings]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      if (newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      setIsFocusLocked(false); // Auto unlock on finish
      onSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, onSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      // Allow user to choose if they want lock screen or not, enforcing it for now for "Deep" feel
      setIsFocusLocked(true); 
      sendNotification("Deep Work Started", "Stay focused and minimize distractions.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    setIsFocusLocked(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const progress = 100 - (timeLeft / ((mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60)) * 100;

  // Render Full Screen Lock Mode
  if (isFocusLocked && isActive) {
    return (
      <div className="fixed inset-0 z-50 bg-slate-900 text-white flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
        <div className="absolute top-8 left-8 flex items-center gap-2 opacity-50">
          <Lock className="w-5 h-5" />
          <span className="text-sm font-medium tracking-widest uppercase">Deep Work Mode Locked</span>
        </div>

        <div className="text-[12rem] font-bold tabular-nums leading-none tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-orange-400 to-red-600 select-none scale-y-110 transform">
          {formatTime(timeLeft)}
        </div>

        <div className="mt-12 w-full max-w-2xl space-y-4">
          <p className="text-center text-slate-400 mb-2 text-sm uppercase tracking-wide">Capture thoughts quickly & return to focus</p>
          <textarea
            value={currentNote}
            onChange={(e) => onNoteChange(e.target.value)}
            placeholder="Type your distraction/idea here..."
            className="w-full h-32 bg-slate-800/50 border border-slate-700 rounded-xl p-6 text-lg text-slate-200 focus:outline-none focus:ring-2 focus:ring-orange-500/50 resize-none transition-all"
            autoFocus
          />
        </div>

        <button 
          onClick={() => setIsFocusLocked(false)}
          className="absolute bottom-8 text-slate-500 hover:text-white transition-colors flex items-center gap-2 text-sm"
        >
           <Unlock className="w-4 h-4" /> Pause & Unlock
        </button>
      </div>
    );
  }

  // Normal UI
  return (
    <div className="flex flex-col items-center w-full max-w-xl mx-auto space-y-8 py-8">

      {/* Mode Indicator */}
      <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700">
        <button
          onClick={() => { setMode(TimerMode.FOCUS); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.FOCUS ? "bg-orange-100 text-orange-700 shadow-sm dark:bg-orange-900/50 dark:text-orange-200" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Deep Focus
        </button>
        <button
          onClick={() => { setMode(TimerMode.SHORT_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.SHORT_BREAK ? "bg-blue-100 text-blue-700 shadow-sm dark:bg-blue-900/50 dark:text-blue-200" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Short Break
        </button>
        <button
          onClick={() => { setMode(TimerMode.LONG_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.LONG_BREAK ? "bg-indigo-100 text-indigo-700 shadow-sm dark:bg-indigo-900/50 dark:text-indigo-200" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Long Break
        </button>
      </div>

      {/* Timer Display */}
      {/* Increased container size to w-96 (24rem) for larger visual impact */}
      <div className="relative w-96 h-96 flex items-center justify-center">
        {/* SVG Progress Circle */}
        <svg className="absolute inset-0 w-full h-full transform -rotate-90">
