            r="180"  // Radius
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            className="text-slate-100 dark:text-slate-800"
          />
          <circle
            cx="192"
            cy="192"
            r="180"
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            strokeDasharray={2 * Math.PI * 180}
            strokeDashoffset={2 * Math.PI * 180 * (1 - progress / 100)}
            className={cn("transition-all duration-1000 ease-linear", 
              mode === TimerMode.FOCUS ? "text-orange-500" : "text-blue-500"
            )}
            strokeLinecap="round"
          />
        </svg>

        {/* Text Container centered absolutely */}
        <div className="absolute inset-0 flex flex-col items-center justify-center z-10">
          <span className="text-8xl font-bold text-slate-800 tracking-tighter tabular-nums leading-none dark:text-slate-100 scale-y-110 transform">
            {formatTime(timeLeft)}
          </span>
          <span className="text-slate-400 mt-4 font-medium uppercase tracking-[0.2em] text-xs dark:text-slate-500">
