    deadline: new Date(Date.now() + 1 * 24 * 60 * 60 * 1000),
    status: 'pending',
  }
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState<string>('');
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  // Dark mode state
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
  };

  // Cron Job Simulation: Check for expired notes every minute
  useEffect(() => {
    const checkExpiration = () => {
      const now = new Date();
      setInbox(prev => prev.filter(item => item.deadline > now));
    };

    const interval = setInterval(checkExpiration, 60000);
    return () => clearInterval(interval);
  }, []);

  const handleSessionComplete = (mode: TimerMode) => {
    // Record History
    const duration = mode === TimerMode.FOCUS ? settings.focusDuration : 
                     mode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000), // Approximate start
        endTime: new Date(),
        mode: mode,
        duration: duration,
        noteSnapshot: mode === TimerMode.FOCUS ? currentNote : undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    // Handle Notes
    if (mode === TimerMode.FOCUS && currentNote.trim().length > 0) {
      // Save note to Inbox automatically
      const newItem: InboxItem = {
        id: generateId(),
        noteContent: currentNote,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), // 8 days from now
        status: 'pending'
      };
      setInbox(prev => [newItem, ...prev]);
      setCurrentNote('');
    }
  };

  const handleInboxAction = (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction') => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else {
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: action === 'schedule' ? 'scheduled' : 'completed' } : i));

        if (action === 'schedule') alert('Opened Google Calendar Integration Mock');
        if (action === 'nextAction') alert('Opened Next Action Definition Mock');
    }
  };

  const handleExport = (type: string) => {
      if (credits.available > 0) {
          setCredits(prev => ({ ...prev, available: prev.available - 1, used: prev.used + 1}));
          alert(`Exporting to ${type}... Credit deducted.`);
      } else {
          alert('Insufficient credits. Please upgrade.');
      }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 dark:bg-black font-sans transition-colors duration-300 relative">

      {/* Main Content Area */}
      {/* Logic: margin-right adjusts based on sidebar width */}
      <main 
        className={cn(
            "flex-1 p-8 overflow-y-auto min-h-screen transition-all duration-300 ease-in-out",
            isSidebarCollapsed ? "mr-20" : "mr-64"
        )}
      >
        <header className="mb-8 flex justify-between items-center max-w-7xl mx-auto">
             <div>
                <h2 className="text-2xl font-bold text-slate-900 capitalize dark:text-white">
                    {currentView === 'timer' ? 'Focus Session' : currentView}
                </h2>
                <p className="text-slate-500 text-sm dark:text-slate-400">
                    {currentView === 'timer' ? 'Stay in the flow.' : 'Manage your outcomes.'}
                </p>
             </div>
             {/* Simple User Profile & Dark Mode Toggle */}
             <div className="flex items-center gap-4">
                <button 
                  onClick={toggleDarkMode}
                  className="p-2 rounded-full text-slate-500 hover:bg-slate-200 dark:text-slate-400 dark:hover:bg-slate-800 transition-colors"
                  title="Toggle Dark Mode"
                >
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>

                <div className="h-8 w-px bg-slate-200 dark:bg-slate-800"></div>

                <div className="flex items-center gap-3">
                    <div className="text-right hidden sm:block">
                        <p className="text-sm font-medium text-slate-900 dark:text-white">Alex Designer</p>
                        <p className="text-xs text-slate-500 dark:text-slate-400">Free Tier</p>
                    </div>
                    <div className="w-10 h-10 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden dark:border-slate-800">
                        <img src="https://picsum.photos/100/100" alt="Avatar" className="w-full h-full object-cover" />
                    </div>
                </div>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
            {currentView === 'timer' && (
            <Timer 
                settings={settings} 
                onSessionComplete={handleSessionComplete}
                onNoteChange={setCurrentNote}
                currentNote={currentNote}
            />
            )}

            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} />
            )}

            {currentView === 'dashboard' && (
            <Dashboard credits={credits} onExport={handleExport} />
            )}

            {currentView === 'history' && (
            <History history={history} />
            )}

            {currentView === 'settings' && (
                <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800">
                    <h3 className="text-lg font-bold mb-6 dark:text-white">Timer Configuration</h3>
                    <div className="space-y-6">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2 dark:text-slate-300">Deep Work Duration (min)</label>
                            <input 
                                type="range" 
                                min="15" 
                                max="60" 
                                value={settings.focusDuration}
                                onChange={(e) => setSettings({...settings, focusDuration: parseInt(e.target.value)})}
                                className="w-full accent-red-600 cursor-pointer" 
                            />
                            <div className="flex justify-between text-xs text-slate-400 mt-1">
                                <span>15m</span>
                                <span className="font-bold text-red-600">{settings.focusDuration}m</span>
                                <span>60m</span>
                            </div>
                        </div>

                        <div className="flex items-center justify-between pt-4 border-t border-slate-100 dark:border-slate-800">
                             <div>
                                <h4 className="font-medium text-slate-900 dark:text-white">Deep Work Extension</h4>
                                <p className="text-xs text-slate-500 dark:text-slate-400">Enable 1 hour deep work sessions</p>
                             </div>
                             <button 
                                onClick={() => setSettings(prev => ({...prev, focusDuration: prev.focusDuration === 60 ? 25 : 60}))}
                                className={
                                    `w-12 h-6 rounded-full transition-colors relative ${settings.focusDuration === 60 ? 'bg-red-600' : 'bg-slate-200 dark:bg-slate-700'}`
                                }
                             >
                                <span className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform ${settings.focusDuration === 60 ? 'translate-x-6' : ''}`} />
                             </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
      </main>

      {/* Right Sidebar */}
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        badgeCount={inbox.filter(i => i.status === 'pending').length}
        isCollapsed={isSidebarCollapsed}
        toggleSidebar={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Play, Pause, RotateCcw, Lock, Unlock, CheckCircle2, Coffee, Zap } from 'lucide-react';
import { TimerMode, Settings } from '../types';
import { formatTime, cn } from '../utils';

interface TimerProps {
  settings: Settings;
  onSessionComplete: (mode: TimerMode) => void;
  onNoteChange: (note: string) => void;
  currentNote: string;
}

const Timer: React.FC<TimerProps> = ({ settings, onSessionComplete, onNoteChange, currentNote }) => {
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const [isFocusLocked, setIsFocusLocked] = useState(false);
  const startTimeRef = useRef<Date | null>(null);

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  useEffect(() => {
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  }, [mode, settings]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      if (newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      setIsFocusLocked(false);
      onSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, onSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      setIsFocusLocked(true); 
      sendNotification("Deep Work Started", "Stay focused and minimize distractions.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    setIsFocusLocked(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const progress = 100 - (timeLeft / ((mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60)) * 100;

  if (isFocusLocked && isActive) {
    return (
      <div className="fixed inset-0 z-50 bg-slate-950 text-white flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
        <div className="absolute top-8 left-8 flex items-center gap-2 opacity-50">
          <Lock className="w-5 h-5" />
          <span className="text-sm font-medium tracking-widest uppercase">Deep Work Mode Locked</span>
        </div>

        <div className="text-[12rem] font-bold tabular-nums leading-none tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-500 to-rose-700 select-none scale-y-110 transform drop-shadow-2xl">
          {formatTime(timeLeft)}
        </div>

        <div className="mt-12 w-full max-w-2xl space-y-4">
          <p className="text-center text-slate-400 mb-2 text-sm uppercase tracking-wide">Capture thoughts quickly & return to focus</p>
          <textarea
            value={currentNote}
            onChange={(e) => onNoteChange(e.target.value)}
            placeholder="Type your distraction/idea here..."
            className="w-full h-32 bg-slate-800/50 border border-slate-700 rounded-xl p-6 text-lg text-slate-200 focus:outline-none focus:ring-2 focus:ring-red-500/50 resize-none transition-all"
            autoFocus
          />
        </div>

        <button 
          onClick={() => setIsFocusLocked(false)}
          className="absolute bottom-8 text-slate-500 hover:text-white transition-colors flex items-center gap-2 text-sm"
        >
           <Unlock className="w-4 h-4" /> Pause & Unlock
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center w-full max-w-xl mx-auto space-y-8 py-8">

      {/* Mode Indicator */}
      <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700">
        <button
          onClick={() => { setMode(TimerMode.FOCUS); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.FOCUS ? "bg-red-50 text-red-700 shadow-sm dark:bg-red-900/40 dark:text-red-200" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Deep Focus
        </button>
        <button
          onClick={() => { setMode(TimerMode.SHORT_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.SHORT_BREAK ? "bg-slate-100 text-slate-700 shadow-sm dark:bg-slate-700 dark:text-slate-200" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Short Break
        </button>
        <button
          onClick={() => { setMode(TimerMode.LONG_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.LONG_BREAK ? "bg-slate-100 text-slate-700 shadow-sm dark:bg-slate-700 dark:text-slate-200" : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Long Break
        </button>
      </div>

      <div className="relative w-96 h-96 flex items-center justify-center">
        <svg className="absolute inset-0 w-full h-full transform -rotate-90">
          <circle
            cx="192"
            cy="192"
            r="180"
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            strokeDasharray={2 * Math.PI * 180}
            strokeDashoffset={2 * Math.PI * 180 * (1 - progress / 100)}
            className={cn("transition-all duration-1000 ease-linear", 
              mode === TimerMode.FOCUS ? "text-red-600 drop-shadow-lg" : "text-slate-400"
            )}
            strokeLinecap="round"
          />
        </svg>

        <div className="absolute inset-0 flex flex-col items-center justify-center z-10">
          <span className="text-8xl font-bold text-slate-800 tracking-tighter tabular-nums leading-none dark:text-slate-100 scale-y-110 transform">
            {formatTime(timeLeft)}
          </span>
          <span className="text-slate-400 mt-4 font-medium uppercase tracking-[0.2em] text-xs dark:text-slate-500">
            {isActive ? 'Running' : 'Paused'}
          </span>
        </div>
      </div>

      <div className="flex items-center gap-6">
        <button
          onClick={toggleTimer}
          className={cn(
            "h-16 w-16 rounded-2xl flex items-center justify-center shadow-lg hover:shadow-xl hover:-translate-y-1 transition-all",
            isActive ? "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : "bg-slate-900 text-white dark:bg-red-600 dark:text-white"
          )}
        >
          {isActive ? <Pause className="w-8 h-8" /> : <Play className="w-8 h-8 ml-1" />}
        </button>

        <button
          onClick={resetTimer}
          className="h-12 w-12 rounded-xl bg-slate-100 text-slate-500 flex items-center justify-center hover:bg-slate-200 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700"
        >
          <RotateCcw className="w-5 h-5" />
        </button>
      </div>

      <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-xl border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400">
        <div className="flex items-center gap-2">
            <Zap className="w-4 h-4 text-red-500" />
            <span>{sessionsCompleted} Sessions</span>
        </div>
        <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
        <div className="flex items-center gap-2">
            <Coffee className="w-4 h-4 text-slate-400" />
            <span>Next: {sessionsCompleted > 0 && (sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long Break' : 'Short Break'}</span>
        </div>
      </div>
    </div>
  );
};

export default Timer;

