import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Play, Pause, RotateCcw, Lock, Unlock, Zap, Coffee } from 'lucide-react';
import { TimerMode, Settings } from '../types';
import { formatTime, cn } from '../utils';

interface TimerProps {
  settings: Settings;
  onSessionComplete: (mode: TimerMode) => void;
  onNoteChange: (note: string) => void;
  currentNote: string;
}

const Timer: React.FC<TimerProps> = ({ settings, onSessionComplete, onNoteChange, currentNote }) => {
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const [isFocusLocked, setIsFocusLocked] = useState(false);
  const startTimeRef = useRef<Date | null>(null);

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  useEffect(() => {
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  }, [mode, settings]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      if (newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      setIsFocusLocked(false);
      onSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, onSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      setIsFocusLocked(true); 
      sendNotification("Deep Work Started", "Stay focused and minimize distractions.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    setIsFocusLocked(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const progress = 100 - (timeLeft / ((mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60)) * 100;

  // Theme configuration based on mode
  const getTheme = () => {
    switch(mode) {
      case TimerMode.SHORT_BREAK:
        return {
          primary: 'text-emerald-500',
          bg: 'bg-emerald-50',
          btnBg: 'bg-emerald-500',
          btnText: 'text-white',
          glow: 'shadow-emerald-500/30',
          darkText: 'dark:text-emerald-400',
          pillActive: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return {
          primary: 'text-violet-500',
          bg: 'bg-violet-50',
          btnBg: 'bg-violet-600',
          btnText: 'text-white',
          glow: 'shadow-violet-600/30',
          darkText: 'dark:text-violet-400',
          pillActive: 'bg-violet-100 text-violet-700 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default: // FOCUS
        return {
          primary: 'text-red-600',
          bg: 'bg-red-50',
          btnBg: 'bg-red-600',
          btnText: 'text-white',
          glow: 'shadow-red-600/30',
          darkText: 'dark:text-red-500',
          pillActive: 'bg-red-50 text-red-700 dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme();

  if (isFocusLocked && isActive) {
    return (
      <div className="fixed inset-0 z-50 bg-slate-950 text-white flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
        <div className="absolute top-8 left-8 flex items-center gap-2 opacity-50">
          <Lock className="w-5 h-5" />
          <span className="text-sm font-medium tracking-widest uppercase">Deep Work Mode Locked</span>
        </div>

        <div className="text-[12rem] font-bold tabular-nums leading-none tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-500 to-rose-700 select-none scale-y-110 transform drop-shadow-2xl">
          {formatTime(timeLeft)}
        </div>

        <div className="mt-12 w-full max-w-2xl space-y-4">
          <p className="text-center text-slate-400 mb-2 text-sm uppercase tracking-wide">Capture thoughts quickly & return to focus</p>
          <textarea
            value={currentNote}
            onChange={(e) => onNoteChange(e.target.value)}
            placeholder="Type your distraction/idea here..."
            className="w-full h-32 bg-slate-800/50 border border-slate-700 rounded-xl p-6 text-lg text-slate-200 focus:outline-none focus:ring-2 focus:ring-red-500/50 resize-none transition-all"
            autoFocus
          />
        </div>

        <button 
          onClick={() => setIsFocusLocked(false)}
          className="absolute bottom-8 text-slate-500 hover:text-white transition-colors flex items-center gap-2 text-sm"
        >
           <Unlock className="w-4 h-4" /> Pause & Unlock
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center w-full max-w-xl mx-auto space-y-8 py-8">

      {/* Mode Indicator */}
      <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700">
        <button
          onClick={() => { setMode(TimerMode.FOCUS); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Deep Focus
        </button>
        <button
          onClick={() => { setMode(TimerMode.SHORT_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Short Break
        </button>
        <button
          onClick={() => { setMode(TimerMode.LONG_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Long Break
        </button>
      </div>

      {/* Timer Display */}
      <div className="relative w-96 h-96 flex items-center justify-center">
        <svg className="absolute inset-0 w-full h-full transform -rotate-90">
          <circle
            cx="192"
            cy="192"
            r="180"
            stroke="currentColor"
            strokeWidth="8"
            fill="transparent"
            strokeDasharray={2 * Math.PI * 180}
            strokeDashoffset={2 * Math.PI * 180 * (1 - progress / 100)}
            className={cn("transition-all duration-1000 ease-linear drop-shadow-lg", 
              theme.primary
            )}
            strokeLinecap="round"
          />
        </svg>

        <div className="absolute inset-0 flex flex-col items-center justify-center z-10">
          <span className={cn("text-8xl font-bold tracking-tighter tabular-nums leading-none scale-y-110 transform transition-colors duration-500", theme.primary)}>
            {formatTime(timeLeft)}
          </span>
          <span className="text-slate-400 mt-4 font-medium uppercase tracking-[0.2em] text-xs dark:text-slate-500">
            {isActive ? 'Running' : 'Paused'}
          </span>
        </div>
      </div>

      {/* Controls - Balanced Buttons */}
      <div className="flex items-center gap-8">
        <button
          onClick={resetTimer}
          className="w-20 h-20 rounded-[2rem] bg-slate-100 text-slate-500 flex items-center justify-center hover:bg-slate-200 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95"
          title="Reset Timer"
        >
          <RotateCcw className="w-8 h-8" />
        </button>

        <button
          onClick={toggleTimer}
          className={cn(
            "w-20 h-20 rounded-[2rem] flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95",
            isActive 
                ? "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300" 
                : `${theme.btnBg} ${theme.btnText} shadow-lg hover:shadow-xl ${theme.glow}`
          )}
          title={isActive ? "Pause" : "Start"}
        >
          {isActive ? <Pause className="w-10 h-10" /> : <Play className="w-10 h-10 ml-1" />}
        </button>
      </div>

      {/* Session Stats */}
      <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-xl border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400">
        <div className="flex items-center gap-2">
            <Zap className={cn("w-4 h-4", theme.primary)} />
            <span>{sessionsCompleted} Sessions</span>
        </div>
        <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
        <div className="flex items-center gap-2">
            <Coffee className="w-4 h-4 text-slate-400" />
            <span>Next: {sessionsCompleted > 0 && (sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long Break' : 'Short Break'}</span>
        </div>
      </div>
    </div>
  );
};

