  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      setIsFocusLocked(true); 
      sendNotification("Deep Work Started", "Stay focused and minimize distractions.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    setIsFocusLocked(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const handleAskAI = async () => {
    setIsAiLoading(true);
    try {
      // NOTE: Ensure process.env.API_KEY is available in your build environment
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: "Generate 3 short, punchy, and actionable bullet points to help me start a new project or improve productivity right now. Keep it under 50 words.",
      });

      const text = response.text;
      if (text) {
        onNoteChange(currentNote + (currentNote ? '\n\n' : '') + "✨ AI Ideas:\n" + text);
      }
    } catch (error) {
      console.error("AI Error:", error);
      alert("Unable to connect to AI. Please check your API configuration.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const totalTime = (mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60;
  const progress = 100 - (timeLeft / totalTime) * 100;

  // Calculate Scale Factor: Grows from 1.0 to 1.4 as time passes (only in Focus mode)
  const growthScale = isActive && mode === TimerMode.FOCUS ? 1 + (progress / 100) * 0.4 : 1;

  // Theme configuration based on mode
  const getTheme = () => {
    switch(mode) {
      case TimerMode.SHORT_BREAK:
        return {
          primary: 'text-emerald-500',
          stroke: 'text-emerald-500',
          bg: 'bg-emerald-50',
          btnBg: 'bg-emerald-500',
          btnText: 'text-white',
          glow: 'shadow-emerald-500/30',
          darkText: 'dark:text-emerald-400',
          pillActive: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return {
          primary: 'text-violet-500',
          stroke: 'text-violet-500',
          bg: 'bg-violet-50',
          btnBg: 'bg-violet-600',
          btnText: 'text-white',
          glow: 'shadow-violet-600/30',
          darkText: 'dark:text-violet-400',
          pillActive: 'bg-violet-100 text-violet-700 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default: // FOCUS
        return {
          primary: 'text-red-600',
          stroke: 'text-red-600',
          bg: 'bg-red-50',
          btnBg: 'bg-red-600',
          btnText: 'text-white',
          glow: 'shadow-red-600/30',
          darkText: 'dark:text-red-500',
          pillActive: 'bg-red-50 text-red-700 dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme();

  return (
    <div className="flex flex-col items-center w-full max-w-xl mx-auto space-y-8 py-8 relative">

      {/* Mode Indicator */}
      <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20">
        <button
          onClick={() => { setMode(TimerMode.FOCUS); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Deep Focus
        </button>
        <button
          onClick={() => { setMode(TimerMode.SHORT_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Short Break
        </button>
        <button
          onClick={() => { setMode(TimerMode.LONG_BREAK); setIsActive(false); }}
          className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
        >
          Long Break
        </button>
      </div>

      {/* Timer Display Container */}
      {/* We use a fixed aspect ratio container that fits well in the viewport */}
      <div className="relative w-full max-w-[500px] aspect-square flex items-center justify-center">

        {/* Background Circle - Counts Down */}
        <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none">
           {/* Track */}
          <circle
            cx="50%"
            cy="50%"
            r="45%"
            stroke="currentColor"
            strokeWidth="4"
            fill="transparent"
            className="text-slate-100 dark:text-slate-800"
          />
          {/* Progress Indicator */}
          <circle
            cx="50%"
            cy="50%"
            r="45%"
            stroke="currentColor"
            strokeWidth="12"
            fill="transparent"
            strokeDasharray={2 * Math.PI * 225} // approx for r=45% of 500px
            // We need a cleaner calc for percentage based strokeDashoffset in CSS or JS.
            // Simplified: circumference = 2 * PI * r. Let's assume unit circle percent logic for the styles.
            pathLength={100}
            strokeDashoffset={100 - progress}
            className={cn("transition-all duration-1000 ease-linear drop-shadow-md", 
              theme.stroke
            )}
            strokeLinecap="round"
          />
        </svg>

        {/* Growing Timer Text */}
        <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
          <span 
            className={cn(
                "font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out", 
                theme.primary
            )}
            style={{ 
                fontSize: 'clamp(5rem, 15vw, 10rem)',
                transform: `scale(${growthScale})` 
            }}
          >
            {formatTime(timeLeft)}
          </span>
          <span className="text-slate-400 mt-4 font-medium uppercase tracking-[0.2em] text-xs dark:text-slate-500 opacity-80">
            {isActive ? 'Deep Work Running' : 'Ready'}
          </span>
        </div>
      </div>

      {/* Note Input & AI Action */}
      <div className="w-full max-w-md relative z-20">
         <div className="relative">
             <textarea
                value={currentNote}
                onChange={(e) => onNoteChange(e.target.value)}
                placeholder="Capture distractions or ideas here..."
                className="w-full h-24 bg-white/50 border border-slate-200 rounded-xl p-4 pr-12 text-sm text-slate-700 focus:outline-none focus:ring-2 focus:ring-red-500/20 resize-none transition-all dark:bg-slate-900/50 dark:border-slate-800 dark:text-slate-300"
              />
              <button 
                onClick={handleAskAI}
                disabled={isAiLoading}
                className={cn(
                    "absolute top-3 right-3 p-2 rounded-lg transition-colors",
                    isAiLoading ? "text-slate-400 cursor-wait" : "text-violet-500 hover:bg-violet-50 hover:text-violet-700 dark:text-violet-400 dark:hover:bg-violet-900/30"
                )}
                title="Ask AI for productivity ideas"
              >
                {isAiLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
              </button>
         </div>
      </div>

      {/* Controls */}
      <div className="flex items-center gap-8 relative z-20">
        <button
          onClick={resetTimer}
          className="w-20 h-20 rounded-[2rem] bg-slate-100 text-slate-500 flex items-center justify-center hover:bg-slate-200 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95"
          title="Reset Timer"
        >
          <RotateCcw className="w-8 h-8" />
        </button>

        <button
          onClick={toggleTimer}
          className={cn(
            "w-20 h-20 rounded-[2rem] flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95",
            isActive 
                ? "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300" 
                : `${theme.btnBg} ${theme.btnText} shadow-lg hover:shadow-xl ${theme.glow}`
          )}
          title={isActive ? "Pause" : "Start"}
        >
          {isActive ? <Pause className="w-10 h-10" /> : <Play className="w-10 h-10 ml-1" />}
        </button>
      </div>

      {/* Session Stats */}
      <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-xl border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
        <div className="flex items-center gap-2">
            <Zap className={cn("w-4 h-4", theme.primary)} />
            <span>{sessionsCompleted} Sessions</span>
        </div>
        <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
        <div className="flex items-center gap-2">
            <Coffee className="w-4 h-4 text-slate-400" />
            <span>Next: {sessionsCompleted > 0 && (sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long Break' : 'Short Break'}</span>
        </div>
      </div>
    </div>
  );
};

