      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
  };

  // Cron Job Simulation: Check for expired notes every minute
  useEffect(() => {
    const checkExpiration = () => {
      const now = new Date();
      setInbox(prev => prev.filter(item => item.deadline > now));
    };

    const interval = setInterval(checkExpiration, 60000);
    return () => clearInterval(interval);
  }, []);

  const handleSessionComplete = (mode: TimerMode) => {
    // Record History
    const duration = mode === TimerMode.FOCUS ? settings.focusDuration : 
                     mode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000), // Approximate start
        endTime: new Date(),
        mode: mode,
        duration: duration,
        noteSnapshot: mode === TimerMode.FOCUS ? currentNote : undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    // Note: Notes are now handled manually by user interaction or we can keep auto-save if text exists
    if (mode === TimerMode.FOCUS && currentNote.trim().length > 0) {
        saveNoteToInbox(currentNote);
        setCurrentNote('');
    }
  };

  const saveNoteToInbox = (content: string, categoryId?: string) => {
      const newItem: InboxItem = {
        id: generateId(),
        noteContent: content,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), // 8 days from now
        status: 'pending',
        categoryId: categoryId
      };
      setInbox(prev => [newItem, ...prev]);
  };

  const handleInboxAction = (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction') => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else {
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: action === 'schedule' ? 'scheduled' : 'completed' } : i));

        if (action === 'schedule') alert('Opened Google Calendar Integration Mock');
        if (action === 'nextAction') alert('Opened Next Action Definition Mock');
    }
  };

  const handleExport = (type: string) => {
      if (credits.available > 0) {
          setCredits(prev => ({ ...prev, available: prev.available - 1, used: prev.used + 1}));
          alert(`Exporting to ${type}... Credit deducted.`);
      } else {
          alert('Insufficient credits. Please upgrade.');
      }
  };

  const handleOpenNewWindow = () => {
      const width = 1000;
      const height = 800;
      const left = (window.screen.width - width) / 2;
      const top = (window.screen.height - height) / 2;
      window.open(window.location.href, '_blank', `width=${width},height=${height},left=${left},top=${top},resizable=yes,scrollbars=yes,status=yes`);
  };

  return (
    <div className="flex min-h-screen bg-slate-50 dark:bg-black font-sans transition-colors duration-300 relative">

      {/* Main Content Area */}
      <main 
        className={cn(
            "flex-1 p-8 overflow-y-auto min-h-screen transition-all duration-300 ease-in-out",
            isSidebarCollapsed ? "mr-20" : "mr-64"
        )}
      >
        <header className="mb-8 flex justify-between items-center max-w-7xl mx-auto">
             <div>
                <h2 className="text-2xl font-bold text-slate-900 capitalize dark:text-white">
                    {currentView === 'timer' ? 'Focus Session' : currentView}
                </h2>
                <p className="text-slate-500 text-sm dark:text-slate-400">
                    {currentView === 'timer' ? 'Stay in the flow.' : 'Manage your outcomes.'}
                </p>
             </div>
             {/* Simple User Profile & Dark Mode Toggle */}
             <div className="flex items-center gap-4">
                <button 
                  onClick={toggleDarkMode}
                  className="p-2 rounded-full text-slate-500 hover:bg-slate-200 dark:text-slate-400 dark:hover:bg-slate-800 transition-colors"
                  title="Toggle Dark Mode"
                >
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>

                <div className="h-8 w-px bg-slate-200 dark:bg-slate-800"></div>

                <div className="flex items-center gap-3">
                    <div className="text-right hidden sm:block">
                        <p className="text-sm font-medium text-slate-900 dark:text-white">Alex Designer</p>
                        <p className="text-xs text-slate-500 dark:text-slate-400">Free Tier</p>
                    </div>
                    <div className="w-10 h-10 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden dark:border-slate-800">
                        <img src="https://picsum.photos/100/100" alt="Avatar" className="w-full h-full object-cover" />
                    </div>
                </div>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
            {currentView === 'timer' && (
            <Timer 
                settings={settings} 
                onSessionComplete={handleSessionComplete}
                onNoteChange={setCurrentNote}
                currentNote={currentNote}
                categories={categories}
                onSaveNote={saveNoteToInbox}
            />
            )}

            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} />
            )}

            {currentView === 'categories' && (
            <Categories 
                categories={categories} 
                onAdd={(c) => setCategories(prev => [...prev, c])}
                onDelete={(id) => setCategories(prev => prev.filter(c => c.id !== id))}
            />
            )}

            {currentView === 'dashboard' && (
            <Dashboard credits={credits} onExport={handleExport} />
            )}

            {currentView === 'history' && (
            <History history={history} />
            )}

            {currentView === 'settings' && (
                <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800">
                    <h3 className="text-lg font-bold mb-6 dark:text-white">Timer Configuration</h3>
                    <div className="space-y-6">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2 dark:text-slate-300">Deep Work Duration (min)</label>
                            <input 
                                type="range" 
                                min="15" 
                                max="60" 
                                value={settings.focusDuration}
                                onChange={(e) => setSettings({...settings, focusDuration: parseInt(e.target.value)})}
                                className="w-full accent-red-600 cursor-pointer" 
                            />
                            <div className="flex justify-between text-xs text-slate-400 mt-1">
                                <span>15m</span>
                                <span className="font-bold text-red-600">{settings.focusDuration}m</span>
                                <span>60m</span>
                            </div>
                        </div>

                        <div className="flex items-center justify-between pt-4 border-t border-slate-100 dark:border-slate-800">
                             <div>
                                <h4 className="font-medium text-slate-900 dark:text-white">Deep Work Extension</h4>
                                <p className="text-xs text-slate-500 dark:text-slate-400">Enable 1 hour deep work sessions</p>
                             </div>
                             <button 
                                onClick={() => setSettings(prev => ({...prev, focusDuration: prev.focusDuration === 60 ? 25 : 60}))}
                                className={
                                    `w-12 h-6 rounded-full transition-colors relative ${settings.focusDuration === 60 ? 'bg-red-600' : 'bg-slate-200 dark:bg-slate-700'}`
                                }
                             >
                                <span className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform ${settings.focusDuration === 60 ? 'translate-x-6' : ''}`} />
                             </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
      </main>

      {/* Right Sidebar */}
      <Sidebar 
        currentView={currentView} 
        onChangeView={setCurrentView} 
        badgeCount={inbox.filter(i => i.status === 'pending').length}
        isCollapsed={isSidebarCollapsed}
        toggleSidebar={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        onOpenNewWindow={handleOpenNewWindow}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Play, Pause, RotateCcw, Lock, Unlock, Zap, Coffee, Sparkles, Loader2, Send, PenLine } from 'lucide-react';
import { TimerMode, Settings, Category } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  onSessionComplete: (mode: TimerMode) => void;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
}

const Timer: React.FC<TimerProps> = ({ settings, onSessionComplete, onNoteChange, currentNote, categories, onSaveNote }) => {
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const [isFocusLocked, setIsFocusLocked] = useState(false);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<string>('');

  const startTimeRef = useRef<Date | null>(null);

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  useEffect(() => {
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  }, [mode, settings]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      if (newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      setIsFocusLocked(false);
      onSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, onSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      setIsFocusLocked(true); 
      sendNotification("Deep Work Started", "Stay focused and minimize distractions.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    setIsFocusLocked(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const handleAskAI = async () => {
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: "Generate 3 short, punchy, and actionable bullet points to help me start a new project or improve productivity right now. Keep it under 50 words.",
      });

      const text = response.text;
      if (text) {
        onNoteChange(currentNote + (currentNote ? '\n\n' : '') + "✨ AI Ideas:\n" + text);
      }
    } catch (error) {
      console.error("AI Error:", error);
      alert("Unable to connect to AI. Please check your API configuration.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleManualSave = () => {
      if (!currentNote.trim()) return;
      onSaveNote(currentNote, selectedCategory);
      onNoteChange(''); // Clear local note after manual save
      // We don't clear category, might want to reuse
  };

  const totalTime = (mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60;

  // Progress Logic for "Depleting Circle"
  // When timeLeft = totalTime (Start), progress should be 100% (Full Circle)
  // When timeLeft = 0 (End), progress should be 0% (Empty Circle)
  const progressRatio = timeLeft / totalTime;

  // Circumference of radius 45% (approx 1131 based on viewBox scaling)
  // We use pathLength=100 for simpler CSS calc
  // strokeDashoffset: 0 = Full, 100 = Empty.
  // We want Full at start (offset 0) and Empty at end (offset 100).
  const strokeDashoffset = 100 - (progressRatio * 100);

  // Calculate Scale Factor: Grows from 1.0 to 1.4 as time passes (only in Focus mode)
  const growthScale = isActive && mode === TimerMode.FOCUS ? 1 + ((totalTime - timeLeft) / totalTime) * 0.4 : 1;

  // Theme configuration based on mode
  const getTheme = () => {
    switch(mode) {
      case TimerMode.SHORT_BREAK:
        return {
          primary: 'text-emerald-500',
          stroke: 'text-emerald-500',
          bg: 'bg-emerald-50',
          btnBg: 'bg-emerald-500',
          btnText: 'text-white',
          glow: 'shadow-emerald-500/30',
          darkText: 'dark:text-emerald-400',
          pillActive: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return {
          primary: 'text-violet-500',
          stroke: 'text-violet-500',
          bg: 'bg-violet-50',
          btnBg: 'bg-violet-600',
          btnText: 'text-white',
          glow: 'shadow-violet-600/30',
          darkText: 'dark:text-violet-400',
          pillActive: 'bg-violet-100 text-violet-700 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default: // FOCUS
        return {
          primary: 'text-red-600',
          stroke: 'text-red-600',
          bg: 'bg-red-50',
          btnBg: 'bg-red-600',
          btnText: 'text-white',
          glow: 'shadow-red-600/30',
          darkText: 'dark:text-red-500',
          pillActive: 'bg-red-50 text-red-700 dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme();

  if (isFocusLocked && isActive) {
      // Locked view code remains mostly same but using the new note saving logic would be good, 
      // keeping it simple for now as per "Minimal changes" unless requested.
      // However, we must ensure the circle logic is consistent if visible here.
      return (
        <div className="fixed inset-0 z-50 bg-slate-950 text-white flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
          <div className="absolute top-8 left-8 flex items-center gap-2 opacity-50">
            <Lock className="w-5 h-5" />
            <span className="text-sm font-medium tracking-widest uppercase">Deep Work Mode Locked</span>
          </div>

          <div className="text-[12rem] font-bold tabular-nums leading-none tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-500 to-rose-700 select-none scale-y-110 transform drop-shadow-2xl">
            {formatTime(timeLeft)}
          </div>

          <div className="mt-12 w-full max-w-2xl space-y-4">
            <p className="text-center text-slate-400 mb-2 text-sm uppercase tracking-wide">Capture thoughts quickly & return to focus</p>
            <textarea
              value={currentNote}
              onChange={(e) => onNoteChange(e.target.value)}
              placeholder="Type your distraction/idea here..."
              className="w-full h-32 bg-slate-800/50 border border-slate-700 rounded-xl p-6 text-lg text-slate-200 focus:outline-none focus:ring-2 focus:ring-red-500/50 resize-none transition-all"
              autoFocus
            />
             <div className="flex justify-end">
                <button onClick={handleManualSave} className="text-sm bg-red-600 hover:bg-red-700 px-4 py-2 rounded-lg text-white">Save & Continue</button>
             </div>
          </div>

          <button 
            onClick={() => setIsFocusLocked(false)}
            className="absolute bottom-8 text-slate-500 hover:text-white transition-colors flex items-center gap-2 text-sm"
          >
             <Unlock className="w-4 h-4" /> Pause & Unlock
          </button>
        </div>
      );
    }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 h-full max-w-6xl mx-auto">

      {/* LEFT COLUMN: Timer & Controls (Takes up 2/3 on large screens) */}
      <div className="lg:col-span-2 flex flex-col items-center justify-center space-y-8 py-8 relative">

        {/* Mode Indicator */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20">
            <button
            onClick={() => { setMode(TimerMode.FOCUS); setIsActive(false); }}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Deep Focus
            </button>
            <button
            onClick={() => { setMode(TimerMode.SHORT_BREAK); setIsActive(false); }}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Short Break
            </button>
            <button
            onClick={() => { setMode(TimerMode.LONG_BREAK); setIsActive(false); }}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Long Break
            </button>
        </div>

        {/* Timer Display Container */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center">

            {/* Background Circle - Depletes from color to invisible */}
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none">
            {/* Track - Always faint visible */}
            <circle
                cx="50%"
                cy="50%"
                r="45%"
                stroke="currentColor"
                strokeWidth="4"
                fill="transparent"
                className="text-slate-100 dark:text-slate-800"
            />
            {/* Progress Indicator - The colored part */}
            <circle
                cx="50%"
                cy="50%"
                r="45%"
                stroke="currentColor"
                strokeWidth="12"
                fill="transparent"
                pathLength={100}
                strokeDasharray="100" 
                strokeDashoffset={strokeDashoffset}
                className={cn("transition-all duration-1000 ease-linear drop-shadow-md", 
                theme.stroke
                )}
                strokeLinecap="round"
            />
            </svg>

            {/* Growing Timer Text */}
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
            <span 
                className={cn(
                    "font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out", 
                    theme.primary
                )}
                style={{ 
                    fontSize: 'clamp(5rem, 15vw, 9rem)',
                    transform: `scale(${growthScale})` 
                }}
            >
                {formatTime(timeLeft)}
            </span>
            <span className="text-slate-400 mt-4 font-medium uppercase tracking-[0.2em] text-xs dark:text-slate-500 opacity-80">
                {isActive ? (mode === TimerMode.FOCUS ? 'Deep Work Running' : 'Break Time') : 'Ready to Start'}
            </span>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-8 relative z-20">
            <button
            onClick={resetTimer}
            className="w-20 h-20 rounded-[2rem] bg-slate-100 text-slate-500 flex items-center justify-center hover:bg-slate-200 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95"
            title="Reset Timer"
            >
            <RotateCcw className="w-8 h-8" />
            </button>

            <button
            onClick={toggleTimer}
            className={cn(
                "w-20 h-20 rounded-[2rem] flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95",
                isActive 
                    ? "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-300" 
                    : `${theme.btnBg} ${theme.btnText} shadow-lg hover:shadow-xl ${theme.glow}`
            )}
            title={isActive ? "Pause" : "Start"}
            >
            {isActive ? <Pause className="w-10 h-10" /> : <Play className="w-10 h-10 ml-1" />}
            </button>
        </div>

         {/* Session Stats */}
        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-xl border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2">
                <Zap className={cn("w-4 h-4", theme.primary)} />
                <span>{sessionsCompleted} Sessions</span>
            </div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2">
                <Coffee className="w-4 h-4 text-slate-400" />
                <span>Next: {sessionsCompleted > 0 && (sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long Break' : 'Short Break'}</span>
            </div>
        </div>
      </div>

      {/* RIGHT COLUMN: Quick Capture / Notes (Takes up 1/3) */}
      <div className="lg:col-span-1 flex flex-col h-full min-h-[400px]">
         <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-full flex flex-col dark:bg-slate-900 dark:border-slate-800 relative overflow-hidden">
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2 text-slate-900 dark:text-white font-bold">
                    <PenLine className="w-5 h-5 text-red-500" />
                    <h3>Quick Capture</h3>
                </div>
                <button 
                    onClick={handleAskAI}
                    disabled={isAiLoading}
                    className={cn(
                        "p-2 rounded-lg transition-colors flex items-center gap-1 text-xs font-medium",
                        isAiLoading ? "text-slate-400 cursor-wait" : "text-violet-500 bg-violet-50 hover:bg-violet-100 dark:bg-violet-900/20 dark:hover:bg-violet-900/30"
                    )}
                >
                    {isAiLoading ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
                    <span>AI Ideas</span>
                </button>
            </div>

            <textarea
                value={currentNote}
                onChange={(e) => onNoteChange(e.target.value)}
                placeholder="Distracted? Capture it here..."
                className="flex-1 w-full bg-slate-50 border-0 rounded-xl p-4 text-sm text-slate-700 focus:outline-none focus:ring-2 focus:ring-red-500/20 resize-none transition-all dark:bg-slate-800/50 dark:text-slate-300 mb-4 custom-scrollbar"
            />

            <div className="space-y-3">
                <div>
                     <label className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1 block">Tag Category</label>
                     <select 
                        value={selectedCategory}
                        onChange={(e) => setSelectedCategory(e.target.value)}
                        className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-700 outline-none focus:border-red-500 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-300"
                     >
                        <option value="">No Category</option>
                        {categories.map(cat => (
                            <option key={cat.id} value={cat.id}>{cat.name}</option>
                        ))}
                     </select>
                </div>

                <div className="pt-2">
                    <button 
                        onClick={handleManualSave}
                        disabled={!currentNote.trim()}
                        className="w-full py-3 bg-slate-900 text-white rounded-xl font-medium shadow-lg shadow-slate-900/20 hover:bg-slate-800 active:scale-[0.98] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 dark:bg-red-600 dark:hover:bg-red-700 dark:shadow-red-900/20"
                    >
                        <Send className="w-4 h-4" />
                        Send to Inbox
                    </button>
