import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Play, Pause, RotateCcw, Lock, Unlock, Zap, Coffee, Sparkles, Loader2, Send, PenLine } from 'lucide-react';
import { TimerMode, Settings, Category } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  onSessionComplete: (mode: TimerMode) => void;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
}

const Timer: React.FC<TimerProps> = ({ settings, onSessionComplete, onNoteChange, currentNote, categories, onSaveNote }) => {
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const [isFocusLocked, setIsFocusLocked] = useState(false);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<string>('');

  const startTimeRef = useRef<Date | null>(null);

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  useEffect(() => {
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  }, [mode, settings]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      if (newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      setIsFocusLocked(false);
      onSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, onSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      setIsFocusLocked(true); 
      sendNotification("Deep Work Started", "Stay focused and minimize distractions.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    setIsFocusLocked(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const handleAskAI = async () => {
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: "Generate 3 short, punchy, and actionable bullet points to help me start a new project or improve productivity right now. Keep it under 50 words.",
      });

      const text = response.text;
      if (text) {
        onNoteChange(currentNote + (currentNote ? '\n\n' : '') + "✨ AI Ideas:\n" + text);
      }
    } catch (error) {
      console.error("AI Error:", error);
      alert("Unable to connect to AI. Please check your API configuration.");
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleManualSave = () => {
      if (!currentNote.trim()) return;
      onSaveNote(currentNote, selectedCategory);
      onNoteChange(''); // Clear local note after manual save
  };

  const totalTime = (mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60;

  // Progress Logic
  const progressRatio = timeLeft / totalTime;
  const strokeDashoffset = 100 - (progressRatio * 100);

  // Growth Scale
  const growthScale = isActive && mode === TimerMode.FOCUS ? 1 + ((totalTime - timeLeft) / totalTime) * 0.2 : 1;

  // Theme configuration based on mode
  const getTheme = () => {
    switch(mode) {
      case TimerMode.SHORT_BREAK:
        return {
          primary: 'text-emerald-600',
          stroke: 'text-emerald-500',
          btnBg: 'bg-emerald-600',
          btnText: 'text-white',
          glow: 'shadow-emerald-600/30',
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return {
          primary: 'text-violet-600',
          stroke: 'text-violet-500',
          btnBg: 'bg-violet-600',
          btnText: 'text-white',
          glow: 'shadow-violet-600/30',
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default: // FOCUS (Dark Red)
        return {
          primary: 'text-pomo', // Custom red-700
          stroke: 'text-pomo-light', // red-500 for the glow/stroke
          btnBg: 'bg-pomo',
          btnText: 'text-white',
          glow: 'shadow-pomo/30',
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme();

  if (isFocusLocked && isActive) {
      return (
        <div className="fixed inset-0 z-50 bg-slate-950 text-white flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
          <div className="absolute top-8 left-8 flex items-center gap-2 opacity-50">
            <Lock className="w-5 h-5" />
            <span className="text-sm font-medium tracking-widest uppercase">Deep Work Mode Locked</span>
          </div>

          <div className="text-[12rem] font-mono font-bold tabular-nums leading-none tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-red-600 to-red-800 select-none scale-y-110 transform drop-shadow-2xl">
            {formatTime(timeLeft)}
          </div>

          <div className="mt-12 w-full max-w-2xl space-y-4">
            <p className="text-center text-slate-400 mb-2 text-sm uppercase tracking-wide">Capture thoughts quickly & return to focus</p>
            <textarea
              value={currentNote}
              onChange={(e) => onNoteChange(e.target.value)}
              placeholder="Type your distraction/idea here..."
              className="w-full h-32 bg-slate-800/50 border border-slate-700 rounded-xl p-6 text-lg text-slate-200 focus:outline-none focus:ring-2 focus:ring-red-500/50 resize-none transition-all"
              autoFocus
            />
             <div className="flex justify-end">
                <button onClick={handleManualSave} className="text-sm bg-pomo hover:bg-pomo-dark px-4 py-2 rounded-lg text-white">Save & Continue</button>
             </div>
          </div>

          <button 
            onClick={() => setIsFocusLocked(false)}
            className="absolute bottom-8 text-slate-500 hover:text-white transition-colors flex items-center gap-2 text-sm"
          >
