import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Play, Pause, RotateCcw, Zap, Coffee } from 'lucide-react';
import { TimerMode, Settings, Category } from '../types';
import { formatTime, cn } from '../utils';

interface TimerProps {
  settings: Settings;
  onSessionComplete: (mode: TimerMode) => void;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
}

const Timer: React.FC<TimerProps> = ({ settings, onSessionComplete, onNoteChange, currentNote, categories, onSaveNote }) => {
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);

  const startTimeRef = useRef<Date | null>(null);

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  useEffect(() => {
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  }, [mode, settings]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      if (newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      onSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, onSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      sendNotification("Deep Work Started", "Stay focused and minimize distractions.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const totalTime = (mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60;

  // Progress Logic
  const progressRatio = timeLeft / totalTime;
  const strokeDashoffset = 100 - (progressRatio * 100);

  // Rotation for the Knob (Tip of the circle)
  // progressRatio goes 1 -> 0
  // Circle track starts at -90deg.
  // We want the knob to follow the end of the stroke.
  // The stroke reduces counter-clockwise or clockwise depending on offset direction, 
  // here the offset makes it shrink.
  // 360 * (1 - progressRatio) gives us the angle traversed.
  const rotationAngle = 360 * (1 - progressRatio);

  // Growth Scale (Subtle breathing effect during active state)
  const growthScale = isActive && mode === TimerMode.FOCUS ? 1.05 : 1;

  // Theme configuration based on mode
  const getTheme = () => {
    switch(mode) {
      case TimerMode.SHORT_BREAK:
        return {
          primary: 'text-emerald-600',
          stroke: 'text-emerald-400',
          knob: 'bg-emerald-400',
          btnBg: 'bg-emerald-600',
          btnText: 'text-white',
          glow: 'shadow-emerald-600/30',
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return {
          primary: 'text-violet-600',
          stroke: 'text-violet-400',
          knob: 'bg-violet-400',
          btnBg: 'bg-violet-600',
          btnText: 'text-white',
          glow: 'shadow-violet-600/30',
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default: // FOCUS (Dark Red)
        return {
          primary: 'text-pomo', 
          stroke: 'text-pomo-light',
          knob: 'bg-pomo-light',
          btnBg: 'bg-pomo',
          btnText: 'text-white',
          glow: 'shadow-pomo/30',
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme();

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-8">

        {/* Mode Indicator */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button
            onClick={() => { setMode(TimerMode.FOCUS); setIsActive(false); }}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Deep Focus
            </button>
            <button
            onClick={() => { setMode(TimerMode.SHORT_BREAK); setIsActive(false); }}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Short Break
            </button>
            <button
            onClick={() => { setMode(TimerMode.LONG_BREAK); setIsActive(false); }}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Long Break
            </button>
        </div>

        {/* Timer Display Container */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">

            {/* Background Circle - Depletes */}
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
            {/* Track - Thin & Faint */}
            <circle
                cx="50%"
                cy="50%"
                r="45%"
                stroke="currentColor"
                strokeWidth="1"
                fill="transparent"
                className="text-slate-100 dark:text-slate-800"
            />
            {/* Progress Indicator - The colored glowing part */}
            <circle
                cx="50%"
                cy="50%"
                r="45%"
                stroke="currentColor"
                strokeWidth="2" // Ultra thin
                fill="transparent"
                pathLength={100}
                strokeDasharray="100" 
                strokeDashoffset={strokeDashoffset}
                className={cn("transition-all duration-1000 ease-linear timer-glow", 
                theme.stroke
                )}
                strokeLinecap="round"
            />
            </svg>

            {/* The Knob / Mini Circle at the tip */}
            {/* We rotate this container to match the stroke progress */}
            <div 
                className="absolute inset-0 pointer-events-none transition-transform duration-1000 ease-linear"
                style={{ transform: `rotate(-${rotationAngle}deg)` }} // Negative because SVG track rotates clockwise visually as offset decreases? Actually wait.
                // SVG -90deg rotation puts start at top.
                // dashOffset reduces from 100 to 0. 
                // Visual effect: bar grows or shrinks. Here it shrinks.
                // To place knob at the END of the current stroke:
                // If shrinking counter-clockwise:
            >
                 <div 
                    className={cn("absolute left-1/2 -top-[1px] w-3 h-3 rounded-full -translate-x-1/2 shadow-lg", theme.knob)}
                    style={{ 
                        // Position based on radius (45%)
                        // It's absolutely positioned at top center, which matches 0deg/-90deg start
                        top: '5%' // 50% - 45% = 5%
                    }}
                 ></div>
            </div>

            {/* Minimalist Timer Text */}
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
            <span 
                className={cn(
                    "font-sans font-light tracking-tight tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", 
                    theme.primary
                )}
                style={{ 
                    fontSize: 'clamp(4rem, 12vw, 8rem)',
                    transform: `scale(${growthScale})` 
                }}
            >
                {formatTime(timeLeft)}
            </span>
            <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">
                {isActive ? (mode === TimerMode.FOCUS ? 'Focusing...' : 'Resting...') : 'Ready'}
            </span>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-8 relative z-20 mb-8">
            <button
            onClick={resetTimer}
            className="w-16 h-16 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95"
            title="Reset Timer"
            >
            <RotateCcw className="w-6 h-6" />
            </button>

            <button
            onClick={toggleTimer}
            className={cn(
                "w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95",
                isActive 
                    ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" 
                    : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`
            )}
            title={isActive ? "Pause" : "Start"}
            >
            {isActive ? <Pause className="w-8 h-8" /> : <Play className="w-8 h-8 ml-1" />}
            </button>
        </div>

         {/* Session Stats */}
        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-full border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2">
                <Zap className={cn("w-4 h-4", theme.primary)} />
                <span>{sessionsCompleted}</span>
            </div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2">
                <Coffee className="w-4 h-4 text-slate-400" />
                <span>Next: {sessionsCompleted > 0 && (sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long' : 'Short'}</span>
            </div>
        </div>
    </div>
  );
};

export default Timer;

import React, { useState } from 'react';
import { InboxItem, Category } from '../types';
import { calculateDaysRemaining, cn } from '../utils';
import { Trash2, Calendar, ArrowRightCircle, CheckCircle, AlertCircle, Bell, Briefcase, User, BookOpen, Lock, Share2, Sparkles } from 'lucide-react';

interface InboxProps {
  items: InboxItem[];
  onAction: (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction') => void;
  categories?: Category[];
}

const Inbox: React.FC<InboxProps> = ({ items, onAction, categories }) => {
  const [activeTab, setActiveTab] = useState<'notifications' | 'work' | 'personal' | 'learning'>('notifications');

  // Filter items based on active tab
  const filteredItems = items.filter(item => {
    if (item.status !== 'pending') return false;

    if (activeTab === 'notifications') {
        return item.type === 'notification';
    }

    // For other tabs, we are filtering notes based on categories.
    // Assuming category IDs match: 'work', 'personal', 'learning' or using names.
    // For this demo, let's assume we map tabs to specific ID patterns or just filter notes that are NOT notifications.
    if (item.type !== 'note') return false;

    // Hardcoded logic for MVP tabs based on prompt requirements
    // Real app would match item.categoryId with category lists.
    // Here we simulate by assuming some items are tagged.
    // If no category is assigned, we might show them in Personal or Work by default or an 'All' tab.
    // For strict compliance with prompt:
    const catName = categories?.find(c => c.id === item.categoryId)?.name.toLowerCase();

    if (activeTab === 'work') return catName === 'work';
    if (activeTab === 'personal') return catName === 'personal' || !catName; // Default to personal if untagged
    if (activeTab === 'learning') return catName === 'learning';

    return true;
  });

  const unreadCount = items.filter(i => i.type === 'notification' && !i.isRead).length;

  const TabButton = ({ id, label, icon: Icon }: { id: typeof activeTab, label: string, icon: any }) => (
      <button
        onClick={() => setActiveTab(id)}
        className={cn(
            "flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all relative",
            activeTab === id 
                ? "bg-slate-900 text-white shadow-md dark:bg-white dark:text-black" 
                : "text-slate-500 hover:bg-slate-100 hover:text-slate-700 dark:text-slate-400 dark:hover:bg-slate-800"
        )}
      >
        <Icon className="w-4 h-4" />
        {label}
        {id === 'notifications' && unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 border-2 border-white dark:border-black rounded-full"></span>
        )}
      </button>
  );

  return (
    <div className="w-full max-w-4xl mx-auto py-8 px-4">
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-4">
        <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Inbox</h2>

        {/* Tabs */}
        <div className="flex flex-wrap gap-2">
            <TabButton id="notifications" label="Notifications" icon={Bell} />
            <TabButton id="work" label="Work" icon={Briefcase} />
            <TabButton id="personal" label="Personal" icon={User} />
            <TabButton id="learning" label="Learning" icon={BookOpen} />
        </div>
      </div>

      {filteredItems.length === 0 ? (
        <div className="flex flex-col items-center justify-center h-64 text-center border-2 border-dashed border-slate-100 rounded-2xl dark:border-slate-800">
            <p className="text-slate-400">No pending items in {activeTab}.</p>
        </div>
      ) : (
        <div className="grid gap-4">
            {filteredItems.map((item) => {
            const daysLeft = calculateDaysRemaining(item.deadline);
            const isUrgent = daysLeft <= 2;
            const isUnreadNotification = item.type === 'notification' && !item.isRead;

            return (
                <div 
                key={item.id} 
                className={cn(
                    "bg-white rounded-xl p-6 shadow-sm border transition-shadow flex flex-col md:flex-row gap-6 items-start md:items-center justify-between group dark:bg-slate-900",
                    isUnreadNotification ? "border-l-4 border-l-red-500 border-y-slate-100 border-r-slate-100 dark:border-y-slate-800 dark:border-r-slate-800" : "border-slate-100 dark:border-slate-800 hover:shadow-md"
                )}
                >
                <div className="flex-1 space-y-2 relative">
                    {isUnreadNotification && (
                        <div className="absolute -left-10 top-1 w-2 h-2 rounded-full bg-red-500" title="Unread"></div>
                    )}

                    {/* Read-Only Content */}
                    <p className="text-lg text-slate-800 font-medium leading-relaxed dark:text-slate-200 cursor-default select-text">
                        {item.noteContent}
                    </p>

                    <div className="flex items-center gap-3 text-xs">
                    {item.type === 'note' && (
                        <span className={cn(
                            "px-2 py-1 rounded-md font-medium flex items-center gap-1",
                            isUrgent ? "bg-red-50 text-red-600 dark:bg-red-900/30 dark:text-red-400" : "bg-slate-100 text-slate-500 dark:bg-slate-800 dark:text-slate-400"
                        )}>
                            <AlertCircle className="w-3 h-3" />
                            {daysLeft} days remaining
                        </span>
                    )}
                    <span className="text-slate-400">
                        {item.type === 'notification' ? 'Received' : 'Created'} {item.createdAt.toLocaleDateString()}
                    </span>
                    </div>
                </div>

                <div className="flex items-center gap-2 w-full md:w-auto">
                    {/* Share / Export Options */}
                    {item.type === 'note' && (
                        <div className="flex items-center mr-2 pr-2 border-r border-slate-100 dark:border-slate-800">
                             <button 
                                className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                                title="Sync to Google/Notion (Free)"
                             >
                                <Share2 className="w-4 h-4" />
                             </button>
                             <button 
                                className="p-2 text-slate-300 hover:text-amber-500 transition-colors relative group/paid"
                                title="AI Enhanced Report (Paid)"
                             >
                                <Sparkles className="w-4 h-4" />
                                <Lock className="w-2 h-2 absolute top-1 right-1" />
                             </button>
                        </div>
                    )}

                    <button
                        onClick={() => onAction(item.id, 'schedule')}
                        className="p-2 rounded-lg hover:bg-slate-50 text-slate-400 hover:text-blue-600 transition-colors dark:hover:bg-slate-800"
                        title="Schedule"
                    >
                        <Calendar className="w-5 h-5" />
                    </button>

                    <button
                        onClick={() => onAction(item.id, 'nextAction')}
                        className="p-2 rounded-lg hover:bg-slate-50 text-slate-400 hover:text-indigo-600 transition-colors dark:hover:bg-slate-800"
                        title="Act"
                    >
                        <ArrowRightCircle className="w-5 h-5" />
                    </button>

                    <button
                        onClick={() => onAction(item.id, 'complete')}
                        className="p-2 rounded-lg hover:bg-slate-50 text-slate-400 hover:text-green-600 transition-colors dark:hover:bg-slate-800"
                        title="Done"
                    >
                        <CheckCircle className="w-5 h-5" />
                    </button>

                    <button
                        onClick={() => onAction(item.id, 'delete')}
                        className="p-2 rounded-lg hover:bg-slate-50 text-slate-400 hover:text-red-500 transition-colors dark:hover:bg-slate-800"
                        title="Delete"
                    >
                        <Trash2 className="w-5 h-5" />
                    </button>
                </div>
                </div>
            );
            })}
        </div>
      )}
    </div>
  );
};

