import React from 'react';
import { Play, Pause, RotateCcw, Zap, Coffee } from 'lucide-react';
import { TimerMode, Settings, Category } from '../types';
import { formatTime, cn } from '../utils';

interface TimerProps {
  settings: Settings;
  mode: TimerMode;
  setMode: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
}

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  mode, 
  setMode, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote 
}) => {

  const totalTime = (mode === TimerMode.FOCUS ? settings.focusDuration : mode === TimerMode.LONG_BREAK ? settings.longBreakDuration : settings.shortBreakDuration) * 60;

  // Progress Logic
  const progressRatio = timeLeft / totalTime;
  const strokeDashoffset = 100 - (progressRatio * 100);

  // Growth Scale (Subtle breathing effect during active state)
  const growthScale = isActive && mode === TimerMode.FOCUS ? 1.05 : 1;

  // Theme configuration based on mode
  const getTheme = () => {
    switch(mode) {
      case TimerMode.SHORT_BREAK:
        return {
          primary: 'text-emerald-600',
          stroke: 'text-emerald-400',
          btnBg: 'bg-emerald-600',
          btnText: 'text-white',
          glow: 'shadow-emerald-600/30',
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return {
          primary: 'text-violet-600',
          stroke: 'text-violet-400',
          btnBg: 'bg-violet-600',
          btnText: 'text-white',
          glow: 'shadow-violet-600/30',
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default: // FOCUS (Dark Red)
        return {
          primary: 'text-pomo', 
          stroke: 'text-pomo-light',
          btnBg: 'bg-pomo',
          btnText: 'text-white',
          glow: 'shadow-pomo/30',
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme();

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-8">

        {/* Mode Indicator */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button
            onClick={() => setMode(TimerMode.FOCUS)}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Deep Focus
            </button>
            <button
            onClick={() => setMode(TimerMode.SHORT_BREAK)}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Short Break
            </button>
            <button
            onClick={() => setMode(TimerMode.LONG_BREAK)}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", mode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Long Break
            </button>
        </div>

        {/* Timer Display Container */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">

            {/* Background Circle */}
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
            {/* Track - Thin & Faint */}
            <circle
                cx="50%"
                cy="50%"
                r="45%"
                stroke="currentColor"
                strokeWidth="1"
                fill="transparent"
                className="text-slate-100 dark:text-slate-800"
            />
            {/* Progress Indicator - The colored glowing part */}
            {/* strokeLinecap="round" adds the rounded tip natively to the stroke */}
            <circle
                cx="50%"
                cy="50%"
                r="45%"
                stroke="currentColor"
                strokeWidth="6" // Increased width to make the round cap more visible
                fill="transparent"
                pathLength={100}
                strokeDasharray="100" 
                strokeDashoffset={strokeDashoffset}
                strokeLinecap="round" 
                className={cn("transition-all duration-1000 ease-linear timer-glow", 
                theme.stroke
                )}
            />
            </svg>

            {/* Minimalist Timer Text */}
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
            <span 
                className={cn(
                    "font-sans font-light tracking-tight tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", 
                    theme.primary
                )}
                style={{ 
                    fontSize: 'clamp(4rem, 12vw, 8rem)',
                    transform: `scale(${growthScale})` 
                }}
            >
                {formatTime(timeLeft)}
            </span>
            <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">
                {isActive ? (mode === TimerMode.FOCUS ? 'Focusing...' : 'Resting...') : 'Ready'}
            </span>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-8 relative z-20 mb-8">
            <button
            onClick={resetTimer}
            className="w-16 h-16 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95"
            title="Reset Timer"
            >
            <RotateCcw className="w-6 h-6" />
            </button>

            <button
            onClick={toggleTimer}
            className={cn(
                "w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95",
                isActive 
                    ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" 
                    : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`
            )}
            title={isActive ? "Pause" : "Start"}
            >
            {isActive ? <Pause className="w-8 h-8" /> : <Play className="w-8 h-8 ml-1" />}
            </button>
        </div>

         {/* Session Stats */}
        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-full border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2">
                <Zap className={cn("w-4 h-4", theme.primary)} />
                <span>{sessionsCompleted}</span>
            </div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2">
                <Coffee className="w-4 h-4 text-slate-400" />
                <span>Next: {(sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long' : 'Short'}</span>
            </div>
        </div>
    </div>
  );
};

export default Timer;

import React, { useState } from 'react';
import { X, Send, Sparkles, Loader2, PenLine, Clock } from 'lucide-react';
import { Category, TimerMode } from '../types';
import { cn, formatTime } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface QuickCaptureProps {
  isOpen: boolean;
  onClose: () => void;
  categories: Category[];
  onSave: (content: string, categoryId?: string) => void;
  timeLeft: number;
  timerMode: TimerMode;
}

const QuickCapture: React.FC<QuickCaptureProps> = ({ isOpen, onClose, categories, onSave, timeLeft, timerMode }) => {
  const [note, setNote] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  if (!isOpen) return null;

  const handleSave = () => {
    if (!note.trim()) return;
    onSave(note, selectedCategory);
    setNote('');
    onClose();
  };

  const handleAskAI = async () => {
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: "Generate 3 short, punchy, and actionable bullet points to help me start a new project or improve productivity right now. Keep it under 50 words.",
      });

      const text = response.text;
      if (text) {
        setNote(prev => prev + (prev ? '\n\n' : '') + "✨ AI Ideas:\n" + text);
      }
    } catch (error) {
      console.error("AI Error:", error);
      alert("Unable to connect to AI.");
    } finally {
      setIsAiLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      {/* Backdrop - Lighter to see background timer */}
      <div 
        className="absolute inset-0 bg-black/40 backdrop-blur-[2px] transition-opacity" 
        onClick={onClose}
      />

      {/* Mini Timer Preview (Floating above modal) */}
      <div className="absolute top-12 left-1/2 -translate-x-1/2 bg-black/50 backdrop-blur-md border border-white/10 text-white px-6 py-2 rounded-full flex items-center gap-3 shadow-2xl animate-in fade-in slide-in-from-top-4 duration-500 pointer-events-none">
         <Clock className={cn("w-4 h-4", 
             timerMode === TimerMode.FOCUS ? "text-pomo-light" : "text-emerald-400"
         )} />
         <span className="font-mono text-xl font-bold tracking-widest">{formatTime(timeLeft)}</span>
         <span className="text-[10px] uppercase tracking-wider opacity-70">
            {timerMode === TimerMode.FOCUS ? 'Focus' : 'Break'}
         </span>
      </div>

      {/* Modal */}
      <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-2xl shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
        <div className="flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800">
           <div className="flex items-center gap-2 text-slate-900 dark:text-white font-bold">
                <PenLine className="w-5 h-5 text-pomo" />
                <h3>Quick Capture</h3>
            </div>
          <button 
            onClick={onClose}
            className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 p-1"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 space-y-4">
          <textarea
            value={note}
            onChange={(e) => setNote(e.target.value)}
            placeholder="What's on your mind? Capture tasks, ideas, or distractions..."
            className="w-full h-40 bg-slate-50 border-0 rounded-xl p-4 text-slate-700 focus:outline-none focus:ring-1 focus:ring-pomo/20 resize-none dark:bg-slate-800 dark:text-slate-300 placeholder:text-slate-400"
            autoFocus
          />

          <div className="flex items-center justify-between">
              <button 
                onClick={handleAskAI}
                disabled={isAiLoading}
                className={cn(
                    "text-xs font-medium flex items-center gap-1 transition-colors px-3 py-1.5 rounded-lg",
                    isAiLoading ? "text-slate-400" : "text-violet-600 bg-violet-50 hover:bg-violet-100 dark:bg-violet-900/20 dark:hover:bg-violet-900/30"
                )}
            >
                {isAiLoading ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
                AI Assist
            </button>

            <select 
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
                className="bg-white border border-slate-200 rounded-lg px-3 py-1.5 text-sm text-slate-600 outline-none focus:border-pomo dark:bg-slate-800 dark:border-slate-700 dark:text-slate-300"
            >
                <option value="">No Category</option>
                {categories.map(cat => (
                    <option key={cat.id} value={cat.id}>{cat.name}</option>
                ))}
            </select>
          </div>
        </div>

        <div className="p-4 bg-slate-50 dark:bg-slate-800/50 flex justify-end">
             <button 
                onClick={handleSave}
                disabled={!note.trim()}
                className="bg-pomo text-white px-6 py-2.5 rounded-xl font-medium shadow-lg shadow-pomo/20 hover:bg-pomo-dark active:scale-[0.98] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
            >
                <Send className="w-4 h-4" />
                Save Note
            </button>
        </div>
      </div>
    </div>
  );
};

export default QuickCapture;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Timer from './components/Timer';
import Inbox from './components/Inbox';
import Dashboard from './components/Dashboard';
import History from './components/History';
import Categories from './components/Categories';
import QuickCapture from './components/QuickCapture';
import { View, TimerMode, InboxItem, Settings, UserCredits, SessionHistoryItem, Category } from './types';
import { generateId, cn } from './utils';
import { Moon, Sun } from 'lucide-react';

// Mock Data
const INITIAL_SETTINGS: Settings = {
  focusDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  longBreakInterval: 4,
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: 'Work', color: 'bg-red-500' },
  { id: 'c2', name: 'Personal', color: 'bg-blue-500' },
  { id: 'c3', name: 'Learning', color: 'bg-emerald-500' },
];

const INITIAL_INBOX: InboxItem[] = [
  {
    id: '1',
    type: 'note',
    noteContent: 'Research API endpoints for Notion integration',
    createdAt: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000), 
    deadline: new Date(Date.now() + 5 * 24 * 60 * 60 * 1000),
    status: 'pending',
    categoryId: 'c1' // Work
  },
  {
    id: '2',
    type: 'note',
    noteContent: 'Buy groceries for the week',
    createdAt: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000),
    deadline: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
    status: 'pending',
    categoryId: 'c2' // Personal
  },
  {
    id: '3',
    type: 'notification',
    noteContent: 'Payment Successful: Pro Plan renewed for October.',
    createdAt: new Date(),
    deadline: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
    status: 'pending',
    isRead: false
  }
];

const App: React.FC = () => {
  // Navigation & Data State
  const [currentView, setCurrentView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState<string>(''); 
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(true);
  const [isQuickCaptureOpen, setIsQuickCaptureOpen] = useState(false);

  // Timer State (Lifted from Timer.tsx)
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const startTimeRef = useRef<Date | null>(null);

  // Dark mode state
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
  };

  // --- Timer Logic (Lifted) ---
  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  // Update timer when settings change (if not active)
  useEffect(() => {
    if (!isActive) {
      let duration = settings.focusDuration;
      if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
      if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
      setTimeLeft(duration * 60);
    }
  }, [mode, settings, isActive]);

  const handleSessionComplete = useCallback((completedMode: TimerMode) => {
    const duration = completedMode === TimerMode.FOCUS ? settings.focusDuration : 
                     completedMode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000),
        endTime: new Date(),
        mode: completedMode,
        duration: duration,
        noteSnapshot: completedMode === TimerMode.FOCUS ? currentNote : undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    if (currentNote.trim()) {
        saveNoteToInbox(currentNote);
        setCurrentNote('');
    }
  }, [currentNote, settings]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      // After 4 cycles (or whatever setting is), take a long break
      if (newCompleted > 0 && newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  // The Tick
  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      setIsActive(false);
      handleSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, handleSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      sendNotification("Deep Work Started", "Stay focused.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  // Specific function to switch and start a new mode immediately
  const startSession = (newMode: TimerMode) => {
    setIsActive(false);
    setMode(newMode);

    let duration = settings.focusDuration;
    if (newMode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (newMode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;

    setTimeLeft(duration * 60);

    // Slight delay to ensure state updates before starting
    setTimeout(() => {
        setIsActive(true);
        if (newMode === TimerMode.FOCUS) {
            startTimeRef.current = new Date();
        }
    }, 0);
  };

  // ---------------------------

  // Cron Job Simulation
  useEffect(() => {
    const checkExpiration = () => {
      const now = new Date();
      setInbox(prev => prev.filter(item => item.deadline > now));
    };
    const interval = setInterval(checkExpiration, 60000);
    return () => clearInterval(interval);
  }, []);

  const saveNoteToInbox = (content: string, categoryId?: string) => {
      const newItem: InboxItem = {
        id: generateId(),
        type: 'note',
        noteContent: content,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), 
        status: 'pending',
        categoryId: categoryId
      };
      setInbox(prev => [newItem, ...prev]);
  };

  const handleInboxAction = (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction') => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else {
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: action === 'schedule' ? 'scheduled' : 'completed', isRead: true } : i));
        if (action === 'schedule') alert('Opened Google Calendar Integration Mock');
        if (action === 'nextAction') alert('Opened Next Action Definition Mock');
    }
  };

  const handleExport = (type: string) => {
      if (credits.available > 0) {
          setCredits(prev => ({ ...prev, available: prev.available - 1, used: prev.used + 1}));
          alert(`Exporting to ${type}... Credit deducted.`);
      } else {
          alert('Insufficient credits. Please upgrade.');
      }
  };

  const handleOpenNewWindow = () => {
      const width = 1000;
      const height = 800;
      const left = (window.screen.width - width) / 2;
      const top = (window.screen.height - height) / 2;
      window.open(window.location.href, '_blank', `width=${width},height=${height},left=${left},top=${top},resizable=yes,scrollbars=yes,status=yes`);
  };

  const handleViewChange = (view: View) => {
    setCurrentView(view);
    if (!isSidebarCollapsed) {
        setIsSidebarCollapsed(true);
    }
  };

  const handleQuickCaptureOpen = () => {
      setIsQuickCaptureOpen(true);
      setIsSidebarCollapsed(true);
  };

  return (
    <div className="flex min-h-screen bg-white dark:bg-black font-sans transition-colors duration-300 relative overflow-hidden">

      {/* Quick Capture Modal (Global) - Now receives timer state */}
      <QuickCapture 
        isOpen={isQuickCaptureOpen} 
        onClose={() => setIsQuickCaptureOpen(false)}
        categories={categories}
        onSave={saveNoteToInbox}
        timeLeft={timeLeft} // Pass timer data
        timerMode={mode}    // Pass timer data
      />

      {/* Backdrop for Sidebar */}
      {!isSidebarCollapsed && (
        <div 
            className="fixed inset-0 bg-black/40 backdrop-blur-sm z-40 transition-opacity duration-300 animate-in fade-in"
            onClick={() => setIsSidebarCollapsed(true)}
        />
      )}

      {/* Main Content Area */}
      <main 
        className={cn(
            "flex-1 p-8 overflow-y-auto min-h-screen transition-all duration-300 ease-in-out",
            "w-full max-w-7xl mx-auto"
        )}
      >
        {/* Header: Adjusted padding to prevent Dark Mode button overlap with Fixed Menu button on mobile */}
        <header className="mb-8 flex justify-between items-center pr-16 md:pr-0 relative z-0">
             <div className="flex items-center gap-3">
                <div className="w-10 h-10 bg-pomo rounded-xl flex items-center justify-center shadow-lg shadow-pomo/30 flex-shrink-0 text-white">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="w-6 h-6">
                        <path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z" />
                        <path d="M12 6v6l4 2" />
                    </svg>
                </div>
                <div>
                    <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white leading-none">
                        Pomo<span className="text-pomo">Deep</span>
                    </h1>
                    <p className="text-[10px] text-slate-400 font-medium tracking-widest uppercase mt-1">Focus OS</p>
                </div>
             </div>

             <div className="flex items-center gap-4">
                <button 
                  onClick={toggleDarkMode}
                  className="p-2 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-colors"
                  title="Toggle Dark Mode"
                >
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Timer now receives state via props, making it a controlled component */}
            {currentView === 'timer' && (
            <Timer 
                settings={settings}
                activeMode={mode} // Renamed for clarity
                startSession={startSession} // New Prop
                timeLeft={timeLeft}
                isActive={isActive}
                toggleTimer={toggleTimer}
                resetTimer={resetTimer}
                sessionsCompleted={sessionsCompleted}
                currentNote={currentNote}
                onNoteChange={setCurrentNote}
                categories={categories}
                onSaveNote={saveNoteToInbox}
            />
            )}

            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} categories={categories} />
            )}

            {currentView === 'categories' && (
            <Categories 
                categories={categories} 
                onAdd={(c) => setCategories(prev => [...prev, c])}
                onDelete={(id) => setCategories(prev => prev.filter(c => c.id !== id))}
            />
            )}

            {currentView === 'dashboard' && (
            <Dashboard credits={credits} onExport={handleExport} />
            )}

            {currentView === 'history' && (
            <History history={history} />
            )}

            {currentView === 'settings' && (
                <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800">
                    <h3 className="text-lg font-bold mb-6 dark:text-white">Timer Configuration</h3>
                    <div className="space-y-6">
                        <div>
