import React, { useState, useEffect } from 'react';
import { Play, Pause, RotateCcw, Zap, Coffee, Lock } from 'lucide-react';
import { TimerMode, Settings, Category } from '../types';
import { formatTime, cn } from '../utils';

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode; // The mode currently running in App state
  startSession: (mode: TimerMode) => void; // Function to force switch and start
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
}

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote 
}) => {

  // Local view state: Which tab is the user looking at?
  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);

  // If the global active mode changes (e.g. timer finishes and auto-switches), sync the view
  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  // Determine what to display based on whether we are looking at the active timer
  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
      }
  };

  const displayDuration = getDurationForMode(viewMode);

  // If viewing active, show real countdown. If previewing another tab, show that tab's full duration.
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;

  // Progress Logic
  // If previewing (inactive), show full circle (0 progress).
  // If active, show actual progress.
  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);

  // Growth Scale (Subtle breathing effect only when actually active and viewing it)
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  // Theme configuration based on VIEW mode (changes immediately on tab click)
  const getTheme = (m: TimerMode) => {
    switch(m) {
      case TimerMode.SHORT_BREAK:
        return {
          primary: 'text-emerald-600',
          stroke: 'text-emerald-400',
          btnBg: 'bg-emerald-600',
          btnText: 'text-white',
          glow: 'shadow-emerald-600/30',
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return {
          primary: 'text-violet-600',
          stroke: 'text-violet-400',
          btnBg: 'bg-violet-600',
          btnText: 'text-white',
          glow: 'shadow-violet-600/30',
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default: // FOCUS (Dark Red)
        return {
          primary: 'text-pomo', 
          stroke: 'text-pomo-light',
          btnBg: 'bg-pomo',
          btnText: 'text-white',
          glow: 'shadow-pomo/30',
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme(viewMode);

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-8">

        {/* Mode Indicator Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button
            onClick={() => setViewMode(TimerMode.FOCUS)}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Deep Focus
            </button>
            <button
            onClick={() => setViewMode(TimerMode.SHORT_BREAK)}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Short Break
            </button>
            <button
            onClick={() => setViewMode(TimerMode.LONG_BREAK)}
            className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}
            >
            Long Break
            </button>
        </div>

        {/* Timer Display Container */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">

            {/* Background Circle */}
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
            {/* Track - Thin & Faint */}
            <circle
                cx="50%"
                cy="50%"
                r="45%"
                stroke="currentColor"
                strokeWidth="1"
                fill="transparent"
                className="text-slate-100 dark:text-slate-800"
            />
            {/* Progress Indicator - The colored glowing part */}
            {/* strokeLinecap="round" adds the rounded tip natively to the stroke */}
            <circle
                cx="50%"
                cy="50%"
                r="45%"
                stroke="currentColor"
                strokeWidth="6" 
                fill="transparent"
                pathLength={100}
                strokeDasharray="100" 
                strokeDashoffset={strokeDashoffset}
                strokeLinecap="round" 
                className={cn("transition-all duration-1000 ease-linear timer-glow", 
                theme.stroke
                )}
            />
            </svg>

            {/* Minimalist Timer Text */}
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
            <span 
                className={cn(
                    "font-sans font-light tracking-tight tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", 
                    theme.primary
                )}
                style={{ 
                    fontSize: 'clamp(4rem, 12vw, 8rem)',
                    transform: `scale(${growthScale})` 
                }}
            >
                {formatTime(displayTime)}
            </span>
            <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">
                {isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Focusing...' : 'Resting...') : 'Ready'}
            </span>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-8 relative z-20 mb-8">
            {/* Hide reset button if we are previewing a different mode (confusing to reset active timer from here) */}
            <button
            onClick={resetTimer}
            className={cn(
                "w-16 h-16 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95",
                !isViewingActive && "opacity-0 pointer-events-none" 
            )}
            title="Reset Timer"
            >
            <RotateCcw className="w-6 h-6" />
            </button>

            <button
            onClick={() => {
                if (isActive) {
                    if (isViewingActive) {
                        toggleTimer(); // Pause current
                    } else {
                        // Do nothing (Locked) - Optional: Alert user
                    }
                } else {
                    if (isViewingActive) {
                        toggleTimer(); // Start current
                    } else {
                        // Switch to this mode and start
                        startSession(viewMode);
                    }
                }
            }}
            disabled={isActive && !isViewingActive} // Disable click if another timer is running
            className={cn(
                "w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95",
                isActive && isViewingActive 
                    ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" 
                    : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`,
                isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale"
            )}
            title={isActive ? (isViewingActive ? "Pause" : "Another timer is running") : "Start"}
            >
            {isActive ? (
                isViewingActive ? <Pause className="w-8 h-8" /> : <Lock className="w-6 h-6" />
            ) : (
                <Play className="w-8 h-8 ml-1" />
            )}
            </button>
        </div>

         {/* Session Stats */}
        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-full border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2">
                <Zap className={cn("w-4 h-4", theme.primary)} />
                <span>{sessionsCompleted}</span>
            </div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2">
                <Coffee className="w-4 h-4 text-slate-400" />
                <span>Next: {(sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long' : 'Short'}</span>
            </div>
        </div>
    </div>
  );
};

export default Timer;

export enum TimerMode {
  FOCUS = 'FOCUS',
  SHORT_BREAK = 'SHORT_BREAK',
  LONG_BREAK = 'LONG_BREAK',
}

export interface Category {
  id: string;
  name: string;
  color: string; // Tailwind class or hex
}

export interface Note {
  id: string;
  content: string;
  createdAt: Date;
}

export interface InboxItem {
  id: string;
  type: 'note' | 'notification'; 
  noteContent: string;
  createdAt: Date;
  deadline: Date;
  status: 'pending' | 'in-progress' | 'completed' | 'scheduled';
  categoryId?: string;
  nextAction?: string;
  scheduledDate?: Date;
  isRead?: boolean;
  timeSpent?: number; // Minutes spent on this task
  reminderSet?: boolean;
}

export interface UserCredits {
  available: number;
  used: number;
}

export interface Settings {
  focusDuration: number; // in minutes
  shortBreakDuration: number;
  longBreakDuration: number;
  longBreakInterval: number;
}

export interface SessionHistoryItem {
  id: string;
  startTime: Date;
  endTime: Date;
  mode: TimerMode;
  duration: number; // in minutes
  noteSnapshot?: string;
  relatedTaskId?: string;
}

export type View = 'timer' | 'inbox' | 'dashboard' | 'settings' | 'history' | 'categories';

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Timer from './components/Timer';
import Inbox from './components/Inbox';
import Dashboard from './components/Dashboard';
import History from './components/History';
import Categories from './components/Categories';
import QuickCapture from './components/QuickCapture';
import { View, TimerMode, InboxItem, Settings, UserCredits, SessionHistoryItem, Category } from './types';
import { generateId, cn } from './utils';
import { Moon, Sun } from 'lucide-react';

// Mock Data
const INITIAL_SETTINGS: Settings = {
  focusDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  longBreakInterval: 4,
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: 'Work', color: 'bg-red-500' },
  { id: 'c2', name: 'Personal', color: 'bg-blue-500' },
  { id: 'c3', name: 'Learning', color: 'bg-emerald-500' },
];

const INITIAL_INBOX: InboxItem[] = [
  {
    id: '1',
    type: 'note',
    noteContent: 'Research API endpoints for Notion integration',
    createdAt: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000), 
    deadline: new Date(Date.now() + 5 * 24 * 60 * 60 * 1000),
    status: 'pending',
    categoryId: 'c1', // Work
    timeSpent: 45
  },
  {
    id: '2',
    type: 'note',
    noteContent: 'Buy groceries for the week',
    createdAt: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000),
    deadline: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
    status: 'pending',
    categoryId: 'c2', // Personal
    timeSpent: 0
  },
  {
    id: '3',
    type: 'notification',
    noteContent: 'Payment Successful: Pro Plan renewed for October.',
    createdAt: new Date(),
    deadline: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
    status: 'pending',
    isRead: false
  }
];

const App: React.FC = () => {
  // Navigation & Data State
  const [currentView, setCurrentView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState<string>(''); 
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(true);
  const [isQuickCaptureOpen, setIsQuickCaptureOpen] = useState(false);

  // Active Task State (Working on specific task)
  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);

  // Timer State (Lifted from Timer.tsx)
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const startTimeRef = useRef<Date | null>(null);

  // Dark mode state
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
  };

  // --- Timer Logic (Lifted) ---
  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  // Update timer when settings change (if not active)
  useEffect(() => {
    if (!isActive) {
      let duration = settings.focusDuration;
      if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
      if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
      setTimeLeft(duration * 60);
    }
  }, [mode, settings, isActive]);

  const handleSessionComplete = useCallback((completedMode: TimerMode) => {
    const duration = completedMode === TimerMode.FOCUS ? settings.focusDuration : 
                     completedMode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000),
        endTime: new Date(),
        mode: completedMode,
        duration: duration,
        noteSnapshot: completedMode === TimerMode.FOCUS ? currentNote : undefined,
        relatedTaskId: activeTaskId || undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    // If working on a task, add time to it
    if (activeTaskId && completedMode === TimerMode.FOCUS) {
        setInbox(prev => prev.map(item => 
            item.id === activeTaskId 
            ? { ...item, timeSpent: (item.timeSpent || 0) + duration } 
            : item
        ));
    }

    // Save note if exists
    if (currentNote.trim()) {
        saveNoteToInbox(currentNote, undefined, activeTaskId || undefined); // Link note to task if active
        setCurrentNote('');
    }
  }, [currentNote, settings, activeTaskId]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      // After 4 cycles (or whatever setting is), take a long break
      if (newCompleted > 0 && newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  // The Tick
  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      setIsActive(false);
      handleSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, handleSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      sendNotification("Deep Work Started", "Stay focused.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
    setActiveTaskId(null); // Clear active task on reset? Optional.
  };

  // Specific function to switch and start a new mode immediately
  const startSession = (newMode: TimerMode) => {
    setIsActive(false);
    setMode(newMode);

    let duration = settings.focusDuration;
    if (newMode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (newMode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;

    setTimeLeft(duration * 60);

    setTimeout(() => {
        setIsActive(true);
        if (newMode === TimerMode.FOCUS) {
            startTimeRef.current = new Date();
        }
    }, 0);
  };

  // Start working on a specific task from Inbox
  const handleStartTaskFocus = (taskId: string) => {
    setActiveTaskId(taskId);
    setCurrentView('timer');
    startSession(TimerMode.FOCUS);

    // Also move task to "In Progress" if pending
    setInbox(prev => prev.map(item => 
       item.id === taskId && item.status === 'pending' 
       ? { ...item, status: 'in-progress' } 
       : item
    ));
  };

  // ---------------------------

  // Cron Job Simulation
  useEffect(() => {
    const checkExpiration = () => {
      const now = new Date();
      setInbox(prev => prev.filter(item => item.deadline > now));
    };
    const interval = setInterval(checkExpiration, 60000);
    return () => clearInterval(interval);
  }, []);

  const saveNoteToInbox = (content: string, categoryId?: string, relatedTaskId?: string) => {
      const newItem: InboxItem = {
        id: generateId(),
        type: 'note',
        noteContent: content,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), // Default 8 days logic, visual says 3 days often
        status: 'pending',
        categoryId: categoryId,
        // If it's a sub-note of a task, we could link it, but for now flat inbox
      };
      setInbox(prev => [newItem, ...prev]);
  };

  const handleInboxAction = (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction' | 'update', payload?: any) => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else if (action === 'update') {
      setInbox(prev => prev.map(i => i.id === id ? { ...i, ...payload } : i));
    } else {
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: action === 'schedule' ? 'scheduled' : 'completed', isRead: true } : i));
        if (action === 'schedule') alert('Opened Google Calendar Integration Mock');
    }
  };

  const handleExport = (type: string) => {
      if (credits.available > 0) {
          setCredits(prev => ({ ...prev, available: prev.available - 1, used: prev.used + 1}));
          alert(`Exporting to ${type}... Credit deducted.`);
      } else {
          alert('Insufficient credits. Please upgrade.');
      }
  };

  const handleOpenNewWindow = () => {
      const width = 1000;
      const height = 800;
      const left = (window.screen.width - width) / 2;
      const top = (window.screen.height - height) / 2;
      window.open(window.location.href, '_blank', `width=${width},height=${height},left=${left},top=${top},resizable=yes,scrollbars=yes,status=yes`);
  };

  const handleViewChange = (view: View) => {
    setCurrentView(view);
    if (!isSidebarCollapsed) {
        setIsSidebarCollapsed(true);
    }
  };

  const handleQuickCaptureOpen = () => {
      setIsQuickCaptureOpen(true);
      setIsSidebarCollapsed(true);
  };

  const activeTask = inbox.find(i => i.id === activeTaskId);

  return (
    <div className="flex min-h-screen bg-white dark:bg-black font-sans transition-colors duration-300 relative overflow-hidden">

      <QuickCapture 
        isOpen={isQuickCaptureOpen} 
        onClose={() => setIsQuickCaptureOpen(false)}
        categories={categories}
        onSave={saveNoteToInbox}
        timeLeft={timeLeft} 
        timerMode={mode}    
      />

      {!isSidebarCollapsed && (
        <div 
            className="fixed inset-0 bg-black/40 backdrop-blur-sm z-40 transition-opacity duration-300 animate-in fade-in"
            onClick={() => setIsSidebarCollapsed(true)}
        />
      )}

      <main 
        className={cn(
            "flex-1 p-8 overflow-y-auto min-h-screen transition-all duration-300 ease-in-out",
            "w-full max-w-7xl mx-auto"
        )}
      >
        <header className="mb-8 flex justify-between items-center pr-16 md:pr-0 relative z-0">
             <div 
                className="flex items-center gap-3 cursor-pointer group"
                onClick={() => setCurrentView('timer')}
             >
                <div className="w-10 h-10 bg-pomo rounded-xl flex items-center justify-center shadow-lg shadow-pomo/30 flex-shrink-0 text-white group-hover:scale-105 transition-transform">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="w-6 h-6">
                        <path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z" />
                        <path d="M12 6v6l4 2" />
                    </svg>
                </div>
                <div>
                    <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white leading-none group-hover:text-pomo transition-colors">
                        Pomo<span className="text-pomo">Deep</span>
                    </h1>
                    <p className="text-[10px] text-slate-400 font-medium tracking-widest uppercase mt-1">Focus OS</p>
                </div>
             </div>

             <div className="flex items-center gap-4">
                <button 
                  onClick={toggleDarkMode}
                  className="p-2 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-colors"
                  title="Toggle Dark Mode"
                >
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            {currentView === 'timer' && (
            <Timer 
                settings={settings}
                activeMode={mode} 
                startSession={startSession} 
                timeLeft={timeLeft}
                isActive={isActive}
                toggleTimer={toggleTimer}
                resetTimer={resetTimer}
                sessionsCompleted={sessionsCompleted}
                currentNote={currentNote}
                onNoteChange={setCurrentNote}
                categories={categories}
                onSaveNote={saveNoteToInbox}
                activeTask={activeTask} // Pass currently working task
                onStopTask={() => setActiveTaskId(null)}
            />
            )}

            {currentView === 'inbox' && (
            <Inbox 
                items={inbox} 
                onAction={handleInboxAction} 
                categories={categories} 
                onStartSession={handleStartTaskFocus}
                onManageCategories={() => setCurrentView('categories')}
            />
            )}

            {currentView === 'categories' && (
            <Categories 
                categories={categories} 
                onAdd={(c) => setCategories(prev => [...prev, c])}
                onDelete={(id) => setCategories(prev => prev.filter(c => c.id !== id))}
            />
            )}

            {currentView === 'dashboard' && (
            <Dashboard credits={credits} onExport={handleExport} />
            )}

            {currentView === 'history' && (
            <History history={history} />
            )}

            {currentView === 'settings' && (
                <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800">
                    <h3 className="text-lg font-bold mb-6 dark:text-white">Timer Configuration</h3>
                    <div className="space-y-6">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2 dark:text-slate-300">Deep Work Duration (min)</label>
                            <input 
                                type="range" 
                                min="15" 
                                max="60" 
                                value={settings.focusDuration}
                                onChange={(e) => setSettings({...settings, focusDuration: parseInt(e.target.value)})}
                                className="w-full accent-pomo cursor-pointer" 
                            />
                            <div className="flex justify-between text-xs text-slate-400 mt-1">
                                <span>15m</span>
                                <span className="font-bold text-pomo">{settings.focusDuration}m</span>
                                <span>60m</span>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
      </main>

      <Sidebar 
        currentView={currentView} 
        onChangeView={handleViewChange} 
        badgeCount={inbox.filter(i => i.status === 'pending' && i.type === 'notification' && !i.isRead).length}
        isCollapsed={isSidebarCollapsed}
        toggleSidebar={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        onOpenNewWindow={handleOpenNewWindow}
        onQuickCapture={handleQuickCaptureOpen}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, RotateCcw, Zap, Coffee, Lock, PenLine, X, Target } from 'lucide-react';
import { TimerMode, Settings, Category, InboxItem } from '../types';
import { formatTime, cn } from '../utils';

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode;
  startSession: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem; // Task being worked on
  onStopTask?: () => void;
}

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isNoteOpen, setIsNoteOpen] = useState(false);
  const noteInputRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  useEffect(() => {
    if (isNoteOpen && noteInputRef.current) {
        noteInputRef.current.focus();
    }
  }, [isNoteOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;

  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const getTheme = (m: TimerMode) => {
    switch(m) {
      case TimerMode.SHORT_BREAK:
        return {
          primary: 'text-emerald-600',
          stroke: 'text-emerald-400',
          btnBg: 'bg-emerald-600',
          btnText: 'text-white',
          glow: 'shadow-emerald-600/30',
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return {
          primary: 'text-violet-600',
          stroke: 'text-violet-400',
          btnBg: 'bg-violet-600',
          btnText: 'text-white',
          glow: 'shadow-violet-600/30',
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default: // FOCUS
        return {
          primary: 'text-pomo', 
          stroke: 'text-pomo-light',
          btnBg: 'bg-pomo',
          btnText: 'text-white',
          glow: 'shadow-pomo/30',
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme(viewMode);

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-8">

        {/* Active Task Indicator */}
        {activeTask && isViewingActive && (
            <div className="absolute top-24 md:top-8 bg-blue-50 text-blue-700 px-4 py-2 rounded-full flex items-center gap-2 text-sm font-medium border border-blue-100 dark:bg-blue-900/20 dark:text-blue-300 dark:border-blue-800 animate-in fade-in slide-in-from-top-4 z-30">
                <Target className="w-4 h-4" />
                <span className="max-w-[200px] truncate">Working on: {activeTask.noteContent}</span>
                <button 
                    onClick={onStopTask}
                    className="hover:bg-blue-200 dark:hover:bg-blue-800 rounded-full p-0.5 ml-1"
                >
                    <X className="w-3 h-3" />
                </button>
            </div>
        )}

        {/* Mode Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
        </div>

        {/* Timer Display */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
            <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-slate-100 dark:text-slate-800" />
            <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="6" fill="transparent" pathLength={100} strokeDasharray="100" strokeDashoffset={strokeDashoffset} strokeLinecap="round" className={cn("transition-all duration-1000 ease-linear timer-glow", theme.stroke)} />
            </svg>

            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
            <span className={cn("font-sans font-light tracking-tight tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: 'clamp(4rem, 12vw, 8rem)', transform: `scale(${growthScale})` }}>{formatTime(displayTime)}</span>
            <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">{isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Focusing...' : 'Resting...') : 'Ready'}</span>
            </div>
        </div>

        {/* Controls Row */}
        <div className="flex items-center gap-6 relative z-20 mb-8">
            <button onClick={resetTimer} className={cn("w-14 h-14 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95", !isViewingActive && "opacity-0 pointer-events-none")} title="Reset Timer">
                <RotateCcw className="w-5 h-5" />
            </button>

            <button
            onClick={() => {
                if (isActive) {
                    if (isViewingActive) toggleTimer(); 
                } else {
                    if (isViewingActive) toggleTimer(); else startSession(viewMode);
                }
            }}
            disabled={isActive && !isViewingActive}
            className={cn("w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95", isActive && isViewingActive ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`, isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale")}
            title={isActive ? (isViewingActive ? "Pause" : "Another timer is running") : "Start"}
            >
            {isActive ? (isViewingActive ? <Pause className="w-8 h-8" /> : <Lock className="w-6 h-6" />) : (<Play className="w-8 h-8 ml-1" />)}
            </button>

            {/* Note Button (New) */}
            <button 
                onClick={() => setIsNoteOpen(!isNoteOpen)}
                className={cn(
                    "w-14 h-14 rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95",
                    isNoteOpen ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-slate-50 text-slate-400 hover:text-slate-700 hover:bg-slate-100 dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700"
                )}
                title="Session Notes"
            >
                <PenLine className="w-5 h-5" />
            </button>
        </div>

        {/* Inline Note Taker */}
        <div className={cn(
            "w-full max-w-md transition-all duration-300 overflow-hidden mb-8",
            isNoteOpen ? "h-32 opacity-100" : "h-0 opacity-0"
        )}>
            <textarea
                ref={noteInputRef}
                value={currentNote}
                onChange={(e) => onNoteChange(e.target.value)}
                placeholder="Type your thoughts here..."
                className="w-full h-full p-4 bg-slate-50 border border-slate-200 rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-slate-200 text-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
            />
        </div>

        {/* Stats */}
        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-full border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2"><Zap className={cn("w-4 h-4", theme.primary)} /><span>{sessionsCompleted}</span></div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2"><Coffee className="w-4 h-4 text-slate-400" /><span>Next: {(sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long' : 'Short'}</span></div>
        </div>
    </div>
  );
};

export default Timer;

import React, { useState } from 'react';
import { InboxItem, Category } from '../types';
import { calculateDaysRemaining, cn } from '../utils';
import { 
    Trash2, Calendar, ArrowRightCircle, CheckCircle, AlertCircle, Bell, Briefcase, 
    User, BookOpen, Lock, Share2, Sparkles, LayoutList, Kanban, Play, MoreHorizontal,
    Trophy, Clock, Tag
} from 'lucide-react';

interface InboxProps {
  items: InboxItem[];
  onAction: (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction' | 'update', payload?: any) => void;
  categories?: Category[];
  onStartSession: (taskId: string) => void;
  onManageCategories: () => void;
}

const Inbox: React.FC<InboxProps> = ({ items, onAction, categories, onStartSession, onManageCategories }) => {
  const [activeTab, setActiveTab] = useState<'notifications' | 'all'>('all');
  const [viewMode, setViewMode] = useState<'list' | 'board'>('list');
  const [selectedItem, setSelectedItem] = useState<InboxItem | null>(null);

  // Filter items
  const filteredItems = items.filter(item => {
    if (activeTab === 'notifications') return item.type === 'notification';
    return item.type === 'note' && item.status !== 'completed'; // Hide completed in main view usually
  });

  const unreadCount = items.filter(i => i.type === 'notification' && !i.isRead).length;

  const getCategoryColor = (id?: string) => {
      const cat = categories?.find(c => c.id === id);
      return cat ? cat.color : 'bg-slate-200 dark:bg-slate-700';
  };

  const getCategoryName = (id?: string) => {
      return categories?.find(c => c.id === id)?.name || 'Uncategorized';
  };

  const handleUpdateItem = (updates: Partial<InboxItem>) => {
      if (selectedItem) {
          onAction(selectedItem.id, 'update', updates);
          setSelectedItem(prev => prev ? { ...prev, ...updates } : null);
      }
  };

  // --- Renderers ---

  const renderCard = (item: InboxItem) => {
      const daysLeft = calculateDaysRemaining(item.deadline);
      const isUrgent = daysLeft <= 2;
      const hasTrophy = (item.timeSpent || 0) > 60; // 1 hour trophy

      return (
        <div 
            key={item.id}
            onClick={() => setSelectedItem(item)}
            className={cn(
                "group relative bg-white dark:bg-slate-900 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm transition-all duration-300 hover:shadow-md hover:scale-[1.01] cursor-pointer p-4 flex flex-col gap-3",
                item.type === 'notification' && !item.isRead && "border-l-4 border-l-red-500"
            )}
        >
            <div className="flex justify-between items-start">
                 {/* Checkbox (Animated) */}
                 <button 
                    onClick={(e) => { e.stopPropagation(); onAction(item.id, 'complete'); }}
                    className="mt-1 w-5 h-5 rounded-full border-2 border-slate-300 dark:border-slate-600 mr-3 flex items-center justify-center text-transparent hover:border-green-500 hover:text-green-500 transition-all"
                    title="Mark Done"
                 >
                    <CheckCircle className="w-4 h-4" />
                 </button>

                 <div className="flex-1 min-w-0">
                     <p className="text-sm font-medium text-slate-800 dark:text-slate-200 line-clamp-2 leading-relaxed">
                         {item.noteContent}
                     </p>

                     <div className="flex items-center gap-2 mt-2 text-xs text-slate-400">
                        {item.categoryId && (
                            <span className="flex items-center gap-1">
                                <span className={cn("w-2 h-2 rounded-full", getCategoryColor(item.categoryId))} />
                                {getCategoryName(item.categoryId)}
                            </span>
                        )}
                        {daysLeft <= 3 && (
                            <span className="text-red-400 flex items-center gap-1">
                                <Clock className="w-3 h-3" /> {daysLeft}d left
                            </span>
                        )}
                     </div>
                 </div>

                 {/* Quick Action: Start Focus */}
                 {item.type === 'note' && (
                     <button
                        onClick={(e) => { e.stopPropagation(); onStartSession(item.id); }}
                        className="p-2 bg-slate-100 hover:bg-pomo hover:text-white rounded-lg text-slate-500 transition-colors opacity-0 group-hover:opacity-100 dark:bg-slate-800"
                        title="Focus on this"
                     >
                        <Play className="w-4 h-4 fill-current" />
                     </button>
                 )}
            </div>

            {/* Progress / Trophy */}
            {(item.timeSpent || 0) > 0 && (
                <div className="flex items-center gap-2 pt-2 border-t border-slate-50 dark:border-slate-800">
                    <div className="flex-1 h-1 bg-slate-100 rounded-full overflow-hidden dark:bg-slate-800">
                        <div className="h-full bg-blue-500 rounded-full" style={{ width: `${Math.min(((item.timeSpent || 0) / 120) * 100, 100)}%` }}></div>
                    </div>
                    <span className="text-[10px] text-slate-400 whitespace-nowrap">
                        {item.timeSpent}m
                    </span>
                    {hasTrophy && <Trophy className="w-3 h-3 text-amber-400" />}
                </div>
            )}
        </div>
      );
  };

  return (
    <div className="w-full max-w-5xl mx-auto py-8 px-4">

      {/* Header Controls */}
      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Inbox & Tasks</h2>
            <p className="text-xs text-slate-500 mt-1 dark:text-slate-400">Items expire in 3 days if not categorized.</p>
        </div>

        <div className="flex items-center gap-2">
             <div className="flex bg-slate-100 p-1 rounded-lg dark:bg-slate-800">
                <button 
                    onClick={() => setActiveTab('all')} 
                    className={cn("px-3 py-1.5 rounded-md text-sm font-medium transition-all", activeTab === 'all' ? "bg-white shadow-sm dark:bg-slate-700 dark:text-white" : "text-slate-500")}
                >
                    Tasks
                </button>
                <button 
                    onClick={() => setActiveTab('notifications')} 
                    className={cn("px-3 py-1.5 rounded-md text-sm font-medium transition-all flex items-center gap-2", activeTab === 'notifications' ? "bg-white shadow-sm dark:bg-slate-700 dark:text-white" : "text-slate-500")}
                >
                    Alerts
                    {unreadCount > 0 && <span className="bg-red-500 text-white text-[10px] px-1.5 rounded-full">{unreadCount}</span>}
                </button>
             </div>

             <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-2"></div>

             <div className="flex bg-slate-100 p-1 rounded-lg dark:bg-slate-800">
                <button onClick={() => setViewMode('list')} className={cn("p-1.5 rounded-md", viewMode === 'list' ? "bg-white shadow-sm dark:bg-slate-700 text-pomo" : "text-slate-400")}>
                    <LayoutList className="w-4 h-4" />
                </button>
                <button onClick={() => setViewMode('board')} className={cn("p-1.5 rounded-md", viewMode === 'board' ? "bg-white shadow-sm dark:bg-slate-700 text-pomo" : "text-slate-400")}>
                    <Kanban className="w-4 h-4" />
                </button>
             </div>

             <button 
                onClick={onManageCategories}
                className="ml-2 text-xs font-medium text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white border border-slate-200 dark:border-slate-700 px-3 py-2 rounded-lg transition-colors"
             >
                Manage Tags
             </button>
        </div>
      </div>

      {/* Main Content */}
      {viewMode === 'list' ? (
          <div className="grid gap-3">
              {filteredItems.length === 0 && (
                  <div className="text-center py-12 text-slate-400 italic">No items found. Capture something!</div>
              )}
              {filteredItems.map(renderCard)}
          </div>
      ) : (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 overflow-x-auto pb-4">
              {/* Kanban Columns */}
              {['pending', 'in-progress', 'scheduled'].map(status => (
                  <div key={status} className="bg-slate-50 dark:bg-slate-800/50 rounded-xl p-4 min-h-[400px]">
                      <h3 className="font-bold text-slate-400 uppercase text-xs tracking-wider mb-4 flex items-center gap-2">
                          <span className={cn("w-2 h-2 rounded-full", status === 'pending' ? 'bg-slate-400' : status === 'in-progress' ? 'bg-blue-400' : 'bg-purple-400')}></span>
                          {status.replace('-', ' ')}
                      </h3>
                      <div className="space-y-3">
                        {filteredItems.filter(i => i.status === status).map(renderCard)}
                      </div>
                  </div>
              ))}
          </div>
      )}

      {/* Item Details Modal */}
      {selectedItem && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setSelectedItem(null)} />
              <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-2xl shadow-2xl p-6 border border-slate-100 dark:border-slate-800 animate-in fade-in zoom-in-95">
                   {/* Header */}
                   <div className="flex justify-between items-start mb-6">
                        <h3 className="text-xl font-bold dark:text-white leading-tight pr-8">{selectedItem.noteContent}</h3>
                        <button onClick={() => setSelectedItem(null)} className="text-slate-400 hover:text-slate-600"><MoreHorizontal className="w-5 h-5" /></button>
                   </div>

                   {/* Stats */}
                   <div className="grid grid-cols-2 gap-4 mb-6">
                       <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-xl flex items-center gap-3">
                           <Clock className="w-8 h-8 text-blue-500 bg-blue-100 p-1.5 rounded-lg dark:bg-blue-900/30" />
                           <div>
                               <p className="text-xs text-slate-500 uppercase font-bold">Time Spent</p>
                               <p className="font-mono font-bold text-lg dark:text-white">{selectedItem.timeSpent || 0}m</p>
                           </div>
                       </div>
                       <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-xl flex items-center gap-3">
                           <Trophy className="w-8 h-8 text-amber-500 bg-amber-100 p-1.5 rounded-lg dark:bg-amber-900/30" />
                           <div>
                               <p className="text-xs text-slate-500 uppercase font-bold">Goal</p>
