  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isNoteOpen, setIsNoteOpen] = useState(false);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);

  // AI Chat State
  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const noteInputRef = useRef<HTMLTextAreaElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  useEffect(() => {
    if (isNoteOpen && noteInputRef.current) {
        noteInputRef.current.focus();
    }
  }, [isNoteOpen]);

  useEffect(() => {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isDocViewOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;

  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const getTheme = (m: TimerMode) => {
    switch(m) {
      case TimerMode.SHORT_BREAK:
        return {
          primary: 'text-emerald-600',
          stroke: 'text-emerald-400',
          btnBg: 'bg-emerald-600',
          btnText: 'text-white',
          glow: 'shadow-emerald-600/30',
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return {
          primary: 'text-violet-600',
          stroke: 'text-violet-400',
          btnBg: 'bg-violet-600',
          btnText: 'text-white',
          glow: 'shadow-violet-600/30',
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default: // FOCUS
        return {
          primary: 'text-pomo', 
          stroke: 'text-pomo-light',
          btnBg: 'bg-pomo',
          btnText: 'text-white',
          glow: 'shadow-pomo/30',
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme(viewMode);

  // AI Chat Function
  const handleAiChat = async () => {
      if (!chatMessage.trim() || !activeTask) return;

      const userMsg = chatMessage;
      setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
      setChatMessage('');
      setIsAiThinking(true);

      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const prompt = `
            Context Document: "${activeTask.noteContent}"

            Current Session Note Draft: "${currentNote}"

            User Question: "${userMsg}"

            You are a helpful writing assistant. Answer the user's question based on the document context. Keep it concise.
          `;

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: prompt
          });

          const text = response.text || "I couldn't generate a response.";
          setChatHistory(prev => [...prev, { role: 'model', text }]);

      } catch (e) {
          console.error(e);
          setChatHistory(prev => [...prev, { role: 'model', text: "Error connecting to AI assistant." }]);
      } finally {
          setIsAiThinking(false);
      }
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-8">

        {/* Active Task Indicator */}
        {activeTask && isViewingActive && (
            <div className="absolute top-24 md:top-8 flex items-center gap-3 animate-in fade-in slide-in-from-top-4 z-30 w-full justify-center px-4">
                <div className="bg-blue-50 text-blue-700 px-4 py-2 rounded-full flex items-center gap-2 text-sm font-medium border border-blue-100 dark:bg-blue-900/20 dark:text-blue-300 dark:border-blue-800 shadow-sm max-w-[70%]">
                    <Target className="w-4 h-4 shrink-0" />
                    <span className="truncate">{activeTask.noteContent}</span>
                    <button 
                        onClick={onStopTask}
                        className="hover:bg-blue-200 dark:hover:bg-blue-800 rounded-full p-0.5 ml-1 shrink-0"
                    >
                        <X className="w-3 h-3" />
                    </button>
                </div>

                {/* Document View Button */}
                <button 
                    onClick={() => setIsDocViewOpen(true)}
                    className="bg-white text-slate-600 px-4 py-2 rounded-full flex items-center gap-2 text-sm font-medium border border-slate-200 shadow-sm hover:bg-slate-50 dark:bg-slate-800 dark:text-slate-300 dark:border-slate-700 transition-colors"
                >
                    <FileText className="w-4 h-4" />
                    <span className="hidden sm:inline">View Doc</span>
                </button>
            </div>
        )}

        {/* Mode Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
        </div>

        {/* Timer Display */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
            <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-slate-100 dark:text-slate-800" />
            <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="6" fill="transparent" pathLength={100} strokeDasharray="100" strokeDashoffset={strokeDashoffset} strokeLinecap="round" className={cn("transition-all duration-1000 ease-linear timer-glow", theme.stroke)} />
            </svg>

            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
            <span className={cn("font-sans font-light tracking-tight tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: 'clamp(4rem, 12vw, 8rem)', transform: `scale(${growthScale})` }}>{formatTime(displayTime)}</span>
            <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">{isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Focusing...' : 'Resting...') : 'Ready'}</span>
            </div>
        </div>

        {/* Controls Row */}
        <div className="flex items-center gap-6 relative z-20 mb-8">
            <button onClick={resetTimer} className={cn("w-14 h-14 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95", !isViewingActive && "opacity-0 pointer-events-none")} title="Reset Timer">
                <RotateCcw className="w-5 h-5" />
            </button>

            <button
            onClick={() => {
                if (isActive) {
                    if (isViewingActive) toggleTimer(); 
                } else {
                    if (isViewingActive) toggleTimer(); else startSession(viewMode);
                }
            }}
            disabled={isActive && !isViewingActive}
            className={cn("w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95", isActive && isViewingActive ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`, isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale")}
            title={isActive ? (isViewingActive ? "Pause" : "Another timer is running") : "Start"}
            >
            {isActive ? (isViewingActive ? <Pause className="w-8 h-8" /> : <Lock className="w-6 h-6" />) : (<Play className="w-8 h-8 ml-1" />)}
            </button>

            {/* Note Button */}
            <button 
                onClick={() => setIsNoteOpen(!isNoteOpen)}
                className={cn(
                    "w-14 h-14 rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95",
                    isNoteOpen ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-slate-50 text-slate-400 hover:text-slate-700 hover:bg-slate-100 dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700"
                )}
                title="Session Notes"
            >
                <PenLine className="w-5 h-5" />
            </button>
        </div>

        {/* Inline Note Taker */}
        <div className={cn(
            "w-full max-w-md transition-all duration-300 overflow-hidden mb-8",
            isNoteOpen ? "h-32 opacity-100" : "h-0 opacity-0"
        )}>
            <textarea
                ref={noteInputRef}
                value={currentNote}
                onChange={(e) => onNoteChange(e.target.value)}
                placeholder="Type new content here to append to document..."
                className="w-full h-full p-4 bg-slate-50 border border-slate-200 rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-slate-200 text-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
            />
        </div>

        {/* Stats */}
        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-full border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2"><Zap className={cn("w-4 h-4", theme.primary)} /><span>{sessionsCompleted}</span></div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2"><Coffee className="w-4 h-4 text-slate-400" /><span>Next: {(sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long' : 'Short'}</span></div>
        </div>

        {/* --- Document View Panel --- */}
        {isDocViewOpen && activeTask && (
            <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setIsDocViewOpen(false)} />
                <div className="relative bg-white dark:bg-slate-900 w-full max-w-4xl h-[85vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in-95">

                    {/* Header Mobile */}
                    <div className="md:hidden flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800">
                        <h3 className="font-bold truncate dark:text-white">{activeTask.noteContent}</h3>
                        <button onClick={() => setIsDocViewOpen(false)}><X className="w-5 h-5" /></button>
                    </div>

                    {/* Left: Document Content (Read Only Reference) */}
                    <div className="flex-1 p-8 overflow-y-auto custom-scrollbar border-r border-slate-100 dark:border-slate-800">
                         <div className="flex items-center justify-between mb-6">
                            <h2 className="text-2xl font-bold dark:text-white">Document View</h2>
                            <div className="hidden md:block">
                                <button onClick={() => setIsDocViewOpen(false)} className="text-slate-400 hover:text-slate-600"><Maximize2 className="w-5 h-5" /></button>
                            </div>
                         </div>
                         <div className="prose dark:prose-invert max-w-none">
                             <p className="whitespace-pre-wrap text-slate-600 dark:text-slate-300 leading-relaxed">
                                 {activeTask.noteContent}
                             </p>
                         </div>
                         <div className="mt-8 p-4 bg-blue-50 dark:bg-blue-900/20 rounded-xl text-sm text-blue-800 dark:text-blue-300 border border-blue-100 dark:border-blue-800">
                             <strong>Editing Mode:</strong> Use the "Session Notes" (Pen Icon) on the main timer screen to add new paragraphs. They will be appended when the session ends.
                         </div>
                    </div>

                    {/* Right: AI Chat */}
                    <div className="w-full md:w-80 flex flex-col bg-slate-50 dark:bg-slate-950 border-l border-slate-100 dark:border-slate-800">
                        <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center gap-2 font-bold text-slate-700 dark:text-slate-200 bg-white dark:bg-slate-900">
                            <Bot className="w-5 h-5 text-violet-500" />
                            AI Editor
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 space-y-4">
                            {chatHistory.length === 0 && (
                                <div className="text-center text-slate-400 text-xs mt-10">
                                    <Bot className="w-8 h-8 mx-auto mb-2 opacity-50" />
                                    Ask me to summarize, critique, or suggest ideas for this document.
                                </div>
                            )}
                            {chatHistory.map((msg, i) => (
                                <div key={i} className={cn("text-sm p-3 rounded-xl max-w-[90%]", 
                                    msg.role === 'user' ? "bg-violet-600 text-white self-end ml-auto" : "bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 border border-slate-200 dark:border-slate-700"
                                )}>
                                    {msg.text}
                                </div>
                            ))}
                            {isAiThinking && (
                                <div className="flex gap-1 justify-center p-2">
                                    <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}} />
                                    <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}} />
                                    <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}} />
                                </div>
                            )}
                            <div ref={chatEndRef} />
                        </div>

                        <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                            <div className="relative">
                                <input 
                                    type="text" 
                                    value={chatMessage}
                                    onChange={(e) => setChatMessage(e.target.value)}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAiChat()}
                                    placeholder="Ask AI..."
                                    className="w-full bg-slate-100 dark:bg-slate-800 rounded-full pl-4 pr-10 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-violet-500"
                                />
                                <button 
                                    onClick={handleAiChat}
                                    disabled={!chatMessage.trim() || isAiThinking}
                                    className="absolute right-1 top-1 p-1.5 bg-violet-600 text-white rounded-full hover:bg-violet-700 disabled:opacity-50"
                                >
                                    <Send className="w-3 h-3" />
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Timer;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Timer from './components/Timer';
import Inbox from './components/Inbox';
import Dashboard from './components/Dashboard';
import History from './components/History';
import Categories from './components/Categories';
import QuickCapture from './components/QuickCapture';
import { View, TimerMode, InboxItem, Settings, UserCredits, SessionHistoryItem, Category } from './types';
import { generateId, cn } from './utils';
import { Moon, Sun } from 'lucide-react';

// Mock Data
const INITIAL_SETTINGS: Settings = {
  focusDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  longBreakInterval: 4,
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: 'Work', color: 'bg-red-500' },
  { id: 'c2', name: 'Personal', color: 'bg-blue-500' },
  { id: 'c3', name: 'Learning', color: 'bg-emerald-500' },
];

const INITIAL_INBOX: InboxItem[] = [
  {
    id: '1',
    type: 'note',
    noteContent: 'Research API endpoints for Notion integration. Need to verify authentication flows and rate limits.',
    createdAt: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000), 
    deadline: new Date(Date.now() + 5 * 24 * 60 * 60 * 1000),
    status: 'pending',
    categoryId: 'c1', // Work
    timeSpent: 45
  },
  {
    id: '2',
    type: 'note',
    noteContent: 'Buy groceries for the week',
    createdAt: new Date(Date.now() - 1 * 24 * 60 * 60 * 1000),
    deadline: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
    status: 'pending',
    categoryId: 'c2', // Personal
    timeSpent: 0
  },
  {
    id: '3',
    type: 'notification',
    noteContent: 'Payment Successful: Pro Plan renewed for October.',
    createdAt: new Date(),
    deadline: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
    status: 'pending',
    isRead: false
  }
];

const App: React.FC = () => {
  // Navigation & Data State
  const [currentView, setCurrentView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState<string>(''); 
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(true);
  const [isQuickCaptureOpen, setIsQuickCaptureOpen] = useState(false);

  // Active Task State (Working on specific task)
  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);

  // Timer State (Lifted from Timer.tsx)
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const startTimeRef = useRef<Date | null>(null);

  // Dark mode state
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
  };

  // --- Timer Logic (Lifted) ---
  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  // Update timer when settings change (if not active)
  useEffect(() => {
    if (!isActive) {
      let duration = settings.focusDuration;
      if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
      if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
      setTimeLeft(duration * 60);
    }
  }, [mode, settings, isActive]);

  const handleSessionComplete = useCallback((completedMode: TimerMode) => {
    const duration = completedMode === TimerMode.FOCUS ? settings.focusDuration : 
                     completedMode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000),
        endTime: new Date(),
        mode: completedMode,
        duration: duration,
        noteSnapshot: completedMode === TimerMode.FOCUS ? currentNote : undefined,
        relatedTaskId: activeTaskId || undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    // If working on a task, add time to it AND append notes to content
    if (activeTaskId && completedMode === TimerMode.FOCUS) {
        setInbox(prev => prev.map(item => {
            if (item.id === activeTaskId) {
                // Append notes if they exist
                const updatedContent = currentNote.trim() 
                    ? item.noteContent + "\n\n" + `[Session Note ${new Date().toLocaleTimeString()}]: ` + currentNote 
                    : item.noteContent;

                return { 
                    ...item, 
                    timeSpent: (item.timeSpent || 0) + duration,
                    noteContent: updatedContent
                };
            }
            return item;
        }));
    } else if (currentNote.trim() && !activeTaskId) {
        // Standalone note save
        saveNoteToInbox(currentNote);
    }

    setCurrentNote('');

  }, [currentNote, settings, activeTaskId]);

  const switchMode = useCallback(() => {
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);

      let nextMode = TimerMode.SHORT_BREAK;
      // After 4 cycles (or whatever setting is), take a long break
      if (newCompleted > 0 && newCompleted % settings.longBreakInterval === 0) {
        nextMode = TimerMode.LONG_BREAK;
      }
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting ${nextMode === TimerMode.LONG_BREAK ? 'Long' : 'Short'} Break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to deep work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval]);

  // The Tick
  useEffect(() => {
    let interval: number | undefined;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      setIsActive(false);
      handleSessionComplete(mode);
      switchMode();
    }

    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, handleSessionComplete, switchMode]);

  const toggleTimer = () => {
    const willBeActive = !isActive;
    if (willBeActive && mode === TimerMode.FOCUS) {
      sendNotification("Deep Work Started", "Stay focused.");
      startTimeRef.current = new Date();
    }
    setIsActive(willBeActive);
  };

  const resetTimer = () => {
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
    setActiveTaskId(null); 
  };

  // Specific function to switch and start a new mode immediately
  const startSession = (newMode: TimerMode) => {
    setIsActive(false);
    setMode(newMode);

    let duration = settings.focusDuration;
    if (newMode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (newMode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;

    setTimeLeft(duration * 60);

    setTimeout(() => {
        setIsActive(true);
        if (newMode === TimerMode.FOCUS) {
            startTimeRef.current = new Date();
        }
    }, 0);
  };

  // Start working on a specific task from Inbox
  const handleStartTaskFocus = (taskId: string) => {
    setActiveTaskId(taskId);
    setCurrentView('timer');
    startSession(TimerMode.FOCUS);

    // Also move task to "In Progress" if pending
    setInbox(prev => prev.map(item => 
       item.id === taskId && item.status === 'pending' 
       ? { ...item, status: 'in-progress' } 
       : item
    ));
  };

  // ---------------------------

  // Cron Job Simulation
  useEffect(() => {
    const checkExpiration = () => {
      const now = new Date();
      setInbox(prev => prev.filter(item => item.deadline > now));
    };
    const interval = setInterval(checkExpiration, 60000);
    return () => clearInterval(interval);
  }, []);

