              <span className="text-slate-400 text-sm font-medium border border-slate-200 dark:border-slate-700 px-2 py-0.5 rounded-full">
                {categoryItems.length} items
              </span>
           </div>
        </div>

        <div className="grid gap-4">
            {categoryItems.length === 0 && (
                <div className="text-center py-12 bg-slate-50 dark:bg-slate-900 rounded-xl border border-dashed border-slate-200 dark:border-slate-800">
                    <p className="text-slate-400">No active tasks in this category.</p>
                </div>
            )}
            {categoryItems.map(item => (
                <div key={item.id} className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm flex items-center justify-between">
                    <div>
                        <p className="font-medium text-slate-800 dark:text-slate-200">{item.noteContent}</p>
                        <div className="flex items-center gap-4 mt-2 text-xs text-slate-400">
                             <span className={cn("px-1.5 py-0.5 rounded border capitalize", 
                                item.status === 'in-progress' ? 'border-amber-200 text-amber-600 bg-amber-50' : 'border-slate-200'
                             )}>
                                {item.status.replace('-', ' ')}
                             </span>
                             {item.timeSpent ? (
                                <span className="flex items-center gap-1"><Clock className="w-3 h-3" /> {item.timeSpent}m</span>
                             ) : null}
                        </div>
                    </div>
                </div>
            ))}
        </div>
      </div>
    );
  }

  // --- Main List View ---
  return (
    <div className="w-full max-w-4xl mx-auto py-8 px-4 animate-in fade-in">
      <div className="mb-8">
        <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Center of Categories</h2>
        <p className="text-slate-500 text-sm dark:text-slate-400">Manage tags and drill down into specific contexts.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Create Form */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 dark:bg-slate-900 dark:border-slate-800 h-fit">
          <h3 className="text-lg font-bold mb-4 dark:text-white flex items-center gap-2">
            <Plus className="w-5 h-5" /> New Category
          </h3>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-1">Name</label>
              <input
                type="text"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                placeholder="e.g. Work, Personal, Project X"
                className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-red-500 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
              />
            </div>

            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-2">Color Tag</label>
              <div className="flex flex-wrap gap-2">
                {COLORS.map((c) => (
                  <button
                    key={c.value}
                    type="button"
                    onClick={() => setSelectedColor(c.value)}
                    className={cn(
                      "w-6 h-6 rounded-full transition-transform hover:scale-110",
                      c.value,
                      selectedColor === c.value ? "ring-2 ring-offset-2 ring-slate-400 dark:ring-slate-600 scale-110" : ""
                    )}
                    title={c.name}
                  />
                ))}
              </div>
            </div>

            <button
              type="submit"
              disabled={!newName.trim()}
              className="w-full bg-slate-900 text-white py-2 rounded-lg font-medium hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors dark:bg-red-600 dark:hover:bg-red-700"
            >
              Create Category
            </button>
          </form>
        </div>

        {/* Category List */}
        <div className="space-y-3">
          <h3 className="text-lg font-bold mb-4 dark:text-white">Existing Tags</h3>
          {categories.length === 0 && (
             <p className="text-slate-400 text-sm italic">No categories defined yet.</p>
          )}
          {categories.map((cat) => {
            const count = inboxItems.filter(i => i.categoryId === cat.id && i.status !== 'completed' && i.status !== 'scheduled' && i.type === 'note').length;
            return (
                <div 
                    key={cat.id} 
                    onClick={() => setActiveCategory(cat)}
                    className="flex items-center justify-between p-3 bg-white rounded-xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800 group cursor-pointer hover:border-slate-300 dark:hover:border-slate-600 transition-all"
                >
                <div className="flex items-center gap-3">
                    <div className={cn("w-4 h-4 rounded-full", cat.color)} />
                    <span className="font-medium text-slate-700 dark:text-slate-200">{cat.name}</span>
                    <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full dark:bg-slate-800">{count}</span>
                </div>
                <button
                    onClick={(e) => { e.stopPropagation(); onDelete(cat.id); }}
                    className="text-slate-400 hover:text-red-500 transition-colors p-2"
                    title="Delete"
                >
                    <Trash2 className="w-4 h-4" />
                </button>
                </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

