                    <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white leading-none group-hover:text-pomo transition-colors">
                        Pomo<span className="text-pomo">Deep</span>
                    </h1>
                    <p className="text-[10px] text-slate-400 font-medium tracking-widest uppercase mt-1">Focus OS</p>
                </div>
             </div>

             {/* Header Controls adjusted to prevent overlap with floating sidebar button */}
             <div className="flex items-center gap-2 mr-16 md:mr-0">
                <button onClick={toggleSound} className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" title={isSoundEnabled ? "Mute" : "Enable Sounds"}>
                  {isSoundEnabled ? <Volume2 className="w-5 h-5" /> : <VolumeX className="w-5 h-5" />}
                </button>
                <button onClick={toggleDarkMode} className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" title="Toggle Mode">
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
