                     <Hourglass progress={progressRatio} colorClass={theme.bg} />
                     <span className={cn("font-sans font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: '3rem' }}>{formatTime(displayTime)}</span>
