            <button onClick={() => setIsNoteOpen(!isNoteOpen)} className={cn("w-14 h-14 rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95", isNoteOpen ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-slate-50 text-slate-400 hover:text-slate-700 hover:bg-slate-100 dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700")}><PenLine className="w-5 h-5" /></button>
        </div>

        <div className={cn("w-full max-w-md transition-all duration-300 overflow-hidden mb-8", isNoteOpen ? "h-32 opacity-100" : "h-0 opacity-0")}>
            <textarea ref={noteInputRef} value={currentNote} onChange={(e) => onNoteChange(e.target.value)} placeholder="Type new content to append..." className="w-full h-full p-4 bg-slate-50 border border-slate-200 rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-slate-200 text-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200" />
        </div>

        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-full border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2"><Zap className={cn("w-4 h-4", theme.primary)} /><span>{sessionsCompleted}</span></div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2"><Coffee className="w-4 h-4 text-slate-400" /><span>Next: {(sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long' : 'Short'}</span></div>
        </div>

        {isDocViewOpen && activeTask && (
            <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setIsDocViewOpen(false)} />
                <div className="relative bg-white dark:bg-slate-900 w-full max-w-4xl h-[85vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in-95">
                    <div className="md:hidden flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800">
                        <h3 className="font-bold truncate dark:text-white">{activeTask.noteContent}</h3>
                        <button onClick={() => setIsDocViewOpen(false)}><X className="w-5 h-5" /></button>
                    </div>
                    <div className="flex-1 p-8 overflow-y-auto custom-scrollbar border-r border-slate-100 dark:border-slate-800">
                         <div className="flex items-center justify-between mb-6"><h2 className="text-2xl font-bold dark:text-white">Document View</h2><button onClick={() => setIsDocViewOpen(false)} className="hidden md:block text-slate-400 hover:text-slate-600"><Maximize2 className="w-5 h-5" /></button></div>
                         <div className="prose dark:prose-invert max-w-none"><p className="whitespace-pre-wrap text-slate-600 dark:text-slate-300 leading-relaxed">{activeTask.noteContent}</p></div>
                    </div>
                    <div className="w-full md:w-80 flex flex-col bg-slate-50 dark:bg-slate-950 border-l border-slate-100 dark:border-slate-800">
                        <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center gap-2 font-bold text-slate-700 bg-white dark:bg-slate-900 dark:text-slate-200"><Bot className="w-5 h-5 text-violet-500" />AI Editor</div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-4">
                            {chatHistory.map((msg, i) => (<div key={i} className={cn("text-sm p-3 rounded-xl max-w-[90%]", msg.role === 'user' ? "bg-violet-600 text-white self-end ml-auto" : "bg-white dark:bg-slate-800 dark:text-slate-300 border border-slate-200 dark:border-slate-700")}>{msg.text}</div>))}
                            {isAiThinking && <div className="flex gap-1 justify-center p-2"><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-300" /></div>}
                            <div ref={chatEndRef} />
                        </div>
                        <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                            <div className="relative">
                                <input type="text" value={chatMessage} onChange={(e) => setChatMessage(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAiChat()} placeholder="Ask AI..." className="w-full bg-slate-100 dark:bg-slate-800 rounded-full pl-4 pr-10 py-2 text-sm focus:outline-none" />
                                <button onClick={handleAiChat} disabled={!chatMessage.trim() || isAiThinking} className="absolute right-1 top-1 p-1.5 bg-violet-600 text-white rounded-full hover:bg-violet-700 disabled:opacity-50"><Send className="w-3 h-3" /></button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

