  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem;
  onStopTask?: () => void;
}

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isNoteOpen, setIsNoteOpen] = useState(false);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);

  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const noteInputRef = useRef<HTMLTextAreaElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  useEffect(() => {
    if (isNoteOpen && noteInputRef.current) noteInputRef.current.focus();
  }, [isNoteOpen]);

  useEffect(() => {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isDocViewOpen]);

  const isViewingActive = viewMode === activeMode;
  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
          default: return 25;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;
  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const getTheme = (m: TimerMode) => {
    switch(m) {
      case TimerMode.SHORT_BREAK:
        return { primary: 'text-emerald-600', stroke: 'text-emerald-400', btnBg: 'bg-emerald-600', btnText: 'text-white', glow: 'shadow-emerald-600/30', pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200', bg: 'bg-emerald-500' };
      case TimerMode.LONG_BREAK:
        return { primary: 'text-violet-600', stroke: 'text-violet-400', btnBg: 'bg-violet-600', btnText: 'text-white', glow: 'shadow-violet-600/30', pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200', bg: 'bg-violet-500' };
      default:
        return { primary: 'text-pomo', stroke: 'text-pomo-light', btnBg: 'bg-pomo', btnText: 'text-white', glow: 'shadow-pomo/30', pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200', bg: 'bg-pomo' };
    }
  };

  const theme = getTheme(viewMode);

  const handleAiChat = async () => {
      if (!chatMessage.trim() || !activeTask) return;
      const userMsg = chatMessage;
      setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
      setChatMessage('');
      setIsAiThinking(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `Context: "${activeTask.noteContent}". Question: "${userMsg}". Provide a concise writing critique.`
          });
          setChatHistory(prev => [...prev, { role: 'model', text: response.text || "I couldn't generate a response." }]);
      } catch (e) {
          setChatHistory(prev => [...prev, { role: 'model', text: "Error connecting to AI assistant." }]);
      } finally {
          setIsAiThinking(false);
      }
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-8">

        {activeTask && isViewingActive && (
            <div className="absolute top-24 md:top-8 flex items-center gap-3 animate-in fade-in slide-in-from-top-4 z-30 w-full justify-center px-4">
                <div className="bg-blue-50 text-blue-700 px-4 py-2 rounded-full flex items-center gap-2 text-sm font-medium border border-blue-100 dark:bg-blue-900/20 dark:text-blue-300 dark:border-blue-800 shadow-sm max-w-[70%]">
                    <Target className="w-4 h-4 shrink-0" />
                    <span className="truncate">{activeTask.noteContent}</span>
                    <button onClick={onStopTask} className="hover:bg-blue-200 dark:hover:bg-blue-800 rounded-full p-0.5 ml-1 shrink-0"><X className="w-3 h-3" /></button>
                </div>
                <button onClick={() => setIsDocViewOpen(true)} className="bg-white text-slate-600 px-4 py-2 rounded-full flex items-center gap-2 text-sm font-medium border border-slate-200 shadow-sm hover:bg-slate-50 dark:bg-slate-800 dark:text-slate-300 dark:border-slate-700 transition-colors"><FileText className="w-4 h-4" /><span className="hidden sm:inline">View Doc</span></button>
            </div>
        )}

        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
        </div>

        {/* Visualizer Area */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-slate-100 dark:text-slate-800" />
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="6" fill="transparent" pathLength={100} strokeDasharray="100" strokeDashoffset={strokeDashoffset} strokeLinecap="round" className={cn("transition-all duration-1000 ease-linear timer-glow", theme.stroke)} />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
                <span className={cn("font-sans font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: 'clamp(4.5rem, 14vw, 9rem)', transform: `scale(${growthScale})` }}>{formatTime(displayTime)}</span>
                <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">{isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Flowing...' : 'Resting...') : 'Ready'}</span>
            </div>
        </div>

        <div className="flex items-center gap-6 relative z-20 mb-8">
            <button onClick={resetTimer} className={cn("w-14 h-14 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95", !isViewingActive && "opacity-0 pointer-events-none")}><RotateCcw className="w-5 h-5" /></button>
            <button onClick={toggleTimer} disabled={isActive && !isViewingActive} className={cn("w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95", isActive && isViewingActive ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`, isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale")}>
                {isActive ? (isViewingActive ? <Pause className="w-8 h-8" /> : <Lock className="w-6 h-6" />) : (<Play className="w-8 h-8 ml-1" />)}
            </button>
            <button onClick={() => setIsNoteOpen(!isNoteOpen)} className={cn("w-14 h-14 rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95", isNoteOpen ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-slate-50 text-slate-400 hover:text-slate-700 hover:bg-slate-100 dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700")}><PenLine className="w-5 h-5" /></button>
        </div>

        <div className={cn("w-full max-w-md transition-all duration-300 overflow-hidden mb-8", isNoteOpen ? "h-32 opacity-100" : "h-0 opacity-0")}>
            <textarea ref={noteInputRef} value={currentNote} onChange={(e) => onNoteChange(e.target.value)} placeholder="Type new content to append..." className="w-full h-full p-4 bg-slate-50 border border-slate-200 rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-slate-200 text-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200" />
        </div>

        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-full border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2"><Zap className={cn("w-4 h-4", theme.primary)} /><span>{sessionsCompleted}</span></div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2"><Coffee className="w-4 h-4 text-slate-400" /><span>Next: {(sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long' : 'Short'}</span></div>
        </div>

        {isDocViewOpen && activeTask && (
            <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setIsDocViewOpen(false)} />
                <div className="relative bg-white dark:bg-slate-900 w-full max-w-4xl h-[85vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in-95">
                    <div className="md:hidden flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800">
                        <h3 className="font-bold truncate dark:text-white">{activeTask.noteContent}</h3>
                        <button onClick={() => setIsDocViewOpen(false)} className="p-2"><X className="w-6 h-6" /></button>
                    </div>
                    <div className="flex-1 p-8 overflow-y-auto custom-scrollbar border-r border-slate-100 dark:border-slate-800">
                         <div className="flex items-center justify-between mb-6">
                            <h2 className="text-2xl font-bold dark:text-white">Document View</h2>
                            <button onClick={() => setIsDocViewOpen(false)} className="hidden md:block text-slate-400 hover:text-slate-600">
                                <X className="w-6 h-6" />
                            </button>
                         </div>
                         <div className="prose dark:prose-invert max-w-none"><p className="whitespace-pre-wrap text-slate-600 dark:text-slate-300 leading-relaxed">{activeTask.noteContent}</p></div>
                    </div>
                    <div className="w-full md:w-80 flex flex-col bg-slate-50 dark:bg-slate-950 border-l border-slate-100 dark:border-slate-800">
                        <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center gap-2 font-bold text-slate-700 bg-white dark:bg-slate-900 dark:text-slate-200"><Bot className="w-5 h-5 text-violet-500" />AI Editor</div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-4">
                            {chatHistory.map((msg, i) => (<div key={i} className={cn("text-sm p-3 rounded-xl max-w-[90%]", msg.role === 'user' ? "bg-violet-600 text-white self-end ml-auto" : "bg-white dark:bg-slate-800 dark:text-slate-300 border border-slate-200 dark:border-slate-700")}>{msg.text}</div>))}
                            {isAiThinking && <div className="flex gap-1 justify-center p-2"><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-300" /></div>}
                            <div ref={chatEndRef} />
                        </div>
                        <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                            <div className="relative">
                                <input type="text" value={chatMessage} onChange={(e) => setChatMessage(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAiChat()} placeholder="Ask AI..." className="w-full bg-slate-100 dark:bg-slate-800 rounded-full pl-4 pr-10 py-2 text-sm focus:outline-none" />
                                <button onClick={handleAiChat} disabled={!chatMessage.trim() || isAiThinking} className="absolute right-1 top-1 p-1.5 bg-violet-600 text-white rounded-full hover:bg-violet-700 disabled:opacity-50"><Send className="w-3 h-3" /></button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Timer;

import React, { useState } from 'react';
import { X, Send, Sparkles, Loader2, PenLine, Clock } from 'lucide-react';
import { Category, TimerMode } from '../types';
import { cn, formatTime } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface QuickCaptureProps {
  isOpen: boolean;
  onClose: () => void;
  categories: Category[];
  onSave: (content: string, categoryId?: string) => void;
  timeLeft: number;
  timerMode: TimerMode;
}

const QuickCapture: React.FC<QuickCaptureProps> = ({ isOpen, onClose, categories, onSave, timeLeft, timerMode }) => {
  const [note, setNote] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  if (!isOpen) return null;

  const handleSave = () => {
    if (!note.trim()) return;
    onSave(note, selectedCategory);
    setNote('');
    onClose();
  };

  const handleAskAI = async () => {
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: "Generate 3 short productivity tips for the current context. Keep it very brief.",
      });

      const text = response.text;
      if (text) {
        setNote(prev => prev + (prev ? '\n\n' : '') + "✨ AI Ideas:\n" + text);
      }
    } catch (error) {
      console.error("AI Error:", error);
    } finally {
      setIsAiLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      />

      {/* Mini Timer Preview */}
      <div className="absolute top-12 left-1/2 -translate-x-1/2 bg-white/10 backdrop-blur-md border border-white/20 text-white px-6 py-2 rounded-full flex items-center gap-3 shadow-2xl animate-in fade-in slide-in-from-top-4 duration-500 pointer-events-none">
         <Clock className={cn("w-4 h-4", 
             timerMode === TimerMode.FOCUS ? "text-pomo-light" : "text-emerald-400"
         )} />
         <span className="font-mono text-xl font-bold tracking-widest tabular-nums">{formatTime(timeLeft)}</span>
      </div>

      {/* Modal */}
      <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-2xl shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
        <div className="flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800">
           <div className="flex items-center gap-2 text-slate-900 dark:text-white font-bold text-lg">
                <PenLine className="w-5 h-5 text-pomo" />
                <h3>Quick Capture</h3>
            </div>
          <button 
            onClick={onClose}
            className="text-slate-400 hover:text-pomo hover:bg-red-50 dark:hover:bg-red-900/20 p-2 rounded-xl transition-all"
            aria-label="Close"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="p-6 space-y-4">
          <textarea
            value={note}
            onChange={(e) => setNote(e.target.value)}
            placeholder="Capture tasks, ideas, or distractions..."
            className="w-full h-44 bg-slate-50 border-0 rounded-xl p-4 text-slate-700 focus:outline-none focus:ring-2 focus:ring-pomo/10 resize-none dark:bg-slate-800 dark:text-slate-200 placeholder:text-slate-400 text-base"
            autoFocus
          />

          <div className="flex items-center justify-between">
              <button 
                onClick={handleAskAI}
                disabled={isAiLoading}
                className={cn(
                    "text-xs font-bold flex items-center gap-2 transition-all px-4 py-2 rounded-xl",
                    isAiLoading ? "text-slate-400" : "text-violet-600 bg-violet-50 hover:bg-violet-100 dark:bg-violet-900/20 dark:hover:bg-violet-900/30"
                )}
            >
                {isAiLoading ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
                AI Assist
            </button>

            <select 
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
                className="bg-white border border-slate-200 rounded-xl px-4 py-2 text-sm text-slate-600 outline-none focus:border-pomo dark:bg-slate-800 dark:border-slate-700 dark:text-slate-300 shadow-sm"
            >
                <option value="">No Tag</option>
                {categories.map(cat => (
                    <option key={cat.id} value={cat.id}>{cat.name}</option>
                ))}
            </select>
          </div>
        </div>

        <div className="p-4 bg-slate-50 dark:bg-slate-800/50 flex justify-end gap-3">
             <button 
                onClick={onClose}
                className="px-6 py-2.5 rounded-xl font-bold text-slate-500 hover:bg-slate-200 dark:text-slate-400 dark:hover:bg-slate-700 transition-colors"
            >
                Cancel
            </button>
             <button 
                onClick={handleSave}
                disabled={!note.trim()}
                className="bg-pomo text-white px-8 py-2.5 rounded-xl font-bold shadow-xl shadow-pomo/20 hover:bg-pomo-dark active:scale-[0.98] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
            >
                <Send className="w-4 h-4" />
                Save Note
            </button>
        </div>
      </div>
    </div>
  );
};

export default QuickCapture;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import Timer from './components/Timer';
import Inbox from './components/Inbox';
import Dashboard from './components/Dashboard';
import History from './components/History';
import Categories from './components/Categories';
import QuickCapture from './components/QuickCapture';
import { View, TimerMode, InboxItem, Settings, UserCredits, SessionHistoryItem, Category } from './types';
import { generateId, cn, playSynthSound } from './utils';
import { Moon, Sun, Volume2, VolumeX, Timer as TimerIcon } from 'lucide-react';

// Mock Data
const INITIAL_SETTINGS: Settings = {
  focusDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  longBreakInterval: 4,
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: 'Work', color: 'bg-red-500' },
  { id: 'c2', name: 'Personal', color: 'bg-blue-500' },
  { id: 'c3', name: 'Learning', color: 'bg-emerald-500' },
];

const INITIAL_INBOX: InboxItem[] = [
  {
    id: 'w1', type: 'note', status: 'pending', categoryId: 'c1',
    noteContent: 'Q3 Financial Report Analysis',
    createdAt: new Date(), deadline: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000), timeSpent: 0
  },
  {
    id: 'w2', type: 'note', status: 'in-progress', categoryId: 'c1',
    noteContent: 'Design System Migration to Tailwind v4',
    createdAt: new Date(), deadline: new Date(Date.now() + 5 * 24 * 60 * 60 * 1000), timeSpent: 120
  },
  {
    id: 'w3', type: 'note', status: 'pending', categoryId: 'c1',
    noteContent: 'Client Meeting Preparation: Alpha Corp',
    createdAt: new Date(), deadline: new Date(Date.now() + 1 * 24 * 60 * 60 * 1000), timeSpent: 15
  },
  {
    id: 'n1', type: 'notification', noteContent: 'Payment Successful: Pro Plan renewed.', createdAt: new Date(), deadline: new Date(), status: 'pending', isRead: false
  }
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState<string>(''); 
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(true);
  const [isQuickCaptureOpen, setIsQuickCaptureOpen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);

  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);

  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);
  const startTimeRef = useRef<Date | null>(null);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
    if (isSoundEnabled) playSynthSound('theme-change');
  };

  const toggleSound = () => {
    setIsSoundEnabled(prev => {
      const newVal = !prev;
      if (newVal) playSynthSound('toggle');
      return newVal;
    });
  };

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  useEffect(() => {
    if (!isActive) {
      let duration = settings.focusDuration;
      if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
      if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
      setTimeLeft(duration * 60);
    }
  }, [mode, settings, isActive]);

  const handleSessionComplete = useCallback((completedMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('complete');

    const duration = completedMode === TimerMode.FOCUS ? settings.focusDuration : 
                     completedMode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000),
        endTime: new Date(),
        mode: completedMode,
        duration: duration,
        noteSnapshot: completedMode === TimerMode.FOCUS ? currentNote : undefined,
        relatedTaskId: activeTaskId || undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    if (activeTaskId && completedMode === TimerMode.FOCUS) {
        setInbox(prev => prev.map(item => {
            if (item.id === activeTaskId) {
                const updatedContent = currentNote.trim() 
                    ? item.noteContent + "\n\n" + `[Session Note ${new Date().toLocaleTimeString()}]: ` + currentNote 
                    : item.noteContent;
                return { ...item, timeSpent: (item.timeSpent || 0) + duration, noteContent: updatedContent };
            }
            return item;
        }));
    } else if (currentNote.trim() && !activeTaskId) {
        saveNoteToInbox(currentNote);
    }
    setCurrentNote('');
  }, [currentNote, settings, activeTaskId, isSoundEnabled]);

  const switchMode = useCallback(() => {
    if (isSoundEnabled) playSynthSound('switch');
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);
      let nextMode = (newCompleted > 0 && newCompleted % settings.longBreakInterval === 0) ? TimerMode.LONG_BREAK : TimerMode.SHORT_BREAK;
      setMode(nextMode);
      sendNotification("Time for a break!", `Focus session complete. Starting break.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Break Over", "Time to get back to work!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval, isSoundEnabled]);

  useEffect(() => {
    let interval: number | undefined;
    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => {
           if (isSoundEnabled && prev > 1) playSynthSound('tick');
           return prev - 1;
        });
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      setIsActive(false);
      handleSessionComplete(mode);
      switchMode();
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, handleSessionComplete, switchMode, isSoundEnabled]);

  const toggleTimer = () => {
    const nextActive = !isActive;
    if (isSoundEnabled) {
        playSynthSound(nextActive ? 'start' : 'pause');
    }
    setIsActive(nextActive);
  };

  const resetTimer = () => {
    if (isSoundEnabled) playSynthSound('toggle');
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
    setActiveTaskId(null); 
  };

  const startSession = (newMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('switch');
    setIsActive(false);
    setMode(newMode);
    let duration = settings.focusDuration;
    if (newMode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (newMode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
    setTimeout(() => {
        setIsActive(true);
        if (isSoundEnabled) playSynthSound('start');
    }, 0);
  };

  const handleStartTaskFocus = (taskId: string) => {
    setActiveTaskId(taskId);
    setCurrentView('timer');
    startSession(TimerMode.FOCUS);
    setInbox(prev => prev.map(item => item.id === taskId && item.status === 'pending' ? { ...item, status: 'in-progress' } : item));
  };

  const saveNoteToInbox = (content: string, categoryId?: string) => {
      const newItem: InboxItem = {
        id: generateId(),
        type: 'note',
        noteContent: content,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), 
        status: 'pending',
        categoryId: categoryId,
      };
      setInbox(prev => [newItem, ...prev]);
  };

  const handleInboxAction = (id: string, action: string, payload?: any) => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else if (action === 'update') {
      setInbox(prev => prev.map(i => i.id === id ? { ...i, ...payload } : i));
    } else if (action === 'schedule') {
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: 'scheduled', isRead: true } : i));
    }
  };

  const handleViewChange = (view: View) => {
    setCurrentView(view);
    if (isSoundEnabled) playSynthSound('toggle');
    setIsSidebarCollapsed(true);
  };

  const handleOpenNewWindow = () => {
    window.open(window.location.href, '_blank', 'width=500,height=800,resizable=yes,scrollbars=yes');
  };

  const handleQuickCaptureOpen = () => {
    setIsQuickCaptureOpen(true);
  };

  const activeTask = inbox.find(i => i.id === activeTaskId);

  return (
    <div className="flex min-h-screen bg-white dark:bg-black font-sans transition-colors duration-300 relative overflow-hidden">

      <QuickCapture isOpen={isQuickCaptureOpen} onClose={() => setIsQuickCaptureOpen(false)} categories={categories} onSave={saveNoteToInbox} timeLeft={timeLeft} timerMode={mode} />

      {!isSidebarCollapsed && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-40 transition-opacity duration-300" onClick={() => setIsSidebarCollapsed(true)} />
      )}

      <main className={cn("flex-1 p-8 overflow-y-auto min-h-screen transition-all duration-300 ease-in-out w-full max-w-7xl mx-auto")}>
        <header className="mb-8 flex justify-between items-center pr-16 relative z-10">
             <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setCurrentView('timer')}>
                <div className="w-10 h-10 bg-pomo rounded-xl flex items-center justify-center shadow-lg shadow-pomo/30 flex-shrink-0 text-white group-hover:scale-105 transition-transform">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="w-6 h-6">
                        <path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z" />
                        <path d="M12 6v6l4 2" />
                    </svg>
                </div>
                <div>
                    <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white leading-none group-hover:text-pomo transition-colors">
                        Pomo<span className="text-pomo">Deep</span>
                    </h1>
                    <p className="text-[10px] text-slate-400 font-medium tracking-widest uppercase mt-1">Focus OS</p>
                </div>
             </div>

             {/* Header Controls adjusted: Settings (Chronometer) -> Sound -> Dark Mode */}
             <div className="flex items-center gap-1 mr-4">
                <button 
                  onClick={() => handleViewChange('settings')} 
                  className={cn(
                    "p-2 rounded-full transition-all active:scale-90",
                    currentView === 'settings' ? "bg-pomo text-white" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800"
                  )}
                  title="Timer Configuration"
                >
                  <TimerIcon className="w-5 h-5" />
                </button>
                <button 
                  onClick={toggleSound} 
                  className="p-2 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" 
                  title={isSoundEnabled ? "Mute" : "Enable Sounds"}
                >
                  {isSoundEnabled ? <Volume2 className="w-5 h-5" /> : < VolumeX className="w-5 h-5" />}
                </button>
                <button 
                  onClick={toggleDarkMode} 
                  className="p-2 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" 
                  title="Toggle Mode"
                >
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            {currentView === 'timer' && (
            <Timer settings={settings} activeMode={mode} startSession={startSession} timeLeft={timeLeft} isActive={isActive} toggleTimer={toggleTimer} resetTimer={resetTimer} sessionsCompleted={sessionsCompleted} currentNote={currentNote} onNoteChange={setCurrentNote} categories={categories} onSaveNote={saveNoteToInbox} activeTask={activeTask} onStopTask={() => setActiveTaskId(null)} />
            )}
            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} categories={categories} onStartSession={handleStartTaskFocus} onManageCategories={() => setCurrentView('categories')} />
            )}
            {currentView === 'categories' && (
            <Categories categories={categories} onAdd={(c) => setCategories(prev => [...prev, c])} onDelete={(id) => setCategories(prev => prev.filter(c => c.id !== id))} inboxItems={inbox} />
            )}
            {currentView === 'dashboard' && <Dashboard credits={credits} onExport={() => {}} />}
            {currentView === 'history' && <History history={history} />}
            {currentView === 'settings' && (
                <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800">
                    <h3 className="text-lg font-bold mb-6 dark:text-white">Timer Configuration</h3>
                    <div className="space-y-8">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2 dark:text-slate-300">Deep Work Duration (min)</label>
                            <input type="range" min="15" max="60" value={settings.focusDuration} onChange={(e) => setSettings({...settings, focusDuration: parseInt(e.target.value)})} className="w-full accent-pomo cursor-pointer" />
                            <div className="flex justify-between text-xs text-slate-400 mt-1"><span>15m</span><span className="font-bold text-pomo">{settings.focusDuration}m</span><span>60m</span></div>
                        </div>
                    </div>
                </div>
            )}
        </div>
      </main>

      <Sidebar currentView={currentView} onChangeView={handleViewChange} badgeCount={inbox.filter(i => i.status === 'pending' && i.type === 'notification' && !i.isRead).length} isCollapsed={isSidebarCollapsed} toggleSidebar={() => setIsSidebarCollapsed(!isSidebarCollapsed)} onOpenNewWindow={handleOpenNewWindow} onQuickCapture={handleQuickCaptureOpen} />
    </div>
  );
};

export default App;

