const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('timer');
  const [previousView, setPreviousView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState(''); 
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isQuickCaptureOpen, setIsQuickCaptureOpen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);

  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);

  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
    if (isSoundEnabled) playSynthSound('theme-change');
  };

  const toggleSound = () => {
    setIsSoundEnabled(prev => {
      const newVal = !prev;
      if (newVal) playSynthSound('toggle');
      return newVal;
    });
  };

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  // Sincronización de timeLeft al cambiar configuraciones o modos cuando el timer está inactivo
  useEffect(() => {
    if (!isActive) {
      let duration = settings.focusDuration;
      if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
      if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
      setTimeLeft(duration * 60);
    }
  }, [mode, settings, isActive]);

  const handleSessionComplete = useCallback((completedMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('complete');

    const duration = completedMode === TimerMode.FOCUS ? settings.focusDuration : 
                     completedMode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000),
        endTime: new Date(),
        mode: completedMode,
        duration: duration,
        noteSnapshot: completedMode === TimerMode.FOCUS ? currentNote : undefined,
        relatedTaskId: activeTaskId || undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    if (activeTaskId && completedMode === TimerMode.FOCUS) {
        setInbox(prev => prev.map(item => {
            if (item.id === activeTaskId) {
                const updatedContent = currentNote.trim() 
                    ? item.noteContent + "\n\n" + `[Sesión ${new Date().toLocaleTimeString()}]: ` + currentNote 
                    : item.noteContent;
                return { ...item, timeSpent: (item.timeSpent || 0) + duration, noteContent: updatedContent };
            }
            return item;
        }));
    } else if (currentNote.trim() && !activeTaskId) {
        saveNoteToInbox(currentNote);
    }
    setCurrentNote('');
  }, [currentNote, settings, activeTaskId, isSoundEnabled]);

  const switchMode = useCallback(() => {
    if (isSoundEnabled) playSynthSound('switch');
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);
      let nextMode = (newCompleted > 0 && newCompleted % settings.longBreakInterval === 0) ? TimerMode.LONG_BREAK : TimerMode.SHORT_BREAK;
      setMode(nextMode);
      sendNotification("¡Hora de un descanso!", `Sesión de enfoque completada.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Descanso terminado", "¡A darle con todo!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval, isSoundEnabled]);

  useEffect(() => {
    let interval: number | undefined;
    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => {
           if (isSoundEnabled && prev > 1) playSynthSound('tick');
           return prev - 1;
        });
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      setIsActive(false);
      handleSessionComplete(mode);
      switchMode();
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, handleSessionComplete, switchMode, isSoundEnabled]);

  const toggleTimer = () => {
    const nextActive = !isActive;
    if (isSoundEnabled) {
        playSynthSound(nextActive ? 'start' : 'pause');
    }
    setIsActive(nextActive);
  };

  const resetTimer = () => {
    if (isSoundEnabled) playSynthSound('toggle');
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
    // Nota: El reset no debería quitar la tarea activa a menos que se quiera explícitamente.
    // Lo dejamos para que el usuario pueda reiniciar el tiempo de la tarea actual.
  };

  const startSession = (newMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('switch');
    setIsActive(false);
    setMode(newMode);

    let duration = settings.focusDuration;
    if (newMode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (newMode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);

    setTimeout(() => {
        setIsActive(true);
        if (isSoundEnabled) playSynthSound('start');
    }, 10);
  };

  const handleStartTaskFocus = (taskId: string) => {
    setActiveTaskId(taskId);
    setCurrentView('timer');
    startSession(TimerMode.FOCUS);
    setInbox(prev => prev.map(item => item.id === taskId && item.status === 'pending' ? { ...item, status: 'in-progress' } : item));
  };

  const saveNoteToInbox = (content: string, categoryId?: string) => {
      const newItem: InboxItem = {
        id: generateId(),
        type: 'note',
        noteContent: content,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), 
        status: 'pending',
        categoryId: categoryId,
      };
      setInbox(prev => [newItem, ...prev]);
  };

  const handleInboxAction = (id: string, action: string, payload?: any) => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else if (action === 'update') {
      setInbox(prev => prev.map(i => i.id === id ? { ...i, ...payload } : i));
    } else if (action === 'schedule') {
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: 'scheduled', isRead: true } : i));
    }
  };

  const handleUpdateTask = (id: string, content: string) => {
    setInbox(prev => prev.map(item => item.id === id ? { ...item, noteContent: content } : item));
  };

  const handleViewChange = (view: View) => {
    if (view === currentView) return;
    setPreviousView(currentView);
    setCurrentView(view);
    if (isSoundEnabled) playSynthSound('toggle');
    setIsMenuOpen(false);
  };

  const toggleSettings = () => {
    if (currentView === 'settings') {
        setCurrentView(previousView || 'timer');
    } else {
        setPreviousView(currentView);
        setCurrentView('settings');
    }
    if (isSoundEnabled) playSynthSound('toggle');
  };

  const activeTask = inbox.find(i => i.id === activeTaskId);
  const badgeCount = inbox.filter(i => i.status === 'pending' && i.type === 'notification' && !i.isRead).length;

  return (
    <div className="flex flex-col min-h-screen bg-white dark:bg-black font-sans transition-colors duration-300 relative overflow-hidden">

      <QuickCapture isOpen={isQuickCaptureOpen} onClose={() => setIsQuickCaptureOpen(false)} categories={categories} onSave={saveNoteToInbox} timeLeft={timeLeft} timerMode={mode} />

      {isMenuOpen && (
        <div className="fixed inset-0 bg-black/20 backdrop-blur-sm z-40 transition-opacity duration-300" onClick={() => setIsMenuOpen(false)} />
      )}

      <main className="flex-1 p-8 overflow-y-auto w-full max-w-7xl mx-auto flex flex-col items-center pb-32">
        <header className="mb-8 w-full grid grid-cols-3 items-center relative z-50 px-2">
             {/* Left: Logo */}
             <div className="flex items-center gap-3 cursor-pointer group justify-self-start" onClick={() => handleViewChange('timer')}>
                <div className="w-10 h-10 bg-pomo rounded-xl flex items-center justify-center shadow-lg shadow-pomo/30 flex-shrink-0 text-white group-hover:scale-105 transition-transform">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="w-6 h-6">
                        <path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z" />
                        <path d="M12 6v6l4 2" />
                    </svg>
                </div>
                <div className="hidden lg:block">
                    <h1 className="text-xl font-bold tracking-tight text-slate-900 dark:text-white leading-none group-hover:text-pomo transition-colors">
                        Pomo<span className="text-pomo">Deep</span>
                    </h1>
                    <p className="text-[9px] text-slate-400 font-medium tracking-widest uppercase mt-0.5">Focus OS</p>
                </div>
             </div>

             {/* Center: User Profile */}
             <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 dark:bg-slate-900 rounded-full border border-slate-100 dark:border-slate-800 justify-self-center group transition-all hover:bg-slate-100 dark:hover:bg-slate-800 cursor-default">
                <div className="w-7 h-7 rounded-full bg-slate-200 dark:bg-slate-800 overflow-hidden ring-2 ring-white dark:ring-slate-900 flex-shrink-0">
                    <img src="https://picsum.photos/100/100" alt="User" className="w-full h-full object-cover" />
                </div>
                <div className="flex flex-col leading-none">
                    <p className="text-[11px] font-bold text-slate-900 dark:text-white whitespace-nowrap">Alex Designer</p>
                    <p className="text-[9px] text-slate-400 font-medium uppercase tracking-tighter">Pro Plan</p>
                </div>
                <button className="text-slate-400 hover:text-pomo transition-colors ml-1" title="Suscripción Pro">
                    <CreditCard className="w-3 h-3" />
                </button>
             </div>

             {/* Right: Controls */}
             <div className="flex items-center gap-1.5 justify-self-end">
                <button 
                  onClick={toggleSettings} 
                  className={cn(
                    "p-2.5 rounded-full transition-all active:scale-90",
                    currentView === 'settings' ? "bg-pomo text-white shadow-lg shadow-pomo/30" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800"
                  )}
                  title="Configuración"
                >
                  <TimerIcon className="w-5 h-5" />
                </button>
                <button 
                  onClick={toggleSound} 
                  className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" 
                  title={isSoundEnabled ? "Silenciar" : "Activar Sonidos"}
                >
                  {isSoundEnabled ? <Volume2 className="w-5 h-5" /> : < VolumeX className="w-5 h-5" />}
                </button>
                <button 
                  onClick={toggleDarkMode} 
                  className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" 
                  title="Tema"
                >
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>

                <div className="relative">
                  <button 
                    onClick={() => setIsMenuOpen(!isMenuOpen)} 
                    className={cn(
                      "p-2.5 rounded-full transition-all active:scale-90 relative",
                      isMenuOpen ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800"
                    )}
                    title="Menú"
                  >
                    {isMenuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
                    {badgeCount > 0 && !isMenuOpen && (
                      <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-pomo border-2 border-white dark:border-black rounded-full" />
                    )}
                  </button>

                  {/* Dropdown Menu */}
                  {isMenuOpen && (
                    <div className="absolute right-0 mt-3 w-64 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl shadow-2xl p-4 animate-in fade-in zoom-in-95 duration-200">
                        <button 
                          onClick={() => { setIsQuickCaptureOpen(true); setIsMenuOpen(false); }}
                          className="w-full bg-slate-900 hover:bg-slate-800 text-white p-3 rounded-xl flex items-center justify-center gap-2 transition-all mb-4 dark:bg-white dark:text-black dark:hover:bg-slate-200 font-bold text-sm"
                        >
                          <PenLine className="w-4 h-4" /> Captura Rápida
                        </button>

                        <nav className="space-y-1">
                          {[
                            { id: 'timer', icon: TimerIcon, label: 'Enfoque' },
                            { id: 'inbox', icon: InboxIcon, label: 'Inbox', badge: badgeCount },
                            { id: 'categories', icon: Tags, label: 'Categorías' },
                            { id: 'dashboard', icon: BarChart2, label: 'Estadísticas' },
                            { id: 'history', icon: HistoryIcon, label: 'Historial' },
                          ].map((item) => (
                            <button
                              key={item.id}
                              onClick={() => handleViewChange(item.id as View)}
                              className={cn(
                                "w-full flex items-center justify-between px-4 py-3 rounded-xl transition-colors font-medium text-sm",
                                currentView === item.id 
                                  ? "bg-pomo/5 text-pomo dark:bg-pomo/10" 
                                  : "text-slate-500 hover:bg-slate-50 dark:text-slate-400 dark:hover:bg-slate-800"
                              )}
                            >
                              <div className="flex items-center gap-3">
                                <item.icon className="w-4 h-4" />
                                {item.label}
                              </div>
                              {item.badge ? (
                                <span className="bg-pomo text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full">{item.badge}</span>
                              ) : null}
                            </button>
                          ))}
                        </nav>
                    </div>
                  )}
                </div>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 w-full flex-1">
            {currentView === 'timer' && (
            <Timer 
              settings={settings} 
              activeMode={mode} 
              startSession={startSession} 
              timeLeft={timeLeft} 
              isActive={isActive} 
              toggleTimer={toggleTimer} 
              resetTimer={resetTimer} 
              sessionsCompleted={sessionsCompleted} 
              currentNote={currentNote} 
              onNoteChange={setCurrentNote} 
              categories={categories} 
              onSaveNote={saveNoteToInbox} 
              activeTask={activeTask} 
              onStopTask={() => setActiveTaskId(null)}
              onGoToInbox={() => handleViewChange('inbox')}
              onUpdateTask={handleUpdateTask}
            />
            )}
            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} categories={categories} onStartSession={handleStartTaskFocus} onManageCategories={() => setCurrentView('categories')} />
            )}
            {currentView === 'categories' && (
            <Categories categories={categories} onAdd={(c) => setCategories(prev => [...prev, c])} onDelete={(id) => setCategories(prev => prev.filter(c => c.id !== id))} inboxItems={inbox} />
            )}
            {currentView === 'dashboard' && <Dashboard credits={credits} onExport={() => {}} />}
            {currentView === 'history' && <History history={history} />}
            {currentView === 'settings' && (
                <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800">
                    <h3 className="text-lg font-bold mb-6 dark:text-white">Duración de Sesión</h3>
                    <div className="space-y-8">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2 dark:text-slate-300">Enfoque Profundo (min)</label>
                            <input type="range" min="15" max="60" value={settings.focusDuration} onChange={(e) => setSettings({...settings, focusDuration: parseInt(e.target.value)})} className="w-full accent-pomo cursor-pointer" />
                            <div className="flex justify-between text-xs text-slate-400 mt-1"><span>15m</span><span className="font-bold text-pomo">{settings.focusDuration}m</span><span>60m</span></div>
                        </div>
                    </div>
                </div>
            )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
// Added Edit3 to the lucide-react import list
import { Play, Pause, RotateCcw, Zap, Coffee, Lock, PenLine, X, Target, FileText, Bot, Send, Maximize2, Inbox as InboxIcon, Download, Code, Eye, Save, HelpCircle, Edit3 } from 'lucide-react';
import { TimerMode, Settings, Category, InboxItem } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode;
  startSession: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem;
  onStopTask?: () => void;
  onGoToInbox: () => void;
  onUpdateTask: (id: string, content: string) => void;
}

const DEEP_WORK_TEMPLATE = (title: string) => `# ${title}
## 🎯 Objetivos de la Sesión
- [ ] Objetivo principal: 
- [ ] Tarea técnica 1:

## 📝 Notas de Enfoque
*Escribe aquí tus ideas y descubrimientos durante el flujo...*

## 🚀 Próximos Pasos
- 

---
*Sesión iniciada: ${new Date().toLocaleTimeString()}*`;

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask,
  onGoToInbox,
  onUpdateTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);

  // Doc Editor State
  const [docContent, setDocContent] = useState('');
  const [showPreview, setShowPreview] = useState(false);

  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  useEffect(() => {
    if (activeTask) {
        // Si la tarea está vacía o solo tiene un título básico, inyectamos la plantilla
        const content = activeTask.noteContent.trim();
        if (!content || content.split('\n').length <= 1) {
            const title = content.replace(/^#+\s/, '') || 'Nueva Tarea';
            setDocContent(DEEP_WORK_TEMPLATE(title));
        } else {
            setDocContent(activeTask.noteContent);
        }
    }
  }, [activeTask]);

  useEffect(() => {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isDocViewOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
          default: return 25;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;
  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const getTheme = (m: TimerMode) => {
    switch(m) {
      case TimerMode.SHORT_BREAK:
        return { 
          primary: 'text-emerald-600', 
          stroke: 'text-emerald-400', 
          btnBg: 'bg-emerald-600', 
          btnText: 'text-white', 
          glow: 'shadow-emerald-600/30', 
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return { 
          primary: 'text-violet-600', 
          stroke: 'text-violet-400', 
          btnBg: 'bg-violet-600', 
          btnText: 'text-white', 
          glow: 'shadow-violet-600/30', 
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default:
        return { 
          primary: 'text-pomo', 
          stroke: 'text-pomo-light', 
          btnBg: 'bg-pomo', 
          btnText: 'text-white', 
          glow: 'shadow-pomo/30', 
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme(viewMode);

  const handlePlayAction = () => {
    if (isViewingActive) {
      toggleTimer();
    } else {
      startSession(viewMode);
    }
  };

  const handleAiChat = async () => {
      if (!chatMessage.trim() || !activeTask) return;
      const userMsg = chatMessage;
      setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
      setChatMessage('');
      setIsAiThinking(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `Context: "${docContent}". Question: "${userMsg}". Provide a concise writing critique or help based on the markdown content.`
          });
          setChatHistory(prev => [...prev, { role: 'model', text: response.text || "I couldn't generate a response." }]);
      } catch (e) {
          setChatHistory(prev => [...prev, { role: 'model', text: "Error connecting to AI assistant." }]);
      } finally {
          setIsAiThinking(false);
      }
  };

  const handleDownloadMd = () => {
      if (!activeTask) return;
      const element = document.createElement("a");
      const file = new Blob([docContent], {type: 'text/markdown'});
      element.href = URL.createObjectURL(file);
      element.download = `focus-session-${activeTask.id}.md`;
      document.body.appendChild(element);
      element.click();
      document.body.removeChild(element);
  };

  const saveDocChanges = () => {
    if (activeTask) {
        onUpdateTask(activeTask.id, docContent);
    }
  };

  const renderPreview = (content: string) => {
    return content.split('\n').map((line, i) => {
        if (line.startsWith('# ')) return <h1 key={i} className="text-3xl font-bold mb-4 mt-6 dark:text-white">{line.slice(2)}</h1>;
        if (line.startsWith('## ')) return <h2 key={i} className="text-2xl font-bold mb-3 mt-5 dark:text-white border-b border-slate-100 dark:border-slate-800 pb-1">{line.slice(3)}</h2>;
        if (line.startsWith('### ')) return <h3 key={i} className="text-xl font-bold mb-2 mt-4 dark:text-white">{line.slice(4)}</h3>;
        if (line.startsWith('- ') || line.startsWith('* ')) {
            if (line.includes('[ ]') || line.includes('[x]')) {
                const checked = line.includes('[x]');
                return <div key={i} className="flex items-center gap-2 mb-1"><input type="checkbox" checked={checked} readOnly className="rounded border-slate-300 dark:bg-slate-800" /><span className={cn("text-slate-600 dark:text-slate-300", checked && "line-through opacity-50")}>{line.split(']')[1]}</span></div>;
            }
            return <li key={i} className="ml-4 mb-1 text-slate-600 dark:text-slate-300">{line.slice(2)}</li>;
        }
        if (line.trim() === '') return <br key={i} />;
        return <p key={i} className="mb-3 text-slate-600 dark:text-slate-300 leading-relaxed">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-4 relative">

        {/* Navigation Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
        </div>

        {/* Visualizer Area */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-slate-100 dark:text-slate-800" />
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="6" fill="transparent" pathLength={100} strokeDasharray="100" strokeDashoffset={strokeDashoffset} strokeLinecap="round" className={cn("transition-all duration-1000 ease-linear timer-glow", theme.stroke)} />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
                <span className={cn("font-sans font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: 'clamp(4.5rem, 14vw, 9rem)', transform: `scale(${growthScale})` }}>{formatTime(displayTime)}</span>
                <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">{isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Flowing...' : 'Resting...') : 'Ready'}</span>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-6 relative z-20 mb-8">
            <button onClick={resetTimer} className={cn("w-14 h-14 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95", !isViewingActive && "opacity-0 pointer-events-none")}><RotateCcw className="w-5 h-5" /></button>

            <button 
              onClick={handlePlayAction} 
              disabled={isActive && !isViewingActive} 
              className={cn(
                "w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95", 
                isActive && isViewingActive ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`, 
                isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale"
              )}
            >
                {isActive && isViewingActive ? <Pause className="w-8 h-8" /> : (isActive && !isViewingActive ? <Lock className="w-6 h-6" /> : <Play className="w-8 h-8 ml-1" />)}
            </button>

            <div className="w-14 h-14">
              {viewMode === TimerMode.FOCUS && (
                <button 
                  onClick={onGoToInbox} 
                  className={cn(
                    "w-full h-full rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95 shadow-lg",
                    isViewingActive ? `${theme.btnBg} ${theme.btnText} ${theme.glow} dark:brightness-110` : "bg-slate-900 text-white dark:bg-white dark:text-black"
                  )}
                >
                    <InboxIcon className="w-5 h-5" />
                </button>
              )}
            </div>
        </div>

        {/* Session Stats */}
        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-full border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2"><Zap className={cn("w-4 h-4", theme.primary)} /><span>{sessionsCompleted}</span></div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2"><Coffee className="w-4 h-4 text-slate-400" /><span>Next: {(sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long' : 'Short'}</span></div>
        </div>

        {/* Active Task Dock */}
        {activeTask && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[60] w-[90%] max-w-lg">
                <div className="bg-white/80 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-4 flex items-center justify-between animate-in slide-in-from-bottom-8">
                    <div className="flex items-center gap-4 flex-1 min-w-0">
                        <div className="w-10 h-10 bg-blue-500 rounded-xl flex items-center justify-center text-white shrink-0 shadow-lg shadow-blue-500/20">
                            <Target className="w-5 h-5" />
                        </div>
                        <div className="min-w-0">
                            <p className="text-[10px] uppercase font-bold tracking-widest text-slate-400 leading-none mb-1">Active Mission</p>
                            <p className="text-sm font-bold text-slate-900 dark:text-white truncate">
                                {activeTask.noteContent.split('\n')[0].replace(/^#+\s/, '')}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 pl-4 border-l border-slate-100 dark:border-slate-800 ml-4">
                        <button 
                            onClick={() => setIsDocViewOpen(true)} 
                            className="p-2.5 rounded-xl bg-slate-50 text-slate-600 hover:bg-blue-50 hover:text-blue-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-blue-900/20"
                            title="Open Editor"
                        >
                            <FileText className="w-5 h-5" />
                        </button>
                        <button 
                            onClick={onStopTask} 
                            className="p-2.5 rounded-xl bg-slate-50 text-slate-400 hover:bg-red-50 hover:text-red-500 transition-all dark:bg-slate-800"
                            title="End Task Connection (Keeps Timer)"
                        >
                            <X className="w-5 h-5" />
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Improved Editor Modal */}
        {isDocViewOpen && activeTask && (
            <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} />
                <div className="relative bg-white dark:bg-slate-900 w-full max-w-5xl h-[90vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in-95">

                    <div className="flex-1 flex flex-col overflow-hidden border-r border-slate-100 dark:border-slate-800">
                         {/* Integrated Toolbar */}
                         <div className="flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30">
                            <div className="flex items-center gap-4">
                                <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                                    {/* Added Edit3 icon as requested */}
                                    <Edit3 className="w-4 h-4 text-blue-500" /> Editor de Sesión
                                </h3>
                                <button 
                                  onClick={() => setShowPreview(!showPreview)}
                                  className={cn("px-4 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2", showPreview ? "bg-pomo text-white" : "bg-white dark:bg-slate-700 text-slate-500 hover:bg-slate-100 shadow-sm")}
                                >
                                    {showPreview ? <PenLine className="w-3.5 h-3.5" /> : <Eye className="w-3.5 h-3.5" />}
                                    {showPreview ? "Regresar a Editar" : "Vista Previa"}
                                </button>
                            </div>
                            <div className="flex items-center gap-2">
                                <button 
                                  onClick={saveDocChanges}
                                  className="p-2 text-slate-400 hover:text-green-500 transition-colors"
                                  title="Guardar"
                                >
                                    <Save className="w-5 h-5" />
                                </button>
                                <button 
                                  onClick={handleDownloadMd}
                                  className="p-2 text-slate-400 hover:text-pomo transition-colors"
                                  title="Descargar Markdown"
                                >
                                    <Download className="w-5 h-5" />
                                </button>
                                <button onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} className="p-2 text-slate-400 hover:text-slate-600">
                                    <X className="w-6 h-6" />
                                </button>
                            </div>
                         </div>

                         {/* Editor Workspace */}
                         <div className="flex-1 overflow-hidden relative">
                             {showPreview ? (
                                <div className="h-full overflow-y-auto p-10 prose dark:prose-invert max-w-none bg-slate-50/30 dark:bg-slate-900/50 custom-scrollbar">
                                    {renderPreview(docContent)}
                                </div>
                             ) : (
                                <div className="h-full flex flex-col p-6">
                                    <div className="mb-4 p-3 bg-blue-50 dark:bg-blue-900/10 border border-blue-100 dark:border-blue-800 rounded-xl text-[11px] text-blue-600 dark:text-blue-300 flex items-start gap-2">
                                        <HelpCircle className="w-4 h-4 shrink-0 mt-0.5" />
                                        <p>Utiliza <b>Markdown</b> para dar formato: <b>#</b> Títulos, <b>- [ ]</b> para checklists, <b>**negrita**</b> para énfasis. Los cambios se guardarán al salir o presionar el icono de disco.</p>
                                    </div>
                                    <textarea 
                                        value={docContent}
                                        onChange={(e) => setDocContent(e.target.value)}
                                        placeholder="Escribe el plan para esta sesión de Deep Work..."
                                        className="flex-1 w-full text-base font-sans leading-relaxed text-slate-700 dark:text-slate-200 bg-transparent resize-none focus:outline-none custom-scrollbar"
                                        autoFocus
                                    />
                                </div>
                             )}
                         </div>
                    </div>

                    <div className="w-full md:w-80 flex flex-col bg-slate-50 dark:bg-slate-950">
                        <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center gap-2 font-bold text-slate-700 bg-white dark:bg-slate-900 dark:text-slate-200"><Bot className="w-5 h-5 text-violet-500" />AI Assistant</div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-widest text-center mb-4">Chat Context: Session Doc</div>
                            {chatHistory.map((msg, i) => (<div key={i} className={cn("text-sm p-3 rounded-xl max-w-[90%] shadow-sm", msg.role === 'user' ? "bg-violet-600 text-white self-end ml-auto" : "bg-white dark:bg-slate-800 dark:text-slate-300 border border-slate-200 dark:border-slate-700")}>{msg.text}</div>))}
                            {isAiThinking && <div className="flex gap-1 justify-center p-2"><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-300" /></div>}
                            <div ref={chatEndRef} />
                        </div>
                        <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                            <div className="relative">
                                <input type="text" value={chatMessage} onChange={(e) => setChatMessage(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAiChat()} placeholder="Ask AI about this session..." className="w-full bg-slate-100 dark:bg-slate-800 rounded-full pl-4 pr-10 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-violet-500/20" />
                                <button onClick={handleAiChat} disabled={!chatMessage.trim() || isAiThinking} className="absolute right-1 top-1 p-1.5 bg-violet-600 text-white rounded-full hover:bg-violet-700 disabled:opacity-50 transition-colors"><Send className="w-3 h-3" /></button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Timer;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, RotateCcw, Zap, Coffee, Lock, PenLine, X, Target, FileText, 
  Bot, Send, Download, Eye, Save, Type, Bold, Strikethrough, Underline, 
  ChevronDown, Type as TypeIcon, Edit3
} from 'lucide-react';
import { TimerMode, Settings, Category, InboxItem } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode;
  startSession: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem;
  onStopTask?: () => void;
  onGoToInbox: () => void;
  onUpdateTask: (id: string, content: string) => void;
}

const DEEP_WORK_TEMPLATE = (title: string) => `# ${title}
## 🎯 Objetivos de la Sesión
- [ ] Objetivo principal: 
- [ ] Tarea técnica 1:

## 📝 Notas de Enfoque
*Escribe aquí tus ideas y descubrimientos durante el flujo...*

## 🚀 Próximos Pasos
- 

---
*Sesión iniciada: ${new Date().toLocaleTimeString()}*`;

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask,
  onGoToInbox,
  onUpdateTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);

  // Doc Editor State
  const [docContent, setDocContent] = useState('');
  const [showPreview, setShowPreview] = useState(false);

  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  useEffect(() => {
    if (activeTask) {
        const content = activeTask.noteContent.trim();
        if (!content || content.split('\n').length <= 1) {
            const title = content.replace(/^#+\s/, '') || 'Nueva Tarea';
            setDocContent(DEEP_WORK_TEMPLATE(title));
        } else {
            setDocContent(activeTask.noteContent);
        }
    }
  }, [activeTask]);

  useEffect(() => {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isDocViewOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
          default: return 25;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;
  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const getTheme = (m: TimerMode) => {
    switch(m) {
      case TimerMode.SHORT_BREAK:
        return { 
          primary: 'text-emerald-600', 
          stroke: 'text-emerald-400', 
          btnBg: 'bg-emerald-600', 
          btnText: 'text-white', 
          glow: 'shadow-emerald-600/30', 
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return { 
          primary: 'text-violet-600', 
          stroke: 'text-violet-400', 
          btnBg: 'bg-violet-600', 
          btnText: 'text-white', 
          glow: 'shadow-violet-600/30', 
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default:
        return { 
          primary: 'text-pomo', 
          stroke: 'text-pomo-light', 
          btnBg: 'bg-pomo', 
          btnText: 'text-white', 
          glow: 'shadow-pomo/30', 
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme(viewMode);

  const handlePlayAction = () => {
    if (isViewingActive) {
      toggleTimer();
    } else {
      startSession(viewMode);
    }
  };

  const handleFormat = (type: 'bold' | 'strike' | 'underline' | 'h1' | 'h2' | 'p' | 'caps') => {
    if (!textareaRef.current) return;
    const start = textareaRef.current.selectionStart;
    const end = textareaRef.current.selectionEnd;
    const selectedText = docContent.substring(start, end);
    let newText = docContent;

    switch(type) {
        case 'bold':
            newText = docContent.substring(0, start) + `**${selectedText}**` + docContent.substring(end);
            break;
        case 'strike':
            newText = docContent.substring(0, start) + `~~${selectedText}~~` + docContent.substring(end);
            break;
        case 'underline':
            newText = docContent.substring(0, start) + `<u>${selectedText}</u>` + docContent.substring(end);
            break;
        case 'caps':
            newText = docContent.substring(0, start) + selectedText.toUpperCase() + docContent.substring(end);
            break;
        case 'h1':
            newText = docContent.substring(0, start) + `# ${selectedText.replace(/^#+\s*/, '')}` + docContent.substring(end);
            break;
        case 'h2':
            newText = docContent.substring(0, start) + `## ${selectedText.replace(/^#+\s*/, '')}` + docContent.substring(end);
            break;
        case 'p':
            newText = docContent.substring(0, start) + selectedText.replace(/^#+\s*/, '') + docContent.substring(end);
            break;
    }

    setDocContent(newText);
    setTimeout(() => {
        if (textareaRef.current) {
            textareaRef.current.focus();
            textareaRef.current.setSelectionRange(start, start + newText.length - docContent.length + selectedText.length);
        }
    }, 0);
  };

  const handleAiChat = async () => {
      if (!chatMessage.trim() || !activeTask) return;
      const userMsg = chatMessage;
      setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
      setChatMessage('');
      setIsAiThinking(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `Context: "${docContent}". Question: "${userMsg}". Provide a concise writing critique or help based on the markdown content.`
          });
          setChatHistory(prev => [...prev, { role: 'model', text: response.text || "I couldn't generate a response." }]);
      } catch (e) {
          setChatHistory(prev => [...prev, { role: 'model', text: "Error connecting to AI assistant." }]);
      } finally {
          setIsAiThinking(false);
      }
  };

  const handleDownloadMd = () => {
      if (!activeTask) return;
      const element = document.createElement("a");
      const file = new Blob([docContent], {type: 'text/markdown'});
      element.href = URL.createObjectURL(file);
      element.download = `focus-session-${activeTask.id}.md`;
      document.body.appendChild(element);
      element.click();
      document.body.removeChild(element);
  };

  const saveDocChanges = () => {
    if (activeTask) {
        onUpdateTask(activeTask.id, docContent);
    }
  };

  const parseInlineStyles = (text: string) => {
    let parts = [];
    let current = text;

    // Bold **text**
    const boldRegex = /\*\*(.*?)\*\*/g;
    // Strike ~~text~~
    const strikeRegex = /~~(.*?)~~/g;
    // Underline <u>text</u>
    const underlineRegex = /<u>(.*?)<\/u>/g;

    return current.split(/(\*\*.*?\*\*|~~.*?~~|<u>.*?<\/u>)/g).map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
            return <strong key={i}>{part.slice(2, -2)}</strong>;
        }
        if (part.startsWith('~~') && part.endsWith('~~')) {
            return <del key={i}>{part.slice(2, -2)}</del>;
        }
        if (part.startsWith('<u>') && part.endsWith('</u>')) {
            return <span key={i} className="underline">{part.slice(3, -4)}</span>;
        }
        return part;
    });
  };

  const renderPreview = (content: string) => {
    return content.split('\n').map((line, i) => {
        if (line.startsWith('# ')) return <h1 key={i} className="text-3xl font-bold mb-4 mt-6 dark:text-white">{parseInlineStyles(line.slice(2))}</h1>;
        if (line.startsWith('## ')) return <h2 key={i} className="text-2xl font-bold mb-3 mt-5 dark:text-white border-b border-slate-100 dark:border-slate-800 pb-1">{parseInlineStyles(line.slice(3))}</h2>;
        if (line.startsWith('### ')) return <h3 key={i} className="text-xl font-bold mb-2 mt-4 dark:text-white">{parseInlineStyles(line.slice(4)}</h3>;

        if (line.startsWith('- ') || line.startsWith('* ')) {
            if (line.includes('[ ]') || line.includes('[x]')) {
                const checked = line.includes('[x]');
                const taskText = line.split(']')[1];
                return (
                  <div key={i} className="flex items-center gap-2 mb-1">
                    <input type="checkbox" checked={checked} readOnly className="rounded border-slate-300 dark:bg-slate-800" />
                    <span className={cn("text-slate-600 dark:text-slate-300", checked && "line-through opacity-50")}>{parseInlineStyles(taskText)}</span>
                  </div>
                );
            }
            return <li key={i} className="ml-4 mb-1 text-slate-600 dark:text-slate-300">{parseInlineStyles(line.slice(2))}</li>;
        }
        if (line.trim() === '') return <br key={i} />;
        return <p key={i} className="mb-3 text-slate-600 dark:text-slate-300 leading-relaxed">{parseInlineStyles(line)}</p>;
    });
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-4 relative">

        {/* Navigation Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
        </div>

        {/* Visualizer Area */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-slate-100 dark:text-slate-800" />
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="6" fill="transparent" pathLength={100} strokeDasharray="100" strokeDashoffset={strokeDashoffset} strokeLinecap="round" className={cn("transition-all duration-1000 ease-linear timer-glow", theme.stroke)} />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
                <span className={cn("font-sans font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: 'clamp(4.5rem, 14vw, 9rem)', transform: `scale(${growthScale})` }}>{formatTime(displayTime)}</span>
                <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">{isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Flowing...' : 'Resting...') : 'Ready'}</span>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-6 relative z-20 mb-8">
            <button onClick={resetTimer} className={cn("w-14 h-14 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95", !isViewingActive && "opacity-0 pointer-events-none")}><RotateCcw className="w-5 h-5" /></button>

            <button 
              onClick={handlePlayAction} 
              disabled={isActive && !isViewingActive} 
              className={cn(
                "w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95", 
                isActive && isViewingActive ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`, 
                isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale"
              )}
            >
                {isActive && isViewingActive ? <Pause className="w-8 h-8" /> : (isActive && !isViewingActive ? <Lock className="w-6 h-6" /> : <Play className="w-8 h-8 ml-1" />)}
            </button>

            <div className="w-14 h-14">
              {viewMode === TimerMode.FOCUS && (
                <button 
                  onClick={onGoToInbox} 
                  className={cn(
                    "w-full h-full rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95 shadow-lg",
                    isViewingActive ? `${theme.btnBg} ${theme.btnText} ${theme.glow} dark:brightness-110` : "bg-slate-900 text-white dark:bg-white dark:text-black"
                  )}
                >
                    <InboxIcon className="w-5 h-5" />
                </button>
              )}
            </div>
        </div>

        {/* Session Stats */}
        <div className="flex gap-4 text-sm text-slate-500 bg-white px-6 py-3 rounded-full border border-slate-100 shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400 relative z-20">
            <div className="flex items-center gap-2"><Zap className={cn("w-4 h-4", theme.primary)} /><span>{sessionsCompleted}</span></div>
            <div className="w-px h-4 bg-slate-200 dark:bg-slate-600"></div>
            <div className="flex items-center gap-2"><Coffee className="w-4 h-4 text-slate-400" /><span>Next: {(sessionsCompleted + 1) % settings.longBreakInterval === 0 ? 'Long' : 'Short'}</span></div>
        </div>

        {/* Active Task Dock */}
        {activeTask && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[60] w-[90%] max-w-lg">
                <div className="bg-white/80 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-4 flex items-center justify-between animate-in slide-in-from-bottom-8">
                    <div className="flex items-center gap-4 flex-1 min-w-0">
                        <div className="w-10 h-10 bg-blue-500 rounded-xl flex items-center justify-center text-white shrink-0 shadow-lg shadow-blue-500/20">
                            <Target className="w-5 h-5" />
                        </div>
                        <div className="min-w-0">
                            <p className="text-[10px] uppercase font-bold tracking-widest text-slate-400 leading-none mb-1">Misión Activa</p>
                            <p className="text-sm font-bold text-slate-900 dark:text-white truncate">
                                {activeTask.noteContent.split('\n')[0].replace(/^#+\s/, '')}
                            </p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 pl-4 border-l border-slate-100 dark:border-slate-800 ml-4">
                        <button 
                            onClick={() => setIsDocViewOpen(true)} 
                            className="p-2.5 rounded-xl bg-slate-50 text-slate-600 hover:bg-blue-50 hover:text-blue-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-blue-900/20"
                            title="Abrir Editor"
                        >
                            <FileText className="w-5 h-5" />
                        </button>
                        <button 
                            onClick={onStopTask} 
                            className="p-2.5 rounded-xl bg-slate-50 text-slate-400 hover:bg-red-50 hover:text-red-500 transition-all dark:bg-slate-800"
                            title="Desvincular Tarea (Mantiene Cronómetro)"
                        >
                            <X className="w-5 h-5" />
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Editor Modal */}
        {isDocViewOpen && activeTask && (
            <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} />
                <div className="relative bg-white dark:bg-slate-900 w-full max-w-5xl h-[90vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in-95">

                    <div className="flex-1 flex flex-col overflow-hidden border-r border-slate-100 dark:border-slate-800">
                         {/* Toolbar Superior */}
                         <div className="flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30">
                            <div className="flex items-center gap-4">
                                <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                                    <Edit3 className="w-4 h-4 text-blue-500" /> Editor
                                </h3>
                                <button 
                                  onClick={() => setShowPreview(!showPreview)}
                                  className={cn("px-4 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2", showPreview ? "bg-pomo text-white" : "bg-white dark:bg-slate-700 text-slate-500 hover:bg-slate-100 shadow-sm")}
                                >
                                    {showPreview ? <PenLine className="w-3.5 h-3.5" /> : <Eye className="w-3.5 h-3.5" />}
                                    {showPreview ? "Regresar a Editar" : "Vista Previa"}
                                </button>
                            </div>
                            <div className="flex items-center gap-2">
                                <button 
                                  onClick={saveDocChanges}
                                  className="p-2 text-slate-400 hover:text-green-500 transition-colors"
                                  title="Guardar"
                                >
                                    <Save className="w-5 h-5" />
                                </button>
                                <button onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} className="p-2 text-slate-400 hover:text-slate-600">
                                    <X className="w-6 h-6" />
                                </button>
                            </div>
                         </div>

                         {/* Workspace */}
                         <div className="flex-1 overflow-hidden relative flex flex-col">
                             {!showPreview && (
                                <div className="flex items-center gap-1 p-2 bg-slate-100/50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700 overflow-x-auto">
                                    <button onClick={() => handleFormat('h1')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md text-xs font-bold" title="Título">H1</button>
                                    <button onClick={() => handleFormat('h2')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md text-xs font-bold" title="Subtítulo">H2</button>
                                    <button onClick={() => handleFormat('p')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md text-xs font-bold" title="Párrafo">P</button>
                                    <div className="w-px h-4 bg-slate-300 dark:bg-slate-600 mx-1" />
                                    <button onClick={() => handleFormat('bold')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md" title="Negrita"><Bold className="w-4 h-4" /></button>
                                    <button onClick={() => handleFormat('strike')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md" title="Tachado"><Strikethrough className="w-4 h-4" /></button>
                                    <button onClick={() => handleFormat('underline')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md" title="Subrayado"><Underline className="w-4 h-4" /></button>
                                    <button onClick={() => handleFormat('caps')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md text-[10px] font-bold" title="MAYÚSCULAS">ABC</button>
                                </div>
                             )}

                             {showPreview ? (
                                <div className="h-full overflow-y-auto p-10 prose dark:prose-invert max-w-none bg-slate-50/30 dark:bg-slate-900/50 custom-scrollbar">
                                    {renderPreview(docContent)}
                                </div>
                             ) : (
                                <textarea 
                                    ref={textareaRef}
                                    value={docContent}
                                    onChange={(e) => setDocContent(e.target.value)}
                                    placeholder="Escribe libremente aquí. Selecciona texto para aplicar formato..."
                                    className="flex-1 w-full p-8 text-base font-sans leading-relaxed text-slate-700 dark:text-slate-200 bg-transparent resize-none focus:outline-none custom-scrollbar"
                                    autoFocus
                                />
                             )}
                         </div>
                    </div>

                    <div className="w-full md:w-80 flex flex-col bg-slate-50 dark:bg-slate-950">
                        <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center gap-2 font-bold text-slate-700 bg-white dark:bg-slate-900 dark:text-slate-200"><Bot className="w-5 h-5 text-violet-500" />AI Assistant</div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                            {chatHistory.map((msg, i) => (<div key={i} className={cn("text-sm p-3 rounded-xl max-w-[90%] shadow-sm", msg.role === 'user' ? "bg-violet-600 text-white self-end ml-auto" : "bg-white dark:bg-slate-800 dark:text-slate-300 border border-slate-200 dark:border-slate-700")}>{msg.text}</div>))}
                            {isAiThinking && <div className="flex gap-1 justify-center p-2"><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-300" /></div>}
                            <div ref={chatEndRef} />
                        </div>
                        <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                            <div className="relative">
                                <input type="text" value={chatMessage} onChange={(e) => setChatMessage(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAiChat()} placeholder="Pregunta a la IA..." className="w-full bg-slate-100 dark:bg-slate-800 rounded-full pl-4 pr-10 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-violet-500/20" />
                                <button onClick={handleAiChat} disabled={!chatMessage.trim() || isAiThinking} className="absolute right-1 top-1 p-1.5 bg-violet-600 text-white rounded-full hover:bg-violet-700 disabled:opacity-50 transition-colors"><Send className="w-3 h-3" /></button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

export default Timer;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, RotateCcw, Zap, Coffee, Lock, PenLine, X, Target, FileText, 
  Bot, Send, Download, Eye, Save, Type, Bold, Strikethrough, Underline, 
  ChevronDown, Type as TypeIcon, Edit3, Inbox as InboxIcon
} from 'lucide-react';
import { TimerMode, Settings, Category, InboxItem } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode;
  startSession: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem;
  onStopTask?: () => void;
  onGoToInbox: () => void;
  onUpdateTask: (id: string, content: string) => void;
}

const DEEP_WORK_TEMPLATE = (title: string) => `# ${title}
## 🎯 Objetivos de la Sesión
- [ ] Objetivo principal: 
- [ ] Tarea técnica 1:

## 📝 Notas de Enfoque
*Escribe aquí tus ideas y descubrimientos durante el flujo...*

## 🚀 Próximos Pasos
- 

---
*Sesión iniciada: ${new Date().toLocaleTimeString()}*`;

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask,
  onGoToInbox,
  onUpdateTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);

  // Doc Editor State
  const [docContent, setDocContent] = useState('');
  const [showPreview, setShowPreview] = useState(false);

  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  useEffect(() => {
    if (activeTask) {
        const content = activeTask.noteContent.trim();
        if (!content || content.split('\n').length <= 1) {
            const title = content.replace(/^#+\s/, '') || 'Nueva Tarea';
            setDocContent(DEEP_WORK_TEMPLATE(title));
        } else {
            setDocContent(activeTask.noteContent);
        }
    }
  }, [activeTask]);

  useEffect(() => {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isDocViewOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
          default: return 25;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;
  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const getTheme = (m: TimerMode) => {
    switch(m) {
      case TimerMode.SHORT_BREAK:
        return { 
          primary: 'text-emerald-600', 
          stroke: 'text-emerald-400', 
          btnBg: 'bg-emerald-600', 
          btnText: 'text-white', 
          glow: 'shadow-emerald-600/30', 
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return { 
          primary: 'text-violet-600', 
          stroke: 'text-violet-400', 
          btnBg: 'bg-violet-600', 
          btnText: 'text-white', 
          glow: 'shadow-violet-600/30', 
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default:
        return { 
          primary: 'text-pomo', 
          stroke: 'text-pomo-light', 
          btnBg: 'bg-pomo', 
          btnText: 'text-white', 
          glow: 'shadow-pomo/30', 
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme(viewMode);

  const handlePlayAction = () => {
    if (isViewingActive) {
      toggleTimer();
    } else {
      startSession(viewMode);
    }
  };

  const handleFormat = (type: 'bold' | 'strike' | 'underline' | 'h1' | 'h2' | 'p' | 'caps') => {
    if (!textareaRef.current) return;
    const start = textareaRef.current.selectionStart;
    const end = textareaRef.current.selectionEnd;
    const selectedText = docContent.substring(start, end);
    let newText = docContent;

    switch(type) {
        case 'bold':
            newText = docContent.substring(0, start) + `**${selectedText}**` + docContent.substring(end);
            break;
        case 'strike':
            newText = docContent.substring(0, start) + `~~${selectedText}~~` + docContent.substring(end);
            break;
        case 'underline':
            newText = docContent.substring(0, start) + `<u>${selectedText}</u>` + docContent.substring(end);
            break;
        case 'caps':
            newText = docContent.substring(0, start) + selectedText.toUpperCase() + docContent.substring(end);
            break;
        case 'h1':
            newText = docContent.substring(0, start) + `# ${selectedText.replace(/^#+\s*/, '')}` + docContent.substring(end);
            break;
        case 'h2':
            newText = docContent.substring(0, start) + `## ${selectedText.replace(/^#+\s*/, '')}` + docContent.substring(end);
            break;
        case 'p':
            newText = docContent.substring(0, start) + selectedText.replace(/^#+\s*/, '') + docContent.substring(end);
            break;
    }

    setDocContent(newText);
    setTimeout(() => {
        if (textareaRef.current) {
            textareaRef.current.focus();
            textareaRef.current.setSelectionRange(start, start + newText.length - docContent.length + selectedText.length);
        }
    }, 0);
  };

  const handleAiChat = async () => {
      if (!chatMessage.trim() || !activeTask) return;
      const userMsg = chatMessage;
      setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
      setChatMessage('');
      setIsAiThinking(true);
      try {
          // Create a new GoogleGenAI instance right before making an API call to ensure it always uses the most up-to-date API key
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `Context: "${docContent}". Question: "${userMsg}". Provide a concise writing critique or help based on the markdown content.`
          });
          // Directly access the .text property from GenerateContentResponse
          setChatHistory(prev => [...prev, { role: 'model', text: response.text || "I couldn't generate a response." }]);
      } catch (e) {
          setChatHistory(prev => [...prev, { role: 'model', text: "Error connecting to AI assistant." }]);
      } finally {
          setIsAiThinking(false);
      }
  };

  const handleDownloadMd = () => {
      if (!activeTask) return;
      const element = document.createElement("a");
      const file = new Blob([docContent], {type: 'text/markdown'});
      element.href = URL.createObjectURL(file);
      element.download = `focus-session-${activeTask.id}.md`;
      document.body.appendChild(element);
      element.click();
      document.body.removeChild(element);
  };

  const saveDocChanges = () => {
    if (activeTask) {
        onUpdateTask(activeTask.id, docContent);
    }
  };

  const parseInlineStyles = (text: string) => {
    let parts = [];
    let current = text;

    // Bold **text**
    const boldRegex = /\*\*(.*?)\*\*/g;
    // Strike ~~text~~
    const strikeRegex = /~~(.*?)~~/g;
    // Underline <u>text</u>
    const underlineRegex = /<u>(.*?)<\/u>/g;

    return current.split(/(\*\*.*?\*\*|~~.*?~~|<u>.*?<\/u>)/g).map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
            return <strong key={i}>{part.slice(2, -2)}</strong>;
        }
        if (part.startsWith('~~') && part.endsWith('~~')) {
            return <del key={i}>{part.slice(2, -2)}</del>;
        }
        if (part.startsWith('<u>') && part.endsWith('</u>')) {
            return <span key={i} className="underline">{part.slice(3, -4)}</span>;
        }
        return part;
    });
  };

  const renderPreview = (content: string) => {
    return content.split('\n').map((line, i) => {
        if (line.startsWith('# ')) return <h1 key={i} className="text-3xl font-bold mb-4 mt-6 dark:text-white">{parseInlineStyles(line.slice(2))}</h1>;
        if (line.startsWith('## ')) return <h2 key={i} className="text-2xl font-bold mb-3 mt-5 dark:text-white border-b border-slate-100 dark:border-slate-800 pb-1">{parseInlineStyles(line.slice(3))}</h2>;
        if (line.startsWith('### ')) return <h3 key={i} className="text-xl font-bold mb-2 mt-4 dark:text-white">{parseInlineStyles(line.slice(4))}</h3>;

        if (line.startsWith('- ') || line.startsWith('* ')) {
            if (line.includes('[ ]') || line.includes('[x]')) {
                const checked = line.includes('[x]');
                const taskText = line.split(']')[1];
                return (
                  <div key={i} className="flex items-center gap-2 mb-1">
                    <input type="checkbox" checked={checked} readOnly className="rounded border-slate-300 dark:bg-slate-800" />
                    <span className={cn("text-slate-600 dark:text-slate-300", checked && "line-through opacity-50")}>{parseInlineStyles(taskText)}</span>
                  </div>
                );
            }
            return <li key={i} className="ml-4 mb-1 text-slate-600 dark:text-slate-300">{parseInlineStyles(line.slice(2))}</li>;
        }
        if (line.trim() === '') return <br key={i} />;
        return <p key={i} className="mb-3 text-slate-600 dark:text-slate-300 leading-relaxed">{parseInlineStyles(line)}</p>;
    });
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-4 relative">

        {/* Navigation Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
