import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, RotateCcw, Zap, Coffee, Lock, PenLine, X, Target, FileText, 
  Bot, Send, Download, Eye, Save, Type, Bold, Strikethrough, Underline, 
  Edit3, Inbox as InboxIcon, Heading1, Heading2, CaseSensitive, Pilcrow
} from 'lucide-react';
import { TimerMode, Settings, Category, InboxItem } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode;
  startSession: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem;
  onStopTask?: () => void;
  onGoToInbox: () => void;
  onUpdateTask: (id: string, content: string) => void;
}

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask,
  onGoToInbox,
  onUpdateTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);

  // Doc Editor State (Stored as HTML for Rich Text)
  const [docHTML, setDocHTML] = useState('');

  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const editorRef = useRef<HTMLDivElement>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  useEffect(() => {
    if (activeTask) {
        // Inicializamos el contenido. Si es la primera vez, ponemos un placeholder amigable.
        const content = activeTask.noteContent || '<div>Empieza a escribir tus notas de enfoque...</div>';
        setDocHTML(content);
    }
  }, [activeTask]);

  useEffect(() => {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isDocViewOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
          default: return 25;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;
  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const getTheme = (m: TimerMode) => {
    switch(m) {
      case TimerMode.SHORT_BREAK:
        return { 
          primary: 'text-emerald-600', stroke: 'text-emerald-400', btnBg: 'bg-emerald-600', 
          btnText: 'text-white', glow: 'shadow-emerald-600/30', 
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return { 
          primary: 'text-violet-600', stroke: 'text-violet-400', btnBg: 'bg-violet-600', 
          btnText: 'text-white', glow: 'shadow-violet-600/30', 
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default:
        return { 
          primary: 'text-pomo', stroke: 'text-pomo-light', btnBg: 'bg-pomo', 
          btnText: 'text-white', glow: 'shadow-pomo/30', 
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  };

  const theme = getTheme(viewMode);

  const handlePlayAction = () => {
    if (isViewingActive) {
      toggleTimer();
    } else {
      startSession(viewMode);
    }
  };

  // Función mejorada para ejecutar comandos de edición sin perder el foco del editor
  const handleExecCommand = (e: React.MouseEvent, command: string, value: string | undefined = undefined) => {
    e.preventDefault(); // Evita que el botón robe el foco
    document.execCommand(command, false, value);
    if (editorRef.current) {
        setDocHTML(editorRef.current.innerHTML);
        editorRef.current.focus();
    }
  };

  const handleToUpperCase = (e: React.MouseEvent) => {
    e.preventDefault();
    const selection = window.getSelection();
    if (!selection || selection.rangeCount === 0 || selection.isCollapsed) return;

    const range = selection.getRangeAt(0);
    const selectedText = selection.toString();

    // Reemplazamos el texto seleccionado por su versión en mayúsculas
    document.execCommand('insertText', false, selectedText.toUpperCase());

    if (editorRef.current) {
        setDocHTML(editorRef.current.innerHTML);
        editorRef.current.focus();
    }
  };

  const handleAiChat = async () => {
      if (!chatMessage.trim() || !activeTask) return;
      const userMsg = chatMessage;
      setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
      setChatMessage('');
      setIsAiThinking(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const textContext = editorRef.current?.innerText || "";
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `Contexto de las notas actuales: "${textContext}". El usuario pregunta: "${userMsg}". Responde de forma breve y profesional.`
          });
          setChatHistory(prev => [...prev, { role: 'model', text: response.text || "No pude procesar la solicitud." }]);
      } catch (e) {
          setChatHistory(prev => [...prev, { role: 'model', text: "Error de conexión con el asistente." }]);
      } finally {
          setIsAiThinking(false);
      }
  };

  const handleDownload = () => {
      if (!activeTask) return;
      const text = editorRef.current?.innerText || "";
      const element = document.createElement("a");
      const file = new Blob([text], {type: 'text/plain'});
      element.href = URL.createObjectURL(file);
      element.download = `notas-sesion-${activeTask.id}.txt`;
      document.body.appendChild(element);
      element.click();
      document.body.removeChild(element);
  };

  const saveDocChanges = () => {
    if (activeTask && editorRef.current) {
        onUpdateTask(activeTask.id, editorRef.current.innerHTML);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-4 relative">

        {/* Navigation Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
