                         <div className="flex items-center gap-1 p-2 bg-slate-100/50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700 overflow-x-auto shrink-0">
                            <button onMouseDown={(e) => handleExecCommand(e, 'formatBlock', 'h1')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md transition-colors" title="Título principal"><Heading1 className="w-4 h-4" /></button>
                            <button onMouseDown={(e) => handleExecCommand(e, 'formatBlock', 'h2')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md transition-colors" title="Subtítulo"><Heading2 className="w-4 h-4" /></button>
                            <button onMouseDown={(e) => handleExecCommand(e, 'formatBlock', 'p')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md transition-colors" title="Párrafo normal"><Pilcrow className="w-4 h-4" /></button>
                            <div className="w-px h-4 bg-slate-300 dark:bg-slate-600 mx-1" />
                            <button onMouseDown={(e) => handleExecCommand(e, 'bold')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md transition-colors" title="Negrita"><Bold className="w-4 h-4" /></button>
                            <button onMouseDown={(e) => handleExecCommand(e, 'underline')} className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-md transition-colors" title="Subrayado"><Underline className="w-4 h-4" /></button>
