                                placeholder="Escribe aquí tus ideas de hoy..."
                            />
                         </div>
                    </div>

                    {/* AI Sidebar */}
                    <div className="w-full md:w-80 flex flex-col bg-slate-50 dark:bg-slate-950">
                        <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center gap-2 font-bold text-slate-700 bg-white dark:bg-slate-900 dark:text-slate-200"><Bot className="w-5 h-5 text-violet-500" />AI Assistant</div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-widest text-center mb-4">Chat Context: Session Doc</div>
                            {chatHistory.map((msg, i) => (<div key={i} className={cn("text-sm p-3 rounded-xl max-w-[90%] shadow-sm", msg.role === 'user' ? "bg-violet-600 text-white self-end ml-auto" : "bg-white dark:bg-slate-800 dark:text-slate-300 border border-slate-200 dark:border-slate-700")}>{msg.text}</div>))}
                            {isAiThinking && <div className="flex gap-1 justify-center p-2"><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-300" /></div>}
