                                <button onClick={saveDocChanges} className="p-2 text-slate-400 hover:text-green-500 transition-colors" title="Guardar cambios"><Save className="w-5 h-5" /></button>
                                <button onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} className="p-2 text-slate-400 hover:text-slate-600"><X className="w-6 h-6" /></button>
