  { name: 'Indigo', value: 'bg-indigo-500' },
  { name: 'Violet', value: 'bg-violet-500' },
  { name: 'Purple', value: 'bg-purple-500' },
  { name: 'Fuchsia', value: 'bg-fuchsia-500' },
  { name: 'Pink', value: 'bg-pink-500' },
  { name: 'Rose', value: 'bg-rose-500' },
  { name: 'Slate', value: 'bg-slate-500' },
];

const Categories: React.FC<CategoriesProps> = ({ categories, onAdd, onDelete, inboxItems }) => {
  const [newName, setNewName] = useState('');
  const [selectedColor, setSelectedColor] = useState(COLORS[0].value);
  const [activeCategory, setActiveCategory] = useState<Category | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName.trim()) return;

    onAdd({
      id: generateId(),
      name: newName.trim(),
      color: selectedColor
    });
    setNewName('');
  };

  if (activeCategory) {
    const categoryItems = inboxItems.filter(item => item.categoryId === activeCategory.id && item.type === 'note' && item.status !== 'completed' && item.status !== 'scheduled');

    return (
      <div className="w-full max-w-4xl mx-auto py-8 px-4 animate-in fade-in slide-in-from-right-8">
        <div className="mb-8 flex items-center gap-4">
           <button 
             onClick={() => setActiveCategory(null)}
             className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
           >
             <ArrowLeft className="w-6 h-6 text-slate-500" />
           </button>
           <div className="flex items-center gap-3">
              <div className={cn("w-6 h-6 rounded-full", activeCategory.color)} />
              <h2 className="text-2xl font-bold text-slate-900 dark:text-white">{activeCategory.name}</h2>
              <span className="text-slate-400 text-sm font-medium border border-slate-200 dark:border-slate-700 px-2 py-0.5 rounded-full">
                {categoryItems.length} items
              </span>
           </div>
        </div>

        <div className="grid gap-4">
            {categoryItems.length === 0 && (
                <div className="text-center py-12 bg-slate-50 dark:bg-slate-900 rounded-xl border border-dashed border-slate-200 dark:border-slate-800">
                    <p className="text-slate-400">No active tasks in this category.</p>
                </div>
            )}
            {categoryItems.map(item => (
                <div key={item.id} className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm flex items-center justify-between">
                    <div>
                        <p className="font-medium text-slate-800 dark:text-slate-200">{item.noteContent}</p>
                        <div className="flex items-center gap-4 mt-2 text-xs text-slate-400">
                             <span className={cn("px-1.5 py-0.5 rounded border capitalize", 
                                item.status === 'in-progress' ? 'border-amber-200 text-amber-600 bg-amber-50' : 'border-slate-200'
                             )}>
                                {item.status.replace('-', ' ')}
                             </span>
                             {item.timeSpent ? (
                                <span className="flex items-center gap-1"><Clock className="w-3 h-3" /> {item.timeSpent}m</span>
                             ) : null}
                        </div>
                    </div>
                </div>
            ))}
        </div>
      </div>
    );
  }

  return (
    <div className="w-full max-w-4xl mx-auto py-8 px-4 animate-in fade-in">
      <div className="mb-8">
        <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Centro de Categorías</h2>
        <p className="text-slate-500 text-sm dark:text-slate-400">Gestiona etiquetas y profundiza en contextos específicos.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Category List - MOVED TO TOP */}
        <div className="space-y-3">
          <h3 className="text-lg font-bold mb-4 dark:text-white">Existing Tags</h3>
          {categories.length === 0 && (
             <p className="text-slate-400 text-sm italic">No categories defined yet.</p>
          )}
          {categories.map((cat) => {
            const count = inboxItems.filter(i => i.categoryId === cat.id && i.status !== 'completed' && i.status !== 'scheduled' && i.type === 'note').length;
            return (
                <div 
                    key={cat.id} 
                    onClick={() => setActiveCategory(cat)}
                    className="flex items-center justify-between p-3 bg-white rounded-xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800 group cursor-pointer hover:border-slate-300 dark:hover:border-slate-600 transition-all"
                >
                <div className="flex items-center gap-3">
                    <div className={cn("w-4 h-4 rounded-full", cat.color)} />
                    <span className="font-medium text-slate-700 dark:text-slate-200">{cat.name}</span>
                    <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full dark:bg-slate-800">{count}</span>
                </div>
                <button
                    onClick={(e) => { e.stopPropagation(); onDelete(cat.id); }}
                    className="text-slate-400 hover:text-red-500 transition-colors p-2"
                    title="Delete"
                >
                    <Trash2 className="w-4 h-4" />
                </button>
                </div>
            );
          })}
        </div>

        {/* Create Form - MOVED TO BOTTOM / RIGHT */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 dark:bg-slate-900 dark:border-slate-800 h-fit">
          <h3 className="text-lg font-bold mb-4 dark:text-white flex items-center gap-2">
            <Plus className="w-5 h-5" /> Nueva Categoría
          </h3>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-1">Nombre</label>
              <input
                type="text"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                placeholder="Ej. Trabajo, Personal, Proyecto X"
                className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-red-500 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
              />
            </div>

            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-2">Color de Etiqueta</label>
              <div className="flex flex-wrap gap-2">
                {COLORS.map((c) => (
                  <button
                    key={c.value}
                    type="button"
                    onClick={() => setSelectedColor(c.value)}
                    className={cn(
                      "w-6 h-6 rounded-full transition-transform hover:scale-110",
                      c.value,
                      selectedColor === c.value ? "ring-2 ring-offset-2 ring-slate-400 dark:ring-slate-600 scale-110" : ""
                    )}
                    title={c.name}
                  />
                ))}
              </div>
            </div>

            <button
              type="submit"
              disabled={!newName.trim()}
              className="w-full bg-slate-900 text-white py-2 rounded-lg font-medium hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors dark:bg-red-600 dark:hover:bg-red-700"
            >
              Crear Categoría
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Categories;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, RotateCcw, Zap, Coffee, Lock, X, Target, FileText, 
  Bot, Send, Save, Edit3, Inbox as InboxIcon, MessageSquare, Clock
} from 'lucide-react';
import { TimerMode, Settings, Category, InboxItem } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode;
  startSession: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem;
  onStopTask?: () => void;
  onGoToInbox: () => void;
  onUpdateTask: (id: string, content: string) => void;
}

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask,
  onGoToInbox,
  onUpdateTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);
  const [isAiChatOpen, setIsAiChatOpen] = useState(false);

  // Estado local para el contenido de texto plano
  const [localNote, setLocalNote] = useState('');

  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  // Carga el contenido inicial al abrir el modal o cambiar de tarea
  useEffect(() => {
    if (activeTask && isDocViewOpen) {
        setLocalNote(activeTask.noteContent || '');
    }
  }, [activeTask, isDocViewOpen]);

  useEffect(() => {
      if (isAiChatOpen) {
          chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
      }
  }, [chatHistory, isAiChatOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
          default: return 25;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;
  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const theme = (() => {
    switch(viewMode) {
      case TimerMode.SHORT_BREAK:
        return { 
          primary: 'text-emerald-600', stroke: 'text-emerald-400', btnBg: 'bg-emerald-600', 
          btnText: 'text-white', glow: 'shadow-emerald-600/30', 
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return { 
          primary: 'text-violet-600', stroke: 'text-violet-400', btnBg: 'bg-violet-600', 
          btnText: 'text-white', glow: 'shadow-violet-600/30', 
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default:
        return { 
          primary: 'text-pomo', stroke: 'text-pomo-light', btnBg: 'bg-pomo', 
          btnText: 'text-white', glow: 'shadow-pomo/30', 
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  })();

  const handlePlayAction = () => {
    if (isViewingActive) {
      toggleTimer();
    } else {
      startSession(viewMode);
    }
  };

  const handleAiChat = async () => {
      if (!chatMessage.trim() || !activeTask) return;
      const userMsg = chatMessage;
      setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
      setChatMessage('');
      setIsAiThinking(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `El usuario está tomando estas notas: "${localNote}". Pregunta: "${userMsg}". Ayúdale de forma muy breve.`
          });
          setChatHistory(prev => [...prev, { role: 'model', text: response.text || "No pude procesar la solicitud." }]);
      } catch (e) {
          setChatHistory(prev => [...prev, { role: 'model', text: "Error de conexión con la IA." }]);
      } finally {
          setIsAiThinking(false);
      }
  };

  const saveDocChanges = () => {
    if (activeTask) {
        onUpdateTask(activeTask.id, localNote);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-4 relative">

        {/* Navigation Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
        </div>

        {/* Visualizer Area */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-slate-100 dark:text-slate-800" />
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="6" fill="transparent" pathLength={100} strokeDasharray="100" strokeDashoffset={strokeDashoffset} strokeLinecap="round" className={cn("transition-all duration-1000 ease-linear timer-glow", theme.stroke)} />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
                <span className={cn("font-sans font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: 'clamp(4.5rem, 14vw, 9rem)', transform: `scale(${growthScale})` }}>{formatTime(displayTime)}</span>
                <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">{isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Flowing...' : 'Resting...') : 'Ready'}</span>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-6 relative z-20 mb-8">
            <button onClick={resetTimer} className={cn("w-14 h-14 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95", !isViewingActive && "opacity-0 pointer-events-none")}><RotateCcw className="w-5 h-5" /></button>
            <button 
              onClick={handlePlayAction} 
              disabled={isActive && !isViewingActive} 
              className={cn(
                "w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95", 
                isActive && isViewingActive ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`, 
                isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale"
              )}
            >
                {isActive && isViewingActive ? <Pause className="w-8 h-8" /> : (isActive && !isViewingActive ? <Lock className="w-6 h-6" /> : <Play className="w-8 h-8 ml-1" />)}
            </button>
            <div className="w-14 h-14">
              {viewMode === TimerMode.FOCUS && (
                <button onClick={onGoToInbox} className={cn("w-full h-full rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95 shadow-lg", isViewingActive ? `${theme.btnBg} ${theme.btnText} ${theme.glow} dark:brightness-110` : "bg-slate-900 text-white dark:bg-white dark:text-black")}><InboxIcon className="w-5 h-5" /></button>
              )}
            </div>
        </div>

        {/* Active Task Dock */}
        {activeTask && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[60] w-[90%] max-w-lg">
                <div className="bg-white/80 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-4 flex items-center justify-between animate-in slide-in-from-bottom-8">
                    <div className="flex items-center gap-4 flex-1 min-w-0">
                        <div className="w-10 h-10 bg-blue-500 rounded-xl flex items-center justify-center text-white shrink-0 shadow-lg shadow-blue-500/20"><Target className="w-5 h-5" /></div>
                        <div className="min-w-0">
                            <p className="text-[10px] uppercase font-bold tracking-widest text-slate-400 leading-none mb-1">Misión Activa</p>
                            <p className="text-sm font-bold text-slate-900 dark:text-white truncate">{activeTask.noteContent.split('\n')[0] || 'Tarea en curso'}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 pl-4 border-l border-slate-100 dark:border-slate-800 ml-4">
                        <button onClick={() => setIsDocViewOpen(true)} className="p-2.5 rounded-xl bg-slate-50 text-slate-600 hover:bg-blue-50 hover:text-blue-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-blue-900/20" title="Abrir Notas"><FileText className="w-5 h-5" /></button>
                        <button onClick={onStopTask} className="p-2.5 rounded-xl bg-slate-50 text-slate-400 hover:bg-red-50 hover:text-red-500 transition-all dark:bg-slate-800"><X className="w-5 h-5" /></button>
                    </div>
                </div>
            </div>
        )}

        {/* Editor Modal Simplificado */}
        {isDocViewOpen && activeTask && (
            <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} />
                <div className="relative bg-white dark:bg-slate-900 w-full max-w-5xl h-[90vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in-95">

                    <div className="flex-1 flex flex-col overflow-hidden border-r border-slate-100 dark:border-slate-800">
                         {/* Header del Editor */}
                         <div className="flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30">
                            <div className="flex items-center gap-3">
                                <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2"><Edit3 className="w-4 h-4 text-blue-500" /> Notas de la Tarea</h3>
                                {/* Mini Timer Preview Inside Editor */}
                                <div className="px-3 py-1 bg-slate-200/50 dark:bg-slate-800/50 rounded-full flex items-center gap-2 text-[11px] font-mono font-bold text-slate-600 dark:text-slate-400">
                                    <Clock className="w-3 h-3" />
                                    <span>{formatTime(timeLeft)}</span>
                                </div>
                            </div>
                            <div className="flex items-center gap-2">
                                <button 
                                  onClick={() => setIsAiChatOpen(!isAiChatOpen)} 
                                  className={cn(
                                    "p-2 rounded-lg transition-all", 
                                    isAiChatOpen ? "bg-violet-100 text-violet-600 dark:bg-violet-900/40" : "text-slate-400 hover:text-violet-500"
                                  )} 
                                  title="Alternar Asistente IA"
                                >
                                    <Bot className="w-5 h-5" />
                                </button>
                                <button onClick={saveDocChanges} className="p-2 text-slate-400 hover:text-green-500 transition-colors" title="Guardar cambios"><Save className="w-5 h-5" /></button>
                                <button onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} className="p-2 text-slate-400 hover:text-slate-600"><X className="w-6 h-6" /></button>
                            </div>
                         </div>

                         {/* Workspace de texto plano */}
                         <div className="flex-1 overflow-hidden relative flex flex-col bg-white dark:bg-slate-900">
                            <textarea 
                                value={localNote}
                                onChange={(e) => setLocalNote(e.target.value)}
                                className="flex-1 w-full p-10 text-lg font-sans leading-relaxed text-slate-700 dark:text-slate-200 bg-transparent resize-none focus:outline-none overflow-y-auto custom-scrollbar"
                                placeholder="Escribe aquí tus ideas, notas o distracciones..."
                                autoFocus
                            />
                         </div>
                    </div>

                    {/* AI Sidebar - Desplegable */}
                    {isAiChatOpen && (
                        <div className="w-full md:w-80 flex flex-col bg-slate-50 dark:bg-slate-950 animate-in slide-in-from-right duration-300 border-l border-slate-200 dark:border-slate-800">
                            <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between font-bold text-slate-700 bg-white dark:bg-slate-900 dark:text-slate-200">
                                <div className="flex items-center gap-2">
                                    <Bot className="w-5 h-5 text-violet-500" />
                                    <span>Asistente IA</span>
                                </div>
                                <button onClick={() => setIsAiChatOpen(false)} className="md:hidden text-slate-400">
                                    <X className="w-4 h-4" />
                                </button>
                            </div>
                            <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                                <div className="text-[10px] text-slate-400 uppercase font-bold tracking-widest text-center mb-4">Contexto: Notas Actuales</div>
                                {chatHistory.map((msg, i) => (
                                    <div key={i} className={cn("text-sm p-3 rounded-xl max-w-[90%] shadow-sm", msg.role === 'user' ? "bg-violet-600 text-white self-end ml-auto" : "bg-white dark:bg-slate-800 dark:text-slate-300 border border-slate-200 dark:border-slate-700")}>
                                        {msg.text}
                                    </div>
                                ))}
                                {isAiThinking && (
                                    <div className="flex gap-1 justify-center p-2">
                                        <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" />
                                        <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" />
                                        <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-300" />
                                    </div>
                                )}
                                <div ref={chatEndRef} />
                            </div>
                            <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                                <div className="relative">
                                    <input 
                                        type="text" 
                                        value={chatMessage} 
                                        onChange={(e) => setChatMessage(e.target.value)} 
                                        onKeyDown={(e) => e.key === 'Enter' && handleAiChat()} 
                                        placeholder="Pregunta algo..." 
                                        className="w-full bg-slate-100 dark:bg-slate-800 rounded-full pl-4 pr-10 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-violet-500/20" 
                                    />
                                    <button onClick={handleAiChat} disabled={!chatMessage.trim() || isAiThinking} className="absolute right-1 top-1 p-1.5 bg-violet-600 text-white rounded-full hover:bg-violet-700 disabled:opacity-50 transition-colors">
                                        <Send className="w-3 h-3" />
                                    </button>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        )}
    </div>
  );
};

export default Timer;

import React, { useState, useEffect } from 'react';
import { InboxItem, Category } from '../types';
import { calculateDaysRemaining, cn, generateId } from '../utils';
import { 
    Trash2, Calendar, ArrowRightCircle, CheckCircle, AlertCircle, Bell, Briefcase, 
    User, BookOpen, Lock, Share2, Sparkles, LayoutList, Kanban, Play, MoreHorizontal,
    Trophy, Clock, Tag, Edit3, AlertTriangle, ChevronDown, Plus, Zap
} from 'lucide-react';

interface InboxProps {
  items: InboxItem[];
  onAction: (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction' | 'update', payload?: any) => void;
  categories?: Category[];
  onStartSession: (taskId: string) => void;
  onManageCategories: () => void;
  onSaveNote: (content: string, categoryId?: string) => string;
}

const Inbox: React.FC<InboxProps> = ({ items, onAction, categories, onStartSession, onManageCategories, onSaveNote }) => {
  const [activeTab, setActiveTab] = useState<'notifications' | 'all'>('all');
  const [viewMode, setViewMode] = useState<'list' | 'board'>('list');
  const [selectedItem, setSelectedItem] = useState<InboxItem | null>(null);
  const [confirmAction, setConfirmAction] = useState<{ id: string, type: 'delete' | 'resolve' } | null>(null);

  // New Task Quick Start State
  const [isNewTaskFormOpen, setIsNewTaskFormOpen] = useState(false);
  const [newTaskContent, setNewTaskContent] = useState('');
  const [newTaskCategory, setNewTaskCategory] = useState('');

  // Confetti State
  const [confetti, setConfetti] = useState<{id: number, x: number, y: number, color: string}[]>([]);

  const triggerConfetti = (e: React.MouseEvent) => {
      const x = e.clientX;
      const y = e.clientY;
      const colors = ['#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];

      const newConfetti = Array.from({ length: 20 }).map((_, i) => ({
          id: Date.now() + i,
          x: x,
          y: y,
          color: colors[Math.floor(Math.random() * colors.length)]
      }));

      setConfetti(prev => [...prev, ...newConfetti]);

      setTimeout(() => {
          setConfetti(prev => prev.filter(c => !newConfetti.find(n => n.id === c.id)));
      }, 1000);
  };

  const filteredItems = items.filter(item => {
    if (activeTab === 'notifications') return item.type === 'notification';
    return item.type === 'note' && item.status !== 'completed' && item.status !== 'scheduled'; 
  });

  const unreadCount = items.filter(i => i.type === 'notification' && !i.isRead).length;

  const getCategoryColor = (id?: string) => {
      const cat = categories?.find(c => c.id === id);
      return cat ? cat.color : 'bg-slate-200 dark:bg-slate-700';
  };

  const getCategoryName = (id?: string) => {
      return categories?.find(c => c.id === id)?.name || 'Uncategorized';
  };

  const handleUpdateItem = (updates: Partial<InboxItem>) => {
      if (selectedItem) {
          onAction(selectedItem.id, 'update', updates);
          setSelectedItem(prev => prev ? { ...prev, ...updates } : null);
      }
  };

  const handleCreateAndStartFocus = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newTaskContent.trim()) return;
      const newId = onSaveNote(newTaskContent, newTaskCategory || undefined);
      onStartSession(newId);
      setIsNewTaskFormOpen(false);
      setNewTaskContent('');
      setNewTaskCategory('');
  };

  const getStatusColor = (status: string) => {
      switch(status) {
          case 'pending': return 'border-l-red-500 bg-red-50/10';
          case 'in-progress': return 'border-l-amber-400 bg-amber-50/10';
          case 'scheduled': return 'border-l-green-500 bg-green-50/10'; 
          default: return 'border-l-slate-300';
      }
  };

  const getStatusBadge = (status: string) => {
      switch(status) {
          case 'pending': return 'text-red-500 bg-red-50 border-red-100 dark:bg-red-900/20 dark:border-red-900';
          case 'in-progress': return 'text-amber-500 bg-amber-50 border-amber-100 dark:bg-amber-900/20 dark:border-amber-900';
          case 'scheduled': return 'text-green-500 bg-green-50 border-green-100 dark:bg-green-900/20 dark:border-green-900';
          default: return 'text-slate-500';
      }
  };

  const renderCard = (item: InboxItem) => {
      const daysLeft = calculateDaysRemaining(item.deadline);
      const isUrgent = daysLeft <= 2;
      const hasTrophy = (item.timeSpent || 0) > 60; 

      return (
        <div 
            key={item.id}
            onClick={() => setSelectedItem(item)}
            className={cn(
                "group relative bg-white dark:bg-slate-900 rounded-xl border-l-[6px] border-y border-r border-slate-100 dark:border-slate-800 shadow-sm transition-all duration-300 hover:shadow-md hover:scale-[1.01] cursor-pointer p-4 flex flex-col gap-3",
                item.type === 'note' ? getStatusColor(item.status) : (item.type === 'notification' && !item.isRead ? "border-l-red-500" : "border-l-slate-300")
            )}
        >
            <div className="flex justify-between items-start">
                 {item.type === 'note' ? (
                     <button 
                        onClick={(e) => { e.stopPropagation(); setConfirmAction({ id: item.id, type: 'resolve' }); }}
                        className="mt-1 w-5 h-5 rounded-full border-2 border-slate-300 dark:border-slate-600 mr-3 flex items-center justify-center text-transparent hover:border-green-500 hover:text-green-500 transition-all shrink-0"
                        title="Mark as Resolved"
                     >
                        <CheckCircle className="w-4 h-4" />
                     </button>
                 ) : (
                     <div className="mt-1 mr-3 text-slate-400"><Bell className="w-4 h-4" /></div>
                 )}

                 <div className="flex-1 min-w-0">
                     <p className="text-sm font-medium text-slate-800 dark:text-slate-200 line-clamp-2 leading-relaxed">
                         {item.noteContent}
                     </p>

                     <div className="flex flex-wrap items-center gap-2 mt-2 text-xs text-slate-400">
                         {item.type === 'note' && (
                             <span className={cn("px-1.5 py-0.5 rounded border text-[10px] uppercase font-bold tracking-wider", getStatusBadge(item.status))}>
                                {item.status.replace('-', ' ')}
                             </span>
                         )}

                        {item.categoryId && (
                            <span className="flex items-center gap-1">
                                <span className={cn("w-2 h-2 rounded-full", getCategoryColor(item.categoryId))} />
                                {getCategoryName(item.categoryId)}
                            </span>
                        )}
                        {daysLeft <= 3 && item.type === 'note' && (
                            <span className="text-red-400 flex items-center gap-1">
                                <Clock className="w-3 h-3" /> {daysLeft}d left
                            </span>
                        )}
                        {item.type === 'notification' && (
                            <span className="text-slate-400">{item.createdAt.toLocaleDateString()}</span>
                        )}
                     </div>
                 </div>

                 <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                     {item.type === 'note' && (
                         <>
                            <button
                                onClick={(e) => { e.stopPropagation(); setSelectedItem(item); }}
                                className="p-2 bg-slate-100 hover:bg-slate-200 rounded-lg text-slate-500 transition-colors dark:bg-slate-800 dark:hover:bg-slate-700"
                                title="Edit Details"
                            >
                                <Edit3 className="w-4 h-4" />
                            </button>
                            <button
                                onClick={(e) => { e.stopPropagation(); onStartSession(item.id); }}
                                className="p-2 bg-slate-100 hover:bg-pomo hover:text-white rounded-lg text-slate-500 transition-colors dark:bg-slate-800"
                                title="Focus on this"
                            >
                                <Play className="w-4 h-4 fill-current" />
                            </button>
                         </>
                     )}
                 </div>
            </div>

            {(item.timeSpent || 0) > 0 && (
                <div className="flex items-center gap-2 pt-2 border-t border-slate-50 dark:border-slate-800">
                    <div className="flex-1 h-1 bg-slate-100 rounded-full overflow-hidden dark:bg-slate-800">
                        <div className="h-full bg-blue-500 rounded-full" style={{ width: `${Math.min(((item.timeSpent || 0) / 120) * 100, 100)}%` }}></div>
                    </div>
                    <span className="text-[10px] text-slate-400 whitespace-nowrap">
                        {item.timeSpent}m
                    </span>
                    {hasTrophy && <Trophy className="w-3 h-3 text-amber-400" />}
                </div>
            )}
        </div>
      );
  };

  return (
    <div className="w-full max-w-5xl mx-auto py-8 px-4 relative">

      <div className="fixed inset-0 pointer-events-none z-[100] overflow-hidden">
          {confetti.map(p => (
              <div key={p.id} className="absolute w-2 h-2 rounded-full animate-ping" style={{ left: p.x, top: p.y, backgroundColor: p.color, transform: `translate(${Math.random() * 100 - 50}px, ${Math.random() * 100 + 20}px)`, opacity: 0, transition: 'all 0.8s ease-out' }} />
          ))}
      </div>

      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900 dark:text-white">
                {activeTab === 'all' ? 'Inbox & Tareas' : 'Notificaciones'}
            </h2>
            <p className="text-xs text-slate-500 mt-1 dark:text-slate-400">
                {activeTab === 'all' ? 'Gestiona tus ítems de enfoque diario.' : 'Alertas del sistema.'}
            </p>
        </div>

        <div className="flex items-center gap-2">
             <div className="flex bg-slate-100 p-1 rounded-xl dark:bg-slate-800 border border-slate-200 dark:border-slate-700">
                <button onClick={() => setActiveTab('all')} className={cn("px-4 py-2 rounded-lg text-sm font-bold transition-all", activeTab === 'all' ? "bg-white shadow-sm dark:bg-slate-600 dark:text-white text-slate-900" : "text-slate-500 hover:text-slate-700")}>Mis Tareas</button>
                <button onClick={() => setActiveTab('notifications')} className={cn("px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2", activeTab === 'notifications' ? "bg-white shadow-sm dark:bg-slate-600 dark:text-white text-slate-900" : "text-slate-500 hover:text-slate-700")}>
                    Alertas
                    {unreadCount > 0 && <span className="bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full leading-none">{unreadCount}</span>}
                </button>
             </div>

             {activeTab === 'all' && (
                 <>
                    <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-2"></div>
                    <button 
                        onClick={() => setIsNewTaskFormOpen(!isNewTaskFormOpen)}
                        className={cn(
                            "px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 transition-all shadow-lg",
                            isNewTaskFormOpen ? "bg-slate-900 text-white" : "bg-pomo text-white shadow-pomo/30 hover:scale-105 active:scale-95"
                        )}
                    >
                        <Zap className="w-4 h-4" /> Nuevo Focus
                    </button>
                 </>
             )}
        </div>
      </div>

      {/* Quick Task Focus Form */}
      {isNewTaskFormOpen && (
          <form onSubmit={handleCreateAndStartFocus} className="mb-8 bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl animate-in slide-in-from-top-4">
              <div className="flex flex-col gap-4">
                  <div className="flex-1">
                      <label className="block text-[10px] uppercase font-black text-slate-400 tracking-widest mb-2">¿En qué vas a enfocarte?</label>
                      <input 
                        type="text" 
                        autoFocus
                        value={newTaskContent}
                        onChange={(e) => setNewTaskContent(e.target.value)}
                        placeholder="Ej. Escribir propuesta de diseño..." 
                        className="w-full bg-slate-50 dark:bg-slate-800 p-4 rounded-xl text-lg font-bold outline-none border border-transparent focus:border-pomo/30 transition-all dark:text-white"
                      />
                  </div>
                  <div className="flex items-center gap-3">
                      <div className="flex-1">
                        <label className="block text-[10px] uppercase font-black text-slate-400 tracking-widest mb-2">Etiqueta</label>
                        <select 
                            value={newTaskCategory}
                            onChange={(e) => setNewTaskCategory(e.target.value)}
                            className="w-full bg-slate-50 dark:bg-slate-800 p-3 rounded-xl text-sm font-bold outline-none dark:text-white"
                        >
                            <option value="">Sin Etiqueta</option>
                            {categories?.map(cat => (
                                <option key={cat.id} value={cat.id}>{cat.name}</option>
                            ))}
                        </select>
                      </div>
                      <div className="flex items-end h-full mt-6">
                        <button 
                            type="submit" 
                            disabled={!newTaskContent.trim()}
                            className="bg-pomo text-white p-4 rounded-xl shadow-xl shadow-pomo/20 hover:scale-105 active:scale-95 disabled:opacity-50 transition-all font-bold flex items-center gap-2"
                        >
                            <Play className="w-5 h-5 fill-current" /> Iniciar Sesión
                        </button>
                      </div>
                  </div>
              </div>
          </form>
      )}

      {/* Main Content */}
      <div className="grid gap-3">
          {filteredItems.length === 0 && (
              <div className="text-center py-12 text-slate-400 italic">No hay ítems para mostrar.</div>
          )}
          {filteredItems.map(renderCard)}
      </div>

      {/* Item Details Modal */}
      {selectedItem && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setSelectedItem(null)} />
              <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-2xl shadow-2xl p-6 border border-slate-100 dark:border-slate-800 animate-in fade-in zoom-in-95 max-h-[90vh] overflow-y-auto custom-scrollbar">
                   <div className="flex justify-between items-start mb-6">
                        <div>
                            {selectedItem.type === 'note' && (
                                <span className={cn("px-2 py-0.5 rounded text-[10px] uppercase font-bold tracking-wider mb-2 inline-block", getStatusBadge(selectedItem.status))}>
                                    {selectedItem.status}
                                </span>
                            )}
                            <h3 className="text-xl font-bold dark:text-white leading-tight pr-8">
                                {selectedItem.noteContent.substring(0, 50)}{selectedItem.noteContent.length > 50 ? '...' : ''}
                            </h3>
                        </div>
                        <button onClick={() => setSelectedItem(null)} className="text-slate-400 hover:text-slate-600 p-1"><MoreHorizontal className="w-5 h-5" /></button>
                   </div>

                   <div className="mb-6">
                        <div className="relative group">
                            <textarea 
                                readOnly
                                value={selectedItem.noteContent}
                                className="w-full h-32 bg-slate-50 border border-slate-200 rounded-xl p-4 text-slate-500 resize-none focus:outline-none cursor-not-allowed dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400"
                            />
                            {selectedItem.type === 'note' && (
                                <div className="absolute inset-0 flex items-center justify-center bg-white/50 dark:bg-black/50 backdrop-blur-[1px] opacity-0 group-hover:opacity-100 transition-opacity rounded-xl">
                                    <div className="bg-white dark:bg-slate-900 px-4 py-2 rounded-full shadow-lg flex items-center gap-2 text-xs font-bold text-slate-600 dark:text-slate-200 border border-slate-200 dark:border-slate-700">
                                        <Lock className="w-3 h-3" />
                                        Contenido bloqueado. Inicia Focus para editar.
                                    </div>
                                </div>
                            )}
                        </div>
                   </div>

                   {selectedItem.type === 'note' && (
                   <div className="grid grid-cols-2 gap-4 mb-6">
                       <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-xl flex items-center gap-3">
                           <Clock className="w-8 h-8 text-blue-500 bg-blue-100 p-1.5 rounded-lg dark:bg-blue-900/30" />
                           <div>
                               <p className="text-xs text-slate-500 uppercase font-bold">Tiempo</p>
                               <p className="font-mono font-bold text-lg dark:text-white">{selectedItem.timeSpent || 0}m</p>
                           </div>
                       </div>
                       <div className="bg-slate-50 dark:bg-slate-800 p-3 rounded-xl flex items-center gap-3">
                           <Trophy className="w-8 h-8 text-amber-500 bg-amber-100 p-1.5 rounded-lg dark:bg-amber-900/30" />
                           <div>
                               <p className="text-xs text-slate-500 uppercase font-bold">Meta</p>
                               <p className="font-mono font-bold text-lg dark:text-white text-slate-400">60m</p>
                           </div>
                       </div>
                   </div>
                   )}

                   {selectedItem.type === 'note' && (
                   <div className="space-y-4 border-t border-slate-100 dark:border-slate-800 pt-6">
                       <div className="flex items-center justify-between">
                            <label className="text-xs font-bold text-slate-500 uppercase">Estado</label>
                            <div className="flex bg-slate-100 p-1 rounded-lg dark:bg-slate-800">
                                {['pending', 'in-progress'].map(s => (
                                    <button
                                        key={s}
                                        onClick={() => handleUpdateItem({ status: s as any })}
                                        className={cn(
                                            "px-3 py-1 text-xs font-medium rounded-md capitalize transition-all",
                                            selectedItem.status === s 
                                                ? "bg-white shadow text-slate-900 dark:bg-slate-700 dark:text-white" 
                                                : "text-slate-400 hover:text-slate-600"
                                        )}
                                    >
                                        {s.replace('-', ' ')}
                                    </button>
                                ))}
                            </div>
                       </div>

                       <div>
                           <label className="text-xs font-bold text-slate-500 uppercase mb-2 block">Categoría</label>
                           <div className="flex flex-wrap gap-2">
                                {categories?.map(cat => (
                                    <button 
                                        key={cat.id}
                                        onClick={() => handleUpdateItem({ categoryId: cat.id })}
                                        className={cn(
                                            "px-3 py-1.5 rounded-full text-xs font-medium transition-all border",
                                            selectedItem.categoryId === cat.id 
                                                ? "bg-slate-900 text-white border-slate-900 dark:bg-white dark:text-black" 
                                                : "bg-white text-slate-600 border-slate-200 hover:border-slate-300 dark:bg-slate-800 dark:text-slate-300 dark:border-slate-700"
                                        )}
                                    >
                                        <span className={cn("inline-block w-2 h-2 rounded-full mr-1.5", cat.color)}></span>
                                        {cat.name}
                                    </button>
                                ))}
                           </div>
                       </div>
                   </div>
                   )}

                   <div className="flex gap-3 mt-8">
                       {selectedItem.type === 'note' && (
                       <button 
                            onClick={() => { onStartSession(selectedItem.id); setSelectedItem(null); }}
                            className="flex-1 bg-pomo text-white py-3 rounded-xl font-bold shadow-lg shadow-pomo/30 hover:bg-pomo-dark transition-colors flex items-center justify-center gap-2"
                        >
                           <Play className="w-4 h-4 fill-current" /> Enfocar y Editar
                       </button>
                       )}
                       <button onClick={() => { setConfirmAction({ id: selectedItem.id, type: 'delete' }); }} className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors dark:hover:bg-red-900/20"><Trash2 className="w-5 h-5" /></button>
                       {selectedItem.type === 'note' && (
                       <button onClick={() => { setConfirmAction({ id: selectedItem.id, type: 'resolve' }); }} className="p-3 text-slate-400 hover:text-green-500 hover:bg-green-50 rounded-xl transition-colors dark:hover:bg-green-900/20"><CheckCircle className="w-5 h-5" /></button>
                       )}
                   </div>
              </div>
          </div>
      )}

      {confirmAction && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setConfirmAction(null)} />
              <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-2xl shadow-2xl p-6 border border-slate-100 dark:border-slate-800 animate-in fade-in zoom-in-95">
                  <div className="flex flex-col items-center text-center gap-4">
                      <div className="w-12 h-12 bg-red-100 text-red-600 rounded-full flex items-center justify-center dark:bg-red-900/30 dark:text-red-400">
                          {confirmAction.type === 'resolve' ? <Sparkles className="w-6 h-6 text-amber-500" /> : <AlertTriangle className="w-6 h-6" />}
                      </div>
                      <div>
                          <h3 className="text-lg font-bold dark:text-white">¿Estás seguro?</h3>
                          <p className="text-sm text-slate-500 mt-1">
                              {confirmAction.type === 'resolve' ? "¡Buen trabajo! Esto archivará la tarea." : "Esto eliminará permanentemente el ítem."}
                          </p>
                      </div>
                      <div className="flex gap-3 w-full mt-2">
                          <button onClick={() => setConfirmAction(null)} className="flex-1 py-2.5 rounded-xl border border-slate-200 text-slate-600 hover:bg-slate-50 font-medium dark:border-slate-700 dark:text-slate-300 dark:hover:bg-slate-800">Cancelar</button>
                          <button onClick={(e) => { if (confirmAction.type === 'resolve') triggerConfetti(e); onAction(confirmAction.id, confirmAction.type === 'resolve' ? 'schedule' : 'delete'); setConfirmAction(null); }} className={cn("flex-1 py-2.5 rounded-xl text-white font-medium shadow-lg", confirmAction.type === 'resolve' ? "bg-green-600 hover:bg-green-700 shadow-green-600/20" : "bg-red-600 hover:bg-red-700 shadow-red-600/20")}>{confirmAction.type === 'resolve' ? 'Resolver' : 'Eliminar'}</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Inbox;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Timer from './components/Timer';
import Inbox from './components/Inbox';
import Dashboard from './components/Dashboard';
import History from './components/History';
import Categories from './components/Categories';
import QuickCapture from './components/QuickCapture';
import { View, TimerMode, InboxItem, Settings, UserCredits, SessionHistoryItem, Category } from './types';
import { generateId, cn, playSynthSound } from './utils';
import { Moon, Sun, Volume2, VolumeX, Timer as TimerIcon, Menu, X, PenLine, BarChart2, History as HistoryIcon, Tags, Inbox as InboxIcon, ExternalLink, User as UserIcon, CreditCard } from 'lucide-react';

// Mock Data
const INITIAL_SETTINGS: Settings = {
  focusDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  longBreakInterval: 4,
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: 'Trabajo', color: 'bg-red-500' },
  { id: 'c2', name: 'Personal', color: 'bg-blue-500' },
  { id: 'c3', name: 'Estudio', color: 'bg-emerald-500' },
];

const INITIAL_INBOX: InboxItem[] = [
  {
    id: 'w1', type: 'note', status: 'pending', categoryId: 'c1',
    noteContent: 'Reporte Financiero Q3\nResumen\nEl análisis muestra un crecimiento del 15% en ingresos recurrentes.',
    createdAt: new Date(), deadline: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000), timeSpent: 0
  },
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('timer');
  const [previousView, setPreviousView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState(''); 
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isQuickCaptureOpen, setIsQuickCaptureOpen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);

  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);

  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
    if (isSoundEnabled) playSynthSound('theme-change');
  };

  const toggleSound = () => {
    setIsSoundEnabled(prev => {
      const newVal = !prev;
      if (newVal) playSynthSound('toggle');
      return newVal;
    });
  };

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  useEffect(() => {
    if (!isActive) {
      let duration = settings.focusDuration;
      if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
      if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
      setTimeLeft(duration * 60);
    }
  }, [mode, settings, isActive]);

  const handleSessionComplete = useCallback((completedMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('complete');

    const duration = completedMode === TimerMode.FOCUS ? settings.focusDuration : 
                     completedMode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000),
        endTime: new Date(),
        mode: completedMode,
        duration: duration,
        noteSnapshot: completedMode === TimerMode.FOCUS ? currentNote : undefined,
        relatedTaskId: activeTaskId || undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    if (activeTaskId && completedMode === TimerMode.FOCUS) {
        setInbox(prev => prev.map(item => {
            if (item.id === activeTaskId) {
                const updatedContent = currentNote.trim() 
                    ? item.noteContent + "\n\n" + `[Sesión ${new Date().toLocaleTimeString()}]: ` + currentNote 
                    : item.noteContent;
                return { ...item, timeSpent: (item.timeSpent || 0) + duration, noteContent: updatedContent };
            }
            return item;
        }));
    } else if (currentNote.trim() && !activeTaskId) {
        saveNoteToInbox(currentNote);
    }
    setCurrentNote('');
  }, [currentNote, settings, activeTaskId, isSoundEnabled]);

  const switchMode = useCallback(() => {
    if (isSoundEnabled) playSynthSound('switch');
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);
      let nextMode = (newCompleted > 0 && newCompleted % settings.longBreakInterval === 0) ? TimerMode.LONG_BREAK : TimerMode.SHORT_BREAK;
      setMode(nextMode);
      sendNotification("¡Hora de un descanso!", `Sesión de enfoque completada.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Descanso terminado", "¡A darle con todo!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval, isSoundEnabled]);

  useEffect(() => {
    let interval: number | undefined;
    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => {
           if (isSoundEnabled && prev > 1) playSynthSound('tick');
           return prev - 1;
        });
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      setIsActive(false);
      handleSessionComplete(mode);
      switchMode();
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, handleSessionComplete, switchMode, isSoundEnabled]);

  const toggleTimer = () => {
    const nextActive = !isActive;
    if (isSoundEnabled) {
        playSynthSound(nextActive ? 'start' : 'pause');
    }
    setIsActive(nextActive);
  };

  const resetTimer = () => {
    if (isSoundEnabled) playSynthSound('toggle');
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const startSession = (newMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('switch');
    setIsActive(false);
    setMode(newMode);

    let duration = settings.focusDuration;
    if (newMode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (newMode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);

    setTimeout(() => {
        setIsActive(true);
        if (isSoundEnabled) playSynthSound('start');
    }, 10);
  };

  const handleStartTaskFocus = (taskId: string) => {
    setActiveTaskId(taskId);
    setCurrentView('timer');
    startSession(TimerMode.FOCUS);
    setInbox(prev => prev.map(item => item.id === taskId && item.status === 'pending' ? { ...item, status: 'in-progress' } : item));
  };

  const saveNoteToInbox = (content: string, categoryId?: string) => {
      const newItem: InboxItem = {
        id: generateId(),
        type: 'note',
        noteContent: content,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), 
        status: 'pending',
        categoryId: categoryId,
      };
      setInbox(prev => [newItem, ...prev]);
      return newItem.id;
  };

  const handleInboxAction = (id: string, action: string, payload?: any) => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else if (action === 'update') {
      setInbox(prev => prev.map(i => i.id === id ? { ...i, ...payload } : i));
    } else if (action === 'schedule') {
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: 'scheduled', isRead: true } : i));
    }
  };

  const handleUpdateTask = (id: string, content: string) => {
    setInbox(prev => prev.map(item => item.id === id ? { ...item, noteContent: content } : item));
  };

  const handleViewChange = (view: View) => {
    if (view === currentView) return;
    setPreviousView(currentView);
    setCurrentView(view);
    if (isSoundEnabled) playSynthSound('toggle');
    setIsMenuOpen(false);
  };

  const toggleSettings = () => {
    if (currentView === 'settings') {
        setCurrentView(previousView || 'timer');
    } else {
        setPreviousView(currentView);
        setCurrentView('settings');
    }
    if (isSoundEnabled) playSynthSound('toggle');
  };

  const activeTask = inbox.find(i => i.id === activeTaskId);
  const badgeCount = inbox.filter(i => i.status === 'pending' && i.type === 'notification' && !i.isRead).length;

  return (
    <div className="flex flex-col min-h-screen bg-white dark:bg-black font-sans transition-colors duration-300 relative overflow-hidden">

      <QuickCapture isOpen={isQuickCaptureOpen} onClose={() => setIsQuickCaptureOpen(false)} categories={categories} onSave={saveNoteToInbox} timeLeft={timeLeft} timerMode={mode} />

      {isMenuOpen && (
        <div className="fixed inset-0 bg-black/20 backdrop-blur-sm z-40 transition-opacity duration-300" onClick={() => setIsMenuOpen(false)} />
      )}

      <main className="flex-1 p-8 overflow-y-auto w-full max-w-7xl mx-auto flex flex-col items-center pb-32">
        <header className="mb-8 w-full flex items-center justify-between relative z-50 px-2">
             {/* Left: Logo */}
             <div className="flex items-center gap-3 cursor-pointer group" onClick={() => handleViewChange('timer')}>
                <div className="w-10 h-10 bg-pomo rounded-xl flex items-center justify-center shadow-lg shadow-pomo/30 flex-shrink-0 text-white transition-transform group-hover:scale-105">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="w-6 h-6">
                        <path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z" />
                        <path d="M12 6v6l4 2" />
                    </svg>
                </div>
                <div>
                    <h1 className="text-xl font-bold tracking-tight text-slate-900 dark:text-white leading-none">
                        Pomo<span className="text-pomo">Deep</span>
                    </h1>
                    <p className="text-[9px] text-slate-400 font-medium tracking-widest uppercase mt-0.5">Focus OS</p>
                </div>
             </div>

             {/* Right: Controls */}
             <div className="flex items-center gap-1.5">
                <button 
                  onClick={toggleSettings} 
                  className={cn(
                    "p-2.5 rounded-full transition-all active:scale-90",
                    currentView === 'settings' ? "bg-pomo text-white shadow-lg shadow-pomo/30" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800"
                  )}
                  title="Configuración"
                >
                  <TimerIcon className="w-5 h-5" />
                </button>
                <button 
                  onClick={toggleSound} 
                  className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" 
                  title={isSoundEnabled ? "Silenciar" : "Activar Sonidos"}
                >
                  {isSoundEnabled ? <Volume2 className="w-5 h-5" /> : < VolumeX className="w-5 h-5" />}
                </button>
                <button 
                  onClick={toggleDarkMode} 
                  className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" 
                  title="Tema"
                >
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>

                <div className="relative">
                  <button 
                    onClick={() => setIsMenuOpen(!isMenuOpen)} 
                    className={cn(
                      "p-2.5 rounded-full transition-all active:scale-90 relative",
                      isMenuOpen ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800"
                    )}
                    title="Menú"
                  >
                    {isMenuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
                    {badgeCount > 0 && !isMenuOpen && (
                      <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-pomo border-2 border-white dark:border-black rounded-full" />
                    )}
                  </button>

                  {/* Dropdown Menu */}
                  {isMenuOpen && (
                    <div className="absolute right-0 mt-3 w-64 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl shadow-2xl p-4 animate-in fade-in zoom-in-95 duration-200">
                        {/* User Profile in Menu */}
                        <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800 rounded-xl mb-4">
                            <div className="w-10 h-10 rounded-full bg-slate-200 dark:bg-slate-700 overflow-hidden ring-2 ring-white dark:ring-slate-900">
                                <img src="https://picsum.photos/100/100" alt="User" className="w-full h-full object-cover" />
                            </div>
                            <div className="flex flex-col leading-tight">
                                <p className="text-sm font-bold text-slate-900 dark:text-white">Alex Designer</p>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">Pro Plan</p>
                            </div>
                        </div>

                        <button 
                          onClick={() => { setIsQuickCaptureOpen(true); setIsMenuOpen(false); }}
                          className="w-full bg-slate-900 hover:bg-slate-800 text-white p-3 rounded-xl flex items-center justify-center gap-2 transition-all mb-4 dark:bg-white dark:text-black dark:hover:bg-slate-200 font-bold text-sm"
                        >
                          <PenLine className="w-4 h-4" /> Captura Rápida
                        </button>

                        <nav className="space-y-1">
                          {[
                            { id: 'timer', icon: TimerIcon, label: 'Enfoque' },
                            { id: 'inbox', icon: InboxIcon, label: 'Inbox', badge: badgeCount },
                            { id: 'categories', icon: Tags, label: 'Categorías' },
                            { id: 'dashboard', icon: BarChart2, label: 'Estadísticas' },
                            { id: 'history', icon: HistoryIcon, label: 'Historial' },
                          ].map((item) => (
                            <button
                              key={item.id}
                              onClick={() => handleViewChange(item.id as View)}
                              className={cn(
                                "w-full flex items-center justify-between px-4 py-3 rounded-xl transition-colors font-medium text-sm",
                                currentView === item.id 
                                  ? "bg-pomo/5 text-pomo dark:bg-pomo/10" 
                                  : "text-slate-500 hover:bg-slate-50 dark:text-slate-400 dark:hover:bg-slate-800"
                              )}
                            >
                              <div className="flex items-center gap-3">
                                <item.icon className="w-4 h-4" />
                                {item.label}
                              </div>
                              {item.badge ? (
                                <span className="bg-pomo text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full">{item.badge}</span>
                              ) : null}
                            </button>
                          ))}
                        </nav>
                    </div>
                  )}
                </div>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 w-full flex-1">
            {currentView === 'timer' && (
            <Timer 
              settings={settings} 
              activeMode={mode} 
              startSession={startSession} 
              timeLeft={timeLeft} 
              isActive={isActive} 
              toggleTimer={toggleTimer} 
              resetTimer={resetTimer} 
              sessionsCompleted={sessionsCompleted} 
              currentNote={currentNote} 
              onNoteChange={setCurrentNote} 
              categories={categories} 
              onSaveNote={saveNoteToInbox} 
              activeTask={activeTask} 
              onStopTask={() => setActiveTaskId(null)}
              onGoToInbox={() => handleViewChange('inbox')}
              onUpdateTask={handleUpdateTask}
            />
            )}
            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} categories={categories} onStartSession={handleStartTaskFocus} onManageCategories={() => setCurrentView('categories')} onSaveNote={saveNoteToInbox} />
            )}
            {currentView === 'categories' && (
            <Categories categories={categories} onAdd={(c) => setCategories(prev => [...prev, c])} onDelete={(id) => setCategories(prev => prev.filter(c => c.id !== id))} inboxItems={inbox} />
            )}
            {currentView === 'dashboard' && <Dashboard credits={credits} onExport={() => {}} />}
            {currentView === 'history' && <History history={history} />}
            {currentView === 'settings' && (
                <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800">
                    <h3 className="text-lg font-bold mb-6 dark:text-white">Duración de Sesión</h3>
                    <div className="space-y-8">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2 dark:text-slate-300">Enfoque Profundo (min)</label>
                            <input type="range" min="15" max="60" value={settings.focusDuration} onChange={(e) => setSettings({...settings, focusDuration: parseInt(e.target.value)})} className="w-full accent-pomo cursor-pointer" />
                            <div className="flex justify-between text-xs text-slate-400 mt-1"><span>15m</span><span className="font-bold text-pomo">{settings.focusDuration}m</span><span>60m</span></div>
                        </div>
                    </div>
                </div>
            )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Category, InboxItem } from '../types';
import { Plus, Trash2, Tag, ArrowLeft, Clock, CheckCircle } from 'lucide-react';
import { generateId, cn } from '../utils';

interface CategoriesProps {
  categories: Category[];
  onAdd: (category: Category) => void;
  onDelete: (id: string) => void;
  inboxItems: InboxItem[];
}

const COLORS = [
  { name: 'Red', value: 'bg-red-500' },
  { name: 'Orange', value: 'bg-orange-500' },
  { name: 'Amber', value: 'bg-amber-500' },
  { name: 'Green', value: 'bg-green-500' },
  { name: 'Emerald', value: 'bg-emerald-500' },
  { name: 'Teal', value: 'bg-teal-500' },
  { name: 'Cyan', value: 'bg-cyan-500' },
  { name: 'Blue', value: 'bg-blue-500' },
  { name: 'Indigo', value: 'bg-indigo-500' },
  { name: 'Violet', value: 'bg-violet-500' },
  { name: 'Purple', value: 'bg-purple-500' },
  { name: 'Fuchsia', value: 'bg-fuchsia-500' },
  { name: 'Pink', value: 'bg-pink-500' },
  { name: 'Rose', value: 'bg-rose-500' },
  { name: 'Slate', value: 'bg-slate-500' },
];

const Categories: React.FC<CategoriesProps> = ({ categories, onAdd, onDelete, inboxItems }) => {
  const [newName, setNewName] = useState('');
  const [selectedColor, setSelectedColor] = useState(COLORS[0].value);
  const [activeCategory, setActiveCategory] = useState<Category | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName.trim()) return;

    onAdd({
      id: generateId(),
      name: newName.trim(),
      color: selectedColor
    });
    setNewName('');
  };

  if (activeCategory) {
    const categoryItems = inboxItems.filter(item => item.categoryId === activeCategory.id && item.type === 'note' && item.status !== 'completed' && item.status !== 'scheduled');

    return (
      <div className="w-full max-w-2xl mx-auto py-8 px-4 animate-in fade-in slide-in-from-right-8 text-center">
        <div className="mb-8 flex items-center justify-center gap-4">
           <button 
             onClick={() => setActiveCategory(null)}
             className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
           >
             <ArrowLeft className="w-6 h-6 text-slate-500" />
           </button>
           <div className="flex items-center gap-3">
              <div className={cn("w-6 h-6 rounded-full", activeCategory.color)} />
              <h2 className="text-2xl font-bold text-slate-900 dark:text-white">{activeCategory.name}</h2>
              <span className="text-slate-400 text-sm font-medium border border-slate-200 dark:border-slate-700 px-2 py-0.5 rounded-full">
                {categoryItems.length} items
              </span>
           </div>
        </div>

        <div className="grid gap-4">
            {categoryItems.length === 0 && (
                <div className="text-center py-12 bg-slate-50 dark:bg-slate-900 rounded-xl border border-dashed border-slate-200 dark:border-slate-800">
                    <p className="text-slate-400">No hay tareas activas en esta categoría.</p>
                </div>
            )}
            {categoryItems.map(item => (
                <div key={item.id} className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm flex items-center justify-between text-left">
                    <div>
                        <p className="font-medium text-slate-800 dark:text-slate-200">{item.noteContent}</p>
                        <div className="flex items-center gap-4 mt-2 text-xs text-slate-400">
                             <span className={cn("px-1.5 py-0.5 rounded border capitalize", 
                                item.status === 'in-progress' ? 'border-amber-200 text-amber-600 bg-amber-50' : 'border-slate-200'
                             )}>
                                {item.status.replace('-', ' ')}
                             </span>
                             {item.timeSpent ? (
                                <span className="flex items-center gap-1"><Clock className="w-3 h-3" /> {item.timeSpent}m</span>
                             ) : null}
                        </div>
                    </div>
                </div>
            ))}
        </div>
      </div>
    );
  }

  return (
    <div className="w-full max-w-2xl mx-auto py-8 px-4 animate-in fade-in flex flex-col items-center">
      <div className="mb-10 text-center">
        <h2 className="text-3xl font-bold text-slate-900 dark:text-white">Centro de Categorías</h2>
        <p className="text-slate-500 text-sm dark:text-slate-400 mt-2">Gestiona etiquetas y profundiza en contextos específicos.</p>
      </div>

      <div className="w-full space-y-12">
        {/* Existing Tags Section - TOP */}
        <div className="space-y-4">
          <div className="flex items-center justify-center gap-2 mb-4">
            <Tag className="w-5 h-5 text-slate-400" />
            <h3 className="text-lg font-bold dark:text-white">Existing Tags</h3>
          </div>
          <div className="grid grid-cols-1 gap-3">
            {categories.length === 0 && (
               <p className="text-slate-400 text-sm italic text-center">No hay categorías definidas aún.</p>
            )}
            {categories.map((cat) => {
                const count = inboxItems.filter(i => i.categoryId === cat.id && i.status !== 'completed' && i.status !== 'scheduled' && i.type === 'note').length;
                return (
                    <div 
                        key={cat.id} 
                        onClick={() => setActiveCategory(cat)}
                        className="flex items-center justify-between p-4 bg-white rounded-2xl border border-slate-100 shadow-sm dark:bg-slate-900 dark:border-slate-800 group cursor-pointer hover:border-pomo transition-all"
                    >
                        <div className="flex items-center gap-4">
                            <div className={cn("w-4 h-4 rounded-full ring-2 ring-offset-2 ring-transparent group-hover:ring-slate-200", cat.color)} />
                            <span className="font-bold text-slate-700 dark:text-slate-200">{cat.name}</span>
                            <span className="text-xs bg-slate-100 text-slate-500 font-bold px-2 py-0.5 rounded-full dark:bg-slate-800">{count}</span>
                        </div>
                        <button
                            onClick={(e) => { e.stopPropagation(); onDelete(cat.id); }}
                            className="text-slate-300 hover:text-red-500 transition-colors p-2 rounded-xl hover:bg-red-50 dark:hover:bg-red-900/20"
                            title="Eliminar"
                        >
                            <Trash2 className="w-4 h-4" />
                        </button>
                    </div>
                );
            })}
          </div>
        </div>

        {/* Create Form Section - BOTTOM */}
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 dark:bg-slate-900 dark:border-slate-800 w-full">
          <h3 className="text-lg font-bold mb-6 dark:text-white flex items-center justify-center gap-2">
            <Plus className="w-5 h-5 text-pomo" /> Nueva Categoría
          </h3>
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">Nombre de la Etiqueta</label>
              <input
                type="text"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                placeholder="Ej. Trabajo, Proyecto X, Lectura..."
                className="w-full bg-slate-50 border border-transparent rounded-xl px-4 py-3 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-pomo/20 dark:bg-slate-800 dark:text-slate-200"
              />
            </div>

            <div>
              <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-3">Color Visual</label>
              <div className="flex flex-wrap justify-center gap-3">
                {COLORS.map((c) => (
                  <button
                    key={c.value}
                    type="button"
                    onClick={() => setSelectedColor(c.value)}
                    className={cn(
                      "w-7 h-7 rounded-full transition-all hover:scale-125",
                      c.value,
                      selectedColor === c.value ? "ring-2 ring-offset-2 ring-pomo scale-110 shadow-lg shadow-pomo/20" : "opacity-80"
                    )}
                    title={c.name}
                  />
                ))}
              </div>
            </div>

            <button
              type="submit"
              disabled={!newName.trim()}
              className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold hover:bg-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg dark:bg-pomo dark:hover:bg-pomo-dark"
            >
              Crear Categoría
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Categories;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, RotateCcw, Zap, Coffee, Lock, X, Target, FileText, 
  Bot, Send, Save, Edit3, Inbox as InboxIcon, MessageSquare, Clock
} from 'lucide-react';
import { TimerMode, Settings, Category, InboxItem } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode;
  startSession: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem;
  onStopTask?: () => void;
  onGoToInbox: () => void;
  onUpdateTask: (id: string, content: string) => void;
}

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask,
  onGoToInbox,
  onUpdateTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);
  const [isAiChatOpen, setIsAiChatOpen] = useState(false);

  // Estado local para el contenido de texto plano
  const [localNote, setLocalNote] = useState('');

  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  // Carga el contenido inicial al abrir el modal o cambiar de tarea
  useEffect(() => {
    if (activeTask && isDocViewOpen) {
        setLocalNote(activeTask.noteContent || '');
    }
  }, [activeTask, isDocViewOpen]);

  useEffect(() => {
      if (isAiChatOpen) {
          chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
      }
  }, [chatHistory, isAiChatOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
          default: return 25;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;
  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const theme = (() => {
    switch(viewMode) {
      case TimerMode.SHORT_BREAK:
        return { 
          primary: 'text-emerald-600', stroke: 'text-emerald-400', btnBg: 'bg-emerald-600', 
          btnText: 'text-white', glow: 'shadow-emerald-600/30', 
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return { 
          primary: 'text-violet-600', stroke: 'text-violet-400', btnBg: 'bg-violet-600', 
          btnText: 'text-white', glow: 'shadow-violet-600/30', 
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default:
        return { 
          primary: 'text-pomo', stroke: 'text-pomo-light', btnBg: 'bg-pomo', 
          btnText: 'text-white', glow: 'shadow-pomo/30', 
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  })();

  const handlePlayAction = () => {
    if (isViewingActive) {
      toggleTimer();
    } else {
      startSession(viewMode);
    }
  };

  const handleAiChat = async () => {
      if (!chatMessage.trim() || !activeTask) return;
      const userMsg = chatMessage;
      setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
      setChatMessage('');
      setIsAiThinking(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `El usuario está tomando estas notas: "${localNote}". Pregunta: "${userMsg}". Ayúdale de forma muy breve.`
          });
          setChatHistory(prev => [...prev, { role: 'model', text: response.text || "No pude procesar la solicitud." }]);
      } catch (e) {
          setChatHistory(prev => [...prev, { role: 'model', text: "Error de conexión con la IA." }]);
      } finally {
          setIsAiThinking(false);
      }
  };

  const saveDocChanges = () => {
    if (activeTask) {
        onUpdateTask(activeTask.id, localNote);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-4 relative">

        {/* Navigation Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
        </div>

        {/* Visualizer Area */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-slate-100 dark:text-slate-800" />
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="6" fill="transparent" pathLength={100} strokeDasharray="100" strokeDashoffset={strokeDashoffset} strokeLinecap="round" className={cn("transition-all duration-1000 ease-linear timer-glow", theme.stroke)} />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
                <span className={cn("font-sans font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: 'clamp(4.5rem, 14vw, 9rem)', transform: `scale(${growthScale})` }}>{formatTime(displayTime)}</span>
                <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">{isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Flowing...' : 'Resting...') : 'Ready'}</span>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-6 relative z-20 mb-8">
            <button onClick={resetTimer} className={cn("w-14 h-14 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95", !isViewingActive && "opacity-0 pointer-events-none")}><RotateCcw className="w-5 h-5" /></button>
            <button 
              onClick={handlePlayAction} 
              disabled={isActive && !isViewingActive} 
              className={cn(
                "w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95", 
                isActive && isViewingActive ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`, 
                isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale"
              )}
            >
                {isActive && isViewingActive ? <Pause className="w-8 h-8" /> : (isActive && !isViewingActive ? <Lock className="w-6 h-6" /> : <Play className="w-8 h-8 ml-1" />)}
            </button>
            <div className="w-14 h-14">
              {viewMode === TimerMode.FOCUS && (
                <button onClick={onGoToInbox} className={cn("w-full h-full rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95 shadow-lg", isViewingActive ? `${theme.btnBg} ${theme.btnText} ${theme.glow} dark:brightness-110` : "bg-slate-900 text-white dark:bg-white dark:text-black")}><InboxIcon className="w-5 h-5" /></button>
              )}
            </div>
        </div>

        {/* Active Task Dock */}
        {activeTask && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[60] w-[90%] max-w-lg">
                <div className="bg-white/80 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-4 flex items-center justify-between animate-in slide-in-from-bottom-8">
                    <div className="flex items-center gap-4 flex-1 min-w-0">
                        <div className="w-10 h-10 bg-blue-500 rounded-xl flex items-center justify-center text-white shrink-0 shadow-lg shadow-blue-500/20"><Target className="w-5 h-5" /></div>
                        <div className="min-w-0">
                            <p className="text-[10px] uppercase font-bold tracking-widest text-slate-400 leading-none mb-1">Misión Activa</p>
                            <p className="text-sm font-bold text-slate-900 dark:text-white truncate">{activeTask.noteContent.split('\n')[0] || 'Tarea en curso'}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 pl-4 border-l border-slate-100 dark:border-slate-800 ml-4">
                        <button onClick={() => setIsDocViewOpen(true)} className="p-2.5 rounded-xl bg-slate-50 text-slate-600 hover:bg-blue-50 hover:text-blue-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-blue-900/20" title="Abrir Notas"><FileText className="w-5 h-5" /></button>
                        <button onClick={onStopTask} className="p-2.5 rounded-xl bg-slate-50 text-slate-400 hover:bg-red-50 hover:text-red-500 transition-all dark:bg-slate-800"><X className="w-5 h-5" /></button>
                    </div>
                </div>
            </div>
        )}

        {/* Editor Modal Simplificado */}
        {isDocViewOpen && activeTask && (
            <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                {/* Backdrop */}
                <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} />

                {/* Mini Timer Preview - SAME VISUAL AS QUICK CAPTURE */}
                <div className="absolute top-12 left-1/2 -translate-x-1/2 bg-white/10 backdrop-blur-md border border-white/20 text-white px-6 py-2 rounded-full flex items-center gap-3 shadow-2xl animate-in fade-in slide-in-from-top-4 duration-500 pointer-events-none z-[80]">
                    <Clock className={cn("w-4 h-4", 
                        activeMode === TimerMode.FOCUS ? "text-pomo-light" : (activeMode === TimerMode.SHORT_BREAK ? "text-emerald-400" : "text-violet-400")
                    )} />
                    <span className="font-mono text-xl font-bold tracking-widest tabular-nums">{formatTime(timeLeft)}</span>
                </div>

                <div className="relative bg-white dark:bg-slate-900 w-full max-w-5xl h-[90vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in-95">

                    <div className="flex-1 flex flex-col overflow-hidden border-r border-slate-100 dark:border-slate-800">
                         {/* Header del Editor */}
                         <div className="flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30">
                            <div className="flex items-center gap-3">
                                <h3 className="text-sm font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2"><Edit3 className="w-4 h-4 text-blue-500" /> Notas de la Tarea</h3>
                            </div>
                            <div className="flex items-center gap-2">
                                <button 
                                  onClick={() => setIsAiChatOpen(!isAiChatOpen)} 
                                  className={cn(
                                    "p-2 rounded-lg transition-all", 
                                    isAiChatOpen ? "bg-violet-100 text-violet-600 dark:bg-violet-900/40" : "text-slate-400 hover:text-violet-500"
                                  )} 
                                  title="Alternar Asistente IA"
                                >
                                    <Bot className="w-5 h-5" />
                                </button>
                                <button onClick={saveDocChanges} className="p-2 text-slate-400 hover:text-green-500 transition-colors" title="Guardar cambios"><Save className="w-5 h-5" /></button>
                                <button onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} className="p-2 text-slate-400 hover:text-slate-600"><X className="w-6 h-6" /></button>
                            </div>
                         </div>

                         {/* Workspace de texto plano */}
                         <div className="flex-1 overflow-hidden relative flex flex-col bg-white dark:bg-slate-900">
                            <textarea 
                                value={localNote}
                                onChange={(e) => setLocalNote(e.target.value)}
                                className="flex-1 w-full p-10 text-lg font-sans leading-relaxed text-slate-700 dark:text-slate-200 bg-transparent resize-none focus:outline-none overflow-y-auto custom-scrollbar"
                                placeholder="Escribe aquí tus ideas, notas o distracciones..."
                                autoFocus
                            />
                         </div>
                    </div>

                    {/* AI Sidebar - Desplegable */}
                    {isAiChatOpen && (
                        <div className="w-full md:w-80 flex flex-col bg-slate-50 dark:bg-slate-950 animate-in slide-in-from-right duration-300 border-l border-slate-200 dark:border-slate-800">
                            <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between font-bold text-slate-700 bg-white dark:bg-slate-900 dark:text-slate-200">
                                <div className="flex items-center gap-2">
                                    <Bot className="w-5 h-5 text-violet-500" />
                                    <span>Asistente IA</span>
                                </div>
                                <button onClick={() => setIsAiChatOpen(false)} className="md:hidden text-slate-400">
                                    <X className="w-4 h-4" />
                                </button>
                            </div>
                            <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                                <div className="text-[10px] text-slate-400 uppercase font-bold tracking-widest text-center mb-4">Contexto: Notas Actuales</div>
                                {chatHistory.map((msg, i) => (
                                    <div key={i} className={cn("text-sm p-3 rounded-xl max-w-[90%] shadow-sm", msg.role === 'user' ? "bg-violet-600 text-white self-end ml-auto" : "bg-white dark:bg-slate-800 dark:text-slate-300 border border-slate-200 dark:border-slate-700")}>
                                        {msg.text}
                                    </div>
                                ))}
                                {isAiThinking && (
                                    <div className="flex gap-1 justify-center p-2">
                                        <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" />
                                        <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" />
                                        <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-300" />
                                    </div>
                                )}
                                <div ref={chatEndRef} />
                            </div>
                            <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                                <div className="relative">
                                    <input 
                                        type="text" 
                                        value={chatMessage} 
                                        onChange={(e) => setChatMessage(e.target.value)} 
                                        onKeyDown={(e) => e.key === 'Enter' && handleAiChat()} 
                                        placeholder="Pregunta algo..." 
                                        className="w-full bg-slate-100 dark:bg-slate-800 rounded-full pl-4 pr-10 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-violet-500/20" 
                                    />
                                    <button onClick={handleAiChat} disabled={!chatMessage.trim() || isAiThinking} className="absolute right-1 top-1 p-1.5 bg-violet-600 text-white rounded-full hover:bg-violet-700 disabled:opacity-50 transition-colors">
                                        <Send className="w-3 h-3" />
                                    </button>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        )}
    </div>
  );
};

export default Timer;

export enum TimerMode {
  FOCUS = 'FOCUS',
  SHORT_BREAK = 'SHORT_BREAK',
  LONG_BREAK = 'LONG_BREAK',
}

export interface Category {
  id: string;
  name: string;
  color: string; // Tailwind class or hex
}

export interface Note {
  id: string;
  content: string;
  createdAt: Date;
}

export interface InboxItem {
  id: string;
  type: 'note' | 'notification'; 
  noteContent: string;
  createdAt: Date;
  deadline: Date;
  status: 'pending' | 'in-progress' | 'completed' | 'scheduled';
  categoryId?: string;
  nextAction?: string;
  scheduledDate?: Date;
  isRead?: boolean;
  timeSpent?: number; // Minutes spent on this task
  reminderSet?: boolean;
}

export interface UserCredits {
  available: number;
  used: number;
}

export interface Settings {
  focusDuration: number; // in minutes
  shortBreakDuration: number;
  longBreakDuration: number;
  longBreakInterval: number;
  language: 'en' | 'es';
}

export interface SessionHistoryItem {
  id: string;
  startTime: Date;
  endTime: Date;
  mode: TimerMode;
  duration: number; // in minutes
  noteSnapshot?: string;
  relatedTaskId?: string;
}

export type View = 'timer' | 'inbox' | 'dashboard' | 'settings' | 'history' | 'categories';

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Timer from './components/Timer';
import Inbox from './components/Inbox';
import Dashboard from './components/Dashboard';
import History from './components/History';
import Categories from './components/Categories';
import QuickCapture from './components/QuickCapture';
import { View, TimerMode, InboxItem, Settings, UserCredits, SessionHistoryItem, Category } from './types';
import { generateId, cn, playSynthSound } from './utils';
import { Moon, Sun, Volume2, VolumeX, Timer as TimerIcon, Menu, X, PenLine, BarChart2, History as HistoryIcon, Tags, Inbox as InboxIcon, ExternalLink, User as UserIcon, CreditCard, Languages, ChevronDown, ChevronUp } from 'lucide-react';

// Mock Data
const INITIAL_SETTINGS: Settings = {
  focusDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  longBreakInterval: 4,
  language: 'es'
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: 'Trabajo', color: 'bg-red-500' },
  { id: 'c2', name: 'Personal', color: 'bg-blue-500' },
  { id: 'c3', name: 'Estudio', color: 'bg-emerald-500' },
];

const INITIAL_INBOX: InboxItem[] = [
  {
    id: 'w1', type: 'note', status: 'pending', categoryId: 'c1',
    noteContent: 'Reporte Financiero Q3\nResumen\nEl análisis muestra un crecimiento del 15% en ingresos recurrentes.',
    createdAt: new Date(), deadline: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000), timeSpent: 0
  },
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('timer');
  const [previousView, setPreviousView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState(''); 
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isQuickCaptureOpen, setIsQuickCaptureOpen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);
  const [isSettingsExpanded, setIsSettingsExpanded] = useState(false);

  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);

  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const t = {
    es: {
      focus: 'Enfoque',
      inbox: 'Inbox',
      categories: 'Categorías',
      stats: 'Estadísticas',
      history: 'Historial',
      settings: 'Configuración',
      quickCapture: 'Captura Rápida',
      lang: 'Idioma',
      sessionDuration: 'Duración de Sesión',
      focusMin: 'Enfoque (min)',
      theme: 'Tema',
      proPlan: 'Plan Pro'
    },
    en: {
      focus: 'Focus',
      inbox: 'Inbox',
      categories: 'Categories',
      stats: 'Statistics',
      history: 'History',
      settings: 'Settings',
      quickCapture: 'Quick Capture',
      lang: 'Language',
      sessionDuration: 'Session Duration',
      focusMin: 'Focus (min)',
      theme: 'Theme',
      proPlan: 'Pro Plan'
    }
  }[settings.language];

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
    if (isSoundEnabled) playSynthSound('theme-change');
  };

  const toggleSound = () => {
    setIsSoundEnabled(prev => {
      const newVal = !prev;
      if (newVal) playSynthSound('toggle');
      return newVal;
    });
  };

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  }, []);

  const sendNotification = (title: string, body: string) => {
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification(title, { body, icon: '/favicon.ico' });
    }
  };

  useEffect(() => {
    if (!isActive) {
      let duration = settings.focusDuration;
      if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
      if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
      setTimeLeft(duration * 60);
    }
  }, [mode, settings.focusDuration, settings.shortBreakDuration, settings.longBreakDuration, isActive]);

  const handleSessionComplete = useCallback((completedMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('complete');

    const duration = completedMode === TimerMode.FOCUS ? settings.focusDuration : 
                     completedMode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000),
        endTime: new Date(),
        mode: completedMode,
        duration: duration,
        noteSnapshot: completedMode === TimerMode.FOCUS ? currentNote : undefined,
        relatedTaskId: activeTaskId || undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    if (activeTaskId && completedMode === TimerMode.FOCUS) {
        setInbox(prev => prev.map(item => {
            if (item.id === activeTaskId) {
                const updatedContent = currentNote.trim() 
                    ? item.noteContent + "\n\n" + `[Sesión ${new Date().toLocaleTimeString()}]: ` + currentNote 
                    : item.noteContent;
                return { ...item, timeSpent: (item.timeSpent || 0) + duration, noteContent: updatedContent };
            }
            return item;
        }));
    } else if (currentNote.trim() && !activeTaskId) {
        saveNoteToInbox(currentNote);
    }
    setCurrentNote('');
  }, [currentNote, settings, activeTaskId, isSoundEnabled]);

  const switchMode = useCallback(() => {
    if (isSoundEnabled) playSynthSound('switch');
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);
      let nextMode = (newCompleted > 0 && newCompleted % settings.longBreakInterval === 0) ? TimerMode.LONG_BREAK : TimerMode.SHORT_BREAK;
      setMode(nextMode);
      sendNotification("¡Hora de un descanso!", `Sesión de enfoque completada.`);
    } else {
      setMode(TimerMode.FOCUS);
      sendNotification("Descanso terminado", "¡A darle con todo!");
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval, isSoundEnabled]);

  useEffect(() => {
    let interval: number | undefined;
    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => {
           if (isSoundEnabled && prev > 1) playSynthSound('tick');
           return prev - 1;
        });
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      setIsActive(false);
      handleSessionComplete(mode);
      switchMode();
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, handleSessionComplete, switchMode, isSoundEnabled]);

  const toggleTimer = () => {
    const nextActive = !isActive;
    if (isSoundEnabled) {
        playSynthSound(nextActive ? 'start' : 'pause');
    }
    setIsActive(nextActive);
  };

  const resetTimer = () => {
    if (isSoundEnabled) playSynthSound('toggle');
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const startSession = (newMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('switch');
    setIsActive(false);
    setMode(newMode);

    let duration = settings.focusDuration;
    if (newMode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (newMode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);

    setTimeout(() => {
        setIsActive(true);
        if (isSoundEnabled) playSynthSound('start');
    }, 10);
  };

  const handleStartTaskFocus = (taskId: string) => {
    setActiveTaskId(taskId);
    setCurrentView('timer');
    startSession(TimerMode.FOCUS);
    setInbox(prev => prev.map(item => item.id === taskId && item.status === 'pending' ? { ...item, status: 'in-progress' } : item));
  };

  const saveNoteToInbox = (content: string, categoryId?: string) => {
      const newItem: InboxItem = {
        id: generateId(),
        type: 'note',
        noteContent: content,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), 
        status: 'pending',
        categoryId: categoryId,
      };
      setInbox(prev => [newItem, ...prev]);
      return newItem.id;
  };

  const handleInboxAction = (id: string, action: string, payload?: any) => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else if (action === 'update') {
      setInbox(prev => prev.map(i => i.id === id ? { ...i, ...payload } : i));
    } else if (action === 'schedule') {
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: 'scheduled', isRead: true } : i));
    }
  };

  const handleUpdateTask = (id: string, content: string) => {
    setInbox(prev => prev.map(item => item.id === id ? { ...item, noteContent: content } : item));
  };

  const handleViewChange = (view: View) => {
    if (view === currentView) return;
    setPreviousView(currentView);
    setCurrentView(view);
    if (isSoundEnabled) playSynthSound('toggle');
    setIsMenuOpen(false);
  };

  const toggleSettings = () => {
    setIsSettingsExpanded(!isSettingsExpanded);
    if (isSoundEnabled) playSynthSound('toggle');
  };

  const activeTask = inbox.find(i => i.id === activeTaskId);
  const badgeCount = inbox.filter(i => i.status === 'pending' && i.type === 'notification' && !i.isRead).length;

  return (
    <div className="flex flex-col min-h-screen bg-white dark:bg-black font-sans transition-colors duration-300 relative overflow-hidden">

      <QuickCapture isOpen={isQuickCaptureOpen} onClose={() => setIsQuickCaptureOpen(false)} categories={categories} onSave={saveNoteToInbox} timeLeft={timeLeft} timerMode={mode} />

      {isMenuOpen && (
        <div className="fixed inset-0 bg-black/20 backdrop-blur-sm z-40 transition-opacity duration-300" onClick={() => setIsMenuOpen(false)} />
      )}

      <main className="flex-1 p-8 overflow-y-auto w-full max-w-7xl mx-auto flex flex-col items-center pb-32">
        <header className="mb-8 w-full flex items-center justify-between relative z-50 px-2">
             {/* Left: Logo */}
             <div className="flex items-center gap-3 cursor-pointer group" onClick={() => handleViewChange('timer')}>
                <div className="w-10 h-10 bg-pomo rounded-xl flex items-center justify-center shadow-lg shadow-pomo/30 flex-shrink-0 text-white transition-transform group-hover:scale-105">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="w-6 h-6">
                        <path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z" />
                        <path d="M12 6v6l4 2" />
                    </svg>
                </div>
                <div>
                    <h1 className="text-xl font-bold tracking-tight text-slate-900 dark:text-white leading-none">
                        Pomo<span className="text-pomo">Deep</span>
                    </h1>
                    <p className="text-[9px] text-slate-400 font-medium tracking-widest uppercase mt-0.5">Focus OS</p>
                </div>
             </div>

             {/* Right: Controls */}
             <div className="flex items-center gap-1.5">
                <div className="relative">
                  <button 
                    onClick={toggleSettings} 
                    className={cn(
                      "p-2.5 rounded-full transition-all active:scale-90",
                      isSettingsExpanded ? "bg-pomo text-white shadow-lg shadow-pomo/30" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800"
                    )}
                    title={t.settings}
                  >
                    <TimerIcon className="w-5 h-5" />
                  </button>

                  {/* Floating Settings Dropdown */}
                  {isSettingsExpanded && (
                    <div className="absolute top-full mt-2 right-0 w-64 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl shadow-2xl p-6 z-[60] animate-in fade-in slide-in-from-top-2">
                      <div className="space-y-6">
                        <div>
                          <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">{t.focusMin}</label>
                          <input 
                            type="range" min="15" max="60" 
                            value={settings.focusDuration} 
                            onChange={(e) => setSettings({...settings, focusDuration: parseInt(e.target.value)})} 
                            className="w-full accent-pomo" 
                          />
                          <div className="flex justify-between text-xs font-bold text-pomo mt-1"><span>15m</span><span>{settings.focusDuration}m</span><span>60m</span></div>
                        </div>
                        <div className="pt-4 border-t border-slate-50 dark:border-slate-800">
                          <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-3">{t.lang}</label>
                          <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                            <button 
                              onClick={() => setSettings({...settings, language: 'en'})} 
                              className={cn("flex-1 py-1.5 rounded-lg text-xs font-bold transition-all", settings.language === 'en' ? "bg-white shadow dark:bg-slate-700 dark:text-white" : "text-slate-400")}
                            >EN</button>
                            <button 
                              onClick={() => setSettings({...settings, language: 'es'})} 
                              className={cn("flex-1 py-1.5 rounded-lg text-xs font-bold transition-all", settings.language === 'es' ? "bg-white shadow dark:bg-slate-700 dark:text-white" : "text-slate-400")}
                            >ES</button>
                          </div>
                        </div>
                      </div>
                    </div>
                  )}
                </div>

                <button 
                  onClick={toggleSound} 
                  className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" 
                  title={isSoundEnabled ? "Mute" : "Unmute"}
                >
                  {isSoundEnabled ? <Volume2 className="w-5 h-5" /> : < VolumeX className="w-5 h-5" />}
                </button>
                <button 
                  onClick={toggleDarkMode} 
                  className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90" 
                  title={t.theme}
                >
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>

                <div className="relative">
                  <button 
                    onClick={() => setIsMenuOpen(!isMenuOpen)} 
                    className={cn(
                      "p-2.5 rounded-full transition-all active:scale-90 relative",
                      isMenuOpen ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800"
                    )}
                    title="Menu"
                  >
                    {isMenuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
                    {badgeCount > 0 && !isMenuOpen && (
                      <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-pomo border-2 border-white dark:border-black rounded-full" />
                    )}
                  </button>

                  {/* Dropdown Menu */}
                  {isMenuOpen && (
                    <div className="absolute right-0 mt-3 w-64 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl shadow-2xl p-4 animate-in fade-in zoom-in-95 duration-200">
                        {/* User Profile in Menu */}
                        <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800 rounded-xl mb-4">
                            <div className="w-10 h-10 rounded-full bg-slate-200 dark:bg-slate-700 overflow-hidden ring-2 ring-white dark:ring-slate-900">
                                <img src="https://picsum.photos/100/100" alt="User" className="w-full h-full object-cover" />
                            </div>
                            <div className="flex flex-col leading-tight">
                                <p className="text-sm font-bold text-slate-900 dark:text-white">Alex Designer</p>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{t.proPlan}</p>
                            </div>
                        </div>

                        <button 
                          onClick={() => { setIsQuickCaptureOpen(true); setIsMenuOpen(false); }}
                          className="w-full bg-slate-900 hover:bg-slate-800 text-white p-3 rounded-xl flex items-center justify-center gap-2 transition-all mb-4 dark:bg-white dark:text-black dark:hover:bg-slate-200 font-bold text-sm"
                        >
                          <PenLine className="w-4 h-4" /> {t.quickCapture}
                        </button>

                        <nav className="space-y-1">
                          {[
                            { id: 'timer', icon: TimerIcon, label: t.focus },
                            { id: 'inbox', icon: InboxIcon, label: t.inbox, badge: badgeCount },
                            { id: 'categories', icon: Tags, label: t.categories },
                            { id: 'dashboard', icon: BarChart2, label: t.stats },
                            { id: 'history', icon: HistoryIcon, label: t.history },
                          ].map((item) => (
                            <button
                              key={item.id}
                              onClick={() => handleViewChange(item.id as View)}
                              className={cn(
                                "w-full flex items-center justify-between px-4 py-3 rounded-xl transition-colors font-medium text-sm",
                                currentView === item.id 
                                  ? "bg-pomo/5 text-pomo dark:bg-pomo/10" 
                                  : "text-slate-500 hover:bg-slate-50 dark:text-slate-400 dark:hover:bg-slate-800"
                              )}
                            >
                              <div className="flex items-center gap-3">
                                <item.icon className="w-4 h-4" />
                                {item.label}
                              </div>
                              {item.badge ? (
                                <span className="bg-pomo text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full">{item.badge}</span>
                              ) : null}
                            </button>
                          ))}
                        </nav>
                    </div>
                  )}
                </div>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 w-full flex-1">
            {currentView === 'timer' && (
            <Timer 
              settings={settings} 
              activeMode={mode} 
              startSession={startSession} 
              timeLeft={timeLeft} 
              isActive={isActive} 
              toggleTimer={toggleTimer} 
              resetTimer={resetTimer} 
              sessionsCompleted={sessionsCompleted} 
              currentNote={currentNote} 
              onNoteChange={setCurrentNote} 
              categories={categories} 
              onSaveNote={saveNoteToInbox} 
              activeTask={activeTask} 
              onStopTask={() => setActiveTaskId(null)}
              onGoToInbox={() => handleViewChange('inbox')}
              onUpdateTask={handleUpdateTask}
            />
            )}
            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} categories={categories} onStartSession={handleStartTaskFocus} onManageCategories={() => setCurrentView('categories')} onSaveNote={saveNoteToInbox} />
            )}
            {currentView === 'categories' && (
            <Categories categories={categories} onAdd={(c) => setCategories(prev => [...prev, c])} onDelete={(id) => setCategories(prev => prev.filter(c => c.id !== id))} inboxItems={inbox} />
            )}
            {currentView === 'dashboard' && <Dashboard credits={credits} onExport={() => {}} />}
            {currentView === 'history' && <History history={history} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, RotateCcw, Zap, Coffee, Lock, X, Target, FileText, 
  Bot, Send, Save, Edit3, Inbox as InboxIcon, MessageSquare, Clock
} from 'lucide-react';
import { TimerMode, Settings, Category, InboxItem } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode;
  startSession: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem;
  onStopTask?: () => void;
  onGoToInbox: () => void;
  onUpdateTask: (id: string, content: string) => void;
}

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  onNoteChange, 
  currentNote, 
  categories, 
  onSaveNote,
  activeTask,
  onStopTask,
  onGoToInbox,
  onUpdateTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);
  const [isAiChatOpen, setIsAiChatOpen] = useState(false);

  // Estado local para el contenido de texto plano
  const [localNote, setLocalNote] = useState('');

  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  // Carga el contenido inicial al abrir el modal o cambiar de tarea
  useEffect(() => {
    if (activeTask && isDocViewOpen) {
        setLocalNote(activeTask.noteContent || '');
    }
  }, [activeTask, isDocViewOpen]);

  useEffect(() => {
      if (isAiChatOpen) {
          chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
      }
  }, [chatHistory, isAiChatOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
      switch(m) {
          case TimerMode.FOCUS: return settings.focusDuration;
          case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
          case TimerMode.LONG_BREAK: return settings.longBreakDuration;
          default: return 25;
      }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const totalTime = displayDuration * 60;
  const progressRatio = isViewingActive ? displayTime / totalTime : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const theme = (() => {
    switch(viewMode) {
      case TimerMode.SHORT_BREAK:
        return { 
          primary: 'text-emerald-600', stroke: 'text-emerald-400', btnBg: 'bg-emerald-600', 
          btnText: 'text-white', glow: 'shadow-emerald-600/30', 
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return { 
          primary: 'text-violet-600', stroke: 'text-violet-400', btnBg: 'bg-violet-600', 
          btnText: 'text-white', glow: 'shadow-violet-600/30', 
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default:
        return { 
          primary: 'text-pomo', stroke: 'text-pomo-light', btnBg: 'bg-pomo', 
          btnText: 'text-white', glow: 'shadow-pomo/30', 
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  })();

  const handlePlayAction = () => {
    if (isViewingActive) {
      toggleTimer();
    } else {
      startSession(viewMode);
    }
  };

  const handleAiChat = async () => {
      if (!chatMessage.trim() || !activeTask) return;
      const userMsg = chatMessage;
      setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
      setChatMessage('');
      setIsAiThinking(true);
      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `El usuario está tomando estas notas: "${localNote}". Pregunta: "${userMsg}". Ayúdale de forma muy breve.`
          });
          setChatHistory(prev => [...prev, { role: 'model', text: response.text || "No pude procesar la solicitud." }]);
      } catch (e) {
          setChatHistory(prev => [...prev, { role: 'model', text: "Error de conexión con la IA." }]);
      } finally {
          setIsAiThinking(false);
      }
  };

  const saveDocChanges = () => {
    if (activeTask) {
        onUpdateTask(activeTask.id, localNote);
    }
  };

  const taskTitle = activeTask?.noteContent?.split('\n')[0] || (settings.language === 'es' ? 'Notas de la Tarea' : 'Task Notes');

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-4 relative">

        {/* Navigation Tabs */}
        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
        </div>

        {/* Visualizer Area */}
        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-slate-100 dark:text-slate-800" />
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="6" fill="transparent" pathLength={100} strokeDasharray="100" strokeDashoffset={strokeDashoffset} strokeLinecap="round" className={cn("transition-all duration-1000 ease-linear timer-glow", theme.stroke)} />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
                <span className={cn("font-sans font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: 'clamp(4.5rem, 14vw, 9rem)', transform: `scale(${growthScale})` }}>{formatTime(displayTime)}</span>
                <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">{isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Flowing...' : 'Resting...') : 'Ready'}</span>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-6 relative z-20 mb-8">
            <button onClick={resetTimer} className={cn("w-14 h-14 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95", !isViewingActive && "opacity-0 pointer-events-none")}><RotateCcw className="w-5 h-5" /></button>
            <button 
              onClick={handlePlayAction} 
              disabled={isActive && !isViewingActive} 
              className={cn(
                "w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95", 
                isActive && isViewingActive ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`, 
                isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale"
              )}
            >
                {isActive && isViewingActive ? <Pause className="w-8 h-8" /> : (isActive && !isViewingActive ? <Lock className="w-6 h-6" /> : <Play className="w-8 h-8 ml-1" />)}
            </button>
            <div className="w-14 h-14">
              {viewMode === TimerMode.FOCUS && (
                <button onClick={onGoToInbox} className={cn("w-full h-full rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95 shadow-lg", isViewingActive ? `${theme.btnBg} ${theme.btnText} ${theme.glow} dark:brightness-110` : "bg-slate-900 text-white dark:bg-white dark:text-black")}><InboxIcon className="w-5 h-5" /></button>
              )}
            </div>
        </div>

        {/* Active Task Dock */}
        {activeTask && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[60] w-[90%] max-w-lg">
                <div className="bg-white/80 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-4 flex items-center justify-between animate-in slide-in-from-bottom-8">
                    <div className="flex items-center gap-4 flex-1 min-w-0">
                        <div className="w-10 h-10 bg-blue-500 rounded-xl flex items-center justify-center text-white shrink-0 shadow-lg shadow-blue-500/20"><Target className="w-5 h-5" /></div>
                        <div className="min-w-0">
