import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export const formatTime = (seconds: number): string => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
};

export const calculateDaysRemaining = (deadline: Date): number => {
  const now = new Date();
  const diffTime = deadline.getTime() - now.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  return diffDays;
};

export const generateId = () => Math.random().toString(36).substr(2, 9);

// Synthesized Sound Engine
let audioCtx: AudioContext | null = null;

export const playSynthSound = (type: 'toggle' | 'switch' | 'complete' | 'tick' | 'theme-change' | 'start' | 'pause') => {
  try {
    if (!audioCtx) {
      const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
      if (AudioContextClass && typeof AudioContextClass === 'function') {
        audioCtx = new AudioContextClass();
      }
    }

    if (!audioCtx || audioCtx.state === 'closed') return;

    // Resume if suspended (common browser policy)
    if (audioCtx.state === 'suspended') {
      audioCtx.resume();
    }

    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();

    osc.connect(gain);
    gain.connect(audioCtx.destination);

    const now = audioCtx.currentTime;

    switch (type) {
      case 'start':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(440, now);
        osc.frequency.exponentialRampToValueAtTime(880, now + 0.15);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.15);
        osc.start(now);
        osc.stop(now + 0.15);
        break;
      case 'pause':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, now);
        osc.frequency.exponentialRampToValueAtTime(440, now + 0.15);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.15);
        osc.start(now);
        osc.stop(now + 0.15);
        break;
      case 'tick':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(2000, now);
        gain.gain.setValueAtTime(0.02, now);
        gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.02);
        osc.start(now);
        osc.stop(now + 0.02);
        break;
      case 'theme-change':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(220, now);
        osc.frequency.exponentialRampToValueAtTime(110, now + 0.3);
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.3);
        osc.start(now);
        osc.stop(now + 0.3);
        break;
      case 'toggle':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(1200, now);
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.05);
        osc.start(now);
        osc.stop(now + 0.05);
        break;
      case 'switch':
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(440, now);
        osc.frequency.exponentialRampToValueAtTime(660, now + 0.2);
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
        osc.start(now);
        osc.stop(now + 0.2);
        break;
      case 'complete':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(523.25, now); 
        osc.frequency.setValueAtTime(659.25, now + 0.15); 
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.4);
        osc.start(now);
        osc.stop(now + 0.4);
        break;
    }
  } catch (e) {
    console.warn("Audio playback failed:", e);
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Pause, RotateCcw, Target, FileText, 
  Bot, Send, Save, Edit3, Inbox as InboxIcon, Clock, X, Check, Share2, Mail, Layout, Copy, Download
} from 'lucide-react';
import { TimerMode, Settings, Category, InboxItem } from '../types';
import { formatTime, cn } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface TimerProps {
  settings: Settings;
  activeMode: TimerMode;
  startSession: (mode: TimerMode) => void;
  timeLeft: number;
  isActive: boolean;
  toggleTimer: () => void;
  resetTimer: () => void;
  sessionsCompleted: number;
  onNoteChange: (note: string) => void;
  currentNote: string;
  categories: Category[];
  onSaveNote: (content: string, categoryId?: string) => void;
  activeTask?: InboxItem;
  onStopTask?: () => void;
  onGoToInbox: () => void;
  onUpdateTask: (id: string, content: string, title?: string) => void;
}

interface NextAction {
  id: string;
  text: string;
  completed: boolean;
}

const NEXT_ACTION_TEMPLATES: Record<string, string[]> = {
  'Trabajo': [
    'Revisar correos prioritarios',
    'Definir los 3 objetivos principales del bloque',
    'Preparar materiales para la siguiente reunión'
  ],
  'Personal': [
    'Organizar el entorno físico de trabajo',
    'Planificar hidratación y descansos activos',
    'Anotar 1 distracción recurrente para evitarla'
  ],
  'Estudio': [
    'Revisar conceptos clave de la sesión anterior',
    'Esquematizar el tema principal a tratar',
    'Realizar un ejercicio práctico de aplicación'
  ],
  'Default': [
    'Definir el resultado esperado de esta sesión',
    'Listar recursos necesarios',
    'Eliminar notificaciones del móvil'
  ]
};

const Timer: React.FC<TimerProps> = ({ 
  settings, 
  activeMode, 
  startSession, 
  timeLeft, 
  isActive, 
  toggleTimer, 
  resetTimer, 
  sessionsCompleted, 
  categories, 
  activeTask,
  onStopTask,
  onGoToInbox,
  onUpdateTask
}) => {

  const [viewMode, setViewMode] = useState<TimerMode>(activeMode);
  const [isDocViewOpen, setIsDocViewOpen] = useState(false);
  const [isAiChatOpen, setIsAiChatOpen] = useState(false);
  const [isExportMenuOpen, setIsExportMenuOpen] = useState(false);
  const [exportFeedback, setExportFeedback] = useState<string | null>(null);

  // State for interactive editor
  const [taskTitle, setTaskTitle] = useState('');
  const [nextActions, setNextActions] = useState<NextAction[]>([]);
  const [generalNotes, setGeneralNotes] = useState('');

  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setViewMode(activeMode);
  }, [activeMode]);

  const getCategoryName = (id?: string) => {
    return categories.find(c => c.id === id)?.name || 'Default';
  };

  const parseContent = (content: string, task: InboxItem) => {
    const lines = content.split('\n');
    const actions: NextAction[] = [];
    let notesLines: string[] = [];
    let isParsingNotes = false;

    const headerText = settings.language === 'es' ? 'Acción Siguiente' : 'Next Action';

    setTaskTitle(task.title || '');

    if (!content.trim() || !content.includes(headerText)) {
      const placeholders = [
        { id: Math.random().toString(36).substr(2, 9), text: '', completed: false },
        { id: Math.random().toString(36).substr(2, 9), text: '', completed: false },
        { id: Math.random().toString(36).substr(2, 9), text: '', completed: false }
      ];
      setNextActions(placeholders);
      setGeneralNotes(content);
      return;
    }

    lines.forEach(line => {
      if (line.trim() === '---') {
        isParsingNotes = true;
        return;
      }
      if (isParsingNotes) {
        notesLines.push(line);
      } else {
        const match = line.match(/^\[( |x)\] (.*)/);
        if (match) {
          actions.push({
            id: Math.random().toString(36).substr(2, 9),
            completed: match[1] === 'x',
            text: match[2]
          });
        }
      }
    });

    setNextActions(actions.length > 0 ? actions : [
      { id: Math.random().toString(36).substr(2, 9), text: '', completed: false }
    ]);
    setGeneralNotes(notesLines.join('\n').trim());
  };

  const stringifyContent = () => {
    const headerText = settings.language === 'es' ? 'Acción Siguiente' : 'Next Action';
    const actionsStr = nextActions.map(a => `[${a.completed ? 'x' : ' '}] ${a.text}`).join('\n');
    return `${headerText}\n${actionsStr}\n\n---\n\n${generalNotes}`;
  };

  useEffect(() => {
    if (activeTask && isDocViewOpen) {
      parseContent(activeTask.noteContent, activeTask);
    }
  }, [activeTask, isDocViewOpen]);

  useEffect(() => {
    if (isAiChatOpen) {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatHistory, isAiChatOpen]);

  const isViewingActive = viewMode === activeMode;

  const getDurationForMode = (m: TimerMode) => {
    switch(m) {
      case TimerMode.FOCUS: return settings.focusDuration;
      case TimerMode.SHORT_BREAK: return settings.shortBreakDuration;
      case TimerMode.LONG_BREAK: return settings.longBreakDuration;
      default: return 25;
    }
  };

  const displayDuration = getDurationForMode(viewMode);
  const displayTime = isViewingActive ? timeLeft : displayDuration * 60;
  const progressRatio = isViewingActive ? displayTime / (displayDuration * 60) : 1; 
  const strokeDashoffset = 100 - (progressRatio * 100);
  const growthScale = isActive && isViewingActive && viewMode === TimerMode.FOCUS ? 1.05 : 1;

  const theme = (() => {
    switch(viewMode) {
      case TimerMode.SHORT_BREAK:
        return { 
          primary: 'text-emerald-600', stroke: 'text-emerald-400', btnBg: 'bg-emerald-600', 
          btnText: 'text-white', glow: 'shadow-emerald-600/30', 
          pillActive: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200'
        };
      case TimerMode.LONG_BREAK:
        return { 
          primary: 'text-violet-600', stroke: 'text-violet-400', btnBg: 'bg-violet-600', 
          btnText: 'text-white', glow: 'shadow-violet-600/30', 
          pillActive: 'bg-violet-100 text-violet-800 dark:bg-violet-900/40 dark:text-violet-200'
        };
      default:
        return { 
          primary: 'text-pomo', stroke: 'text-pomo-light', btnBg: 'bg-pomo', 
          btnText: 'text-white', glow: 'shadow-pomo/30', 
          pillActive: 'bg-red-100 text-pomo-dark dark:bg-red-900/40 dark:text-red-200'
        };
    }
  })();

  const handlePlayAction = () => {
    if (isViewingActive) toggleTimer();
    else startSession(viewMode);
  };

  const handleAiChat = async () => {
    if (!chatMessage.trim() || !activeTask) return;
    const userMsg = chatMessage;
    setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatMessage('');
    setIsAiThinking(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const fullText = stringifyContent();
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `El usuario está tomando estas notas: "${fullText}". Pregunta: "${userMsg}". Ayúdale de forma muy breve.`
      });
      setChatHistory(prev => [...prev, { role: 'model', text: response.text || "No pude procesar la solicitud." }]);
    } catch (e) {
      setChatHistory(prev => [...prev, { role: 'model', text: "Error de conexión con la IA." }]);
    } finally {
      setIsAiThinking(false);
    }
  };

  const saveDocChanges = () => {
    if (activeTask) {
      onUpdateTask(activeTask.id, stringifyContent(), taskTitle);
    }
  };

  const toggleAction = (id: string) => {
    setNextActions(prev => prev.map(a => a.id === id ? { ...a, completed: !a.completed } : a));
  };

  const updateActionText = (id: string, text: string) => {
    setNextActions(prev => prev.map(a => a.id === id ? { ...a, text } : a));
  };

  const handleActionKeyDown = (e: React.KeyboardEvent, index: number) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      const newAction: NextAction = { id: Math.random().toString(36).substr(2, 9), text: '', completed: false };
      const updated = [...nextActions];
      updated.splice(index + 1, 0, newAction);
      setNextActions(updated);
      setTimeout(() => {
        const nextInput = document.getElementById(`action-input-${newAction.id}`);
        nextInput?.focus();
      }, 0);
    } else if (e.key === 'Backspace' && nextActions[index].text === '' && nextActions.length > 1) {
      e.preventDefault();
      const updated = [...nextActions];
      updated.splice(index, 1);
      setNextActions(updated);
      const prevIndex = index > 0 ? index - 1 : 0;
      setTimeout(() => {
        const prevInput = document.getElementById(`action-input-${nextActions[prevIndex]?.id}`);
        prevInput?.focus();
      }, 0);
    }
  };

  const exportToNotion = () => {
    const md = `# ${taskTitle}\n\n## Next Actions\n${nextActions.map(a => `- [${a.completed ? 'x' : ' '}] ${a.text}`).join('\n')}\n\n## Notes\n${generalNotes}`;
    navigator.clipboard.writeText(md);
    setExportFeedback("Copied for Notion!");
    setIsExportMenuOpen(false);
    setTimeout(() => setExportFeedback(null), 3000);
  };

  const exportToMail = () => {
    const body = `Next Actions:\n${nextActions.map(a => `- [${a.completed ? 'x' : ' '}] ${a.text}`).join('\n')}\n\nNotes:\n${generalNotes}`;
    window.location.href = `mailto:?subject=${encodeURIComponent(taskTitle)}&body=${encodeURIComponent(body)}`;
    setIsExportMenuOpen(false);
  };

  const exportToSheets = () => {
    const csvContent = "data:text/csv;charset=utf-8," 
      + "Task,Status,Content\n"
      + `"${taskTitle}","Title","${taskTitle}"\n`
      + nextActions.map(a => `"${taskTitle}","Action: ${a.completed ? 'Done' : 'Pending'}","${a.text}"`).join('\n')
      + `\n"${taskTitle}","General Notes","${generalNotes.replace(/"/g, '""')}"`;

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${taskTitle.replace(/\s+/g, '_')}_focus.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setIsExportMenuOpen(false);
  };

  return (
    <div className="flex flex-col items-center justify-center h-full max-w-4xl mx-auto py-4 relative">

        {exportFeedback && (
            <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 animate-in fade-in slide-in-from-top-4 font-bold text-sm">
                <Check className="w-4 h-4 text-emerald-400" />
                {exportFeedback}
            </div>
        )}

        <div className="flex bg-white p-1 rounded-full shadow-sm border border-slate-200 dark:bg-slate-800 dark:border-slate-700 relative z-20 mb-12">
            <button onClick={() => setViewMode(TimerMode.FOCUS)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.FOCUS ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Deep Focus</button>
            <button onClick={() => setViewMode(TimerMode.SHORT_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.SHORT_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Short Break</button>
            <button onClick={() => setViewMode(TimerMode.LONG_BREAK)} className={cn("px-6 py-2 rounded-full text-sm font-medium transition-all", viewMode === TimerMode.LONG_BREAK ? theme.pillActive : "text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200")}>Long Break</button>
        </div>

        <div className="relative w-full max-w-[450px] aspect-square flex items-center justify-center mb-12">
            <svg className="absolute inset-0 w-full h-full transform -rotate-90 pointer-events-none overflow-visible">
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-slate-100 dark:text-slate-800" />
                <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="6" fill="transparent" pathLength={100} strokeDasharray="100" strokeDashoffset={strokeDashoffset} strokeLinecap="round" className={cn("transition-all duration-1000 ease-linear timer-glow", theme.stroke)} />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center z-10 pointer-events-none">
                <span className={cn("font-sans font-bold tracking-tighter tabular-nums leading-none transition-transform duration-1000 ease-in-out select-none", theme.primary)} style={{ fontSize: 'clamp(4.5rem, 14vw, 9rem)', transform: `scale(${growthScale})` }}>{formatTime(displayTime)}</span>
                <span className="text-slate-400 mt-2 font-medium uppercase tracking-[0.2em] text-[10px] dark:text-slate-500 opacity-60">{isActive && isViewingActive ? (viewMode === TimerMode.FOCUS ? 'Flowing...' : 'Resting...') : 'Ready'}</span>
            </div>
        </div>

        <div className="flex items-center gap-6 relative z-20 mb-8">
            <button onClick={resetTimer} className={cn("w-14 h-14 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 hover:text-slate-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-slate-700 hover:scale-105 active:scale-95", !isViewingActive && "opacity-0 pointer-events-none")}><RotateCcw className="w-5 h-5" /></button>
            <button 
              onClick={handlePlayAction} 
              disabled={isActive && !isViewingActive} 
              className={cn(
                "w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 active:scale-95", 
                isActive && isViewingActive ? "bg-slate-50 text-slate-600 dark:bg-slate-800 dark:text-slate-300" : `${theme.btnBg} ${theme.btnText} shadow-xl ${theme.glow}`, 
                isActive && !isViewingActive && "opacity-50 cursor-not-allowed grayscale"
              )}
            >
                {isActive && isViewingActive ? <Pause className="w-8 h-8" /> : (isActive && !isViewingActive ? <Lock className="w-6 h-6" /> : <Play className="w-8 h-8 ml-1" />)}
            </button>
            <div className="w-14 h-14">
              {viewMode === TimerMode.FOCUS && (
                <button onClick={onGoToInbox} className={cn("w-full h-full rounded-full flex items-center justify-center transition-all hover:scale-105 active:scale-95 shadow-lg", isViewingActive ? `${theme.btnBg} ${theme.btnText} ${theme.glow} dark:brightness-110` : "bg-slate-900 text-white dark:bg-white dark:text-black")}><InboxIcon className="w-5 h-5" /></button>
              )}
            </div>
        </div>

        {activeTask && (
            <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[60] w-[90%] max-w-lg">
                <div className="bg-white/80 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl p-4 flex items-center justify-between animate-in slide-in-from-bottom-8">
                    <div className="flex items-center gap-4 flex-1 min-w-0">
                        <div className="w-10 h-10 bg-blue-500 rounded-xl flex items-center justify-center text-white shrink-0 shadow-lg shadow-blue-500/20"><Target className="w-5 h-5" /></div>
                        <div className="min-w-0">
                            <p className="text-[10px] uppercase font-bold tracking-widest text-slate-400 leading-none mb-1">{settings.language === 'es' ? 'Misión Activa' : 'Active Mission'}</p>
                            <p className="text-sm font-bold text-slate-900 dark:text-white truncate">{taskTitle || 'Tarea en curso'}</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 pl-4 border-l border-slate-100 dark:border-slate-800 ml-4">
                        <button onClick={() => setIsDocViewOpen(true)} className="p-2.5 rounded-xl bg-slate-50 text-slate-600 hover:bg-blue-50 hover:text-blue-600 transition-all dark:bg-slate-800 dark:text-slate-400 dark:hover:bg-blue-900/20" title="Abrir Notas"><FileText className="w-5 h-5" /></button>
                        <button onClick={onStopTask} className="p-2.5 rounded-xl bg-slate-50 text-slate-400 hover:bg-red-50 hover:text-red-500 transition-all dark:bg-slate-800"><X className="w-5 h-5" /></button>
                    </div>
                </div>
            </div>
        )}

        {isDocViewOpen && activeTask && (
            <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} />

                <div className="absolute top-12 left-1/2 -translate-x-1/2 bg-slate-900 dark:bg-slate-800 backdrop-blur-md border border-white/20 text-white px-6 py-2 rounded-full flex items-center gap-3 shadow-2xl animate-in fade-in slide-in-from-top-4 duration-500 pointer-events-none z-[80]">
                    <Clock className={cn("w-4 h-4", 
                        activeMode === TimerMode.FOCUS ? "text-pomo-light" : (activeMode === TimerMode.SHORT_BREAK ? "text-emerald-400" : "text-violet-400")
                    )} />
                    <span className="font-mono text-xl font-bold tracking-widest tabular-nums">{formatTime(timeLeft)}</span>
                </div>

                <div className="relative bg-white dark:bg-slate-900 w-full max-w-5xl h-[90vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in fade-in zoom-in-95">
                    <div className="flex-1 flex flex-col overflow-hidden border-r border-slate-100 dark:border-slate-800">
                         <div className="flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/30">
                            <div className="flex items-center gap-3 overflow-hidden flex-1">
                                <Target className="w-4 h-4 text-pomo shrink-0" /> 
                                <input 
                                  value={taskTitle} 
                                  onChange={(e) => setTaskTitle(e.target.value)}
                                  placeholder={settings.language === 'es' ? "Título de la Tarea" : "Task Title"}
                                  className="text-sm font-bold text-slate-700 dark:text-slate-300 bg-transparent border-none outline-none focus:ring-0 w-full"
                                />
                            </div>
                            <div className="flex items-center gap-2 shrink-0">
                                <div className="relative">
                                    <button 
                                      onClick={() => setIsExportMenuOpen(!isExportMenuOpen)} 
                                      className={cn("p-2 rounded-lg transition-all", isExportMenuOpen ? "bg-slate-100 dark:bg-slate-800" : "text-slate-400 hover:text-slate-600")}
                                      title="Export / Share"
                                    >
                                        <Share2 className="w-5 h-5" />
                                    </button>
                                    {isExportMenuOpen && (
                                        <div className="absolute right-0 top-full mt-2 w-48 bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-xl shadow-2xl z-[100] animate-in fade-in slide-in-from-top-2">
                                            <div className="p-2 space-y-1">
                                                <button onClick={exportToNotion} className="w-full flex items-center gap-3 px-3 py-2 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 rounded-lg transition-colors">
                                                    <Copy className="w-4 h-4 text-black dark:text-white" /> Notion (Clipboard)
                                                </button>
                                                <button onClick={exportToMail} className="w-full flex items-center gap-3 px-3 py-2 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 rounded-lg transition-colors">
                                                    <Mail className="w-4 h-4 text-blue-500" /> Email
                                                </button>
                                                <button onClick={exportToSheets} className="w-full flex items-center gap-3 px-3 py-2 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 rounded-lg transition-colors">
                                                    <Layout className="w-4 h-4 text-emerald-500" /> Google Sheets (CSV)
                                                </button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                                <button onClick={() => setIsAiChatOpen(!isAiChatOpen)} className={cn("p-2 rounded-lg transition-all", isAiChatOpen ? "bg-violet-100 text-violet-600 dark:bg-violet-900/40" : "text-slate-400 hover:text-violet-500")}>
                                    <Bot className="w-5 h-5" />
                                </button>
                                <button onClick={saveDocChanges} className="p-2 text-slate-400 hover:text-green-500 transition-colors">
                                  <Save className="w-5 h-5" />
                                </button>
                                <button onClick={() => { saveDocChanges(); setIsDocViewOpen(false); }} className="p-2 text-slate-400 hover:text-slate-600"><X className="w-6 h-6" /></button>
                            </div>
                         </div>

                         <div className="flex-1 overflow-y-auto p-10 bg-white dark:bg-slate-900 custom-scrollbar">
                            <div className="max-w-3xl mx-auto space-y-10">
                                <section>
                                    <div className="flex items-center gap-2 mb-6">
                                        <Clock className="w-4 h-4 text-slate-400" />
                                        <h4 className="text-[10px] uppercase font-black text-slate-400 tracking-[0.2em]">{settings.language === 'es' ? 'Acción Siguiente' : 'Next Action'}</h4>
                                    </div>
                                    <div className="space-y-3">
                                        {nextActions.map((action, index) => (
                                            <div key={action.id} className="group flex items-center gap-4">
                                                <button 
                                                    onClick={() => toggleAction(action.id)}
                                                    className={cn(
                                                        "w-6 h-6 rounded-md flex items-center justify-center transition-all border-2",
                                                        action.completed 
                                                            ? "bg-emerald-500 border-emerald-500 text-white" 
                                                            : "border-slate-200 dark:border-slate-700 group-hover:border-slate-300 dark:group-hover:border-slate-600"
                                                    )}
                                                >
                                                    {action.completed ? <Check className="w-4 h-4" /> : null}
                                                </button>
                                                <input 
                                                    id={`action-input-${action.id}`}
                                                    type="text"
                                                    value={action.text}
                                                    onChange={(e) => updateActionText(action.id, e.target.value)}
                                                    onKeyDown={(e) => handleActionKeyDown(e, index)}
                                                    placeholder="..."
                                                    className={cn(
                                                        "flex-1 bg-transparent border-none outline-none text-lg font-medium transition-all placeholder:text-slate-200 dark:placeholder:text-slate-800",
                                                        action.completed ? "text-slate-300 line-through dark:text-slate-600" : "text-slate-700 dark:text-slate-200"
                                                    )}
                                                />
                                            </div>
                                        ))}
                                    </div>
                                </section>

                                <div className="h-px bg-slate-100 dark:bg-slate-800 w-full" />

                                <section className="flex-1 flex flex-col min-h-[400px]">
                                    <div className="flex items-center gap-2 mb-6">
                                        <FileText className="w-4 h-4 text-slate-400" />
                                        <h4 className="text-[10px] uppercase font-black text-slate-400 tracking-[0.2em]">{settings.language === 'es' ? 'Notas Generales' : 'General Notes'}</h4>
                                    </div>
                                    <textarea 
                                        value={generalNotes}
                                        onChange={(e) => setGeneralNotes(e.target.value)}
                                        className="w-full flex-1 bg-transparent text-lg font-sans leading-relaxed text-slate-700 dark:text-slate-200 resize-none focus:outline-none min-h-[300px]"
                                        placeholder={settings.language === 'es' ? "Ideas, reflexiones, distracciones..." : "Thoughts, reflections, distractions..."}
                                    />
                                </section>
                            </div>
                         </div>
                    </div>

                    {isAiChatOpen && (
                        <div className="w-full md:w-80 flex flex-col bg-slate-50 dark:bg-slate-950 animate-in slide-in-from-right duration-300 border-l border-slate-200 dark:border-slate-800">
                            <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between font-bold text-slate-700 bg-white dark:bg-slate-900 dark:text-slate-200">
                                <div className="flex items-center gap-2">
                                    <Bot className="w-5 h-5 text-violet-500" />
                                    <span>{settings.language === 'es' ? 'Asistente IA' : 'AI Assistant'}</span>
                                </div>
                                <button onClick={() => setIsAiChatOpen(false)} className="md:hidden text-slate-400"><X className="w-4 h-4" /></button>
                            </div>
                            <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
                                {chatHistory.map((msg, i) => (
                                    <div key={i} className={cn("text-sm p-3 rounded-xl max-w-[90%] shadow-sm", msg.role === 'user' ? "bg-violet-600 text-white self-end ml-auto" : "bg-white dark:bg-slate-800 dark:text-slate-300 border border-slate-200 dark:border-slate-700")}>
                                        {msg.text}
                                    </div>
                                ))}
                                {isAiThinking && <div className="flex gap-1 justify-center p-2"><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-150" /><span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-300" /></div>}
                                <div ref={chatEndRef} />
                            </div>
                            <div className="p-3 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800">
                                <div className="relative">
                                    <input type="text" value={chatMessage} onChange={(e) => setChatMessage(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAiChat()} placeholder="..." className="w-full bg-slate-100 dark:bg-slate-800 rounded-full pl-4 pr-10 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-violet-500/20" />
                                    <button onClick={handleAiChat} disabled={!chatMessage.trim() || isAiThinking} className="absolute right-1 top-1 p-1.5 bg-violet-600 text-white rounded-full hover:bg-violet-700"><Send className="w-3 h-3" /></button>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        )}
    </div>
  );
};

export default Timer;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Timer from './components/Timer';
import Inbox from './components/Inbox';
import Dashboard from './components/Dashboard';
import History from './components/History';
import Categories from './components/Categories';
import QuickCapture from './components/QuickCapture';
import { View, TimerMode, InboxItem, Settings, UserCredits, SessionHistoryItem, Category } from './types';
import { generateId, cn, playSynthSound } from './utils';
import { Moon, Sun, Volume2, VolumeX, Timer as TimerIcon, Menu, X, PenLine, BarChart2, History as HistoryIcon, Tags, Inbox as InboxIcon } from 'lucide-react';

// Mock Data
const INITIAL_SETTINGS: Settings = {
  focusDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  longBreakInterval: 4,
  language: 'es'
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: 'Trabajo', color: 'bg-red-500' },
  { id: 'c2', name: 'Personal', color: 'bg-blue-500' },
  { id: 'c3', name: 'Estudio', color: 'bg-emerald-500' },
];

const INITIAL_INBOX: InboxItem[] = [
  {
    id: 'w1', title: 'Reporte Financiero Q3', type: 'note', status: 'pending', categoryId: 'c1',
    noteContent: 'Acción Siguiente\n[ ] Revisar correos prioritarios\n[ ] Definir los 3 objetivos principales del bloque\n[ ] Preparar materiales para la siguiente reunión\n\n---\n\nResumen\nEl análisis muestra un crecimiento del 15% en ingresos recurrentes.',
    createdAt: new Date(), deadline: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000), timeSpent: 0
  },
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('timer');
  const [previousView, setPreviousView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState(''); 
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isQuickCaptureOpen, setIsQuickCaptureOpen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);
  const [isSettingsExpanded, setIsSettingsExpanded] = useState(false);

  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);

  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const t = {
    es: {
      focus: 'Enfoque',
      inbox: 'Inbox',
      categories: 'Categorías',
      stats: 'Estadísticas',
      history: 'Historial',
      settings: 'Configuración',
      quickCapture: 'Captura Rápida',
      lang: 'Idioma',
      sessionDuration: 'Duración de Sesión',
      focusMin: 'Enfoque (min)',
      theme: 'Tema',
      proPlan: 'Plan Pro'
    },
    en: {
      focus: 'Focus',
      inbox: 'Inbox',
      categories: 'Categories',
      stats: 'Statistics',
      history: 'History',
      settings: 'Settings',
      quickCapture: 'Quick Capture',
      lang: 'Language',
      sessionDuration: 'Session Duration',
      focusMin: 'Focus (min)',
      theme: 'Theme',
      proPlan: 'Pro Plan'
    }
  }[settings.language];

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      return newVal;
    });
    if (isSoundEnabled) playSynthSound('theme-change');
  };

  const toggleSound = () => {
    setIsSoundEnabled(prev => {
      const newVal = !prev;
      if (newVal) playSynthSound('toggle');
      return newVal;
    });
  };

  useEffect(() => {
    if (!isActive) {
      let duration = settings.focusDuration;
      if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
      if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
      setTimeLeft(duration * 60);
    }
  }, [mode, settings.focusDuration, settings.shortBreakDuration, settings.longBreakDuration, isActive]);

  const handleSessionComplete = useCallback((completedMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('complete');

    const duration = completedMode === TimerMode.FOCUS ? settings.focusDuration : 
                     completedMode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000),
        endTime: new Date(),
        mode: completedMode,
        duration: duration,
        noteSnapshot: completedMode === TimerMode.FOCUS ? currentNote : undefined,
        relatedTaskId: activeTaskId || undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    if (activeTaskId && completedMode === TimerMode.FOCUS) {
        setInbox(prev => prev.map(item => {
            if (item.id === activeTaskId) {
                return { ...item, timeSpent: (item.timeSpent || 0) + duration };
            }
            return item;
        }));
    }
  }, [currentNote, settings, activeTaskId, isSoundEnabled]);

  const switchMode = useCallback(() => {
    if (isSoundEnabled) playSynthSound('switch');
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);
      let nextMode = (newCompleted > 0 && newCompleted % settings.longBreakInterval === 0) ? TimerMode.LONG_BREAK : TimerMode.SHORT_BREAK;
      setMode(nextMode);
    } else {
      setMode(TimerMode.FOCUS);
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval, isSoundEnabled]);

  useEffect(() => {
    let interval: number | undefined;
    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => {
           if (isSoundEnabled && prev > 1) playSynthSound('tick');
           return prev - 1;
        });
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      setIsActive(false);
      handleSessionComplete(mode);
      switchMode();
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, handleSessionComplete, switchMode, isSoundEnabled]);

  const toggleTimer = () => {
    const nextActive = !isActive;
    if (isSoundEnabled) {
        playSynthSound(nextActive ? 'start' : 'pause');
    }
    setIsActive(nextActive);
  };

  const resetTimer = () => {
    if (isSoundEnabled) playSynthSound('toggle');
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const startSession = (newMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('switch');
    setIsActive(false);
    setMode(newMode);

    let duration = settings.focusDuration;
    if (newMode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (newMode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);

    setTimeout(() => {
        setIsActive(true);
        if (isSoundEnabled) playSynthSound('start');
    }, 10);
  };

  const handleStartTaskFocus = (taskId: string) => {
    setActiveTaskId(taskId);
    setCurrentView('timer');
    startSession(TimerMode.FOCUS);
    setInbox(prev => prev.map(item => item.id === taskId && item.status === 'pending' ? { ...item, status: 'in-progress' } : item));
  };

  const saveNoteToInbox = (content: string, categoryId?: string, title?: string) => {
      const newItem: InboxItem = {
        id: generateId(),
        title: title || content.split('\n')[0] || 'Nueva Tarea',
        type: 'note',
        noteContent: content,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), 
        status: 'pending',
        categoryId: categoryId,
      };
      setInbox(prev => [newItem, ...prev]);
      return newItem.id;
  };

  const handleInboxAction = (id: string, action: string, payload?: any) => {
    if (action === 'delete') {
      setInbox(prev => prev.filter(i => i.id !== id));
    } else if (action === 'update') {
      setInbox(prev => prev.map(i => i.id === id ? { ...i, ...payload } : i));
    } else if (action === 'schedule') {
        setInbox(prev => prev.map(i => i.id === id ? { ...i, status: 'scheduled', isRead: true } : i));
    }
  };

  const handleUpdateTask = (id: string, content: string, title?: string) => {
    setInbox(prev => prev.map(item => item.id === id ? { ...item, noteContent: content, title: title ?? item.title } : item));
  };

  const handleViewChange = (view: View) => {
    if (view === currentView) return;
    setPreviousView(currentView);
    setCurrentView(view);
    if (isSoundEnabled) playSynthSound('toggle');
    setIsMenuOpen(false);
  };

  const toggleSettings = () => {
    setIsSettingsExpanded(!isSettingsExpanded);
    if (isSoundEnabled) playSynthSound('toggle');
  };

  const handleGlobalExport = (type: 'notion' | 'sheets' | 'mail' | 'pdf' | 'md') => {
    const summary = inbox.map(i => `- ${i.title} (${i.status})`).join('\n');
    const fullContent = inbox.map(i => `## ${i.title}\nStatus: ${i.status}\n\n${i.noteContent}`).join('\n\n---\n\n');

    switch (type) {
      case 'notion':
        navigator.clipboard.writeText(fullContent);
        break;
      case 'mail':
        window.location.href = `mailto:?subject=PomoDeep%20Export&body=${encodeURIComponent(fullContent)}`;
        break;
      case 'sheets':
        const csv = "Title,Status,Time Spent (min)\n" + inbox.map(i => `"${i.title}","${i.status}",${i.timeSpent || 0}`).join('\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        link.href = URL.createObjectURL(blob);
        link.setAttribute("download", "pomodeep_export.csv");
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        break;
      case 'md':
        const mdBlob = new Blob([fullContent], { type: 'text/markdown;charset=utf-8;' });
        const mdLink = document.createElement("a");
        mdLink.href = URL.createObjectURL(mdBlob);
        mdLink.setAttribute("download", "pomodeep_export.md");
        document.body.appendChild(mdLink);
        mdLink.click();
        document.body.removeChild(mdLink);
        break;
      case 'pdf':
        window.print(); // Simple PDF export via print
        break;
    }
  };

  const activeTask = inbox.find(i => i.id === activeTaskId);
  const badgeCount = inbox.filter(i => i.status === 'pending' && i.type === 'notification' && !i.isRead).length;

  return (
    <div className="flex flex-col min-h-screen bg-white dark:bg-black font-sans transition-colors duration-300 relative overflow-hidden">

      <QuickCapture isOpen={isQuickCaptureOpen} onClose={() => setIsQuickCaptureOpen(false)} categories={categories} onSave={saveNoteToInbox} timeLeft={timeLeft} timerMode={mode} />

      {isMenuOpen && (
        <div className="fixed inset-0 bg-black/20 backdrop-blur-sm z-40 transition-opacity duration-300" onClick={() => setIsMenuOpen(false)} />
      )}

      <main className="flex-1 p-8 overflow-y-auto w-full max-w-7xl mx-auto flex flex-col items-center pb-32">
        <header className="mb-8 w-full flex items-center justify-between relative z-50 px-2">
             <div className="flex items-center gap-3 cursor-pointer group" onClick={() => handleViewChange('timer')}>
                <div className="w-10 h-10 bg-pomo rounded-xl flex items-center justify-center shadow-lg shadow-pomo/30 flex-shrink-0 text-white transition-transform group-hover:scale-105">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="w-6 h-6">
                        <path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z" />
                        <path d="M12 6v6l4 2" />
                    </svg>
                </div>
                <div>
                    <h1 className="text-xl font-bold tracking-tight text-slate-900 dark:text-white leading-none">
                        Pomo<span className="text-pomo">Deep</span>
                    </h1>
                    <p className="text-[9px] text-slate-400 font-medium tracking-widest uppercase mt-0.5">Focus OS</p>
                </div>
             </div>

             <div className="flex items-center gap-1.5">
                <div className="relative">
                  <button onClick={toggleSettings} className={cn("p-2.5 rounded-full transition-all active:scale-90", isSettingsExpanded ? "bg-pomo text-white shadow-lg shadow-pomo/30" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800")}>
                    <TimerIcon className="w-5 h-5" />
                  </button>
                  {isSettingsExpanded && (
                    <div className="absolute top-full mt-2 right-0 w-64 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl shadow-2xl p-6 z-[60] animate-in fade-in slide-in-from-top-2">
                      <div className="space-y-6">
                        <div>
                          <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">{t.focusMin}</label>
                          <input type="range" min="15" max="60" value={settings.focusDuration} onChange={(e) => setSettings({...settings, focusDuration: parseInt(e.target.value)})} className="w-full accent-pomo" />
                          <div className="flex justify-between text-xs font-bold text-pomo mt-1"><span>15m</span><span>{settings.focusDuration}m</span><span>60m</span></div>
                        </div>
                        <div className="pt-4 border-t border-slate-50 dark:border-slate-800">
                          <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-3">{t.lang}</label>
                          <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                            <button onClick={() => setSettings({...settings, language: 'en'})} className={cn("flex-1 py-1.5 rounded-lg text-xs font-bold transition-all", settings.language === 'en' ? "bg-white shadow dark:bg-slate-700 dark:text-white" : "text-slate-400")}>EN</button>
                            <button onClick={() => setSettings({...settings, language: 'es'})} className={cn("flex-1 py-1.5 rounded-lg text-xs font-bold transition-all", settings.language === 'es' ? "bg-white shadow dark:bg-slate-700 dark:text-white" : "text-slate-400")}>ES</button>
                          </div>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
                <button onClick={toggleSound} className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90">
                  {isSoundEnabled ? <Volume2 className="w-5 h-5" /> : < VolumeX className="w-5 h-5" />}
                </button>
                <button onClick={toggleDarkMode} className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90">
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>
                <div className="relative">
                  <button onClick={() => setIsMenuOpen(!isMenuOpen)} className={cn("p-2.5 rounded-full transition-all active:scale-90 relative", isMenuOpen ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800")}>
                    {isMenuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
                  </button>
                  {isMenuOpen && (
                    <div className="absolute right-0 mt-3 w-64 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl shadow-2xl p-4 animate-in fade-in zoom-in-95 duration-200">
                        <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800 rounded-xl mb-4">
                            <div className="w-10 h-10 rounded-full bg-slate-200 dark:bg-slate-700 overflow-hidden ring-2 ring-white dark:ring-slate-900">
                                <img src="https://picsum.photos/100/100" alt="User" className="w-full h-full object-cover" />
                            </div>
                            <div className="flex flex-col leading-tight">
                                <p className="text-sm font-bold text-slate-900 dark:text-white">Alex Designer</p>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{t.proPlan}</p>
                            </div>
                        </div>
                        <button onClick={() => { setIsQuickCaptureOpen(true); setIsMenuOpen(false); }} className="w-full bg-slate-900 hover:bg-slate-800 text-white p-3 rounded-xl flex items-center justify-center gap-2 transition-all mb-4 dark:bg-white dark:text-black dark:hover:bg-slate-200 font-bold text-sm">
                          <PenLine className="w-4 h-4" /> {t.quickCapture}
                        </button>
                        <nav className="space-y-1">
                          {[
                            { id: 'timer', icon: TimerIcon, label: t.focus },
                            { id: 'inbox', icon: InboxIcon, label: t.inbox, badge: badgeCount },
                            { id: 'categories', icon: Tags, label: t.categories },
                            { id: 'dashboard', icon: BarChart2, label: t.stats },
                            { id: 'history', icon: HistoryIcon, label: t.history },
                          ].map((item) => (
                            <button key={item.id} onClick={() => handleViewChange(item.id as View)} className={cn("w-full flex items-center justify-between px-4 py-3 rounded-xl transition-colors font-medium text-sm", currentView === item.id ? "bg-pomo/5 text-pomo dark:bg-pomo/10" : "text-slate-500 hover:bg-slate-50 dark:text-slate-400 dark:hover:bg-slate-800")}>
                              <div className="flex items-center gap-3"><item.icon className="w-4 h-4" />{item.label}</div>
                            </button>
                          ))}
                        </nav>
                    </div>
                  )}
                </div>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 w-full flex-1">
            {currentView === 'timer' && (
            <Timer 
              settings={settings} 
              activeMode={mode} 
              startSession={startSession} 
              timeLeft={timeLeft} 
              isActive={isActive} 
              toggleTimer={toggleTimer} 
              resetTimer={resetTimer} 
              sessionsCompleted={sessionsCompleted} 
              onNoteChange={setCurrentNote}
              currentNote={currentNote}
              categories={categories} 
              onSaveNote={saveNoteToInbox} 
              activeTask={activeTask} 
              onStopTask={() => setActiveTaskId(null)}
              onGoToInbox={() => handleViewChange('inbox')}
              onUpdateTask={handleUpdateTask}
            />
            )}
            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} categories={categories} onStartSession={handleStartTaskFocus} onManageCategories={() => setCurrentView('categories')} onSaveNote={saveNoteToInbox} />
            )}
            {currentView === 'categories' && <Categories categories={categories} onAdd={(c) => setCategories(prev => [...prev, c])} onDelete={(id) => setCategories(prev => prev.filter(c => c.id !== id))} inboxItems={inbox} />}
            {currentView === 'dashboard' && <Dashboard credits={credits} onExport={handleGlobalExport} />}
            {currentView === 'history' && <History history={history} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { InboxItem, Category } from '../types';
import { calculateDaysRemaining, cn } from '../utils';
import { 
    Trash2, CheckCircle, Bell, Play, Clock, Zap, CircleCheckBig
} from 'lucide-react';

interface InboxProps {
  items: InboxItem[];
  onAction: (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction' | 'update', payload?: any) => void;
  categories?: Category[];
  onStartSession: (taskId: string) => void;
  onManageCategories: () => void;
  onSaveNote: (content: string, categoryId?: string, title?: string) => string;
}

const Inbox: React.FC<InboxProps> = ({ items, onAction, categories, onStartSession, onSaveNote }) => {
  const [activeTab, setActiveTab] = useState<'notifications' | 'all'>('all');
  const [selectedItem, setSelectedItem] = useState<InboxItem | null>(null);
  const [confirmAction, setConfirmAction] = useState<{ id: string, type: 'delete' | 'resolve' } | null>(null);
  const [selectedFilterCategory, setSelectedFilterCategory] = useState<string>('');

  const [isNewTaskFormOpen, setIsNewTaskFormOpen] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskCategory, setNewTaskCategory] = useState('');

  const [confetti, setConfetti] = useState<{id: number, x: number, y: number, color: string}[]>([]);

  const triggerConfetti = (e: React.MouseEvent) => {
      const colors = ['#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];
      const newConfetti = Array.from({ length: 20 }).map((_, i) => ({
          id: Date.now() + i, x: e.clientX, y: e.clientY,
