                    <button onClick={(e) => { if(confirmAction.type === 'resolve') triggerConfetti(e); onAction(confirmAction.id, confirmAction.type === 'resolve' ? 'schedule' : 'delete'); setConfirmAction(null); }} className={cn("flex-1 py-2.5 rounded-xl text-white font-medium", confirmAction.type === 'resolve' ? "bg-green-600" : "bg-red-600")}>Sí</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

