import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export const formatTime = (seconds: number): string => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
};

export const calculateDaysRemaining = (deadline: Date): number => {
  const now = new Date();
  const diffTime = deadline.getTime() - now.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  return diffDays;
};

export const calculateDaysAgo = (date: Date): number => {
  const now = new Date();
  const diffTime = now.getTime() - date.getTime();
  const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
  return diffDays;
};

export const generateId = () => Math.random().toString(36).substr(2, 9);

// Synthesized Sound Engine
let audioCtx: AudioContext | null = null;

const getAudioContext = (): AudioContext | null => {
  if (audioCtx) return audioCtx;

  try {
    const Ctor = window.AudioContext || (window as any).webkitAudioContext;
    if (typeof Ctor === 'function') {
      audioCtx = new Ctor();
      return audioCtx;
    }
  } catch (err) {
    console.warn("AudioContext initialization failed", err);
  }
  return null;
};

export const playSynthSound = (type: 'toggle' | 'switch' | 'complete' | 'tick' | 'theme-change' | 'start' | 'pause') => {
  const ctx = getAudioContext();
  if (!ctx || ctx.state === 'closed') return;

  try {
    // Resume if suspended (common browser policy)
    if (ctx.state === 'suspended') {
      ctx.resume();
    }

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    const now = ctx.currentTime;

    switch (type) {
      case 'start':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(440, now);
        osc.frequency.exponentialRampToValueAtTime(880, now + 0.15);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.15);
        osc.start(now);
        osc.stop(now + 0.15);
        break;
      case 'pause':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, now);
        osc.frequency.exponentialRampToValueAtTime(440, now + 0.15);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.15);
        osc.start(now);
        osc.stop(now + 0.15);
        break;
      case 'tick':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(2000, now);
        gain.gain.setValueAtTime(0.02, now);
        gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.02);
        osc.start(now);
        osc.stop(now + 0.02);
        break;
      case 'theme-change':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(220, now);
        osc.frequency.exponentialRampToValueAtTime(110, now + 0.3);
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.3);
        osc.start(now);
        osc.stop(now + 0.3);
        break;
      case 'toggle':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(1200, now);
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.05);
        osc.start(now);
        osc.stop(now + 0.05);
        break;
      case 'switch':
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(440, now);
        osc.frequency.exponentialRampToValueAtTime(660, now + 0.2);
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
        osc.start(now);
        osc.stop(now + 0.2);
        break;
      case 'complete':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(523.25, now); 
        osc.frequency.setValueAtTime(659.25, now + 0.15); 
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.4);
        osc.start(now);
        osc.stop(now + 0.4);
        break;
    }
  } catch (e) {
    console.warn("Audio playback failed:", e);
  }
};

import React, { useState } from 'react';
import { InboxItem, Category } from '../types';
import { calculateDaysAgo, cn } from '../utils';
import { 
    Trash2, CheckCircle, Play, Clock, Zap, CircleCheckBig, Edit3, Calendar
} from 'lucide-react';

interface InboxProps {
  items: InboxItem[];
  onAction: (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction' | 'update', payload?: any) => void;
  categories?: Category[];
  onStartSession: (taskId: string) => void;
  onManageCategories: () => void;
  onSaveNote: (content: string, categoryId?: string, title?: string) => string;
}

const Inbox: React.FC<InboxProps> = ({ items, onAction, categories, onStartSession, onSaveNote }) => {
  const [activeTab, setActiveTab] = useState<'notifications' | 'all'>('all');
  const [selectedItem, setSelectedItem] = useState<InboxItem | null>(null);
  const [confirmAction, setConfirmAction] = useState<{ id: string, type: 'delete' | 'resolve' } | null>(null);
  const [selectedFilterCategory, setSelectedFilterCategory] = useState<string>('');

  const [isNewTaskFormOpen, setIsNewTaskFormOpen] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskCategory, setNewTaskCategory] = useState('');

  const [confetti, setConfetti] = useState<{id: number, x: number, y: number, color: string}[]>([]);

  const triggerConfetti = (e: React.MouseEvent) => {
      const colors = ['#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];
      const newConfetti = Array.from({ length: 20 }).map((_, i) => ({
          id: Date.now() + i, x: e.clientX, y: e.clientY,
          color: colors[Math.floor(Math.random() * colors.length)]
      }));
      setConfetti(prev => [...prev, ...newConfetti]);
      setTimeout(() => setConfetti(prev => prev.filter(c => !newConfetti.find(n => n.id === c.id))), 1000);
  };

  const filteredItems = items.filter(item => {
    if (activeTab === 'notifications') return item.type === 'notification';
    const isNote = item.type === 'note' && item.status !== 'completed' && item.status !== 'scheduled';
    const matchesCategory = !selectedFilterCategory || item.categoryId === selectedFilterCategory;
    return isNote && matchesCategory;
  });

  const getCategoryColor = (id?: string) => categories?.find(c => c.id === id)?.color || 'bg-slate-200 dark:bg-slate-700';
  const getCategoryName = (id?: string) => categories?.find(c => c.id === id)?.name || 'Uncategorized';

  const handleUpdateItem = (updates: Partial<InboxItem>) => {
      if (selectedItem) {
          onAction(selectedItem.id, 'update', updates);
          setSelectedItem(prev => prev ? { ...prev, ...updates } : null);
      }
  };

  const handleCreateAndStartFocus = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newTaskTitle.trim()) return;
      const defaultContent = "Acción Siguiente\n[ ] \n[ ] \n[ ] \n\n---\n\n";
      const newId = onSaveNote(defaultContent, newTaskCategory || undefined, newTaskTitle);
      onStartSession(newId);
      setIsNewTaskFormOpen(false);
      setNewTaskTitle('');
      setNewTaskCategory('');
  };

  const getStatusBadgeClass = (status: string) => {
      switch(status) {
          case 'in-progress': return 'text-amber-500 bg-amber-50 border-amber-100 dark:bg-amber-900/20 dark:border-amber-900';
          case 'scheduled': return 'text-green-500 bg-green-50 border-green-100 dark:bg-green-900/20 dark:border-green-900';
          default: return 'text-slate-500 bg-slate-50 border-slate-100 dark:bg-slate-800 dark:border-slate-700';
      }
  };

  const renderCard = (item: InboxItem) => {
      const daysAgo = calculateDaysAgo(item.createdAt);
      return (
        <div key={item.id} className="group relative bg-white dark:bg-slate-900 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm transition-all p-4 hover:shadow-md">
            <div className="flex justify-between items-center">
                 <div className="flex items-center flex-1 min-w-0">
                    {/* Check resolve button */}
                    <button 
                        onClick={(e) => { e.stopPropagation(); triggerConfetti(e); setConfirmAction({ id: item.id, type: 'resolve' }); }} 
                        className="w-5 h-5 rounded-full border-2 border-slate-300 dark:border-slate-600 mr-4 flex items-center justify-center text-transparent hover:border-green-500 hover:text-green-500 transition-all shrink-0"
                        title="Mark as Resolved"
                    >
                        <CircleCheckBig className="w-4 h-4" />
                    </button>

                    <div className="flex-1 min-w-0 cursor-pointer" onClick={() => setSelectedItem(item)}>
                        <h4 className="text-sm font-bold text-slate-800 dark:text-slate-100 truncate mb-1">{item.title}</h4>
                        <div className="flex flex-wrap items-center gap-3 text-[10px] font-bold tracking-wider uppercase">
                            <span className={cn("px-2 py-0.5 rounded border", getStatusBadgeClass(item.status))}>
                                {item.status.replace('-', ' ')}
                            </span>
                            {item.categoryId && (
                                <span className="flex items-center gap-1.5 text-slate-500 dark:text-slate-400">
                                    <span className={cn("w-2 h-2 rounded-full", getCategoryColor(item.categoryId))} />
                                    {getCategoryName(item.categoryId)}
                                </span>
                            )}
                            <span className="text-slate-400 flex items-center gap-1">
                                <Calendar className="w-3 h-3" /> {daysAgo === 0 ? 'Hoy' : `Hace ${daysAgo}d`}
                            </span>
                        </div>
                    </div>
                 </div>

                 {/* Actions */}
                 <div className="flex gap-1 ml-4 shrink-0">
                    <button onClick={() => setSelectedItem(item)} className="p-2 text-slate-400 hover:text-pomo hover:bg-slate-50 rounded-lg transition-all dark:hover:bg-slate-800" title="Edit Details">
                        <Edit3 className="w-4 h-4" />
                    </button>
                    <button onClick={() => onStartSession(item.id)} className="p-2 bg-pomo text-white rounded-lg shadow-lg shadow-pomo/20 hover:scale-105 active:scale-95 transition-all" title="Focus on this">
                        <Play className="w-4 h-4 fill-current" />
                    </button>
                 </div>
            </div>
        </div>
      );
  };

  return (
    <div className="w-full max-w-5xl mx-auto py-8 px-4 relative">
      {/* Confetti container */}
      <div className="fixed inset-0 pointer-events-none z-[100]">
          {confetti.map(c => (
              <div key={c.id} className="absolute w-2 h-2 rounded-full animate-ping" style={{ left: c.x, top: c.y, backgroundColor: c.color }} />
          ))}
      </div>

      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-4">
        <div><h2 className="text-2xl font-bold text-slate-900 dark:text-white">{activeTab === 'all' ? 'Inbox & Tareas' : 'Notificaciones'}</h2></div>
        <div className="flex items-center gap-2">
             <div className="flex bg-slate-100 p-1 rounded-xl dark:bg-slate-800 border border-slate-200 dark:border-slate-700">
                <button onClick={() => { setActiveTab('all'); setSelectedFilterCategory(''); }} className={cn("px-4 py-2 rounded-lg text-sm font-bold transition-all", activeTab === 'all' ? "bg-white shadow-sm dark:bg-slate-600 dark:text-white text-slate-900" : "text-slate-500 hover:text-slate-700")}>Tareas</button>
                <button onClick={() => setActiveTab('notifications')} className={cn("px-4 py-2 rounded-lg text-sm font-bold transition-all", activeTab === 'notifications' ? "bg-white shadow-sm dark:bg-slate-600 dark:text-white text-slate-900" : "text-slate-500 hover:text-slate-700")}>Alertas</button>
             </div>
             {activeTab === 'all' && <button onClick={() => setIsNewTaskFormOpen(!isNewTaskFormOpen)} className="px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 transition-all bg-pomo text-white shadow-lg"><Zap className="w-4 h-4" /> Nuevo</button>}
        </div>
      </div>

      {isNewTaskFormOpen && (
          <form onSubmit={handleCreateAndStartFocus} className="mb-8 bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl animate-in slide-in-from-top-4">
              <div className="flex flex-col gap-4">
                  <input type="text" autoFocus value={newTaskTitle} onChange={(e) => setNewTaskTitle(e.target.value)} placeholder="Título del nuevo Focus..." className="w-full bg-slate-50 dark:bg-slate-800 p-4 rounded-xl text-lg font-bold outline-none border border-transparent focus:border-pomo/30 transition-all dark:text-white" />
                  <div className="flex items-center gap-3">
                      <select value={newTaskCategory} onChange={(e) => setNewTaskCategory(e.target.value)} className="flex-1 bg-slate-50 dark:bg-slate-800 p-3 rounded-xl text-sm font-bold outline-none dark:text-white">
                        <option value="">Sin Etiqueta</option>
                        {categories?.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                      </select>
                      <button type="submit" disabled={!newTaskTitle.trim()} className="bg-pomo text-white p-3 px-6 rounded-xl shadow-xl font-bold">Iniciar Sesión</button>
                  </div>
              </div>
          </form>
      )}

      {activeTab === 'all' && categories && categories.length > 0 && (
          <div className="flex items-center gap-4 mb-6 overflow-x-auto pb-2 no-scrollbar">
              <button onClick={() => setSelectedFilterCategory('')} className={cn("px-4 py-1.5 rounded-full text-xs font-bold transition-all border shrink-0", !selectedFilterCategory ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-white text-slate-500 border-slate-200 dark:bg-slate-800")}>Todas</button>
              {categories.map(cat => <button key={cat.id} onClick={() => setSelectedFilterCategory(cat.id)} className={cn("px-4 py-1.5 rounded-full text-xs font-bold transition-all border flex items-center gap-2 shrink-0", selectedFilterCategory === cat.id ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-white text-slate-500 border-slate-200 dark:bg-slate-800")}><span className={cn("w-2 h-2 rounded-full", cat.color)} />{cat.name}</button>)}
          </div>
      )}

      <div className="grid gap-3">{filteredItems.length === 0 ? <p className="text-center py-16 text-slate-400 italic">No hay tareas en esta vista.</p> : filteredItems.map(renderCard)}</div>

      {selectedItem && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setSelectedItem(null)} />
              <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-2xl shadow-2xl p-6 border dark:border-slate-800 animate-in fade-in zoom-in-95 max-h-[90vh] overflow-y-auto">
                   <div className="flex items-center gap-2 mb-2 text-slate-400">
                        <Edit3 className="w-4 h-4" />
                        <span className="text-[10px] font-bold uppercase tracking-widest">Editar Tarea</span>
                   </div>
                   <input 
                        value={selectedItem.title} 
                        onChange={(e) => handleUpdateItem({ title: e.target.value })} 
                        className="text-xl font-bold dark:text-white w-full bg-slate-50 dark:bg-slate-800 p-3 rounded-xl border border-transparent focus:border-pomo/30 outline-none mb-4" 
                        placeholder="Título de la tarea"
                   />
                   <div className="mb-6">
                       <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">Contenido de la Nota</label>
                       <textarea value={selectedItem.noteContent} readOnly className="w-full h-32 bg-slate-100 border rounded-xl p-4 text-slate-500 outline-none dark:bg-slate-800 dark:text-slate-500 cursor-not-allowed italic text-sm" />
                       <p className="text-[10px] text-slate-400 mt-1 italic">* El contenido de la nota se edita durante la sesión de enfoque.</p>
                   </div>
                   <div className="flex gap-3">
                       <button onClick={() => { onStartSession(selectedItem.id); setSelectedItem(null); }} className="flex-1 bg-pomo text-white py-3 rounded-xl font-bold shadow-lg flex items-center justify-center gap-2"><Play className="w-4 h-4 fill-current" /> Enfocar</button>
                       <button onClick={() => setConfirmAction({ id: selectedItem.id, type: 'delete' })} className="p-3 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-400 hover:text-red-500 transition-colors"><Trash2 className="w-5 h-5" /></button>
                       <button onClick={() => setConfirmAction({ id: selectedItem.id, type: 'resolve' })} className="p-3 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-400 hover:text-green-500 transition-colors"><CheckCircle className="w-4 h-4" /></button>
                   </div>
              </div>
          </div>
      )}

      {confirmAction && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setConfirmAction(null)} />
              <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-2xl p-6 text-center shadow-2xl">
                  <h3 className="text-lg font-bold dark:text-white mb-2">¿Confirmar Acción?</h3>
                  <p className="text-sm text-slate-500 mb-6">{confirmAction.type === 'resolve' ? 'Se archivará la tarea.' : 'Se eliminará permanentemente.'}</p>
