interface InboxProps {
  items: InboxItem[];
  onAction: (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction' | 'update', payload?: any) => void;
  categories?: Category[];
  onStartSession: (taskId: string) => void;
  onManageCategories: () => void;
  onSaveNote: (content: string, categoryId?: string, title?: string) => string;
}

const Inbox: React.FC<InboxProps> = ({ items, onAction, categories, onStartSession, onSaveNote }) => {
  const [activeTab, setActiveTab] = useState<'notifications' | 'all'>('all');
  const [selectedItem, setSelectedItem] = useState<InboxItem | null>(null);
  const [confirmAction, setConfirmAction] = useState<{ id: string, type: 'delete' | 'resolve' } | null>(null);
  const [selectedFilterCategory, setSelectedFilterCategory] = useState<string>('');

  const [isNewTaskFormOpen, setIsNewTaskFormOpen] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskCategory, setNewTaskCategory] = useState('');

  const [scheduleDate, setScheduleDate] = useState<string>('');

  const [confetti, setConfetti] = useState<{id: number, x: number, y: number, color: string}[]>([]);

  const triggerConfetti = (e: React.MouseEvent) => {
      const colors = ['#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];
      const newConfetti = Array.from({ length: 20 }).map((_, i) => ({
          id: Date.now() + i, x: e.clientX, y: e.clientY,
          color: colors[Math.floor(Math.random() * colors.length)]
      }));
      setConfetti(prev => [...prev, ...newConfetti]);
      setTimeout(() => setConfetti(prev => prev.filter(c => !newConfetti.find(n => n.id === c.id))), 1000);
  };

  const filteredItems = items.filter(item => {
    const isNote = item.type === 'note' && item.status !== 'completed';
    const matchesCategory = !selectedFilterCategory || item.categoryId === selectedFilterCategory;
    return isNote && matchesCategory;
  });

  const getCategoryColor = (id?: string) => categories?.find(c => c.id === id)?.color || 'bg-slate-200 dark:bg-slate-700';
  const getCategoryName = (id?: string) => categories?.find(c => c.id === id)?.name || 'Sin Etiqueta';

  const handleUpdateItem = (updates: Partial<InboxItem>) => {
      if (selectedItem) {
          onAction(selectedItem.id, 'update', updates);
          setSelectedItem(prev => prev ? { ...prev, ...updates } : null);
      }
  };

  const handleCreateAndStartFocus = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newTaskTitle.trim()) return;
      const defaultContent = "Acción Siguiente\n[ ] \n[ ] \n[ ] \n\n---\n\n";
      const newId = onSaveNote(defaultContent, newTaskCategory || undefined, newTaskTitle);
      onStartSession(newId);
      setIsNewTaskFormOpen(false);
      setNewTaskTitle('');
      setNewTaskCategory('');
  };

  const getStatusBadgeClass = (status: string) => {
      switch(status) {
          case 'in-progress': return 'text-amber-500 bg-amber-50 border-amber-100 dark:bg-amber-900/20 dark:border-amber-900';
          case 'scheduled': return 'text-blue-500 bg-blue-50 border-blue-100 dark:bg-blue-900/20 dark:border-blue-900';
          default: return 'text-slate-500 bg-slate-50 border-slate-100 dark:bg-slate-800 dark:border-slate-700';
      }
  };

  const renderCard = (item: InboxItem) => {
      const daysAgo = calculateDaysAgo(item.createdAt);
      return (
        <div key={item.id} className="group relative bg-white dark:bg-slate-900 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm transition-all p-4 hover:shadow-md">
            <div className="flex justify-between items-center">
                 <div className="flex items-center flex-1 min-w-0">
                    <button 
                        onClick={(e) => { e.stopPropagation(); triggerConfetti(e); setConfirmAction({ id: item.id, type: 'resolve' }); }} 
                        className="w-5 h-5 rounded-full border-2 border-slate-300 dark:border-slate-600 mr-4 flex items-center justify-center text-transparent hover:border-green-500 hover:text-green-500 transition-all shrink-0"
                    >
                        <CircleCheckBig className="w-4 h-4" />
                    </button>

                    <div className="flex-1 min-w-0 cursor-pointer" onClick={() => { setSelectedItem(item); setScheduleDate(item.scheduledDate ? new Date(item.scheduledDate).toISOString().split('T')[0] : ''); }}>
                        <h4 className="text-sm font-bold text-slate-800 dark:text-slate-100 truncate mb-1">{item.title}</h4>
                        <div className="flex flex-wrap items-center gap-3 text-[10px] font-bold tracking-wider uppercase">
                            <span className={cn("px-2 py-0.5 rounded border", getStatusBadgeClass(item.status))}>
                                {item.status.replace('-', ' ')}
                            </span>
                            {item.categoryId && (
                                <span className="flex items-center gap-1.5 text-slate-500 dark:text-slate-400">
                                    <span className={cn("w-2 h-2 rounded-full", getCategoryColor(item.categoryId))} />
                                    {getCategoryName(item.categoryId)}
                                </span>
                            )}
                            <span className="text-slate-400 flex items-center gap-1">
                                <Calendar className="w-3 h-3" /> {daysAgo === 0 ? 'Hoy' : `Hace ${daysAgo}d`}
                            </span>
                            {item.scheduledDate && (
                                <span className="text-blue-500 flex items-center gap-1">
                                    <Bell className="w-3 h-3" /> {new Date(item.scheduledDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short' })}
                                </span>
                            )}
                        </div>
                    </div>
                 </div>

                 <div className="flex gap-1 ml-4 shrink-0">
                    <button onClick={() => { setSelectedItem(item); setScheduleDate(item.scheduledDate ? new Date(item.scheduledDate).toISOString().split('T')[0] : ''); }} className="p-2 text-slate-400 hover:text-pomo hover:bg-slate-50 rounded-lg transition-all dark:hover:bg-slate-800">
                        <Edit3 className="w-4 h-4" />
                    </button>
                    <button onClick={() => onStartSession(item.id)} className="p-2 bg-pomo text-white rounded-lg shadow-lg shadow-pomo/20 hover:scale-105 active:scale-95 transition-all">
                        <Play className="w-4 h-4 fill-current" />
                    </button>
                 </div>
            </div>
        </div>
      );
  };

  return (
    <div className="w-full max-w-5xl mx-auto py-8 px-4 relative">
      <div className="fixed inset-0 pointer-events-none z-[100]">
          {confetti.map(c => (
              <div key={c.id} className="absolute w-2 h-2 rounded-full animate-ping" style={{ left: c.x, top: c.y, backgroundColor: c.color }} />
          ))}
      </div>

      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-4">
        <div><h2 className="text-2xl font-bold text-slate-900 dark:text-white">Bandeja de entrada</h2></div>
        <div className="flex items-center gap-2">
             <button onClick={() => setIsNewTaskFormOpen(!isNewTaskFormOpen)} className="px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 transition-all bg-pomo text-white shadow-lg"><Zap className="w-4 h-4" /> Nuevo focus time</button>
        </div>
      </div>

      {isNewTaskFormOpen && (
          <form onSubmit={handleCreateAndStartFocus} className="mb-8 bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl animate-in slide-in-from-top-4">
              <div className="flex flex-col gap-4">
                  <input type="text" autoFocus value={newTaskTitle} onChange={(e) => setNewTaskTitle(e.target.value)} placeholder="Título del nuevo Focus..." className="w-full bg-slate-50 dark:bg-slate-800 p-4 rounded-xl text-lg font-bold outline-none border border-transparent focus:border-pomo/30 transition-all dark:text-white" />
                  <div className="flex items-center gap-3">
                      <select value={newTaskCategory} onChange={(e) => setNewTaskCategory(e.target.value)} className="flex-1 bg-slate-50 dark:bg-slate-800 p-3 rounded-xl text-sm font-bold outline-none dark:text-white">
                        <option value="">Sin Etiqueta</option>
                        {categories?.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                      </select>
                      <button type="submit" disabled={!newTaskTitle.trim()} className="bg-pomo text-white p-3 px-6 rounded-xl shadow-xl font-bold">Iniciar Sesión</button>
                  </div>
              </div>
          </form>
      )}

      {categories && categories.length > 0 && (
          <div className="flex items-center gap-4 mb-6 overflow-x-auto pb-2 no-scrollbar">
              <button onClick={() => setSelectedFilterCategory('')} className={cn("px-4 py-1.5 rounded-full text-xs font-bold transition-all border shrink-0", !selectedFilterCategory ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-white text-slate-500 border-slate-200 dark:bg-slate-800")}>Todas</button>
              {categories.map(cat => <button key={cat.id} onClick={() => setSelectedFilterCategory(cat.id)} className={cn("px-4 py-1.5 rounded-full text-xs font-bold transition-all border flex items-center gap-2 shrink-0", selectedFilterCategory === cat.id ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-white text-slate-500 border-slate-200 dark:bg-slate-800")}><span className={cn("w-2 h-2 rounded-full", cat.color)} />{cat.name}</button>)}
          </div>
      )}

      <div className="grid gap-3">{filteredItems.length === 0 ? <p className="text-center py-16 text-slate-400 italic">No hay tareas activas.</p> : filteredItems.map(renderCard)}</div>

      {selectedItem && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setSelectedItem(null)} />
              <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-2xl shadow-2xl p-6 border dark:border-slate-800 animate-in fade-in zoom-in-95 max-h-[90vh] overflow-y-auto">
                   <div className="flex items-center justify-between mb-4">
                        <div className="flex items-center gap-2 text-slate-400">
                            <Edit3 className="w-4 h-4" />
                            <span className="text-[10px] font-bold uppercase tracking-widest">Detalle de Tarea</span>
                        </div>
                        <button onClick={() => setSelectedItem(null)} className="text-slate-400 hover:text-slate-600 dark:hover:text-white"><X className="w-5 h-5" /></button>
                   </div>

                   <div className="space-y-6">
                       <section>
                           <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">Título</label>
                           <input 
                                value={selectedItem.title} 
                                onChange={(e) => handleUpdateItem({ title: e.target.value })} 
                                className="text-lg font-bold dark:text-white w-full bg-slate-50 dark:bg-slate-800 p-3 rounded-xl border border-transparent focus:border-pomo/30 outline-none" 
                           />
                       </section>

                       <section>
                           <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">Agendar Alerta (Focus Time)</label>
                           <div className="flex gap-2">
                               <input 
                                    type="date"
                                    value={scheduleDate}
                                    onChange={(e) => setScheduleDate(e.target.value)}
                                    className="flex-1 bg-slate-50 dark:bg-slate-800 p-3 rounded-xl text-sm font-bold border border-transparent focus:border-blue-500/30 outline-none dark:text-white"
                               />
                               <button 
                                 onClick={() => {
                                     if (scheduleDate) {
                                         onAction(selectedItem.id, 'schedule', { date: new Date(scheduleDate) });
                                         setSelectedItem(null);
                                     }
                                 }}
                                 disabled={!scheduleDate}
                                 className="px-6 bg-blue-600 text-white rounded-xl font-bold text-xs disabled:opacity-50 hover:bg-blue-700 transition-colors"
                               >
                                   Agendar
                               </button>
                           </div>
                       </section>

                       <section>
                           <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">Contenido (Sólo lectura)</label>
                           <div className="w-full bg-slate-100 dark:bg-slate-800/50 border rounded-xl p-4 text-xs text-slate-500 dark:text-slate-400 italic max-h-32 overflow-y-auto custom-scrollbar">
                               {selectedItem.noteContent || 'Sin contenido adicional.'}
                           </div>
                       </section>

                       <div className="pt-4 flex gap-3">
                           <button onClick={() => { onStartSession(selectedItem.id); setSelectedItem(null); }} className="flex-1 bg-pomo text-white py-3 rounded-xl font-bold shadow-lg flex items-center justify-center gap-2"><Play className="w-4 h-4 fill-current" /> Enfocar Ahora</button>
                           <button onClick={() => setConfirmAction({ id: selectedItem.id, type: 'delete' })} className="p-3 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-400 hover:text-red-500 transition-colors"><Trash2 className="w-5 h-5" /></button>
                           <button onClick={() => setConfirmAction({ id: selectedItem.id, type: 'resolve' })} className="p-3 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-400 hover:text-green-500 transition-colors"><CheckCircle className="w-4 h-4" /></button>
                       </div>
                   </div>
              </div>
          </div>
      )}

      {confirmAction && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setConfirmAction(null)} />
              <div className="relative bg-white dark:bg-slate-900 w-full max-sm rounded-2xl p-6 text-center shadow-2xl border dark:border-slate-800 animate-in fade-in zoom-in-95">
                  <h3 className="text-lg font-bold dark:text-white mb-2">¿Confirmar Acción?</h3>
                  <p className="text-sm text-slate-500 dark:text-slate-400 mb-6">{confirmAction.type === 'resolve' ? 'Se archivará la tarea como completada.' : 'Se eliminará permanentemente.'}</p>
                  <div className="flex gap-3">
                    <button onClick={() => setConfirmAction(null)} className="flex-1 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 font-medium dark:text-slate-300">Cancelar</button>
                    <button onClick={(e) => { 
                        if(confirmAction.type === 'resolve') {
                            triggerConfetti(e);
                            onAction(confirmAction.id, 'update', { status: 'completed' });
                        } else {
                            onAction(confirmAction.id, 'delete');
                        }
                        setConfirmAction(null); 
                    }} className={cn("flex-1 py-2.5 rounded-xl text-white font-medium shadow-lg", confirmAction.type === 'resolve' ? "bg-green-600 hover:bg-green-700" : "bg-red-600 hover:bg-red-700")}>Confirmar</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Inbox;

import React, { useState, useEffect, useCallback } from 'react';
import Timer from './components/Timer';
import Inbox from './components/Inbox';
import Dashboard from './components/Dashboard';
import History from './components/History';
import Categories from './components/Categories';
import SettingsView from './components/SettingsView';
import QuickCapture from './components/QuickCapture';
import NotificationCenter from './components/NotificationCenter';
import { View, TimerMode, InboxItem, Settings, UserCredits, SessionHistoryItem, Category } from './types';
import { generateId, cn, playSynthSound } from './utils';
import { Moon, Sun, Volume2, VolumeX, Menu, X, PenLine, BarChart2, History as HistoryIcon, Tags, Inbox as InboxIcon, Settings as SettingsIcon, Timer as TimerIcon, Bell } from 'lucide-react';

const INITIAL_SETTINGS: Settings = {
  focusDuration: 25,
  shortBreakDuration: 5,
  longBreakDuration: 15,
  longBreakInterval: 4,
  language: 'es'
};

const INITIAL_CATEGORIES: Category[] = [
  { id: 'c1', name: 'Trabajo', color: 'bg-red-500' },
  { id: 'c2', name: 'Personal', color: 'bg-blue-500' },
  { id: 'c3', name: 'Estudio', color: 'bg-emerald-500' },
];

const INITIAL_INBOX: InboxItem[] = [
  {
    id: 'w1', title: 'Reporte Financiero Q3', type: 'note', status: 'pending', categoryId: 'c1',
    noteContent: 'Acción Siguiente\n[ ] Revisar correos prioritarios\n[ ] Definir los 3 objetivos principales del bloque\n[ ] Preparar materiales para la siguiente reunión\n\n---\n\nResumen\nEl análisis muestra un crecimiento del 15% en ingresos recurrentes.',
    createdAt: new Date(), deadline: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000), timeSpent: 0
  },
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('timer');
  const [settings, setSettings] = useState<Settings>(INITIAL_SETTINGS);
  const [currentNote, setCurrentNote] = useState(''); 
  const [inbox, setInbox] = useState<InboxItem[]>(INITIAL_INBOX);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [credits, setCredits] = useState<UserCredits>({ available: 10, used: 145 });
  const [history, setHistory] = useState<SessionHistoryItem[]>([]);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isQuickCaptureOpen, setIsQuickCaptureOpen] = useState(false);
  const [isNotificationsOpen, setIsNotificationsOpen] = useState(false);
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);

  const [activeTaskId, setActiveTaskId] = useState<string | null>(null);
  const [mode, setMode] = useState<TimerMode>(TimerMode.FOCUS);
  const [timeLeft, setTimeLeft] = useState(settings.focusDuration * 60);
  const [isActive, setIsActive] = useState(false);
  const [sessionsCompleted, setSessionsCompleted] = useState(0);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark');
    }
    return false;
  });

  const t = {
    es: {
      focus: 'Enfoque',
      inbox: 'Bandeja de entrada',
      categories: 'Categorías',
      stats: 'Estadísticas',
      history: 'Historial',
      settings: 'Configuración',
      quickCapture: 'Captura Rápida',
      proPlan: 'Plan Pro'
    },
    en: {
      focus: 'Focus',
      inbox: 'Inbox',
      categories: 'Categories',
      stats: 'Statistics',
      history: 'History',
      settings: 'Settings',
      quickCapture: 'Quick Capture',
      proPlan: 'Pro Plan'
    }
  }[settings.language];

  const toggleDarkMode = () => {
    setIsDarkMode(prev => {
      const newVal = !prev;
      if (newVal) document.documentElement.classList.add('dark');
      else document.documentElement.classList.remove('dark');
      return newVal;
    });
    if (isSoundEnabled) playSynthSound('theme-change');
  };

  const toggleSound = () => {
    setIsSoundEnabled(prev => {
      const newVal = !prev;
      if (newVal) playSynthSound('toggle');
      return newVal;
    });
  };

  useEffect(() => {
    if (!isActive) {
      let duration = settings.focusDuration;
      if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
      if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
      setTimeLeft(duration * 60);
    }
  }, [mode, settings.focusDuration, settings.shortBreakDuration, settings.longBreakDuration, isActive]);

  const handleSessionComplete = useCallback((completedMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('complete');
    const duration = completedMode === TimerMode.FOCUS ? settings.focusDuration : 
                     completedMode === TimerMode.SHORT_BREAK ? settings.shortBreakDuration : 
                     settings.longBreakDuration;

    const newHistoryItem: SessionHistoryItem = {
        id: generateId(),
        startTime: new Date(Date.now() - duration * 60 * 1000),
        endTime: new Date(),
        mode: completedMode,
        duration: duration,
        noteSnapshot: completedMode === TimerMode.FOCUS ? currentNote : undefined,
        relatedTaskId: activeTaskId || undefined
    };

    setHistory(prev => [newHistoryItem, ...prev]);

    if (activeTaskId && completedMode === TimerMode.FOCUS) {
        setInbox(prev => prev.map(item => item.id === activeTaskId ? { ...item, timeSpent: (item.timeSpent || 0) + duration } : item));
    }
  }, [currentNote, settings, activeTaskId, isSoundEnabled]);

  const switchMode = useCallback(() => {
    if (isSoundEnabled) playSynthSound('switch');
    if (mode === TimerMode.FOCUS) {
      const newCompleted = sessionsCompleted + 1;
      setSessionsCompleted(newCompleted);
      let nextMode = (newCompleted > 0 && newCompleted % settings.longBreakInterval === 0) ? TimerMode.LONG_BREAK : TimerMode.SHORT_BREAK;
      setMode(nextMode);
    } else {
      setMode(TimerMode.FOCUS);
    }
  }, [mode, sessionsCompleted, settings.longBreakInterval, isSoundEnabled]);

  useEffect(() => {
    let interval: number | undefined;
    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((prev) => {
           if (isSoundEnabled && prev > 1) playSynthSound('tick');
           return prev - 1;
        });
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      setIsActive(false);
      handleSessionComplete(mode);
      switchMode();
    }
    return () => clearInterval(interval);
  }, [isActive, timeLeft, mode, handleSessionComplete, switchMode, isSoundEnabled]);

  const toggleTimer = () => {
    const nextActive = !isActive;
    if (isSoundEnabled) playSynthSound(nextActive ? 'start' : 'pause');
    setIsActive(nextActive);
  };

  const resetTimer = () => {
    if (isSoundEnabled) playSynthSound('toggle');
    setIsActive(false);
    let duration = settings.focusDuration;
    if (mode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (mode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
  };

  const startSession = (newMode: TimerMode) => {
    if (isSoundEnabled) playSynthSound('switch');
    setIsActive(false);
    setMode(newMode);
    let duration = settings.focusDuration;
    if (newMode === TimerMode.SHORT_BREAK) duration = settings.shortBreakDuration;
    if (newMode === TimerMode.LONG_BREAK) duration = settings.longBreakDuration;
    setTimeLeft(duration * 60);
    setTimeout(() => {
        setIsActive(true);
        if (isSoundEnabled) playSynthSound('start');
    }, 10);
  };

  const handleStartTaskFocus = (taskId: string) => {
    setActiveTaskId(taskId);
    setCurrentView('timer');
    startSession(TimerMode.FOCUS);
    setInbox(prev => prev.map(item => item.id === taskId ? { ...item, status: 'in-progress' } : item));
  };

  const saveNoteToInbox = (content: string, categoryId?: string, title?: string) => {
      const newItem: InboxItem = {
        id: generateId(),
        title: title || content.split('\n')[0] || (settings.language === 'es' ? 'Nueva Tarea' : 'New Task'),
        type: 'note',
        noteContent: content,
        createdAt: new Date(),
        deadline: new Date(Date.now() + 8 * 24 * 60 * 60 * 1000), 
        status: 'pending',
        categoryId: categoryId,
      };
      setInbox(prev => [newItem, ...prev]);
      return newItem.id;
  };

  const handleInboxAction = (id: string, action: string, payload?: any) => {
    if (action === 'delete') setInbox(prev => prev.filter(i => i.id !== id));
    else if (action === 'update') setInbox(prev => prev.map(i => i.id === id ? { ...i, ...payload } : i));
    else if (action === 'schedule') setInbox(prev => prev.map(i => i.id === id ? { ...i, status: 'scheduled', scheduledDate: payload?.date || new Date(), isRead: true } : i));
  };

  const handleUpdateTask = (id: string, content: string, title?: string) => {
    setInbox(prev => prev.map(item => item.id === id ? { ...item, noteContent: content, title: title ?? item.title } : item));
  };

  const handleViewChange = (view: View) => {
    if (view === currentView) return;
    setCurrentView(view);
    if (isSoundEnabled) playSynthSound('toggle');
    setIsMenuOpen(false);
  };

  const handleDurationChange = (type: 'focus' | 'short' | 'long', value: number) => {
    const confirmChange = () => {
        if (isActive) {
            const msg = settings.language === 'es' 
                ? 'El cronómetro está activo. Si cambias el tiempo, la sesión actual se reiniciará con el nuevo valor. ¿Continuar?'
                : 'Timer is active. Changing the duration will restart the current session. Continue?';
            return window.confirm(msg);
        }
        return true;
    };
    if (confirmChange()) {
        if (isActive) setIsActive(false);
        const newSettings = { ...settings };
        if (type === 'focus') newSettings.focusDuration = value;
        if (type === 'short') newSettings.shortBreakDuration = value;
        if (type === 'long') newSettings.longBreakDuration = value;
        setSettings(newSettings);
    }
  };

  const handleGlobalExport = (type: 'notion' | 'sheets' | 'mail' | 'pdf' | 'md') => {
    const fullContent = inbox.map(i => `## ${i.title}\nStatus: ${i.status}\n\n${i.noteContent}`).join('\n\n---\n\n');
    switch (type) {
      case 'notion': navigator.clipboard.writeText(fullContent); break;
      case 'mail': window.location.href = `mailto:?subject=PomoDeep%20Export&body=${encodeURIComponent(fullContent)}`; break;
      case 'sheets':
        const csv = "Title,Status,Time Spent (min)\n" + inbox.map(i => `"${i.title}","${i.status}",${i.timeSpent || 0}`).join('\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement("a");
        link.href = URL.createObjectURL(blob);
        link.setAttribute("download", "pomodeep_export.csv");
        link.click();
        break;
      case 'md':
        const mdBlob = new Blob([fullContent], { type: 'text/markdown;charset=utf-8;' });
        const mdLink = document.createElement("a");
        mdLink.href = URL.createObjectURL(mdBlob);
        mdLink.setAttribute("download", "pomodeep_export.md");
        mdLink.click();
        break;
      case 'pdf': window.print(); break;
    }
  };

  const activeTask = inbox.find(i => i.id === activeTaskId);

  // Calculate alerts badge
  const todayStr = new Date().toISOString().split('T')[0];
  const activeAlertsCount = inbox.filter(item => 
    item.status === 'scheduled' && 
    item.scheduledDate && 
    new Date(item.scheduledDate).toISOString().split('T')[0] <= todayStr
  ).length;

  return (
    <div className="flex flex-col min-h-screen bg-white dark:bg-black font-sans transition-colors duration-300 relative overflow-hidden">
      <QuickCapture isOpen={isQuickCaptureOpen} onClose={() => setIsQuickCaptureOpen(false)} categories={categories} onSave={saveNoteToInbox} timeLeft={timeLeft} timerMode={mode} language={settings.language} />
      <NotificationCenter isOpen={isNotificationsOpen} onClose={() => setIsNotificationsOpen(false)} items={inbox} onStartSession={handleStartTaskFocus} language={settings.language} />
      {isMenuOpen && <div className="fixed inset-0 bg-black/20 backdrop-blur-sm z-40 transition-opacity duration-300" onClick={() => setIsMenuOpen(false)} />}

      <main className="flex-1 p-8 overflow-y-auto w-full max-w-7xl mx-auto flex flex-col items-center pb-32">
        <header className="mb-8 w-full flex items-center justify-between relative z-50 px-2">
             <div className="flex items-center gap-3 cursor-pointer group" onClick={() => handleViewChange('timer')}>
                <div className="w-10 h-10 bg-pomo rounded-xl flex items-center justify-center shadow-lg shadow-pomo/30 flex-shrink-0 text-white transition-transform group-hover:scale-105">
                    <TimerIcon className="w-6 h-6" />
                </div>
                <div>
                    <h1 className="text-xl font-bold tracking-tight text-slate-900 dark:text-white leading-none">Pomo<span className="text-pomo">Deep</span></h1>
                    <p className="text-[9px] text-slate-400 font-medium tracking-widest uppercase mt-0.5">Focus OS</p>
                </div>
             </div>

             <div className="flex items-center gap-1.5">
                <button 
                  onClick={() => { setIsNotificationsOpen(true); if (isSoundEnabled) playSynthSound('toggle'); }}
                  className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90 relative"
                >
                  <Bell className="w-5 h-5" />
                  {activeAlertsCount > 0 && (
                    <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-amber-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center ring-2 ring-white dark:ring-black animate-pulse">
                      {activeAlertsCount}
                    </span>
                  )}
                </button>
                <button onClick={toggleSound} className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90">
                  {isSoundEnabled ? <Volume2 className="w-5 h-5" /> : < VolumeX className="w-5 h-5" />}
                </button>
                <button onClick={toggleDarkMode} className="p-2.5 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-all active:scale-90">
                  {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                </button>
                <div className="relative">
                  <button onClick={() => setIsMenuOpen(!isMenuOpen)} className={cn("p-2.5 rounded-full transition-all active:scale-90 relative", isMenuOpen ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800")}>
                    {isMenuOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
                  </button>
                  {isMenuOpen && (
                    <div className="absolute right-0 mt-3 w-64 bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 rounded-2xl shadow-2xl p-4 animate-in fade-in zoom-in-95 duration-200">
                        <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800 rounded-xl mb-4">
                            <div className="w-10 h-10 rounded-full bg-slate-200 dark:bg-slate-700 overflow-hidden ring-2 ring-white dark:ring-slate-900">
                                <img src="https://picsum.photos/100/100" alt="User" className="w-full h-full object-cover" />
                            </div>
                            <div className="flex flex-col leading-tight">
                                <p className="text-sm font-bold text-slate-900 dark:text-white">Alex Designer</p>
                                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{t.proPlan}</p>
                            </div>
                        </div>
                        <button onClick={() => { setIsQuickCaptureOpen(true); setIsMenuOpen(false); }} className="w-full bg-slate-900 hover:bg-slate-800 text-white p-3 rounded-xl flex items-center justify-center gap-2 transition-all mb-4 dark:bg-white dark:text-black dark:hover:bg-slate-200 font-bold text-sm">
                          <PenLine className="w-4 h-4" /> {t.quickCapture}
                        </button>
                        <nav className="space-y-1">
                          {[
                            { id: 'timer', icon: TimerIcon, label: t.focus },
                            { id: 'inbox', icon: InboxIcon, label: t.inbox },
                            { id: 'categories', icon: Tags, label: t.categories },
                            { id: 'dashboard', icon: BarChart2, label: t.stats },
                            { id: 'history', icon: HistoryIcon, label: t.history },
                            { id: 'settings', icon: SettingsIcon, label: t.settings },
                          ].map((item) => (
                            <button key={item.id} onClick={() => handleViewChange(item.id as View)} className={cn("w-full flex items-center justify-between px-4 py-3 rounded-xl transition-colors font-medium text-sm", currentView === item.id ? "bg-pomo/5 text-pomo dark:bg-pomo/10" : "text-slate-500 hover:bg-slate-50 dark:text-slate-400 dark:hover:bg-slate-800")}>
                              <div className="flex items-center gap-3"><item.icon className="w-4 h-4" />{item.label}</div>
                            </button>
                          ))}
                        </nav>
                    </div>
                  )}
                </div>
             </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 w-full flex-1">
            {currentView === 'timer' && (
            <Timer settings={settings} activeMode={mode} startSession={startSession} timeLeft={timeLeft} isActive={isActive} toggleTimer={toggleTimer} resetTimer={resetTimer} sessionsCompleted={sessionsCompleted} onNoteChange={setCurrentNote} currentNote={currentNote} categories={categories} onSaveNote={saveNoteToInbox} activeTask={activeTask} onStopTask={() => setActiveTaskId(null)} onGoToInbox={() => handleViewChange('inbox')} onUpdateTask={handleUpdateTask} />
            )}
            {currentView === 'inbox' && (
            <Inbox items={inbox} onAction={handleInboxAction} categories={categories} onStartSession={handleStartTaskFocus} onManageCategories={() => setCurrentView('categories')} onSaveNote={saveNoteToInbox} language={settings.language} />
            )}
            {currentView === 'categories' && <Categories categories={categories} onAdd={(c) => setCategories(prev => [...prev, c])} onDelete={(id) => setCategories(prev => prev.filter(c => c.id !== id))} inboxItems={inbox} language={settings.language} />}
            {currentView === 'dashboard' && <Dashboard credits={credits} onExport={handleGlobalExport} language={settings.language} />}
            {currentView === 'history' && <History history={history} language={settings.language} />}
            {currentView === 'settings' && <SettingsView settings={settings} onUpdateSettings={setSettings} onUpdateDuration={handleDurationChange} />}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { InboxItem, Category } from '../types';
import { calculateDaysAgo, cn } from '../utils';
import { 
    Trash2, CheckCircle, Play, Clock, Zap, CircleCheckBig, Edit3, Calendar, Bell, X
} from 'lucide-react';

interface InboxProps {
  items: InboxItem[];
  onAction: (id: string, action: 'complete' | 'delete' | 'schedule' | 'nextAction' | 'update', payload?: any) => void;
  categories?: Category[];
  onStartSession: (taskId: string) => void;
  onManageCategories: () => void;
  onSaveNote: (content: string, categoryId?: string, title?: string) => string;
  language?: 'en' | 'es';
}

const Inbox: React.FC<InboxProps> = ({ items, onAction, categories, onStartSession, onSaveNote, language = 'es' }) => {
  const [selectedItem, setSelectedItem] = useState<InboxItem | null>(null);
  const [confirmAction, setConfirmAction] = useState<{ id: string, type: 'delete' | 'resolve' } | null>(null);
  const [selectedFilterCategory, setSelectedFilterCategory] = useState<string>('');

  const [isNewTaskFormOpen, setIsNewTaskFormOpen] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskCategory, setNewTaskCategory] = useState('');

  const [scheduleDate, setScheduleDate] = useState<string>('');

  const [confetti, setConfetti] = useState<{id: number, x: number, y: number, color: string}[]>([]);

  const t = {
    es: {
      title: 'Bandeja de entrada',
      newTask: 'Nuevo focus time',
      all: 'Todas',
      noTag: 'Sin Etiqueta',
      today: 'Hoy',
      ago: 'Hace',
      days: 'd',
      noTasks: 'No hay tareas activas.',
      detailTitle: 'Detalle de Tarea',
      fieldTitle: 'Título',
      scheduleTitle: 'Agendar Alerta (Focus Time)',
      scheduleBtn: 'Agendar',
      contentTitle: 'Contenido (Sólo lectura)',
      noContent: 'Sin contenido adicional.',
      focusNow: 'Enfoque Ahora',
      cancel: 'Cancelar',
      confirm: 'Confirmar',
      confirmTitle: '¿Confirmar Acción?',
      archiveText: 'Se archivará la tarea como completada.',
      deleteText: 'Se eliminará permanentemente.',
      taskPlaceholder: 'Título del nuevo Focus...'
    },
    en: {
      title: 'Inbox',
      newTask: 'New focus time',
      all: 'All',
      noTag: 'No Tag',
      today: 'Today',
      ago: 'Ago',
      days: 'd',
      noTasks: 'No active tasks.',
      detailTitle: 'Task Detail',
      fieldTitle: 'Title',
      scheduleTitle: 'Schedule Alert (Focus Time)',
      scheduleBtn: 'Schedule',
      contentTitle: 'Content (Read-only)',
      noContent: 'No additional content.',
      focusNow: 'Focus Now',
      cancel: 'Cancel',
      confirm: 'Confirm',
      confirmTitle: 'Confirm Action?',
      archiveText: 'The task will be archived as completed.',
      deleteText: 'It will be permanently deleted.',
      taskPlaceholder: 'New Focus Title...'
    }
  }[language];

  const triggerConfetti = (e: React.MouseEvent) => {
      const colors = ['#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];
      const newConfetti = Array.from({ length: 20 }).map((_, i) => ({
          id: Date.now() + i, x: e.clientX, y: e.clientY,
          color: colors[Math.floor(Math.random() * colors.length)]
      }));
      setConfetti(prev => [...prev, ...newConfetti]);
      setTimeout(() => setConfetti(prev => prev.filter(c => !newConfetti.find(n => n.id === c.id))), 1000);
  };

  const filteredItems = items.filter(item => {
    const isNote = item.type === 'note' && item.status !== 'completed';
    const matchesCategory = !selectedFilterCategory || item.categoryId === selectedFilterCategory;
    return isNote && matchesCategory;
  });

  const getCategoryColor = (id?: string) => categories?.find(c => c.id === id)?.color || 'bg-slate-200 dark:bg-slate-700';
  const getCategoryName = (id?: string) => categories?.find(c => c.id === id)?.name || t.noTag;

  const handleUpdateItem = (updates: Partial<InboxItem>) => {
      if (selectedItem) {
          onAction(selectedItem.id, 'update', updates);
          setSelectedItem(prev => prev ? { ...prev, ...updates } : null);
      }
  };

  const handleCreateAndStartFocus = (e: React.FormEvent) => {
      e.preventDefault();
      if (!newTaskTitle.trim()) return;
      const defaultContent = language === 'es' ? "Acción Siguiente\n[ ] \n[ ] \n[ ] \n\n---\n\n" : "Next Action\n[ ] \n[ ] \n[ ] \n\n---\n\n";
      const newId = onSaveNote(defaultContent, newTaskCategory || undefined, newTaskTitle);
      onStartSession(newId);
      setIsNewTaskFormOpen(false);
      setNewTaskTitle('');
      setNewTaskCategory('');
  };

  const getStatusBadgeClass = (status: string) => {
      switch(status) {
          case 'in-progress': return 'text-amber-500 bg-amber-50 border-amber-100 dark:bg-amber-900/20 dark:border-amber-900';
          case 'scheduled': return 'text-blue-500 bg-blue-50 border-blue-100 dark:bg-blue-900/20 dark:border-blue-900';
          default: return 'text-slate-500 bg-slate-50 border-slate-100 dark:bg-slate-800 dark:border-slate-700';
      }
  };

  const renderCard = (item: InboxItem) => {
      const daysAgo = calculateDaysAgo(item.createdAt);
      return (
        <div key={item.id} className="group relative bg-white dark:bg-slate-900 rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm transition-all p-4 hover:shadow-md">
            <div className="flex justify-between items-center">
                 <div className="flex items-center flex-1 min-w-0">
                    <button 
                        onClick={(e) => { e.stopPropagation(); triggerConfetti(e); setConfirmAction({ id: item.id, type: 'resolve' }); }} 
                        className="w-5 h-5 rounded-full border-2 border-slate-300 dark:border-slate-600 mr-4 flex items-center justify-center text-transparent hover:border-green-500 hover:text-green-500 transition-all shrink-0"
                    >
                        <CircleCheckBig className="w-4 h-4" />
                    </button>

                    <div className="flex-1 min-w-0 cursor-pointer" onClick={() => { setSelectedItem(item); setScheduleDate(item.scheduledDate ? new Date(item.scheduledDate).toISOString().split('T')[0] : ''); }}>
                        <h4 className="text-sm font-bold text-slate-800 dark:text-slate-100 truncate mb-1">{item.title}</h4>
                        <div className="flex flex-wrap items-center gap-3 text-[10px] font-bold tracking-wider uppercase">
                            <span className={cn("px-2 py-0.5 rounded border", getStatusBadgeClass(item.status))}>
                                {item.status.replace('-', ' ')}
                            </span>
                            {item.categoryId && (
                                <span className="flex items-center gap-1.5 text-slate-500 dark:text-slate-400">
                                    <span className={cn("w-2 h-2 rounded-full", getCategoryColor(item.categoryId))} />
                                    {getCategoryName(item.categoryId)}
                                </span>
                            )}
                            <span className="text-slate-400 flex items-center gap-1">
                                <Calendar className="w-3 h-3" /> {daysAgo === 0 ? t.today : `${t.ago} ${daysAgo}${t.days}`}
                            </span>
                            {item.scheduledDate && (
                                <span className="text-blue-500 flex items-center gap-1">
                                    <Bell className="w-3 h-3" /> {new Date(item.scheduledDate).toLocaleDateString(language === 'es' ? 'es-ES' : 'en-US', { day: 'numeric', month: 'short' })}
                                </span>
                            )}
                        </div>
                    </div>
                 </div>

                 <div className="flex gap-1 ml-4 shrink-0">
                    <button onClick={() => { setSelectedItem(item); setScheduleDate(item.scheduledDate ? new Date(item.scheduledDate).toISOString().split('T')[0] : ''); }} className="p-2 text-slate-400 hover:text-pomo hover:bg-slate-50 rounded-lg transition-all dark:hover:bg-slate-800">
                        <Edit3 className="w-4 h-4" />
                    </button>
                    <button onClick={() => onStartSession(item.id)} className="p-2 bg-pomo text-white rounded-lg shadow-lg shadow-pomo/20 hover:scale-105 active:scale-95 transition-all">
                        <Play className="w-4 h-4 fill-current" />
                    </button>
                 </div>
            </div>
        </div>
      );
  };

  return (
    <div className="w-full max-w-5xl mx-auto py-8 px-4 relative">
      <div className="fixed inset-0 pointer-events-none z-[100]">
          {confetti.map(c => (
              <div key={c.id} className="absolute w-2 h-2 rounded-full animate-ping" style={{ left: c.x, top: c.y, backgroundColor: c.color }} />
          ))}
      </div>

      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-4">
        <div><h2 className="text-2xl font-bold text-slate-900 dark:text-white">{t.title}</h2></div>
        <div className="flex items-center gap-2">
             <button onClick={() => setIsNewTaskFormOpen(!isNewTaskFormOpen)} className="px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 transition-all bg-pomo text-white shadow-lg"><Zap className="w-4 h-4" /> {t.newTask}</button>
        </div>
      </div>

      {isNewTaskFormOpen && (
          <form onSubmit={handleCreateAndStartFocus} className="mb-8 bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl animate-in slide-in-from-top-4">
              <div className="flex flex-col gap-4">
                  <input type="text" autoFocus value={newTaskTitle} onChange={(e) => setNewTaskTitle(e.target.value)} placeholder={t.taskPlaceholder} className="w-full bg-slate-50 dark:bg-slate-800 p-4 rounded-xl text-lg font-bold outline-none border border-transparent focus:border-pomo/30 transition-all dark:text-white" />
                  <div className="flex items-center gap-3">
                      <select value={newTaskCategory} onChange={(e) => setNewTaskCategory(e.target.value)} className="flex-1 bg-slate-50 dark:bg-slate-800 p-3 rounded-xl text-sm font-bold outline-none dark:text-white">
                        <option value="">{t.noTag}</option>
                        {categories?.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                      </select>
                      <button type="submit" disabled={!newTaskTitle.trim()} className="bg-pomo text-white p-3 px-6 rounded-xl shadow-xl font-bold">{t.focusNow}</button>
                  </div>
              </div>
          </form>
      )}

      {categories && categories.length > 0 && (
          <div className="flex items-center gap-4 mb-6 overflow-x-auto pb-2 no-scrollbar">
              <button onClick={() => setSelectedFilterCategory('')} className={cn("px-4 py-1.5 rounded-full text-xs font-bold transition-all border shrink-0", !selectedFilterCategory ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-white text-slate-500 border-slate-200 dark:bg-slate-800")}>{t.all}</button>
              {categories.map(cat => <button key={cat.id} onClick={() => setSelectedFilterCategory(cat.id)} className={cn("px-4 py-1.5 rounded-full text-xs font-bold transition-all border flex items-center gap-2 shrink-0", selectedFilterCategory === cat.id ? "bg-slate-900 text-white dark:bg-white dark:text-black" : "bg-white text-slate-500 border-slate-200 dark:bg-slate-800")}><span className={cn("w-2 h-2 rounded-full", cat.color)} />{cat.name}</button>)}
          </div>
      )}

      <div className="grid gap-3">{filteredItems.length === 0 ? <p className="text-center py-16 text-slate-400 italic">{t.noTasks}</p> : filteredItems.map(renderCard)}</div>

      {selectedItem && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setSelectedItem(null)} />
              <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-2xl shadow-2xl p-6 border dark:border-slate-800 animate-in fade-in zoom-in-95 max-h-[90vh] overflow-y-auto">
                   <div className="flex items-center justify-between mb-4">
                        <div className="flex items-center gap-2 text-slate-400">
                            <Edit3 className="w-4 h-4" />
                            <span className="text-[10px] font-bold uppercase tracking-widest">{t.detailTitle}</span>
                        </div>
                        <button onClick={() => setSelectedItem(null)} className="text-slate-400 hover:text-slate-600 dark:hover:text-white"><X className="w-5 h-5" /></button>
                   </div>

                   <div className="space-y-6">
                       <section>
                           <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">{t.fieldTitle}</label>
                           <input 
                                value={selectedItem.title} 
                                onChange={(e) => handleUpdateItem({ title: e.target.value })} 
                                className="text-lg font-bold dark:text-white w-full bg-slate-50 dark:bg-slate-800 p-3 rounded-xl border border-transparent focus:border-pomo/30 outline-none" 
                           />
                       </section>

                       <section>
                           <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">{t.scheduleTitle}</label>
                           <div className="flex gap-2">
                               <input 
                                    type="date"
                                    value={scheduleDate}
                                    onChange={(e) => setScheduleDate(e.target.value)}
                                    className="flex-1 bg-slate-50 dark:bg-slate-800 p-3 rounded-xl text-sm font-bold border border-transparent focus:border-blue-500/30 outline-none dark:text-white"
                               />
                               <button 
                                 onClick={() => {
                                     if (scheduleDate) {
                                         onAction(selectedItem.id, 'schedule', { date: new Date(scheduleDate) });
                                         setSelectedItem(null);
                                     }
                                 }}
                                 disabled={!scheduleDate}
                                 className="px-6 bg-blue-600 text-white rounded-xl font-bold text-xs disabled:opacity-50 hover:bg-blue-700 transition-colors"
                               >
                                   {t.scheduleBtn}
                               </button>
                           </div>
                       </section>

                       <section>
                           <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">{t.contentTitle}</label>
                           <div className="w-full bg-slate-100 dark:bg-slate-800/50 border rounded-xl p-4 text-xs text-slate-500 dark:text-slate-400 italic max-h-32 overflow-y-auto custom-scrollbar">
                               {selectedItem.noteContent || t.noContent}
                           </div>
                       </section>

                       <div className="pt-4 flex gap-3">
                           <button onClick={() => { onStartSession(selectedItem.id); setSelectedItem(null); }} className="flex-1 bg-pomo text-white py-3 rounded-xl font-bold shadow-lg flex items-center justify-center gap-2"><Play className="w-4 h-4 fill-current" /> {t.focusNow}</button>
                           <button onClick={() => setConfirmAction({ id: selectedItem.id, type: 'delete' })} className="p-3 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-400 hover:text-red-500 transition-colors"><Trash2 className="w-5 h-5" /></button>
                           <button onClick={() => setConfirmAction({ id: selectedItem.id, type: 'resolve' })} className="p-3 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-400 hover:text-green-500 transition-colors"><CheckCircle className="w-4 h-4" /></button>
                       </div>
                   </div>
              </div>
          </div>
      )}

      {confirmAction && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
              <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setConfirmAction(null)} />
              <div className="relative bg-white dark:bg-slate-900 w-full max-sm rounded-2xl p-6 text-center shadow-2xl border dark:border-slate-800 animate-in fade-in zoom-in-95">
                  <h3 className="text-lg font-bold dark:text-white mb-2">{t.confirmTitle}</h3>
                  <p className="text-sm text-slate-500 dark:text-slate-400 mb-6">{confirmAction.type === 'resolve' ? t.archiveText : t.deleteText}</p>
                  <div className="flex gap-3">
                    <button onClick={() => setConfirmAction(null)} className="flex-1 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 font-medium dark:text-slate-300">{t.cancel}</button>
                    <button onClick={(e) => { 
                        if(confirmAction.type === 'resolve') {
                            triggerConfetti(e);
                            onAction(confirmAction.id, 'update', { status: 'completed' });
                        } else {
                            onAction(confirmAction.id, 'delete');
                        }
                        setConfirmAction(null); 
                    }} className={cn("flex-1 py-2.5 rounded-xl text-white font-medium shadow-lg", confirmAction.type === 'resolve' ? "bg-green-600 hover:bg-green-700" : "bg-red-600 hover:bg-red-700")}>{t.confirm}</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default Inbox;

import React, { useState } from 'react';
import { Category, InboxItem } from '../types';
import { Plus, Trash2, Tag, ArrowLeft, Clock } from 'lucide-react';
import { generateId, cn } from '../utils';

interface CategoriesProps {
  categories: Category[];
  onAdd: (category: Category) => void;
  onDelete: (id: string) => void;
  inboxItems: InboxItem[];
  language?: 'en' | 'es';
