                      "w-7 h-7 rounded-full transition-all hover:scale-125",
                      c.value,
                      selectedColor === c.value ? "ring-2 ring-offset-2 ring-pomo scale-110 shadow-lg shadow-pomo/20" : "opacity-80"
                    )}
                    title={c.name}
                  />
                ))}
              </div>
