import React, { useState } from 'react';
import { SessionHistoryItem, TimerMode } from '../types';
import { cn } from '../utils';

interface HistoryProps {
  history: SessionHistoryItem[];
  language?: 'en' | 'es';
}

const History: React.FC<HistoryProps> = ({ history, language = 'es' }) => {
  const [filterMode, setFilterMode] = useState<'ALL' | TimerMode>('ALL');

  const defaultStartDate = new Date();
  defaultStartDate.setDate(defaultStartDate.getDate() - 30);

  const [startDate, setStartDate] = useState<string>(defaultStartDate.toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState<string>(new Date().toISOString().split('T')[0]);

  const t = {
    es: {
      from: 'Desde',
      to: 'Hasta',
      type: 'Tipo de Sesión',
      allTypes: 'Todos los tipos',
      totalTime: 'Tiempo Total',
      colDateTime: 'Fecha y Hora',
      colType: 'Tipo',
      colDuration: 'Duración',
      colNotes: 'Resumen de Notas',
      noSessions: 'No se encontraron sesiones en este período.',
      focus: 'Enfoque',
      shortBreak: 'Descanso Corto',
      longBreak: 'Descanso Largo'
    },
    en: {
      from: 'From',
      to: 'To',
      type: 'Session Type',
      allTypes: 'All Types',
      totalTime: 'Total Time',
      colDateTime: 'Date & Time',
      colType: 'Type',
      colDuration: 'Duration',
      colNotes: 'Notes Snapshot',
      noSessions: 'No sessions found for this period.',
      focus: 'Focus',
      shortBreak: 'Short Break',
      longBreak: 'Long Break'
    }
  }[language];

  const filteredHistory = history.filter(item => {
    const itemDate = new Date(item.startTime);
    const start = new Date(startDate);
    const end = new Date(endDate);
    end.setHours(23, 59, 59, 999); 

    const dateMatch = itemDate >= start && itemDate <= end;
    const modeMatch = filterMode === 'ALL' || item.mode === filterMode;

    return dateMatch && modeMatch;
  });

  const totalMinutes = filteredHistory.reduce((acc, curr) => acc + curr.duration, 0);

  return (
    <div className="w-full max-w-5xl mx-auto py-8 px-4 space-y-8">

      <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 dark:bg-slate-900 dark:border-slate-800">
        <div className="flex flex-col md:flex-row gap-6 items-end md:items-center justify-between">
          <div className="flex flex-col md:flex-row gap-4 w-full md:w-auto">
            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-1 dark:text-slate-400">{t.from}</label>
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-red-500 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-1 dark:text-slate-400">{t.to}</label>
              <input 
                type="date" 
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-red-500 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
              />
            </div>
            <div className="w-full md:w-48">
              <label className="block text-xs font-semibold text-slate-500 mb-1 dark:text-slate-400">{t.type}</label>
              <select 
                value={filterMode}
                onChange={(e) => setFilterMode(e.target.value as 'ALL' | TimerMode)}
                className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-900 outline-none focus:ring-2 focus:ring-red-500 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-200"
              >
                <option value="ALL">{t.allTypes}</option>
                <option value={TimerMode.FOCUS}>{t.focus}</option>
                <option value={TimerMode.SHORT_BREAK}>{t.shortBreak}</option>
                <option value={TimerMode.LONG_BREAK}>{t.longBreak}</option>
              </select>
            </div>
          </div>

          <div className="text-right">
             <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">{t.totalTime}</p>
             <p className="text-2xl font-bold text-slate-900 dark:text-white">
                {Math.floor(totalMinutes / 60)}h {totalMinutes % 60}m
             </p>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden dark:bg-slate-900 dark:border-slate-800">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100 dark:bg-slate-800 dark:border-slate-700">
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider dark:text-slate-400">{t.colDateTime}</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider dark:text-slate-400">{t.colType}</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider dark:text-slate-400">{t.colDuration}</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-500 uppercase tracking-wider dark:text-slate-400">{t.colNotes}</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {filteredHistory.length > 0 ? filteredHistory.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors dark:hover:bg-slate-800/50">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                        <span className="text-sm font-medium text-slate-900 dark:text-slate-200">{item.startTime.toLocaleDateString(language === 'es' ? 'es-ES' : 'en-US')}</span>
                        <span className="text-xs text-slate-500 dark:text-slate-500">
                            {item.startTime.toLocaleTimeString(language === 'es' ? 'es-ES' : 'en-US', {hour: '2-digit', minute:'2-digit'})} - 
                            {item.endTime.toLocaleTimeString(language === 'es' ? 'es-ES' : 'en-US', {hour: '2-digit', minute:'2-digit'})}
                        </span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={cn(
                        "px-2 py-1 rounded-full text-xs font-semibold",
                        item.mode === TimerMode.FOCUS ? "bg-red-50 text-red-700 dark:bg-red-900/30 dark:text-red-400" :
                        "bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-400"
                    )}>
                        {item.mode === TimerMode.FOCUS ? t.focus : item.mode === TimerMode.SHORT_BREAK ? t.shortBreak : t.longBreak}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600 dark:text-slate-400">
                    {item.duration} min
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-400 max-w-xs truncate">
                    {item.noteSnapshot || <span className="text-slate-300 dark:text-slate-600 italic">{language === 'es' ? 'Sin notas' : 'No notes'}</span>}
                  </td>
                </tr>
              )) : (
                <tr>
                    <td colSpan={4} className="px-6 py-12 text-center text-slate-500 dark:text-slate-400">
                        {t.noSessions}
                    </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default History;

import React, { useState } from 'react';
import { X, Send, Sparkles, Loader2, PenLine, Clock } from 'lucide-react';
import { Category, TimerMode } from '../types';
import { cn, formatTime } from '../utils';
import { GoogleGenAI } from "@google/genai";

interface QuickCaptureProps {
  isOpen: boolean;
  onClose: () => void;
  categories: Category[];
  onSave: (content: string, categoryId?: string, title?: string) => void;
  timeLeft: number;
  timerMode: TimerMode;
  language?: 'en' | 'es';
}

const QuickCapture: React.FC<QuickCaptureProps> = ({ isOpen, onClose, categories, onSave, timeLeft, timerMode, language = 'es' }) => {
  const [title, setTitle] = useState('');
  const [note, setNote] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const t = {
    es: {
      title: 'Captura Rápida',
      placeholderTitle: 'Título de la tarea...',
      placeholderNote: 'Captura pensamientos o notas...',
      aiAssist: 'Asistente IA',
      noTag: 'Sin Etiqueta',
      cancel: 'Cancelar',
      save: 'Guardar'
    },
    en: {
      title: 'Quick Capture',
      placeholderTitle: 'Task Title...',
      placeholderNote: 'Capture thoughts or notes...',
      aiAssist: 'AI Assist',
      noTag: 'No Tag',
      cancel: 'Cancel',
      save: 'Save'
    }
  }[language];

  if (!isOpen) return null;

  const handleSave = () => {
    if (!title.trim() && !note.trim()) return;
    onSave(note, selectedCategory, title);
    setTitle('');
    setNote('');
    onClose();
  };

  const handleAskAI = async () => {
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = language === 'es' ? "Genera 3 consejos cortos de productividad para el contexto actual. Sé muy breve." : "Generate 3 short productivity tips for the current context. Keep it very brief.";
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });

      const text = response.text;
      if (text) {
        setNote(prev => prev + (prev ? '\n\n' : '') + (language === 'es' ? "✨ Ideas IA:\n" : "✨ AI Ideas:\n") + text);
      }
    } catch (error) {
      console.error("AI Error:", error);
    } finally {
      setIsAiLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" onClick={onClose} />
      <div className="absolute top-12 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur-md border border-white/20 text-white px-6 py-2 rounded-full flex items-center gap-3 shadow-2xl animate-in fade-in slide-in-from-top-4 duration-500 pointer-events-none">
         <Clock className={cn("w-4 h-4", timerMode === TimerMode.FOCUS ? "text-pomo-light" : "text-emerald-400")} />
         <span className="font-mono text-xl font-bold tracking-widest tabular-nums">{formatTime(timeLeft)}</span>
      </div>
      <div className="relative bg-white dark:bg-slate-900 w-full max-w-lg rounded-2xl shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
        <div className="flex items-center justify-between p-4 border-b border-slate-100 dark:border-slate-800">
           <div className="flex items-center gap-2 text-slate-900 dark:text-white font-bold text-lg">
                <PenLine className="w-5 h-5 text-pomo" />
                <h3>{t.title}</h3>
            </div>
          <button onClick={onClose} className="text-slate-400 hover:text-pomo hover:bg-red-50 dark:hover:bg-red-900/20 p-2 rounded-xl transition-all"><X className="w-6 h-6" /></button>
        </div>
        <div className="p-6 space-y-4">
          <input 
            type="text" 
            value={title} 
            onChange={(e) => setTitle(e.target.value)} 
            placeholder={t.placeholderTitle} 
            className="w-full bg-slate-50 dark:bg-slate-800 border-none rounded-xl px-4 py-3 text-lg font-bold outline-none focus:ring-2 focus:ring-pomo/10 dark:text-white"
          />
          <textarea
            value={note}
            onChange={(e) => setNote(e.target.value)}
            placeholder={t.placeholderNote}
            className="w-full h-32 bg-slate-50 border-0 rounded-xl p-4 text-slate-700 focus:outline-none focus:ring-2 focus:ring-pomo/10 resize-none dark:bg-slate-800 dark:text-slate-200 placeholder:text-slate-400 text-base"
          />
          <div className="flex items-center justify-between">
              <button onClick={handleAskAI} disabled={isAiLoading} className={cn("text-xs font-bold flex items-center gap-2 transition-all px-4 py-2 rounded-xl", isAiLoading ? "text-slate-400" : "text-violet-600 bg-violet-50 hover:bg-violet-100 dark:bg-violet-900/20")}>
                {isAiLoading ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
                {t.aiAssist}
            </button>
            <select value={selectedCategory} onChange={(e) => setSelectedCategory(e.target.value)} className="bg-white border border-slate-200 rounded-xl px-4 py-2 text-sm text-slate-600 outline-none focus:border-pomo dark:bg-slate-800 dark:border-slate-700 dark:text-slate-300">
                <option value="">{t.noTag}</option>
                {categories.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
            </select>
          </div>
        </div>
        <div className="p-4 bg-slate-50 dark:bg-slate-800/50 flex justify-end gap-3">
             <button onClick={onClose} className="px-6 py-2.5 rounded-xl font-bold text-slate-500 hover:bg-slate-200 dark:text-slate-400 dark:hover:bg-slate-700 transition-colors">{t.cancel}</button>
             <button onClick={handleSave} disabled={!title.trim() && !note.trim()} className="bg-pomo text-white px-8 py-2.5 rounded-xl font-bold shadow-xl shadow-pomo/20 hover:bg-pomo-dark transition-all flex items-center gap-2"><Send className="w-4 h-4" />{t.save}</button>
        </div>
      </div>
    </div>
  );
};

export default QuickCapture;

